fn parse_serve_args(args: &[OsString]) -> Result<Option<ServeInvocation>, String> {
    let direct_controller_invocation =
        args.first()
            .and_then(|value| value.to_str())
            .is_some_and(|value| {
                let flag = value.split_once('=').map_or(value, |(flag, _)| flag);
                controller_cli_environment_name(flag).is_some()
            });
    if args.first().is_none_or(|arg| arg != "serve") && !direct_controller_invocation {
        return Ok(None);
    }

    let mut invocation = ServeInvocation::default();
    let mut index = usize::from(args.first().is_some_and(|arg| arg == "serve"));
    while index < args.len() {
        let raw = args[index]
            .to_str()
            .ok_or_else(|| "serve arguments must be valid UTF-8".to_owned())?;
        if raw == "--once" {
            if invocation.once {
                return Err("duplicate serve option --once".to_owned());
            }
            invocation.once = true;
            index += 1;
            continue;
        }
        let (flag, inline_value) = raw
            .split_once('=')
            .map_or((raw, None), |(flag, value)| (flag, Some(value)));
        let Some((environment_name, takes_value)) = controller_cli_environment_name(flag) else {
            return Err(format!("unknown serve option {flag}"));
        };
        let multi_valued = matches!(
            environment_name,
            "SLSKD_SHARED_DIR" | "SLSKD_SHARE_FILTER" | "SLSKD_SEARCH_REQUEST_FILTER"
        );
        if invocation.config_environment.contains_key(environment_name) && !multi_valued {
            return Err(format!("duplicate serve option {flag}"));
        }
        let value = if takes_value {
            if let Some(value) = inline_value {
                if value.is_empty() {
                    return Err(format!("{flag} requires a value"));
                }
                value.to_owned()
            } else {
                index += 1;
                args.get(index)
                    .and_then(|value| value.to_str())
                    .filter(|value| !value.is_empty())
                    .ok_or_else(|| format!("{flag} requires a value"))?
                    .to_owned()
            }
        } else {
            if inline_value.is_some() {
                return Err(format!("{flag} does not accept a value"));
            }
            "true".to_owned()
        };
        invocation
            .config_environment
            .entry(environment_name.to_owned())
            .and_modify(|current| {
                current.push(';');
                current.push_str(&value);
            })
            .or_insert(value);
        index += 1;
    }
    Ok(Some(invocation))
}

#[derive(Clone, Debug)]
struct ShareRoot {
    label: String,
    local_path: PathBuf,
    raw: String,
    directories: usize,
    files: usize,
    bytes: u64,
    extensions: Vec<ShareExtensionSummary>,
    statistics_ready: bool,
}

#[derive(Clone, Debug)]
struct ShareExtensionSummary {
    extension: String,
    files: usize,
    bytes: u64,
}

impl ShareExtensionSummary {
    fn json(&self) -> String {
        format!(
            "{{\"extension\":\"{}\",\"files\":{},\"bytes\":{}}}",
            json_escape(&self.extension),
            self.files,
            self.bytes
        )
    }
}

impl ShareRoot {
    fn json(&self) -> String {
        let extensions = self
            .extensions
            .iter()
            .map(ShareExtensionSummary::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"label\":\"{}\",\"files\":{},\"bytes\":{},\"extensions\":[{}]}}",
            json_escape(&self.label),
            self.files,
            self.bytes,
            extensions
        )
    }
}

fn slskd_share_value(root: &ShareRoot) -> serde_json::Value {
    let mut value = serde_json::json!({
        "localPath": root.local_path.display().to_string(),
        "id": share_root_id(&root.label),
        "alias": root.label,
        "raw": root.raw,
        "remotePath": root.label,
        "isExcluded": root.raw.starts_with(['!', '-']),
    });
    if root.statistics_ready {
        value["directories"] = serde_json::json!(root.directories);
        value["files"] = serde_json::json!(root.files);
    }
    value
}

#[derive(Clone, Debug)]
struct ShareScan {
    entries: Vec<FileEntry>,
    local_paths: BTreeMap<String, PathBuf>,
    roots: Vec<ShareRoot>,
    errors: Vec<String>,
}

#[derive(Clone, Copy, Debug)]
struct ShareScanOptions {
    follow_symlinks: bool,
    include_hidden: bool,
    max_files: usize,
    probe_media_attributes: bool,
}

const MAX_SHARE_SCAN_ENTRIES: usize = 65_536;
#[cfg(unix)]
const MAX_SHARE_SCAN_PENDING_DIRECTORIES: usize = 256;
const SHARE_SCAN_ENTRY_LIMIT_ERROR: &str = "share scan stopped at aggregate directory entry limit";
#[cfg(unix)]
const SHARE_SCAN_PENDING_DIRECTORY_LIMIT_ERROR: &str =
    "share scan stopped at pending directory limit";

fn reserve_share_scan_entry(scanned_entries: &mut usize) -> bool {
    if *scanned_entries >= MAX_SHARE_SCAN_ENTRIES {
        return false;
    }
    *scanned_entries += 1;
    true
}

#[derive(Clone, Debug)]
struct ShareIndexSnapshot {
    entries: Vec<FileEntry>,
    local_paths: BTreeMap<String, PathBuf>,
    roots: Vec<ShareRoot>,
    fixture_files: usize,
    scan_errors: Vec<String>,
    cache_path: PathBuf,
    cache_enabled: bool,
    cache_written_at: Option<u64>,
    cache_error: Option<String>,
    updated_at: u64,
}

#[derive(Clone, Debug)]
struct ShareLifecycleState {
    scan_pending: bool,
    scanning: bool,
    ready: bool,
    faulted: bool,
    cancelled: bool,
    scan_progress: f64,
    directories: usize,
    files: usize,
}

impl ShareLifecycleState {
    fn from_snapshot(snapshot: &ShareIndexSnapshot) -> Self {
        Self {
            scan_pending: false,
            scanning: false,
            ready: true,
            faulted: false,
            cancelled: false,
            scan_progress: 1.0,
            directories: snapshot.roots.iter().map(|root| root.directories).sum(),
            files: snapshot.entries.len(),
        }
    }

    fn uninitialized() -> Self {
        Self {
            scan_pending: false,
            scanning: false,
            ready: false,
            faulted: false,
            cancelled: false,
            scan_progress: 0.0,
            directories: 0,
            files: 0,
        }
    }

    fn json(&self, target: ControllerCompatibilityTarget) -> serde_json::Value {
        let scan_progress = if self.scan_progress.fract() == 0.0 {
            serde_json::json!(self.scan_progress as u64)
        } else {
            serde_json::json!(self.scan_progress)
        };
        let mut value = serde_json::json!({
            "scanPending": self.scan_pending,
            "scanning": self.scanning,
            "ready": self.ready,
            "faulted": self.faulted,
            "cancelled": self.cancelled,
            "scanProgress": scan_progress,
            "directories": self.directories,
            "files": self.files,
        });
        if self.ready {
            value["hosts"] = serde_json::json!(["local"]);
        } else if target == ControllerCompatibilityTarget::Slskdn {
            value["hosts"] = serde_json::json!([]);
        }
        value
    }
}

fn pending_share_roots(settings: &crate::config::ShareSettings) -> Vec<ShareRoot> {
    let mut directories = settings.directories.iter().collect::<Vec<_>>();
    directories.sort_by(|left, right| {
        right
            .local_path
            .as_os_str()
            .len()
            .cmp(&left.local_path.as_os_str().len())
    });
    directories
        .into_iter()
        .map(|directory| ShareRoot {
            label: directory.alias.clone(),
            local_path: directory.local_path.clone(),
            raw: directory.raw.clone(),
            directories: 0,
            files: 0,
            bytes: 0,
            extensions: Vec::new(),
            statistics_ready: false,
        })
        .collect()
}

impl ShareIndexSnapshot {
    fn uninitialized(config: &AppConfig) -> Self {
        Self {
            entries: Vec::new(),
            local_paths: BTreeMap::new(),
            roots: pending_share_roots(&config.share_settings),
            fixture_files: 0,
            scan_errors: Vec::new(),
            cache_path: share_cache_path(&config.state_dir),
            cache_enabled: config.share_settings.cache_tsv_enabled,
            cache_written_at: None,
            cache_error: None,
            updated_at: unix_timestamp(),
        }
    }

    fn json(&self) -> String {
        let roots = self
            .roots
            .iter()
            .map(ShareRoot::json)
            .collect::<Vec<_>>()
            .join(",");
        let errors = self
            .scan_errors
            .iter()
            .map(|error| json_option(Some(error.as_str())))
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"roots\":[{}],\"files\":{},\"fixture_files\":{},\"scan_errors\":[{}],\"cache_file\":\"{}\",\"cache_enabled\":{},\"cache_kind\":\"compatibility-debug\",\"cache_written_at\":{},\"cache_error\":{},\"updated_at\":{}}}",
            roots,
            self.entries.len(),
            self.fixture_files,
            errors,
            json_escape(
                self.cache_path
                    .file_name()
                    .and_then(|name| name.to_str())
                    .unwrap_or("share-index.tsv")
            ),
            self.cache_enabled,
            json_u64_option(self.cache_written_at),
            json_option(public_share_cache_error(self.cache_error.as_deref())),
            self.updated_at
        )
    }

    fn summary_json(&self) -> String {
        let bytes = self.entries.iter().map(|entry| entry.size).sum::<u64>();
        format!(
            "{{\"roots\":{},\"files\":{},\"fixture_files\":{},\"bytes\":{},\"scan_errors\":{},\"cache_enabled\":{},\"cache_error\":{},\"updated_at\":{}}}",
            self.roots.len(),
            self.entries.len(),
            self.fixture_files,
            bytes,
            self.scan_errors.len(),
            self.cache_enabled,
            self.cache_error.is_some(),
            self.updated_at
        )
    }

    fn catalog_json(&self, query: Option<&str>) -> String {
        let filter = CatalogFilter::from_query(query);
        let mut entries = self
            .entries
            .iter()
            .filter(|entry| filter.matches(entry))
            .collect::<Vec<_>>();
        entries.sort_by(|left, right| left.filename.cmp(&right.filename));
        let filtered_count = entries.len();
        let total_bytes = entries.iter().map(|entry| entry.size).sum::<u64>();
        let files = entries
            .iter()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(|entry| {
                format!(
                    "{{\"path\":\"{}\",\"size\":{},\"extension\":\"{}\",\"attribute_count\":{}}}",
                    json_escape(&entry.filename),
                    entry.size,
                    json_escape(&entry.extension),
                    entry.attributes.len()
                )
            })
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"files\":[{}],\"count\":{},\"filtered_count\":{},\"total_bytes\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            files,
            self.entries.len(),
            filtered_count,
            total_bytes,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn from_persisted(config: &AppConfig, records: Vec<persistence::ShareFileRecord>) -> Self {
        let updated_at = records
            .iter()
            .map(|record| record.updated_at.max(0) as u64)
            .max()
            .unwrap_or_else(unix_timestamp);
        let mut local_paths = BTreeMap::new();
        let entries = records
            .iter()
            .map(|record| {
                if let Some(local_path) = record
                    .local_path
                    .as_deref()
                    .filter(|value| !value.trim().is_empty())
                {
                    local_paths.insert(record.filename.clone(), PathBuf::from(local_path));
                }
                FileEntry {
                    filename_encoding: Default::default(),
                    extension_encoding: Default::default(),
                    code: 1,
                    filename: record.filename.clone(),
                    size: record.size.max(0) as u64,
                    extension: record.extension.clone(),
                    attributes: decode_share_attributes(&record.attributes_json),
                }
            })
            .collect::<Vec<_>>();
        let roots = summarize_share_roots_from_persisted(config, &records);
        let cache_path = share_cache_path(&config.state_dir);
        let (cache_written_at, cache_error) = write_share_cache_if_enabled(
            config.share_settings.cache_tsv_enabled,
            &cache_path,
            &entries,
        );
        Self {
            entries,
            local_paths,
            roots,
            fixture_files: 0,
            scan_errors: Vec::new(),
            cache_path,
            cache_enabled: config.share_settings.cache_tsv_enabled,
            cache_written_at,
            cache_error,
            updated_at,
        }
    }
}

fn public_share_cache_error(error: Option<&str>) -> Option<&'static str> {
    error.map(|_| "share cache unavailable")
}

fn summarize_share_roots_from_persisted(
    config: &AppConfig,
    records: &[persistence::ShareFileRecord],
) -> Vec<ShareRoot> {
    let mut grouped = BTreeMap::<String, Vec<FileEntry>>::new();
    for record in records {
        grouped
            .entry(record.root_label.clone())
            .or_default()
            .push(FileEntry {
                filename_encoding: Default::default(),
                extension_encoding: Default::default(),
                code: 1,
                filename: record.filename.clone(),
                size: record.size.max(0) as u64,
                extension: record.extension.clone(),
                attributes: Vec::new(),
            });
    }
    let mut ordered_directories = config.share_settings.directories.iter().collect::<Vec<_>>();
    ordered_directories.sort_by(|left, right| {
        right
            .local_path
            .as_os_str()
            .len()
            .cmp(&left.local_path.as_os_str().len())
    });
    let mut roots = ordered_directories
        .into_iter()
        .map(|directory| {
            let entries = grouped.remove(&directory.alias).unwrap_or_default();
            ShareRoot {
                label: directory.alias.clone(),
                local_path: directory.local_path.clone(),
                raw: directory.raw.clone(),
                directories: persisted_share_directory_count(&entries),
                files: entries.len(),
                bytes: entries.iter().map(|entry| entry.size).sum(),
                extensions: summarize_extensions(&entries),
                statistics_ready: true,
            }
        })
        .collect::<Vec<_>>();
    roots.extend(grouped.into_iter().map(|(label, entries)| ShareRoot {
        local_path: PathBuf::from(&label),
        raw: label.clone(),
        directories: persisted_share_directory_count(&entries),
        label,
        files: entries.len(),
        bytes: entries.iter().map(|entry| entry.size).sum(),
        extensions: summarize_extensions(&entries),
        statistics_ready: true,
    }));
    roots
}

fn persisted_share_directory_count(entries: &[FileEntry]) -> usize {
    entries
        .iter()
        .filter_map(|entry| entry.filename.split_once('/').map(|(_, path)| path))
        .filter_map(|path| path.rsplit_once('/').map(|(directory, _)| directory))
        .flat_map(|directory| {
            let parts = directory.split('/').collect::<Vec<_>>();
            (1..=parts.len())
                .map(move |count| parts[..count].join("/"))
                .collect::<Vec<_>>()
        })
        .collect::<HashSet<_>>()
        .len()
}

#[derive(Debug, Default)]
struct CatalogFilter {
    q: Option<String>,
    prefix: Option<String>,
    extension: Option<String>,
    limit: Option<usize>,
    offset: usize,
}

impl CatalogFilter {
    fn from_query(query: Option<&str>) -> Self {
        let mut filter = Self {
            limit: Some(DEFAULT_LIST_LIMIT),
            ..Self::default()
        };
        for (name, value) in query_params(query.unwrap_or_default()) {
            match name.as_str() {
                "q" => filter.q = non_empty(value.to_ascii_lowercase()),
                "prefix" => filter.prefix = non_empty(value),
                "extension" => {
                    filter.extension =
                        non_empty(value.trim_start_matches('.').to_ascii_lowercase());
                }
                "limit" => filter.limit = Some(parse_list_limit(&value)),
                "offset" => filter.offset = value.parse::<usize>().unwrap_or(0),
                _ => {}
            }
        }
        filter
    }

    fn matches(&self, entry: &FileEntry) -> bool {
        if let Some(q) = &self.q {
            if !entry.filename.to_ascii_lowercase().contains(q) {
                return false;
            }
        }
        if let Some(prefix) = &self.prefix {
            if !entry.filename.starts_with(prefix) {
                return false;
            }
        }
        if let Some(extension) = &self.extension {
            if entry.extension.to_ascii_lowercase() != *extension {
                return false;
            }
        }
        true
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct SearchResultEntry {
    peer_username: Option<String>,
    filename: String,
    size: u64,
    extension: String,
    locked: bool,
    slot_free: Option<bool>,
    average_speed: Option<u32>,
    queue_length: Option<u32>,
}

impl SearchResultEntry {
    fn from_json_file(
        file: &serde_json::Value,
        peer_username: Option<&str>,
        locked: bool,
        slot_free: Option<bool>,
        average_speed: Option<u32>,
        queue_length: Option<u32>,
    ) -> Option<Self> {
        let filename = file.get("filename")?.as_str()?.to_owned();
        let extension = file
            .get("extension")
            .and_then(serde_json::Value::as_str)
            .map(str::to_owned)
            .unwrap_or_else(|| filename.split('.').next_back().unwrap_or("").to_owned());
        Some(Self {
            peer_username: peer_username.map(|username| {
                truncate_utf8_bytes(username.to_owned(), MAX_SEARCH_RESULT_USERNAME_BYTES)
            }),
            filename: truncate_utf8_bytes(filename, MAX_SEARCH_RESULT_FILENAME_BYTES),
            size: file
                .get("size")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0),
            extension: truncate_utf8_bytes(extension, MAX_SEARCH_RESULT_EXTENSION_BYTES),
            locked: file
                .get("locked")
                .or_else(|| file.get("isLocked"))
                .and_then(serde_json::Value::as_bool)
                .unwrap_or(locked),
            slot_free,
            average_speed,
            queue_length,
        })
    }

    fn from_file_entry(entry: &FileEntry) -> Self {
        bounded_search_result_entry(Self {
            peer_username: None,
            filename: entry.filename.clone(),
            size: entry.size,
            extension: entry.extension.clone(),
            locked: false,
            slot_free: Some(true),
            average_speed: Some(0),
            queue_length: Some(0),
        })
    }

    fn from_peer_response_entry(
        response: &FileSearchResponse,
        entry: &FileEntry,
        locked: bool,
    ) -> Self {
        bounded_search_result_entry(Self {
            peer_username: Some(response.username.clone()),
            filename: entry.filename.clone(),
            size: entry.size,
            extension: entry.extension.clone(),
            locked,
            slot_free: Some(response.slot_free),
            average_speed: Some(response.average_speed),
            queue_length: Some(response.queue_length),
        })
    }

    fn from_persisted(record: &persistence::SearchResultRecord) -> Self {
        bounded_search_result_entry(Self {
            peer_username: record.peer_username.clone(),
            filename: record.filename.clone(),
            size: record.size.max(0) as u64,
            extension: record.extension.clone(),
            locked: record.locked,
            slot_free: record.slot_free,
            average_speed: record
                .average_speed
                .and_then(|value| u32::try_from(value).ok()),
            queue_length: record
                .queue_length
                .and_then(|value| u32::try_from(value).ok()),
        })
    }

    fn json(&self) -> String {
        format!(
            "{{\"peer_username\":{},\"filename\":\"{}\",\"size\":{},\"extension\":\"{}\",\"locked\":{},\"slot_free\":{},\"average_speed\":{},\"queue_length\":{}}}",
            json_option(self.peer_username.as_deref()),
            json_escape(&self.filename),
            self.size,
            json_escape(&self.extension),
            self.locked,
            json_bool_option(self.slot_free),
            json_u32_option(self.average_speed),
            json_u32_option(self.queue_length)
        )
    }

    fn slskd_file_json(&self) -> serde_json::Value {
        serde_json::json!({
            "filename": self.filename,
            "size": self.size,
            "code": 1,
            "isLocked": self.locked || !self.slot_free.unwrap_or(true),
            "username": self.peer_username.as_deref().unwrap_or_default(),
            "extension": self.extension,
            "bitRate": null,
            "bitDepth": null,
            "length": null,
            "sampleRate": null,
        })
    }
}

fn bounded_search_result_entry(mut entry: SearchResultEntry) -> SearchResultEntry {
    entry.peer_username = entry
        .peer_username
        .map(|username| truncate_utf8_bytes(username, MAX_SEARCH_RESULT_USERNAME_BYTES));
    entry.filename = truncate_utf8_bytes(entry.filename, MAX_SEARCH_RESULT_FILENAME_BYTES);
    entry.extension = truncate_utf8_bytes(entry.extension, MAX_SEARCH_RESULT_EXTENSION_BYTES);
    entry
}

fn virtual_basename(path: &str) -> &str {
    path.rsplit(['/', '\\']).next().unwrap_or(path)
}

fn stable_content_hash(path: &str, size: u64) -> u64 {
    let mut hash = 0xcbf29ce484222325_u64;
    for byte in path.as_bytes().iter().copied().chain(size.to_le_bytes()) {
        hash ^= u64::from(byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    hash
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct SearchRecord {
    id: String,
    token: u32,
    query: String,
    target: &'static str,
    target_name: Option<String>,
    status: &'static str,
    results: Vec<SearchResultEntry>,
    raw_response_count: usize,
    filtered_out_count: usize,
    ignored_result_count: usize,
    hidden_locked_count: usize,
    expires_at: u64,
    created_at: u64,
    updated_at: u64,
}

impl SearchRecord {
    fn wishlist_item_id(&self) -> Option<&str> {
        (self.target == "wishlist")
            .then_some(self.target_name.as_deref())
            .flatten()
    }

    fn extend_results_with_limit_bounded(
        &mut self,
        results: impl IntoIterator<Item = SearchResultEntry>,
        aggregate_remaining: usize,
        result_limit: usize,
    ) {
        let remaining = result_limit
            .min(MAX_SEARCH_RESULTS_PER_SEARCH)
            .saturating_sub(self.results.len())
            .min(aggregate_remaining);
        self.results.extend(results.into_iter().take(remaining));
    }

    fn json(&self) -> String {
        self.json_with_result_page(0, None)
    }

    fn history_summary(&self) -> serde_json::Value {
        let response_count = self
            .results
            .iter()
            .filter_map(|entry| entry.peer_username.as_deref())
            .collect::<HashSet<_>>()
            .len();
        let locked_file_count = self.results.iter().filter(|entry| entry.locked).count();
        serde_json::json!({
            "id": self.id,
            "token": self.token,
            "query": self.query,
            "searchText": self.query,
            "target": self.target,
            "target_name": self.target_name,
            "wishlistItemId": self.wishlist_item_id(),
            "status": self.status,
            "state": search_state_for_status(self.status),
            "isComplete": self.status != "active",
            "result_count": self.results.len(),
            "fileCount": self.results.len(),
            "lockedFileCount": locked_file_count,
            "responseCount": response_count,
            "responsesAvailable": self.status != "active" || !self.results.is_empty(),
            "startedAt": self.created_at.to_string(),
            "endedAt": (self.status != "active").then(|| self.updated_at.to_string()),
            "expires_at": self.expires_at,
            "created_at": self.created_at,
            "updated_at": self.updated_at,
        })
    }

    fn json_with_query(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        self.json_with_result_page(filter.offset, filter.limit)
    }

    fn json_with_result_page(&self, offset: usize, limit: Option<usize>) -> String {
        let results = self
            .results
            .iter()
            .skip(offset)
            .take(limit.unwrap_or(usize::MAX))
            .map(SearchResultEntry::json)
            .collect::<Vec<_>>()
            .join(",");
        let responses = self.slskd_responses_json();
        let response_count = self
            .results
            .iter()
            .filter(|entry| entry.peer_username.is_some())
            .count();
        let locked_file_count = self.results.iter().filter(|entry| entry.locked).count();
        let state = search_state_for_status(self.status);
        let ended_at = if self.status == "active" {
            "null".to_owned()
        } else {
            format!("\"{}\"", self.updated_at)
        };
        format!(
            "{{\"id\":\"{}\",\"token\":{},\"query\":\"{}\",\"searchText\":\"{}\",\"target\":\"{}\",\"target_name\":{},\"wishlistItemId\":{},\"status\":\"{}\",\"state\":\"{}\",\"isComplete\":{},\"result_count\":{},\"fileCount\":{},\"lockedFileCount\":{},\"responseCount\":{},\"responsesAvailable\":{},\"responses\":{},\"results\":[{}],\"resultOffset\":{},\"resultLimit\":{},\"startedAt\":\"{}\",\"endedAt\":{},\"expires_at\":{},\"created_at\":{},\"updated_at\":{}}}",
            json_escape(&self.id),
            self.token,
            json_escape(&self.query),
            json_escape(&self.query),
            self.target,
            json_option(self.target_name.as_deref()),
            json_option(self.wishlist_item_id()),
            self.status,
            state,
            self.status != "active",
            self.results.len(),
            self.results.len(),
            locked_file_count,
            response_count,
            self.status != "active" || !self.results.is_empty(),
            responses,
            results,
            offset,
            json_usize_option(limit),
            self.created_at,
            ended_at,
            self.expires_at,
            self.created_at,
            self.updated_at
        )
    }

    fn slskd_responses_json(&self) -> String {
        self.slskd_responses_json_with_query(None)
    }

    fn slskd_responses_json_with_query(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let mut grouped: BTreeMap<String, Vec<&SearchResultEntry>> = BTreeMap::new();
        for result in &self.results {
            let username = result.peer_username.clone().unwrap_or_default();
            if filter
                .username
                .as_deref()
                .is_some_and(|needle| !username.eq_ignore_ascii_case(needle))
            {
                continue;
            }
            if filter.q.as_deref().is_some_and(|needle| {
                !username.to_ascii_lowercase().contains(needle)
                    && !result.filename.to_ascii_lowercase().contains(needle)
            }) {
                continue;
            }
            grouped.entry(username).or_default().push(result);
        }
        let responses = grouped
            .into_iter()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(|(username, entries)| {
                let files = entries
                    .iter()
                    .filter(|entry| !entry.locked)
                    .map(|entry| entry.slskd_file_json())
                    .collect::<Vec<_>>();
                let locked_files = entries
                    .iter()
                    .filter(|entry| entry.locked)
                    .map(|entry| entry.slskd_file_json())
                    .collect::<Vec<_>>();
                let file_count = files.len();
                let locked_file_count = locked_files.len();
                let first = entries.first().copied();
                serde_json::json!({
                    "username": username,
                    "token": self.token,
                    "hasFreeUploadSlot": first.and_then(|entry| entry.slot_free).unwrap_or(true),
                    "queueLength": first.and_then(|entry| entry.queue_length).unwrap_or(0),
                    "uploadSpeed": first.and_then(|entry| entry.average_speed).unwrap_or(0),
                    "fileCount": file_count,
                    "files": files,
                    "lockedFileCount": locked_file_count,
                    "lockedFiles": locked_files,
                })
            })
            .collect::<Vec<_>>();
        serde_json::Value::Array(responses).to_string()
    }

    #[cfg(test)]
    fn from_persisted(record: &persistence::SearchRecord) -> Option<Self> {
        Self::from_persisted_with_results(record, Vec::new())
    }

    fn from_persisted_with_results(
        record: &persistence::SearchRecord,
        result_records: Vec<persistence::SearchResultRecord>,
    ) -> Option<Self> {
        let token = record.id.parse::<u32>().ok()?;
        let target = persisted_target(record.target.as_deref());
        let target_name = match target {
            "user" => record.target.clone(),
            "room" => record.room.clone(),
            "wishlist" => record.room.clone(),
            _ => None,
        };
        Some(Self {
            id: record.id.clone(),
            token,
            query: truncate_utf8_bytes(record.query.clone(), MAX_SEARCH_QUERY_BYTES),
            target,
            target_name: target_name
                .map(|name| truncate_utf8_bytes(name, MAX_SEARCH_TARGET_NAME_BYTES)),
            status: persisted_search_status(&record.status),
            results: result_records
                .iter()
                .map(SearchResultEntry::from_persisted)
                .take(MAX_SEARCH_RESULTS_PER_SEARCH)
                .collect(),
            raw_response_count: 0,
            filtered_out_count: 0,
            ignored_result_count: 0,
            hidden_locked_count: 0,
            expires_at: 0,
            created_at: record.created_at.max(0) as u64,
            updated_at: record.completed_at.unwrap_or(record.created_at).max(0) as u64,
        })
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct SearchStore {
    records: Vec<SearchRecord>,
    next_token: u32,
}

#[derive(Debug, PartialEq, Eq)]
enum SearchCreateError {
    CapacityFull,
    DuplicateId,
    TokenSpaceExhausted,
}

#[derive(Debug)]
struct SearchCreateOutcome {
    record: SearchRecord,
    evicted: Vec<SearchRecord>,
}

fn next_search_token_hint(records: &[SearchRecord]) -> u32 {
    records
        .iter()
        .map(|record| record.token)
        .max()
        .unwrap_or(0)
        .wrapping_add(1)
        .max(1)
}

fn search_create_error_response(error: SearchCreateError) -> HttpResponse {
    match error {
        SearchCreateError::DuplicateId => routing::conflict_response("search id already exists"),
        SearchCreateError::CapacityFull => {
            routing::service_unavailable_response("active search capacity is full")
        }
        SearchCreateError::TokenSpaceExhausted => {
            routing::service_unavailable_response("search token space is exhausted")
        }
    }
}

impl SearchStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_token: 1,
        }
    }

    #[cfg(test)]
    fn from_persisted(records: Vec<persistence::SearchRecord>) -> Self {
        let parsed = records
            .iter()
            .filter_map(SearchRecord::from_persisted)
            .collect::<Vec<_>>();
        let next_token = next_search_token_hint(&parsed);
        let mut seen_ids = std::collections::HashSet::new();
        let mut seen_tokens = std::collections::HashSet::new();
        let records = parsed
            .into_iter()
            .filter(|record| seen_ids.insert(record.id.clone()) && seen_tokens.insert(record.token))
            .take(MAX_SEARCH_RECORDS)
            .collect::<Vec<_>>();
        Self {
            records,
            next_token,
        }
    }

    fn from_persisted_with_results(
        records: Vec<persistence::SearchRecord>,
        result_records: Vec<persistence::SearchResultRecord>,
    ) -> Self {
        let mut results_by_search: BTreeMap<String, Vec<persistence::SearchResultRecord>> =
            BTreeMap::new();
        for result in result_records {
            results_by_search
                .entry(result.search_id.clone())
                .or_default()
                .push(result);
        }
        let mut retained_results = 0_usize;
        let parsed = records
            .iter()
            .filter_map(|record| {
                let remaining = MAX_TOTAL_SEARCH_RESULTS.saturating_sub(retained_results);
                let mut parsed = SearchRecord::from_persisted_with_results(
                    record,
                    results_by_search.remove(&record.id).unwrap_or_default(),
                )?;
                parsed.results.truncate(remaining);
                retained_results = retained_results.saturating_add(parsed.results.len());
                Some(parsed)
            })
            .collect::<Vec<_>>();
        let next_token = next_search_token_hint(&parsed);
        let mut seen_ids = std::collections::HashSet::new();
        let mut seen_tokens = std::collections::HashSet::new();
        let records = parsed
            .into_iter()
            .filter(|record| seen_ids.insert(record.id.clone()) && seen_tokens.insert(record.token))
            .take(MAX_SEARCH_RECORDS)
            .collect::<Vec<_>>();
        Self {
            records,
            next_token,
        }
    }

    fn create(
        &mut self,
        id: Option<String>,
        query: String,
        target: &'static str,
        target_name: Option<String>,
        results: Vec<FileEntry>,
        ttl_seconds: u64,
    ) -> Result<SearchCreateOutcome, SearchCreateError> {
        self.expire_due();
        let id = id.filter(|value| !value.trim().is_empty());
        if id.as_deref().is_some_and(|id| {
            self.records
                .iter()
                .any(|record| record.id == id || record.token.to_string() == id)
        }) {
            return Err(SearchCreateError::DuplicateId);
        }
        let token = self.allocate_token()?;
        if id.as_deref().is_some_and(|id| id == token.to_string()) {
            return Err(SearchCreateError::DuplicateId);
        }
        let mut evicted = Vec::new();
        if self.records.len() >= MAX_SEARCH_RECORDS {
            let Some(index) = self
                .records
                .iter()
                .enumerate()
                .filter(|(_, record)| record.status != "active")
                .min_by_key(|(_, record)| record.updated_at)
                .map(|(index, _)| index)
            else {
                return Err(SearchCreateError::CapacityFull);
            };
            evicted.push(self.records.remove(index));
        }
        let now = unix_timestamp();
        let aggregate_remaining = MAX_TOTAL_SEARCH_RESULTS.saturating_sub(self.total_results());
        let record = SearchRecord {
            id: id.unwrap_or_else(|| token.to_string()),
            token,
            query: truncate_utf8_bytes(query, MAX_SEARCH_QUERY_BYTES),
            target,
            target_name: target_name
                .map(|name| truncate_utf8_bytes(name, MAX_SEARCH_TARGET_NAME_BYTES)),
            status: "active",
            results: results
                .iter()
                .map(SearchResultEntry::from_file_entry)
                .take(MAX_SEARCH_RESULTS_PER_SEARCH.min(aggregate_remaining))
                .collect(),
            raw_response_count: 0,
            filtered_out_count: 0,
            ignored_result_count: 0,
            hidden_locked_count: 0,
            expires_at: now.saturating_add(ttl_seconds),
            created_at: now,
            updated_at: now,
        };
        self.next_token = token.wrapping_add(1).max(1);
        self.records.push(record.clone());
        Ok(SearchCreateOutcome { record, evicted })
    }

    #[cfg(test)]
    fn create_scheduled_wishlist(
        &mut self,
        query: String,
        ttl_seconds: u64,
    ) -> Result<SearchCreateOutcome, SearchCreateError> {
        self.create_scheduled_wishlist_for_item(query, None, ttl_seconds)
    }

    fn create_scheduled_wishlist_for_item(
        &mut self,
        query: String,
        wishlist_item_id: Option<String>,
        ttl_seconds: u64,
    ) -> Result<SearchCreateOutcome, SearchCreateError> {
        self.create(
            None,
            query,
            "wishlist",
            wishlist_item_id,
            Vec::new(),
            ttl_seconds,
        )
    }

    fn allocate_token(&self) -> Result<u32, SearchCreateError> {
        let mut candidate = self.next_token.max(1);
        for _ in 0..=MAX_SEARCH_RECORDS {
            let text = candidate.to_string();
            if !self
                .records
                .iter()
                .any(|record| record.token == candidate || record.id == text)
            {
                return Ok(candidate);
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        Err(SearchCreateError::TokenSpaceExhausted)
    }

    fn get_by_identifier(&self, id: &str) -> Option<SearchRecord> {
        self.records
            .iter()
            .find(|record| record.id == id || record.token.to_string() == id)
            .cloned()
    }

    fn remove_by_identifier(&mut self, id: &str) -> Option<SearchRecord> {
        if let Some(pos) = self
            .records
            .iter()
            .position(|record| record.id == id || record.token.to_string() == id)
        {
            Some(self.records.remove(pos))
        } else {
            None
        }
    }

    fn complete(&mut self, token: u32) -> Option<(SearchRecord, bool)> {
        let record = self
            .records
            .iter_mut()
            .find(|record| record.token == token)?;
        let transitioned = record.status != "completed";
        record.status = "completed";
        record.updated_at = unix_timestamp();
        Some((record.clone(), transitioned))
    }

    fn set_status_by_token(
        &mut self,
        token: u32,
        status: &'static str,
    ) -> Option<(SearchRecord, bool)> {
        let record = self
            .records
            .iter_mut()
            .find(|record| record.token == token)?;
        let transitioned = record.status != status;
        record.status = status;
        if transitioned {
            record.updated_at = unix_timestamp();
        }
        Some((record.clone(), transitioned))
    }

    fn update_by_identifier(
        &mut self,
        id: &str,
        query: Option<String>,
        status: Option<&str>,
    ) -> Option<(SearchRecord, bool)> {
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == id || record.token.to_string() == id)?;
        let mut updated = false;
        if let Some(query) = query.map(|value| value.trim().to_owned()) {
            let query = truncate_utf8_bytes(query, MAX_SEARCH_QUERY_BYTES);
            if !query.is_empty() && query != record.query {
                record.query = query;
                updated = true;
            }
        }
        if let Some(status) = status.and_then(normalize_search_status) {
            if status != record.status {
                record.status = status;
                updated = true;
            }
        }
        if updated {
            record.updated_at = unix_timestamp();
        }
        Some((record.clone(), updated))
    }

    fn expire_due(&mut self) -> Vec<SearchRecord> {
        let now = unix_timestamp();
        let mut expired = Vec::new();
        for record in &mut self.records {
            if record.status == "active" && record.expires_at <= now {
                record.status = "expired";
                record.updated_at = now;
                expired.push(record.clone());
            }
        }
        expired
    }

    fn prune_expired(&mut self) -> Vec<SearchRecord> {
        self.expire_due();
        let mut pruned = Vec::new();
        self.records.retain(|record| {
            if record.status == "expired" {
                pruned.push(record.clone());
                false
            } else {
                true
            }
        });
        pruned
    }

    #[cfg(test)]
    fn add_peer_response(&mut self, response: &FileSearchResponse) -> Option<SearchRecord> {
        self.add_peer_response_filtered(response, &[], None)
    }

    fn add_peer_response_filtered(
        &mut self,
        response: &FileSearchResponse,
        ignored_results: &[WishlistIgnoredResult],
        wishlist_policy: Option<&WishlistResultPolicy>,
    ) -> Option<SearchRecord> {
        let aggregate_remaining = MAX_TOTAL_SEARCH_RESULTS.saturating_sub(self.total_results());
        let record = self
            .records
            .iter_mut()
            .find(|record| record.token == response.token)?;
        let result_limit = wishlist_policy
            .map(|policy| policy.max_results)
            .unwrap_or(MAX_SEARCH_RESULTS_PER_SEARCH);
        if let Some(policy) = wishlist_policy {
            record.raw_response_count = record.raw_response_count.saturating_add(1);
            for (entry, locked) in response
                .results
                .iter()
                .map(|entry| (entry, false))
                .chain(response.private_results.iter().map(|entry| (entry, true)))
            {
                if !policy.filter.matches(&entry.filename) {
                    record.filtered_out_count = record.filtered_out_count.saturating_add(1);
                } else if ignored_results
                    .iter()
                    .any(|rule| rule.matches(&response.username, &entry.filename))
                {
                    record.ignored_result_count = record.ignored_result_count.saturating_add(1);
                } else if locked {
                    record.hidden_locked_count = record.hidden_locked_count.saturating_add(1);
                }
            }
        }
        let before = record.results.len();
        record.extend_results_with_limit_bounded(
            response
                .results
                .iter()
                .filter(|entry| {
                    wishlist_policy.is_none_or(|policy| policy.filter.matches(&entry.filename))
                        && !ignored_results
                            .iter()
                            .any(|rule| rule.matches(&response.username, &entry.filename))
                })
                .map(|entry| SearchResultEntry::from_peer_response_entry(response, entry, false)),
            aggregate_remaining,
            result_limit,
        );
        let aggregate_remaining = aggregate_remaining.saturating_sub(record.results.len() - before);
        if wishlist_policy.is_none() {
            record.extend_results_with_limit_bounded(
                response
                    .private_results
                    .iter()
                    .filter(|entry| {
                        !ignored_results
                            .iter()
                            .any(|rule| rule.matches(&response.username, &entry.filename))
                    })
                    .map(|entry| {
                        SearchResultEntry::from_peer_response_entry(response, entry, true)
                    }),
                aggregate_remaining,
                result_limit,
            );
        }
        record.updated_at = unix_timestamp();
        Some(record.clone())
    }

    fn suppress_ignored_result(&mut self, rule: &WishlistIgnoredResult) -> Vec<SearchRecord> {
        let mut changed = Vec::new();
        for record in &mut self.records {
            if record.wishlist_item_id() != Some(rule.wishlist_item_id.as_str()) {
                continue;
            }
            let before = record.results.len();
            record.results.retain(|entry| {
                let Some(username) = entry.peer_username.as_deref() else {
                    return true;
                };
                !rule.matches(username, &entry.filename)
            });
            if record.results.len() != before {
                record.updated_at = unix_timestamp();
                changed.push(record.clone());
            }
        }
        changed
    }

    fn get(&self, token: u32) -> Option<SearchRecord> {
        self.records
            .iter()
            .find(|record| record.token == token)
            .cloned()
    }

    fn total_results(&self) -> usize {
        self.records.iter().map(|record| record.results.len()).sum()
    }

    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self.filtered_records(&filter);
        let filtered_count = records.len();
        let expired = self
            .records
            .iter()
            .filter(|record| record.status == "expired")
            .count();
        let records = records
            .into_iter()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(SearchRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"filtered_count\":{},\"expired\":{},\"offset\":{},\"limit\":{},\"next_token\":{}}}",
            records,
            self.records.len(),
            filtered_count,
            expired,
            filter.offset,
            json_usize_option(filter.limit),
            self.next_token
        )
    }

    fn slskd_list_json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .filtered_records(&filter)
            .into_iter()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(SearchRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }

    fn wishlist_history_json(&self, item_id: &str, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .rev()
            .filter(|record| record.wishlist_item_id() == Some(item_id))
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(DEFAULT_LIST_LIMIT))
            .map(SearchRecord::history_summary)
            .collect::<Vec<_>>();
        serde_json::Value::Array(records).to_string()
    }

    fn filtered_records<'a>(&'a self, filter: &RecordListFilter) -> Vec<&'a SearchRecord> {
        self.records
            .iter()
            .filter(|record| {
                filter
                    .status
                    .as_deref()
                    .is_none_or(|status| record.status == status)
            })
            .filter(|record| {
                filter
                    .target
                    .as_deref()
                    .is_none_or(|target| record.target == target)
            })
            .filter(|record| {
                filter.q.as_deref().is_none_or(|q| {
                    record.query.to_ascii_lowercase().contains(q)
                        || record
                            .target_name
                            .as_deref()
                            .is_some_and(|target| target.to_ascii_lowercase().contains(q))
                })
            })
            .collect::<Vec<_>>()
    }

    fn summary_json(&self) -> String {
        let active = self
            .records
            .iter()
            .filter(|record| record.status == "active")
            .count();
        let completed = self
            .records
            .iter()
            .filter(|record| record.status == "completed")
            .count();
        let expired = self
            .records
            .iter()
            .filter(|record| record.status == "expired")
            .count();
        let results = self
            .records
            .iter()
            .map(|record| record.results.len())
            .sum::<usize>();
        let global = self
            .records
            .iter()
            .filter(|record| record.target == "global")
            .count();
        let user = self
            .records
            .iter()
            .filter(|record| record.target == "user")
            .count();
        let room = self
            .records
            .iter()
            .filter(|record| record.target == "room")
            .count();
        let wishlist = self
            .records
            .iter()
            .filter(|record| record.target == "wishlist")
            .count();
        format!(
            "{{\"total\":{},\"active\":{},\"completed\":{},\"expired\":{},\"results\":{},\"global\":{},\"user\":{},\"room\":{},\"wishlist\":{},\"next_token\":{}}}",
            self.records.len(),
            active,
            completed,
            expired,
            results,
            global,
            user,
            room,
            wishlist,
            self.next_token
        )
    }

    fn transfer_alternatives_json(&self, transfer: &TransferEntry) -> String {
        let original_basename = virtual_basename(&transfer.filename).to_ascii_lowercase();
        let alternatives = self
            .records
            .iter()
            .flat_map(|record| record.results.iter())
            .filter(|result| {
                result.peer_username.is_some()
                    && result.peer_username != transfer.peer_username
                    && virtual_basename(&result.filename).eq_ignore_ascii_case(&original_basename)
            })
            .map(|result| {
                serde_json::json!({
                    "username": result.peer_username.as_deref().unwrap_or_default(),
                    "filename": result.filename,
                    "size": result.size,
                    "locked": result.locked,
                    "slot_free": result.slot_free,
                    "average_speed": result.average_speed,
                    "queue_length": result.queue_length,
                })
            })
            .collect::<Vec<_>>();
        let count = alternatives.len();
        serde_json::json!({
            "transfer_id": transfer.id,
            "filename": transfer.filename,
            "alternatives": alternatives,
            "count": count,
        })
        .to_string()
    }

    fn find_transfer_alternative(
        &self,
        transfer: &TransferEntry,
        username: &str,
        filename: Option<&str>,
    ) -> Option<SearchResultEntry> {
        let original_basename = virtual_basename(&transfer.filename);
        self.records
            .iter()
            .flat_map(|record| record.results.iter())
            .find(|result| {
                result
                    .peer_username
                    .as_deref()
                    .is_some_and(|peer| peer.eq_ignore_ascii_case(username))
                    && filename.map_or_else(
                        || {
                            virtual_basename(&result.filename)
                                .eq_ignore_ascii_case(original_basename)
                        },
                        |filename| result.filename == filename,
                    )
            })
            .cloned()
    }

    fn first_transfer_alternative(&self, transfer: &TransferEntry) -> Option<SearchResultEntry> {
        let original_basename = virtual_basename(&transfer.filename);
        self.records
            .iter()
            .flat_map(|record| record.results.iter())
            .find(|result| {
                result.peer_username.is_some()
                    && result.peer_username != transfer.peer_username
                    && virtual_basename(&result.filename).eq_ignore_ascii_case(original_basename)
            })
            .cloned()
    }

    fn best_transfer_alternative<F>(
        &self,
        transfer: &TransferEntry,
        size_tolerance_percent: f64,
        peer_is_cooling_down: F,
    ) -> Option<SearchResultEntry>
    where
        F: Fn(&str) -> bool,
    {
        let original_basename = virtual_basename(&transfer.filename);
        self.records
            .iter()
            .flat_map(|record| record.results.iter())
            .filter(|result| {
                let Some(username) = result.peer_username.as_deref() else {
                    return false;
                };
                !result.locked
                    && transfer
                        .peer_username
                        .as_deref()
                        .is_none_or(|original| !username.eq_ignore_ascii_case(original))
                    && !peer_is_cooling_down(username)
                    && virtual_basename(&result.filename).eq_ignore_ascii_case(original_basename)
                    && alternate_size_is_eligible(
                        transfer.size,
                        result.size,
                        size_tolerance_percent,
                    )
            })
            .max_by(|left, right| {
                left.slot_free
                    .unwrap_or(false)
                    .cmp(&right.slot_free.unwrap_or(false))
                    .then_with(|| {
                        left.average_speed
                            .unwrap_or(0)
                            .cmp(&right.average_speed.unwrap_or(0))
                    })
                    .then_with(|| {
                        right
                            .queue_length
                            .unwrap_or(u32::MAX)
                            .cmp(&left.queue_length.unwrap_or(u32::MAX))
                    })
            })
            .cloned()
    }
}

fn persisted_search_status(status: &str) -> &'static str {
    match status {
        "active" | "pending" => "active",
        "completed" | "complete" => "completed",
        "expired" => "expired",
        "cancelled" | "canceled" => "cancelled",
        "failed" => "failed",
        _ => "active",
    }
}

fn normalize_search_status(status: &str) -> Option<&'static str> {
    match status {
        "active" | "pending" | "in_progress" | "InProgress" => Some("active"),
        "completed" | "complete" | "Completed" => Some("completed"),
        "expired" | "Expired" => Some("expired"),
        "cancelled" | "canceled" | "Cancelled" | "Canceled" => Some("cancelled"),
        "failed" | "Failed" => Some("failed"),
        _ => None,
    }
}

fn search_state_for_status(status: &str) -> &'static str {
    match status {
        "active" => "InProgress",
        "failed" => "Failed",
        "cancelled" => "Cancelled",
        "expired" => "Expired",
        _ => "Completed",
    }
}

fn search_ttl_seconds_from_body(body: &str) -> Result<u64, &'static str> {
    let ttl_seconds = extract_json_u64_field(body, "ttl_seconds")
        .or_else(|| extract_json_u64_field(body, "ttlSeconds"));
    match ttl_seconds {
        Some(0) => Err("search ttl_seconds must be greater than zero"),
        Some(ttl) => Ok(ttl.min(MAX_SEARCH_TTL_SECONDS)),
        None => Ok(DEFAULT_SEARCH_TTL_SECONDS),
    }
}

fn persisted_target(target: Option<&str>) -> &'static str {
    match target {
        Some("user") => "user",
        Some("room") => "room",
        Some("wishlist") => "wishlist",
        _ => "global",
    }
}

fn persisted_search_record(record: &SearchRecord) -> persistence::SearchRecord {
    let completed_at = if record.status == "active" {
        None
    } else {
        Some(record.updated_at as i64)
    };
    let (room, target) = match record.target {
        "room" => (record.target_name.clone(), Some("room".to_owned())),
        "user" => (None, Some("user".to_owned())),
        "wishlist" => (record.target_name.clone(), Some("wishlist".to_owned())),
        _ => (None, Some("global".to_owned())),
    };
    persistence::SearchRecord {
        id: record.token.to_string(),
        query: record.query.clone(),
        status: record.status.to_string(),
        result_count: record.results.len() as i64,
        created_at: record.created_at as i64,
        completed_at,
        room,
        target,
    }
}

fn persisted_search_result_records(record: &SearchRecord) -> Vec<persistence::SearchResultRecord> {
    let search_id = record.token.to_string();
    record
        .results
        .iter()
        .map(|result| persistence::SearchResultRecord {
            id: 0,
            search_id: search_id.clone(),
            peer_username: result.peer_username.clone(),
            filename: result.filename.clone(),
            size: i64::try_from(result.size).unwrap_or(i64::MAX),
            extension: result.extension.clone(),
            locked: result.locked,
            slot_free: result.slot_free,
            average_speed: result.average_speed.map(i64::from),
            queue_length: result.queue_length.map(i64::from),
            created_at: record.updated_at as i64,
        })
        .collect()
}

async fn persist_search_record(state: &AppState, record: &SearchRecord) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        db.insert_search(&persisted_search_record(record))
            .await
            .map_err(|error| format!("failed to persist search: {error}"))?;
        db.replace_search_results(
            &record.token.to_string(),
            &persisted_search_result_records(record),
        )
        .await
        .map_err(|error| format!("failed to persist search results: {error}"))?;
    }
    Ok(())
}

async fn persist_search_records(state: &AppState, records: &[SearchRecord]) -> Result<(), String> {
    for record in records {
        persist_search_record(state, record).await?;
    }
    Ok(())
}

async fn delete_persisted_search(state: &AppState, record: &SearchRecord) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        db.delete_search(&record.token.to_string())
            .await
            .map_err(|error| format!("failed to delete persisted search: {error}"))?;
    }
    Ok(())
}

async fn delete_persisted_searches(
    state: &AppState,
    records: &[SearchRecord],
) -> Result<(), String> {
    for record in records {
        delete_persisted_search(state, record).await?;
    }
    Ok(())
}

async fn clear_persisted_searches(state: &AppState) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        db.delete_all_searches()
            .await
            .map_err(|error| format!("failed to clear persisted searches: {error}"))?;
    }
    Ok(())
}

#[derive(Debug, Default)]
struct RecordListFilter {
    q: Option<String>,
    status: Option<String>,
    target: Option<String>,
    direction: Option<String>,
    username: Option<String>,
    joined: Option<bool>,
    kind: Option<String>,
    topic: Option<String>,
    limit: Option<usize>,
    offset: usize,
}

impl RecordListFilter {
    fn from_query(query: Option<&str>) -> Self {
        let mut filter = Self {
            limit: Some(DEFAULT_LIST_LIMIT),
            ..Self::default()
        };
        for (name, value) in query_params(query.unwrap_or_default()) {
            match name.as_str() {
                "q" => filter.q = non_empty(value.to_ascii_lowercase()),
                "status" => filter.status = non_empty(value),
                "target" => filter.target = non_empty(value),
                "direction" => filter.direction = non_empty(value),
                "username" => filter.username = non_empty(value),
                "joined" => filter.joined = parse_bool_value(&value),
                "kind" => filter.kind = non_empty(value),
                "topic" => filter.topic = non_empty(value),
                "limit" => filter.limit = Some(parse_list_limit(&value)),
                "offset" => filter.offset = value.parse::<usize>().unwrap_or(0),
                _ => {}
            }
        }
        filter
    }
}

fn parse_list_limit(value: &str) -> usize {
    value
        .parse::<usize>()
        .ok()
        .filter(|limit| *limit > 0)
        .map(|limit| limit.min(DEFAULT_LIST_LIMIT))
        .unwrap_or(DEFAULT_LIST_LIMIT)
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct EventRecord {
    id: u64,
    kind: String,
    resource: String,
    detail: Option<String>,
    created_at: u64,
}

impl EventRecord {
    fn topic(&self) -> &'static str {
        topic_for_event_kind(&self.kind)
    }

    fn data_json(&self) -> serde_json::Value {
        if self.kind == "log.created" {
            let detail = self
                .detail
                .as_deref()
                .and_then(|detail| serde_json::from_str::<serde_json::Value>(detail).ok())
                .unwrap_or_else(|| {
                    serde_json::json!({
                        "level": "Information",
                        "message": self.detail.as_deref().unwrap_or(&self.resource),
                        "category": self.resource,
                    })
                });
            let category = detail
                .get("category")
                .and_then(|v| v.as_str())
                .unwrap_or(&self.resource);
            let context = detail
                .get("context")
                .and_then(|v| v.as_str())
                .unwrap_or(category);
            return serde_json::json!({
                "id": self.id,
                "kind": self.kind,
                "topic": self.topic(),
                "resource": &self.resource,
                "detail": &self.detail,
                "created_at": self.created_at,
                "timestamp": self.created_at,
                "level": detail.get("level").and_then(|v| v.as_str()).unwrap_or("Information"),
                "message": detail.get("message").and_then(|v| v.as_str()).unwrap_or(""),
                "category": category,
                "context": context,
                "request_id": detail.get("request_id").and_then(|v| v.as_str()),
                "method": detail.get("method").and_then(|v| v.as_str()),
                "path": detail.get("path").and_then(|v| v.as_str()),
                "status": detail.get("status").and_then(|v| v.as_u64()),
                "duration_ms": detail.get("duration_ms").and_then(|v| v.as_u64()),
                "remote_addr": detail.get("remote_addr").and_then(|v| v.as_str()),
            });
        }
        serde_json::json!({
            "id": self.id,
            "kind": self.kind,
            "topic": self.topic(),
            "resource": &self.resource,
            "detail": &self.detail,
            "created_at": self.created_at,
        })
    }

    fn json(&self) -> String {
        format!(
            "{{\"id\":{},\"kind\":\"{}\",\"topic\":\"{}\",\"resource\":\"{}\",\"detail\":{},\"created_at\":{}}}",
            self.id,
            self.kind,
            self.topic(),
            json_escape(&self.resource),
            json_option(self.detail.as_deref()),
            self.created_at
        )
    }

    fn slskd_json(&self) -> serde_json::Value {
        let data = self.data_json();
        serde_json::json!({
            "id": self.id.to_string(),
            "timestamp": self.created_at.to_string(),
            "topic": self.topic(),
            "type": self.kind,
            "resource": &self.resource,
            "detail": &self.detail,
            "data": data.to_string(),
            "payload": data,
        })
    }
}

fn topic_for_event_kind(kind: &str) -> &'static str {
    match kind.split('.').next().unwrap_or(kind) {
        "application" | "session" => "application",
        "listener" | "portforwarding" => "listeners",
        "share" => "shares",
        "search" | "wishlist" => "searches",
        "browse" => "browse",
        "transfer" | "upload" | "download" => "transfers",
        "message" | "conversation" => "messages",
        "room" | "listening_party" => "rooms",
        "user" | "contact" | "note" => "users",
        "collection" | "playlist" => "collections",
        "sharegroup" | "grant" => "sharegroups",
        "library" | "catalog" => "library",
        "destination" => "destinations",
        "player" | "playback" | "now_playing" | "external_visualizer" => "player",
        "relay" => "relay",
        "bridge" => "bridge",
        "mesh" => "mesh",
        "webhook" => "webhooks",
        "log" => "logs",
        "security" | "ban" => "security",
        "federation" => "federation",
        "solid" => "solid",
        "lidarr" | "musicbrainz" => "integrations",
        "songid" | "pod" | "stream" => "media",
        "cache" | "backfill" | "telemetry" | "metrics" => "system",
        "config" | "options" => "settings",
        _ => "events",
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct EventStore {
    records: Vec<EventRecord>,
    next_id: u64,
    history_limit: usize,
}

impl EventStore {
    fn new(history_limit: usize) -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            history_limit,
        }
    }

    fn from_persisted(records: Vec<persistence::EventRecord>, history_limit: usize) -> Self {
        let mut records = records
            .into_iter()
            .filter_map(|record| {
                Some(EventRecord {
                    id: u64::try_from(record.id).ok()?,
                    kind: truncate_utf8_bytes(record.kind, MAX_EVENT_KIND_BYTES),
                    resource: truncate_utf8_bytes(record.resource, MAX_EVENT_RESOURCE_BYTES),
                    detail: bounded_event_detail(record.detail),
                    created_at: u64::try_from(record.created_at).ok()?,
                })
            })
            .collect::<Vec<_>>();
        let mut seen_ids = std::collections::HashSet::new();
        records.reverse();
        records.retain(|record| seen_ids.insert(record.id));
        records.reverse();
        if records.len() > history_limit {
            let extra = records.len() - history_limit;
            records.drain(0..extra);
        }
        let next_id = records
            .iter()
            .map(|record| record.id)
            .max()
            .unwrap_or(0)
            .saturating_add(1);
        Self {
            records,
            next_id,
            history_limit,
        }
    }

    fn record(
        &mut self,
        kind: impl Into<String>,
        resource: impl Into<String>,
        detail: Option<String>,
    ) -> EventRecord {
        let id = self.allocate_id();
        let record = EventRecord {
            id,
            kind: truncate_utf8_bytes(kind.into(), MAX_EVENT_KIND_BYTES),
            resource: truncate_utf8_bytes(resource.into(), MAX_EVENT_RESOURCE_BYTES),
            detail: bounded_event_detail(detail),
            created_at: unix_timestamp(),
        };
        self.records.push(record.clone());
        if self.records.len() > self.history_limit {
            let extra = self.records.len() - self.history_limit;
            self.records.drain(0..extra);
        }
        record
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            if !self.records.iter().any(|record| record.id == candidate) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded event history must leave an available u64 id")
    }

    #[allow(dead_code)]
    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .kind
                    .as_deref()
                    .is_none_or(|kind| record.kind == kind)
            })
            .filter(|record| {
                filter
                    .topic
                    .as_deref()
                    .is_none_or(|topic| record.topic() == topic)
            })
            .filter(|record| {
                filter.q.as_deref().is_none_or(|q| {
                    record.kind.to_ascii_lowercase().contains(q)
                        || record.topic().contains(q)
                        || record.resource.to_ascii_lowercase().contains(q)
                        || record
                            .detail
                            .as_deref()
                            .is_some_and(|detail| detail.to_ascii_lowercase().contains(q))
                })
            })
            .collect::<Vec<_>>();
        let filtered_count = records.len();
        let entries = records
            .into_iter()
            .rev()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(EventRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"history_limit\":{},\"next_id\":{}}}",
            entries,
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.history_limit,
            self.next_id
        )
    }

    fn slskd_json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let entries = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .kind
                    .as_deref()
                    .is_none_or(|kind| record.kind == kind)
            })
            .filter(|record| {
                filter
                    .topic
                    .as_deref()
                    .is_none_or(|topic| record.topic() == topic)
            })
            .filter(|record| {
                filter.q.as_deref().is_none_or(|q| {
                    record.kind.to_ascii_lowercase().contains(q)
                        || record.topic().contains(q)
                        || record.resource.to_ascii_lowercase().contains(q)
                        || record
                            .detail
                            .as_deref()
                            .is_some_and(|detail| detail.to_ascii_lowercase().contains(q))
                })
            })
            .rev()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(EventRecord::slskd_json)
            .collect::<Vec<_>>();
        serde_json::Value::Array(entries).to_string()
    }
}

fn truncate_utf8_bytes(mut value: String, max_bytes: usize) -> String {
    if value.len() <= max_bytes {
        return value;
    }
    let mut end = max_bytes;
    while !value.is_char_boundary(end) {
        end -= 1;
    }
    value.truncate(end);
    value
}

fn bounded_event_detail(detail: Option<String>) -> Option<String> {
    detail.map(|detail| {
        if detail.len() <= MAX_EVENT_DETAIL_BYTES {
            detail
        } else {
            format!("<omitted oversized event detail: {} bytes>", detail.len())
        }
    })
}

#[derive(Clone, Debug, Deserialize, Eq, PartialEq, Serialize)]
struct TransferEntry {
    id: u64,
    direction: u32,
    token: u32,
    peer_username: Option<String>,
    filename: String,
    local_path: Option<String>,
    #[serde(default)]
    batch_id: Option<String>,
    #[serde(default)]
    request_id: Option<String>,
    #[serde(default)]
    request_name: Option<String>,
    #[serde(default)]
    destination_directory: Option<String>,
    #[serde(default)]
    bit_rate: Option<u32>,
    #[serde(default)]
    sample_rate: Option<u32>,
    #[serde(default)]
    bit_depth: Option<u32>,
    #[serde(default)]
    length_seconds: Option<u32>,
    #[serde(default)]
    artist: Option<String>,
    #[serde(default)]
    album: Option<String>,
    #[serde(default)]
    title: Option<String>,
    #[serde(default)]
    track_number: Option<u32>,
    #[serde(default)]
    year: Option<u32>,
    size: Option<u64>,
    bytes_transferred: u64,
    status: String,
    reason: Option<String>,
    requested_at: u64,
    #[serde(default)]
    started_at: Option<u64>,
    #[serde(default)]
    start_offset: u64,
    updated_at: u64,
    #[serde(default)]
    updated_at_ms: u64,
}

impl TransferEntry {
    #[allow(dead_code)]
    fn json(&self) -> String {
        format!(
            "{{\"id\":{},\"direction\":{},\"token\":{},\"peer_username\":{},\"filename\":\"{}\",\"local_path\":{},\"batch_id\":{},\"request_id\":{},\"request_name\":{},\"destination_directory\":{},\"bit_rate\":{},\"sample_rate\":{},\"bit_depth\":{},\"length_seconds\":{},\"artist\":{},\"album\":{},\"title\":{},\"track_number\":{},\"year\":{},\"size\":{},\"bytes_transferred\":{},\"status\":\"{}\",\"reason\":{},\"failure_code\":{},\"recovery_action\":{},\"recovery_label\":{},\"requested_at\":{},\"started_at\":{},\"start_offset\":{},\"updated_at\":{}}}",
            self.id,
            self.direction,
            self.token,
            json_option(self.peer_username.as_deref()),
            json_escape(&self.filename),
            "null",
            json_option(self.batch_id.as_deref()),
            json_option(self.request_id.as_deref()),
            json_option(self.request_name.as_deref()),
            json_option(self.destination_directory.as_deref()),
            json_u32_option(self.bit_rate),
            json_u32_option(self.sample_rate),
            json_u32_option(self.bit_depth),
            json_u32_option(self.length_seconds),
            json_option(self.artist.as_deref()),
            json_option(self.album.as_deref()),
            json_option(self.title.as_deref()),
            json_u32_option(self.track_number),
            json_u32_option(self.year),
            json_u64_option(self.size),
            self.bytes_transferred,
            json_escape(&self.status),
            json_option(public_transfer_reason(&self.status, self.reason.as_deref())),
            json_option(transfer_failure_code(&self.status, self.reason.as_deref())),
            json_option(transfer_recovery_action(&self.status, self.reason.as_deref())),
            json_option(transfer_recovery_label(&self.status, self.reason.as_deref())),
            self.requested_at,
            json_u64_option(self.started_at),
            self.start_offset,
            self.updated_at
        )
    }

    fn elapsed_seconds_at(&self, now: u64) -> Option<u64> {
        let started_at = self.started_at?;
        let ended_at = if is_terminal_transfer_status(&self.status) {
            self.updated_at
        } else {
            now
        };
        Some(ended_at.saturating_sub(started_at))
    }

    fn average_speed_at(&self, now: u64) -> f64 {
        let Some(elapsed) = self.elapsed_seconds_at(now) else {
            return 0.0;
        };
        let transferred = self.bytes_transferred.saturating_sub(self.start_offset);
        if transferred == 0 {
            0.0
        } else {
            transferred as f64 / elapsed.max(1) as f64
        }
    }

    fn slskd_file_json(&self) -> serde_json::Value {
        let size = self.size.unwrap_or(0);
        let bytes_remaining = size.saturating_sub(self.bytes_transferred);
        let percent_complete = if size == 0 {
            0.0
        } else {
            ((self.bytes_transferred as f64 / size as f64) * 100.0).min(100.0)
        };
        let now = unix_timestamp();
        let average_speed = self.average_speed_at(now);
        let elapsed_seconds = self.elapsed_seconds_at(now);
        let started_at = self
            .started_at
            .map(|value| value.to_string())
            .unwrap_or_default();
        let ended_at = if is_terminal_transfer_status(&self.status) {
            self.updated_at.to_string()
        } else {
            String::new()
        };
        let remaining_seconds = (!is_terminal_transfer_status(&self.status)
            && average_speed > 0.0
            && bytes_remaining > 0)
            .then(|| (bytes_remaining as f64 / average_speed).ceil() as u64);
        serde_json::json!({
            "id": self.id.to_string(),
            "username": self.peer_username.as_deref().unwrap_or_default(),
            "direction": if self.direction == 0 { "Download" } else { "Upload" },
            "filename": self.filename,
            "batchId": self.batch_id,
            "requestId": self.request_id,
            "requestName": self.request_name,
            "destinationDirectory": self.destination_directory,
            "bitRate": self.bit_rate,
            "sampleRate": self.sample_rate,
            "bitDepth": self.bit_depth,
            "length": self.length_seconds,
            "artist": self.artist,
            "album": self.album,
            "title": self.title,
            "trackNumber": self.track_number,
            "year": self.year,
            "size": size,
            "startOffset": self.start_offset,
            "state": slskd_transfer_state(&self.status),
            "requestedAt": self.requested_at.to_string(),
            "enqueuedAt": self.requested_at.to_string(),
            "startedAt": started_at,
            "endedAt": ended_at,
            "bytesTransferred": self.bytes_transferred,
            "averageSpeed": average_speed,
            "bytesRemaining": bytes_remaining,
            "elapsedTime": elapsed_seconds.map(format_transfer_duration).unwrap_or_default(),
            "percentComplete": percent_complete,
            "remainingTime": remaining_seconds.map(format_transfer_duration).unwrap_or_default(),
            "failureCode": transfer_failure_code(&self.status, self.reason.as_deref()),
            "recoveryAction": transfer_recovery_action(&self.status, self.reason.as_deref()),
            "recoveryLabel": transfer_recovery_label(&self.status, self.reason.as_deref()),
        })
    }
}

fn is_terminal_transfer_status(status: &str) -> bool {
    matches!(
        status,
        "succeeded" | "completed" | "cancelled" | "failed" | "rejected"
    )
}

fn format_transfer_duration(seconds: u64) -> String {
    let hours = seconds / 3_600;
    let minutes = seconds % 3_600 / 60;
    let seconds = seconds % 60;
    format!("{hours:02}:{minutes:02}:{seconds:02}")
}

fn public_transfer_reason(status: &str, reason: Option<&str>) -> Option<&'static str> {
    reason.map(|_| match status {
        "failed" => "transfer failed",
        "rejected" => "transfer rejected",
        "cancelled" => "transfer cancelled",
        _ => "transfer operation unavailable",
    })
}

fn transfer_failure_code(status: &str, reason: Option<&str>) -> Option<&'static str> {
    if !matches!(status, "failed" | "rejected") {
        return None;
    }
    let reason = reason?.to_ascii_lowercase();
    Some(
        if reason.contains("too many megabytes") || reason.contains("overwhelmed") {
            "peer_capacity"
        } else if reason.contains("not shared") || reason.contains("file not found") {
            "remote_file_unavailable"
        } else if reason.contains("size mismatch")
            || reason.contains("does not match expected size")
        {
            "size_mismatch"
        } else if reason.contains("offline") || reason.contains("unavailable") {
            "peer_offline"
        } else if reason.contains("connection closed")
            || reason.contains("connection lost")
            || reason.contains("reset by peer")
        {
            "connection_lost"
        } else if reason.contains("internal error") {
            "remote_internal"
        } else {
            "transfer_failed"
        },
    )
}

fn transfer_recovery_action(status: &str, reason: Option<&str>) -> Option<&'static str> {
    match transfer_failure_code(status, reason)? {
        "peer_offline" => Some("wait"),
        _ => Some("retry"),
    }
}

fn transfer_recovery_label(status: &str, reason: Option<&str>) -> Option<&'static str> {
    match transfer_failure_code(status, reason)? {
        "peer_capacity" => Some("Retry later"),
        "remote_file_unavailable" | "size_mismatch" | "remote_internal" => {
            Some("Find other sources")
        }
        "peer_offline" => Some("Wait for online"),
        "connection_lost" => Some("Retry connection"),
        _ => Some("Retry"),
    }
}

fn download_request_state(entries: &[&TransferEntry]) -> &'static str {
    if entries
        .iter()
        .any(|entry| matches!(entry.status.as_str(), "succeeded" | "completed"))
    {
        "Completed"
    } else if entries.iter().any(|entry| {
        matches!(
            entry.status.as_str(),
            "queued"
                | "accepted"
                | "peer_lookup"
                | "peer_negotiating"
                | "indirect_pending"
                | "in_progress"
        )
    }) {
        "Active"
    } else if entries.iter().all(|entry| entry.status == "cancelled") {
        "Cancelled"
    } else {
        "Failed"
    }
}

fn download_request_projection(
    entries: &[&TransferEntry],
    include_attempts: bool,
) -> serde_json::Value {
    let first = entries
        .iter()
        .min_by_key(|entry| entry.requested_at)
        .copied()
        .expect("download request projection requires an attempt");
    let current = entries
        .iter()
        .filter(|entry| entry.status != "cancelled")
        .max_by_key(|entry| entry.requested_at)
        .or_else(|| entries.iter().max_by_key(|entry| entry.requested_at))
        .copied();
    let state = download_request_state(entries);
    let completed_at = matches!(state, "Completed" | "Failed" | "Cancelled")
        .then(|| entries.iter().map(|entry| entry.updated_at).max())
        .flatten();
    let request = serde_json::json!({
        "id": first.request_id,
        "name": first.request_name.as_deref().unwrap_or_else(|| virtual_basename(&first.filename)),
        "originalFilename": first.filename,
        "size": first.size,
        "batchId": first.batch_id,
        "destinationDirectory": first.destination_directory,
        "state": state,
        "stateDescription": state,
        "createdAt": first.requested_at,
        "completedAt": completed_at,
        "bitRate": first.bit_rate,
        "sampleRate": first.sample_rate,
        "bitDepth": first.bit_depth,
        "length": first.length_seconds,
        "artist": first.artist,
        "album": first.album,
        "title": first.title,
        "trackNumber": first.track_number,
        "year": first.year,
    });
    let current =
        current.and_then(|entry| serde_json::from_str::<serde_json::Value>(&entry.json()).ok());
    if include_attempts {
        let attempts = entries
            .iter()
            .filter_map(|entry| serde_json::from_str::<serde_json::Value>(&entry.json()).ok())
            .collect::<Vec<_>>();
        serde_json::json!({"request": request, "attempts": attempts, "current": current})
    } else {
        serde_json::json!({"request": request, "attemptCount": entries.len(), "current": current})
    }
}

fn persisted_transfer_record(entry: &TransferEntry) -> persistence::TransferRecord {
    let completed_at = if matches!(
        entry.status.as_str(),
        "succeeded" | "completed" | "cancelled" | "failed" | "rejected"
    ) {
        Some(entry.updated_at as i64)
    } else {
        None
    };
    persistence::TransferRecord {
        id: entry.id.to_string(),
        direction: if entry.direction == 0 {
            "download".to_owned()
        } else {
            "upload".to_owned()
        },
        filename: entry.filename.clone(),
        peer_username: entry.peer_username.clone().unwrap_or_default(),
        filesize: entry.size.unwrap_or(0) as i64,
        progress: entry.bytes_transferred as i64,
        status: entry.status.clone(),
        started_at: entry.started_at.unwrap_or(entry.requested_at) as i64,
        completed_at,
        request_id: entry.request_id.clone(),
        request_name: entry.request_name.clone(),
        destination_directory: entry.destination_directory.clone(),
        local_path: entry.local_path.clone(),
        batch_id: entry.batch_id.clone(),
        reason: entry.reason.clone(),
        bit_rate: entry.bit_rate.map(i64::from),
        sample_rate: entry.sample_rate.map(i64::from),
        bit_depth: entry.bit_depth.map(i64::from),
        length_seconds: entry.length_seconds.map(i64::from),
        artist: entry.artist.clone(),
        album: entry.album.clone(),
        title: entry.title.clone(),
        track_number: entry.track_number.map(i64::from),
        year: entry.year.map(i64::from),
    }
}

fn persisted_transfer_event_record(entry: &TransferEntry) -> persistence::TransferEventRecord {
    persistence::TransferEventRecord {
        id: 0,
        transfer_id: entry.id.to_string(),
        direction: if entry.direction == 0 {
            "download".to_owned()
        } else {
            "upload".to_owned()
        },
        token: i64::from(entry.token),
        filename: entry.filename.clone(),
        peer_username: entry.peer_username.clone(),
        filesize: i64::try_from(entry.size.unwrap_or(0)).unwrap_or(i64::MAX),
        progress: i64::try_from(entry.bytes_transferred).unwrap_or(i64::MAX),
        status: entry.status.clone(),
        reason: entry.reason.clone(),
        created_at: i64::try_from(entry.updated_at).unwrap_or(i64::MAX),
    }
}

async fn persist_transfer_record(state: &AppState, entry: &TransferEntry) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        let records = [(
            persisted_transfer_record(entry),
            persisted_transfer_event_record(entry),
        )];
        db.insert_transfer_records_with_events(&records)
            .await
            .map_err(|error| format!("failed to persist transfer and event: {error}"))?;
    }
    Ok(())
}

async fn persist_transfer_projection(state: &AppState, entry: &TransferEntry) {
    if let Err(error) = persist_transfer_record(state, entry).await {
        update_session(state, |snapshot| {
            snapshot.last_error =
                Some(format!("transfer {} persistence failed: {error}", entry.id));
        })
        .await;
    }
}

async fn persist_transfer_records(
    state: &AppState,
    entries: &[TransferEntry],
) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        let records = entries
            .iter()
            .map(|entry| {
                (
                    persisted_transfer_record(entry),
                    persisted_transfer_event_record(entry),
                )
            })
            .collect::<Vec<_>>();
        db.insert_transfer_records_with_events(&records)
            .await
            .map_err(|error| format!("failed to persist transfers and events: {error}"))?;
    }
    Ok(())
}

async fn delete_persisted_transfers(
    state: &AppState,
    entries: &[TransferEntry],
) -> Result<(), String> {
    if let Some(db) = state.db.as_ref() {
        let ids = entries
            .iter()
            .map(|entry| entry.id.to_string())
            .collect::<Vec<_>>();
        db.delete_transfers(&ids)
            .await
            .map_err(|error| format!("failed to delete persisted transfers: {error}"))?;
    }
    Ok(())
}

fn slskd_transfer_state(status: &str) -> &str {
    match status {
        "queued" => "Queued",
        "accepted" | "peer_lookup" | "peer_negotiating" | "indirect_pending" | "in_progress" => {
            "InProgress"
        }
        "succeeded" | "completed" => "Completed",
        "cancelled" => "Cancelled",
        "failed" | "rejected" => "Failed",
        other => other,
    }
}

fn slskd_empty_transfer_json(direction: u32, username: &str, id: u64) -> String {
    serde_json::json!({
        "id": id.to_string(),
        "username": username,
        "direction": if direction == 0 { "Download" } else { "Upload" },
        "filename": "",
        "size": 0,
        "startOffset": 0,
        "state": "None",
        "requestedAt": "",
        "enqueuedAt": "",
        "startedAt": "",
        "endedAt": "",
        "bytesTransferred": 0,
        "averageSpeed": 0.0,
        "bytesRemaining": 0,
        "elapsedTime": "",
        "percentComplete": 0.0,
        "remainingTime": "",
    })
    .to_string()
}

#[derive(Debug)]
struct TransferQueue {
    entries: Vec<TransferEntry>,
    next_id: u64,
    next_token: u32,
    history_limit: usize,
    events_path: PathBuf,
    state_path: PathBuf,
    events_error: Option<String>,
    state_error: Option<String>,
    updated_at: u64,
}

#[derive(Clone, Debug, Default)]
struct TransferRequestDetails {
    request_id: Option<String>,
    request_name: Option<String>,
    destination_directory: Option<String>,
    bit_rate: Option<u32>,
    sample_rate: Option<u32>,
    bit_depth: Option<u32>,
    length_seconds: Option<u32>,
    artist: Option<String>,
    album: Option<String>,
    title: Option<String>,
    track_number: Option<u32>,
    year: Option<u32>,
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct AudioTechnicalMetadata {
    bit_rate: Option<u32>,
    sample_rate: Option<u32>,
    bit_depth: Option<u32>,
    length_seconds: Option<u32>,
}

impl TransferQueue {
    fn new(config: &AppConfig) -> Self {
        let events_path = transfer_events_path(&config.state_dir);
        let state_path = transfer_state_path(&config.state_dir);
        let events_error = write_transfer_events_header(&events_path).err();
        let (entries, state_error) =
            load_transfer_state(&state_path, config.transfer_history_limit)
                .map(|entries| (entries, None))
                .unwrap_or_else(|error| (Vec::new(), Some(error)));
        let next_id = entries
            .iter()
            .map(|entry| entry.id)
            .max()
            .unwrap_or(0)
            .saturating_add(1);
        let next_token = entries
            .iter()
            .map(|entry| entry.token)
            .max()
            .unwrap_or(0)
            .wrapping_add(1)
            .max(1);
        let mut queue = Self {
            entries,
            next_id,
            next_token,
            history_limit: config.transfer_history_limit,
            events_path,
            state_path,
            events_error,
            state_error,
            updated_at: unix_timestamp(),
        };
        if queue.state_error.is_none() {
            queue.persist_state();
        }
        queue
    }

    #[cfg(test)]
    fn new_in_memory(history_limit: usize) -> Self {
        let unique = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|duration| duration.as_nanos())
            .unwrap_or(0);
        let base = std::env::temp_dir().join(format!(
            "slskr-transfer-test-{}-{unique}",
            std::process::id()
        ));
        let events_path = base.with_extension("tsv");
        let state_path = base.with_extension("json");
        let events_error = write_transfer_events_header(&events_path).err();
        Self {
            entries: Vec::new(),
            next_id: 1,
            next_token: 1,
            history_limit,
            events_path,
            state_path,
            events_error,
            state_error: None,
            updated_at: 0,
        }
    }

    fn record_rejected_request(
        &mut self,
        direction: u32,
        token: u32,
        filename: String,
        size: Option<u64>,
        reason: String,
    ) -> TransferEntry {
        let now = unix_timestamp();
        let now_ms = unix_timestamp_millis();
        let id = self.allocate_id();
        let entry = TransferEntry {
            id,
            direction,
            token,
            peer_username: None,
            filename,
            local_path: None,
            batch_id: None,
            request_id: None,
            request_name: None,
            destination_directory: None,
            bit_rate: None,
            sample_rate: None,
            bit_depth: None,
            length_seconds: None,
            artist: None,
            album: None,
            title: None,
            track_number: None,
            year: None,
            size,
            bytes_transferred: 0,
            status: "rejected".to_owned(),
            reason: Some(reason),
            requested_at: now,
            started_at: None,
            start_offset: 0,
            updated_at: now,
            updated_at_ms: now_ms,
        };
        self.push_entry(entry)
    }

    fn record_accepted_inbound_request(
        &mut self,
        direction: u32,
        token: u32,
        peer_username: Option<String>,
        filename: String,
        local_path: String,
        size: u64,
    ) -> TransferEntry {
        let now = unix_timestamp();
        let now_ms = unix_timestamp_millis();
        let id = self.allocate_id();
        let entry = TransferEntry {
            id,
            direction,
            token,
            peer_username,
            filename,
            local_path: Some(local_path),
            batch_id: None,
            request_id: None,
            request_name: None,
            destination_directory: None,
            bit_rate: None,
            sample_rate: None,
            bit_depth: None,
            length_seconds: None,
            artist: None,
            album: None,
            title: None,
            track_number: None,
            year: None,
            size: Some(size),
            bytes_transferred: 0,
            status: "accepted".to_owned(),
            reason: None,
            requested_at: now,
            started_at: None,
            start_offset: 0,
            updated_at: now,
            updated_at_ms: now_ms,
        };
        self.push_entry(entry)
    }

    fn create(
        &mut self,
        direction: u32,
        peer_username: Option<String>,
        filename: String,
        local_path: Option<String>,
        size: Option<u64>,
    ) -> TransferEntry {
        self.create_with_batch(direction, peer_username, filename, local_path, size, None)
    }

    fn create_with_batch(
        &mut self,
        direction: u32,
        peer_username: Option<String>,
        filename: String,
        local_path: Option<String>,
        size: Option<u64>,
        batch_id: Option<String>,
    ) -> TransferEntry {
        let details = if direction == 0 {
            TransferRequestDetails {
                request_id: Some(uuid::Uuid::new_v4().to_string()),
                request_name: Some(virtual_basename(&filename).to_owned()),
                ..TransferRequestDetails::default()
            }
        } else {
            TransferRequestDetails::default()
        };
        self.create_with_details(
            direction,
            peer_username,
            filename,
            local_path,
            size,
            batch_id,
            details,
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn create_with_details(
        &mut self,
        direction: u32,
        peer_username: Option<String>,
        filename: String,
        local_path: Option<String>,
        size: Option<u64>,
        batch_id: Option<String>,
        details: TransferRequestDetails,
    ) -> TransferEntry {
        let now = unix_timestamp();
        let now_ms = unix_timestamp_millis();
        let id = self.allocate_id();
        let token = self.allocate_token();
        let entry = TransferEntry {
            id,
            direction,
            token,
            peer_username,
            filename,
            local_path,
            batch_id,
            request_id: details.request_id,
            request_name: details.request_name,
            destination_directory: details.destination_directory,
            bit_rate: details.bit_rate,
            sample_rate: details.sample_rate,
            bit_depth: details.bit_depth,
            length_seconds: details.length_seconds,
            artist: details.artist,
            album: details.album,
            title: details.title,
            track_number: details.track_number,
            year: details.year,
            size,
            bytes_transferred: 0,
            status: "queued".to_owned(),
            reason: None,
            requested_at: now,
            started_at: None,
            start_offset: 0,
            updated_at: now,
            updated_at_ms: now_ms,
        };
        self.push_entry(entry)
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.entries.len() {
            if !self.entries.iter().any(|entry| entry.id == candidate) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("finite transfer history must leave an available u64 id")
    }

    fn allocate_token(&mut self) -> u32 {
        let mut candidate = self.next_token.max(1);
        for _ in 0..=self.entries.len() {
            if !self.entries.iter().any(|entry| entry.token == candidate) {
                self.next_token = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded transfer history must leave an available u32 token")
    }

    fn update_status(
        &mut self,
        id: u64,
        status: &str,
        bytes_transferred: Option<u64>,
        reason: Option<String>,
    ) -> Option<TransferEntry> {
        let entry = self.entries.iter_mut().find(|entry| entry.id == id)?;
        let now = unix_timestamp();
        if status == "in_progress" && entry.started_at.is_none() {
            entry.started_at = Some(now);
            entry.start_offset = entry.bytes_transferred;
        }
        entry.status = truncate_utf8_bytes(status.to_owned(), MAX_TRANSFER_STATUS_BYTES);
        if let Some(bytes_transferred) = bytes_transferred {
            entry.bytes_transferred = bytes_transferred;
        }
        entry.reason = bounded_transfer_reason(reason);
        entry.updated_at = now;
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn update_local_execution(
        &mut self,
        id: u64,
        status: &str,
        bytes_transferred: u64,
        size: Option<u64>,
        reason: Option<String>,
    ) -> Option<TransferEntry> {
        let entry = self.entries.iter_mut().find(|entry| entry.id == id)?;
        let now = unix_timestamp();
        if entry.started_at.is_none() && bytes_transferred > entry.bytes_transferred {
            entry.started_at = Some(now);
            entry.start_offset = entry.bytes_transferred;
        }
        entry.status = truncate_utf8_bytes(status.to_owned(), MAX_TRANSFER_STATUS_BYTES);
        entry.bytes_transferred = bytes_transferred;
        if size.is_some() {
            entry.size = size;
        }
        entry.reason = bounded_transfer_reason(reason);
        entry.updated_at = now;
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn update_local_path(&mut self, id: u64, local_path: String) -> Option<TransferEntry> {
        let entry = self.entries.iter_mut().find(|entry| entry.id == id)?;
        entry.local_path = Some(truncate_utf8_bytes(
            local_path,
            MAX_TRANSFER_LOCAL_PATH_BYTES,
        ));
        entry.updated_at = unix_timestamp();
        entry.updated_at_ms = unix_timestamp_millis();
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn update_progress(&mut self, id: u64, bytes_transferred: u64) -> Option<TransferEntry> {
        let entry = self.entries.iter_mut().find(|entry| entry.id == id)?;
        let now = unix_timestamp();
        if entry.started_at.is_none() {
            entry.started_at = Some(now);
            entry.start_offset = entry.bytes_transferred;
        }
        entry.status = "in_progress".to_owned();
        entry.bytes_transferred = bytes_transferred;
        entry.reason = None;
        entry.updated_at = now;
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn update_audio_metadata(
        &mut self,
        id: u64,
        metadata: AudioTechnicalMetadata,
    ) -> Option<TransferEntry> {
        let entry = self.entries.iter_mut().find(|entry| entry.id == id)?;
        entry.bit_rate = metadata.bit_rate.or(entry.bit_rate);
        entry.sample_rate = metadata.sample_rate.or(entry.sample_rate);
        entry.bit_depth = metadata.bit_depth.or(entry.bit_depth);
        entry.length_seconds = metadata.length_seconds.or(entry.length_seconds);
        entry.updated_at = unix_timestamp();
        entry.updated_at_ms = unix_timestamp_millis();
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn pending_peer_transfer(&self, username: &str) -> Option<TransferEntry> {
        let username = bounded_transfer_username(username);
        self.entries
            .iter()
            .find(|entry| {
                entry.peer_username.as_deref() == Some(username.as_str())
                    && (entry.status == "peer_lookup" || entry.status == "peer_negotiating")
            })
            .cloned()
    }

    fn pending_indirect_transfer(&self, username: &str, token: u32) -> Option<TransferEntry> {
        let username = bounded_transfer_username(username);
        self.entries
            .iter()
            .find(|entry| {
                entry.peer_username.as_deref() == Some(username.as_str())
                    && entry.token == token
                    && entry.status == "indirect_pending"
            })
            .cloned()
    }

    fn pending_inbound_file_transfer(&self, token: Option<u32>) -> Option<TransferEntry> {
        self.entries
            .iter()
            .find(|entry| {
                entry.local_path.is_some()
                    && (entry.status == "accepted" || entry.status == "in_progress")
                    && token.is_none_or(|token| entry.token == token)
            })
            .cloned()
    }

    fn accept_queued_inbound_negotiation(
        &mut self,
        id: u64,
        token: u32,
        size: Option<u64>,
    ) -> Result<Option<TransferEntry>, String> {
        if token == 0 {
            return Err("queued transfer token must be nonzero".to_owned());
        }
        if self.entries.iter().any(|entry| {
            entry.id != id && entry.token == token && !is_terminal_transfer_status(&entry.status)
        }) {
            return Err("queued transfer token is already active".to_owned());
        }
        let Some(entry) = self.entries.iter_mut().find(|entry| {
            entry.id == id
                && entry.direction == 0
                && entry.local_path.is_some()
                && entry.status == "peer_negotiating"
        }) else {
            return Ok(None);
        };
        entry.token = token;
        if size.is_some() {
            entry.size = size;
        }
        entry.status = "accepted".to_owned();
        entry.reason = None;
        entry.updated_at = unix_timestamp();
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Ok(Some(entry))
    }

    fn accept_pending_remote_upload_request(
        &mut self,
        username: &str,
        filename: &str,
        token: u32,
        size: Option<u64>,
    ) -> Option<TransferEntry> {
        let username = bounded_transfer_username(username);
        let filename = bounded_transfer_filename(filename);
        let entry = self.entries.iter_mut().find(|entry| {
            entry.direction == 0
                && entry.peer_username.as_deref() == Some(username.as_str())
                && entry.filename == filename
                && entry.local_path.is_some()
                && entry.status == "queued"
                && entry
                    .reason
                    .as_deref()
                    .map(is_remote_queue_response)
                    .unwrap_or(false)
        })?;
        entry.token = token;
        if size.is_some() {
            entry.size = size;
        }
        entry.status = "accepted".to_owned();
        entry.reason = None;
        entry.updated_at = unix_timestamp();
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn accept_pending_remote_download_request(
        &mut self,
        username: &str,
        filename: &str,
        token: u32,
        size: Option<u64>,
    ) -> Option<TransferEntry> {
        let username = bounded_transfer_username(username);
        let filename = bounded_transfer_filename(filename);
        let entry = self.entries.iter_mut().find(|entry| {
            entry.direction == 1
                && entry.peer_username.as_deref() == Some(username.as_str())
                && entry.filename == filename
                && entry.local_path.is_some()
                && entry.status == "queued"
                && entry
                    .reason
                    .as_deref()
                    .map(is_remote_queue_response)
                    .unwrap_or(false)
        })?;
        entry.token = token;
        if size.is_some() {
            entry.size = size;
        }
        entry.status = "accepted".to_owned();
        entry.reason = None;
        entry.updated_at = unix_timestamp();
        entry.updated_at_ms = unix_timestamp_millis();
        if let Err(error) = append_transfer_event(&self.events_path, entry) {
            self.events_error = Some(error);
        }
        let entry = entry.clone();
        self.persist_state();
        self.updated_at = unix_timestamp();
        Some(entry)
    }

    fn active_count_excluding(&self, id: Option<u64>) -> usize {
        self.entries
            .iter()
            .filter(|entry| id != Some(entry.id) && is_active_transfer_status(&entry.status))
            .count()
    }

    fn push_entry(&mut self, entry: TransferEntry) -> TransferEntry {
        let entry = bounded_transfer_entry(entry);
        self.entries.push(entry.clone());
        if self.entries.len() > self.history_limit {
            let extra = self.entries.len() - self.history_limit;
            self.entries.drain(0..extra);
        }
        self.updated_at = unix_timestamp();
        if let Err(error) = append_transfer_event(&self.events_path, &entry) {
            self.events_error = Some(error);
        }
        self.persist_state();
        entry
    }

    fn remove_entries(&mut self, ids: &[u64]) -> Vec<TransferEntry> {
        let mut removed = Vec::new();
        self.entries.retain(|entry| {
            if ids.contains(&entry.id) {
                removed.push(entry.clone());
                false
            } else {
                true
            }
        });
        if !removed.is_empty() {
            self.updated_at = unix_timestamp();
            self.persist_state();
        }
        removed
    }

    fn persist_state(&mut self) {
        self.state_error = write_transfer_state(&self.state_path, &self.entries).err();
    }

    fn stats_json(&self) -> String {
        let queued = self
            .entries
            .iter()
            .filter(|entry| entry.status == "queued")
            .count();
        let in_progress = self
            .entries
            .iter()
            .filter(|entry| is_active_transfer_status(&entry.status))
            .count();
        let succeeded = self
            .entries
            .iter()
            .filter(|entry| entry.status == "succeeded")
            .count();
        let cancelled = self
            .entries
            .iter()
            .filter(|entry| entry.status == "cancelled")
            .count();
        let failed = self
            .entries
            .iter()
            .filter(|entry| entry.status == "failed" || entry.status == "rejected")
            .count();
        let bytes_transferred = self
            .entries
            .iter()
            .map(|entry| entry.bytes_transferred)
            .sum::<u64>();
        format!(
             "{{\"total\":{},\"queued\":{},\"in_progress\":{},\"succeeded\":{},\"cancelled\":{},\"failed\":{},\"bytes_transferred\":{},\"updated_at\":{}}}",
             self.entries.len(),
             queued,
             in_progress,
             succeeded,
             cancelled,
             failed,
             bytes_transferred,
             self.updated_at
         )
    }

    fn summary_json(&self) -> String {
        self.stats_json()
    }

    fn slskd_transfers_json(&self, direction: u32, username: Option<&str>) -> String {
        let mut grouped: BTreeMap<String, Vec<&TransferEntry>> = BTreeMap::new();
        for entry in self.entries.iter().filter(|entry| {
            entry.direction == direction
                && username.is_none_or(|username| entry.peer_username.as_deref() == Some(username))
        }) {
            grouped
                .entry(entry.peer_username.clone().unwrap_or_default())
                .or_default()
                .push(entry);
        }

        let transfers = grouped
            .into_iter()
            .map(|(username, entries)| {
                let files = entries
                    .into_iter()
                    .map(TransferEntry::slskd_file_json)
                    .collect::<Vec<_>>();
                serde_json::json!({
                    "username": username,
                    "directories": [{
                        "directory": "",
                        "fileCount": files.len(),
                        "files": files,
                    }],
                })
            })
            .collect::<Vec<_>>();
        serde_json::Value::Array(transfers).to_string()
    }

    fn slskd_transfer_json(&self, direction: u32, username: &str, id: u64) -> Option<String> {
        let entry = self.entries.iter().find(|entry| {
            entry.direction == direction
                && entry.id == id
                && entry.peer_username.as_deref() == Some(username)
        })?;
        Some(entry.slskd_file_json().to_string())
    }

    fn slskd_transfer_position(&self, direction: u32, username: &str, id: u64) -> usize {
        for (position, entry) in self
            .entries
            .iter()
            .filter(|entry| {
                entry.direction == direction
                    && entry.peer_username.as_deref() == Some(username)
                    && (entry.status == "queued" || is_active_transfer_status(&entry.status))
            })
            .enumerate()
        {
            if entry.id == id {
                return position;
            }
        }
        0
    }

    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let entries = self
            .entries
            .iter()
            .filter(|entry| {
                filter
                    .status
                    .as_deref()
                    .is_none_or(|status| entry.status == status)
            })
            .filter(|entry| {
                filter
                    .direction
                    .as_deref()
                    .and_then(|direction| direction.parse::<u32>().ok())
                    .is_none_or(|direction| entry.direction == direction)
            })
            .filter(|entry| {
                filter
                    .username
                    .as_deref()
                    .is_none_or(|username| entry.peer_username.as_deref() == Some(username))
            })
            .filter(|entry| {
                filter.q.as_deref().is_none_or(|q| {
                    entry.filename.to_ascii_lowercase().contains(q)
                        || entry
                            .peer_username
                            .as_deref()
                            .is_some_and(|username| username.to_ascii_lowercase().contains(q))
                })
            })
            .collect::<Vec<_>>();
        let filtered_count = entries.len();
        let entries = entries
            .into_iter()
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(TransferEntry::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"history_limit\":{},\"events_file\":\"{}\",\"events_error\":{},\"state_file\":\"{}\",\"state_error\":{},\"updated_at\":{}}}",
            entries,
            self.entries.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.history_limit,
            json_escape(
                self.events_path
                    .file_name()
                    .and_then(|name| name.to_str())
                    .unwrap_or("transfer-events.tsv")
            ),
            json_option(public_transfer_events_error(self.events_error.as_deref())),
            json_escape(
                self.state_path
                    .file_name()
                    .and_then(|name| name.to_str())
                    .unwrap_or("transfer-state.json")
            ),
            json_option(public_transfer_state_error(self.state_error.as_deref())),
            self.updated_at
        )
    }
}

#[derive(Clone, Debug)]
struct AutoRetryCandidate {
    source: TransferEntry,
    username: String,
    filename: String,
    size: Option<u64>,
    source_kind: &'static str,
}

#[derive(Debug, Default)]
struct AutoRetryTracker {
    retried_ids: HashSet<u64>,
    retry_counts: BTreeMap<String, usize>,
    peer_retry_after: BTreeMap<String, u64>,
    alternate_search_requested_at: BTreeMap<u64, u64>,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum UnderperformanceReason {
    QueuedTooLong,
    ThroughputTooLow,
    Stalled,
}

impl UnderperformanceReason {
    fn as_str(self) -> &'static str {
        match self {
            Self::QueuedTooLong => "queued_too_long",
            Self::ThroughputTooLow => "throughput_too_low",
            Self::Stalled => "stalled",
        }
    }
}

#[derive(Clone, Debug)]
enum RescueAction {
    Search,
    Replace(SearchResultEntry),
}

#[derive(Clone, Debug)]
struct RescueCandidate {
    source: TransferEntry,
    reason: UnderperformanceReason,
    action: RescueAction,
}

#[derive(Debug, Default)]
struct RescueTracker {
    last_progress: BTreeMap<u64, (u64, u64)>,
    search_requested_at: BTreeMap<u64, u64>,
    retry_after: BTreeMap<u64, u64>,
}

fn prune_rescue_tracker(tracker: &mut RescueTracker, entries: &[TransferEntry]) {
    let active_ids = entries
        .iter()
        .filter(|entry| {
            entry.direction == 0 && matches!(entry.status.as_str(), "queued" | "in_progress")
        })
        .map(|entry| entry.id)
        .collect::<HashSet<_>>();
    tracker
        .last_progress
        .retain(|id, _| active_ids.contains(id));
    tracker
        .search_requested_at
        .retain(|id, _| active_ids.contains(id));
    tracker.retry_after.retain(|id, _| active_ids.contains(id));
}

fn underperformance_reason(
    entry: &TransferEntry,
    tracker: &mut RescueTracker,
    settings: &crate::config::TransferRescueSettings,
    now: u64,
) -> Option<UnderperformanceReason> {
    if entry.status == "queued"
        && now.saturating_sub(entry.requested_at) >= settings.max_queue_time.as_secs()
    {
        return Some(UnderperformanceReason::QueuedTooLong);
    }
    if entry.status != "in_progress" {
        return None;
    }
    let duration = entry
        .started_at
        .map(|started_at| now.saturating_sub(started_at))
        .unwrap_or(0);
    if duration >= settings.min_duration.as_secs()
        && entry.average_speed_at(now) < settings.min_throughput_bytes_per_second as f64
    {
        return Some(UnderperformanceReason::ThroughputTooLow);
    }
    let (last_bytes, last_progress_at) = tracker
        .last_progress
        .entry(entry.id)
        .or_insert((entry.bytes_transferred, now));
    if entry.bytes_transferred > *last_bytes {
        *last_bytes = entry.bytes_transferred;
        *last_progress_at = now;
        return None;
    }
    (now.saturating_sub(*last_progress_at) >= settings.stalled_timeout.as_secs())
        .then_some(UnderperformanceReason::Stalled)
}

fn create_rescue_plan(
    entries: &[TransferEntry],
    searches: &SearchStore,
    tracker: &mut RescueTracker,
    settings: &crate::config::TransferRescueSettings,
    now: u64,
) -> Vec<RescueCandidate> {
    prune_rescue_tracker(tracker, entries);
    let latest = latest_download_attempts(entries);
    let mut candidates = entries
        .iter()
        .filter(|entry| {
            if entry.direction != 0
                || !matches!(entry.status.as_str(), "queued" | "in_progress")
                || !is_auto_retry_audio_file(&entry.filename)
                || entry.peer_username.is_none()
                || tracker
                    .retry_after
                    .get(&entry.id)
                    .is_some_and(|retry_after| *retry_after > now)
            {
                return false;
            }
            let identity = entry.request_id.clone().unwrap_or_else(|| {
                auto_retry_key(
                    entry.peer_username.as_deref().unwrap_or_default(),
                    &entry.filename,
                )
            });
            latest.get(&identity) == Some(&entry.id)
        })
        .cloned()
        .collect::<Vec<_>>();
    candidates.sort_by_key(|entry| (entry.requested_at, entry.id));

    let mut plan = Vec::new();
    for source in candidates {
        let Some(reason) = underperformance_reason(&source, tracker, settings, now) else {
            continue;
        };
        let alternative = searches.best_transfer_alternative(
            &source,
            f64::from(settings.alternate_source_size_tolerance_percent),
            |_| false,
        );
        let action = if let Some(alternative) = alternative {
            RescueAction::Replace(alternative)
        } else if tracker
            .search_requested_at
            .get(&source.id)
            .is_none_or(|requested_at| {
                requested_at.saturating_add(settings.retry_cooldown.as_secs()) <= now
            })
        {
            RescueAction::Search
        } else {
            continue;
        };
        plan.push(RescueCandidate {
            source,
            reason,
            action,
        });
        if plan.len() >= settings.max_files_per_cycle {
            break;
        }
    }
    plan
}

fn auto_retry_key(username: &str, filename: &str) -> String {
    format!("{}\u{1f}{}", username.to_ascii_lowercase(), filename)
}

fn prune_auto_retry_tracker(tracker: &mut AutoRetryTracker, entries: &[TransferEntry], now: u64) {
    let live_ids = entries.iter().map(|entry| entry.id).collect::<HashSet<_>>();
    let live_retry_keys = entries
        .iter()
        .filter_map(|entry| {
            entry
                .peer_username
                .as_deref()
                .map(|username| auto_retry_key(username, &entry.filename))
        })
        .collect::<HashSet<_>>();
    tracker.retried_ids.retain(|id| live_ids.contains(id));
    tracker
        .alternate_search_requested_at
        .retain(|id, _| live_ids.contains(id));
    tracker
        .retry_counts
        .retain(|key, _| live_retry_keys.contains(key));
    tracker
        .peer_retry_after
        .retain(|_, retry_after| *retry_after > now);
}

fn is_auto_retry_audio_file(filename: &str) -> bool {
    let extension = virtual_basename(filename)
        .rsplit_once('.')
        .map(|(_, extension)| extension.to_ascii_lowercase());
    matches!(
        extension.as_deref(),
        Some("flac" | "mp3" | "m4a" | "aac" | "ogg" | "opus" | "wav" | "alac")
    )
}

fn alternate_size_is_eligible(original: Option<u64>, candidate: u64, tolerance: f64) -> bool {
    let Some(original) = original.filter(|size| *size > 0) else {
        return true;
    };
    let difference_percent = (original.abs_diff(candidate) as f64 / original as f64) * 100.0;
    difference_percent <= tolerance
}

fn latest_download_attempts(entries: &[TransferEntry]) -> BTreeMap<String, u64> {
    let mut latest = BTreeMap::<String, u64>::new();
    for entry in entries.iter().filter(|entry| entry.direction == 0) {
        let identity = entry.request_id.clone().unwrap_or_else(|| {
            auto_retry_key(
                entry.peer_username.as_deref().unwrap_or_default(),
                &entry.filename,
            )
        });
        latest
            .entry(identity)
            .and_modify(|id| *id = (*id).max(entry.id))
            .or_insert(entry.id);
    }
    latest
}

fn create_auto_retry_plan(
    entries: &[TransferEntry],
    searches: &SearchStore,
    tracker: &AutoRetryTracker,
    settings: &crate::config::TransferAutoRetrySettings,
    now: u64,
    available_slots: usize,
) -> Vec<AutoRetryCandidate> {
    if available_slots == 0 {
        return Vec::new();
    }
    let cutoff = now.saturating_sub(settings.retry_delay.as_secs());
    let latest = latest_download_attempts(entries);
    let mut failed = entries
        .iter()
        .filter(|entry| {
            if entry.direction != 0
                || entry.status != "failed"
                || entry.updated_at > cutoff
                || tracker.retried_ids.contains(&entry.id)
                || !is_auto_retry_audio_file(&entry.filename)
                || entry.peer_username.is_none()
            {
                return false;
            }
            let identity = entry.request_id.clone().unwrap_or_else(|| {
                auto_retry_key(
                    entry.peer_username.as_deref().unwrap_or_default(),
                    &entry.filename,
                )
            });
            latest.get(&identity) == Some(&entry.id)
        })
        .cloned()
        .collect::<Vec<_>>();
    failed.sort_by_key(|entry| (entry.updated_at, entry.id));

    let global_limit = settings.max_files_per_cycle.min(available_slots);
    let mut per_peer = BTreeMap::<String, usize>::new();
    let mut alternate_searches = 0usize;
    let mut plan = Vec::new();
    for source in failed {
        let alternative = settings
            .alternate_sources_enabled
            .then(|| {
                searches.best_transfer_alternative(
                    &source,
                    settings.alternate_source_size_tolerance_percent,
                    |username| {
                        tracker
                            .peer_retry_after
                            .get(&username.to_ascii_lowercase())
                            .is_some_and(|retry_after| *retry_after > now)
                    },
                )
            })
            .flatten();
        let (username, filename, size, source_kind) = if let Some(alternative) = alternative {
            let Some(username) = alternative.peer_username else {
                continue;
            };
            (
                username,
                alternative.filename,
                Some(alternative.size),
                "cached-search",
            )
        } else if settings.alternate_sources_enabled
            && !tracker
                .alternate_search_requested_at
                .contains_key(&source.id)
            && alternate_searches < settings.max_alternate_source_searches_per_cycle
        {
            alternate_searches += 1;
            (
                source
                    .peer_username
                    .clone()
                    .expect("filtered peer username"),
                source.filename.clone(),
                source.size,
                "network-search",
            )
        } else if tracker
            .alternate_search_requested_at
            .get(&source.id)
            .is_some_and(|requested_at| {
                requested_at.saturating_add(settings.check_interval.as_secs()) > now
            })
        {
            continue;
        } else {
            (
                source
                    .peer_username
                    .clone()
                    .expect("filtered peer username"),
                source.filename.clone(),
                source.size,
                "original",
            )
        };
        let peer_key = username.to_ascii_lowercase();
        if tracker
            .peer_retry_after
            .get(&peer_key)
            .is_some_and(|retry_after| *retry_after > now)
        {
            continue;
        }
        if per_peer.get(&peer_key).copied().unwrap_or(0) >= settings.max_files_per_peer_per_cycle {
            continue;
        }
        let retry_key = auto_retry_key(&username, &filename);
        let attempts = tracker.retry_counts.get(&retry_key).copied().unwrap_or(0);
        if settings.max_attempts != 0 && attempts >= settings.max_attempts {
            continue;
        }
        *per_peer.entry(peer_key).or_default() += 1;
        plan.push(AutoRetryCandidate {
            source,
            username,
            filename,
            size,
            source_kind,
        });
        if plan.len() >= global_limit {
            break;
        }
    }
    plan
}

fn public_transfer_events_error(error: Option<&str>) -> Option<&'static str> {
    error.map(|_| "transfer events unavailable")
}

fn public_transfer_state_error(error: Option<&str>) -> Option<&'static str> {
    error.map(|_| "transfer state unavailable")
}

fn bounded_transfer_username(username: &str) -> String {
    truncate_utf8_bytes(username.to_owned(), MAX_TRANSFER_USERNAME_BYTES)
}

fn bounded_transfer_filename(filename: &str) -> String {
    truncate_utf8_bytes(filename.to_owned(), MAX_TRANSFER_FILENAME_BYTES)
}

fn bounded_transfer_reason(reason: Option<String>) -> Option<String> {
    reason.map(|reason| truncate_utf8_bytes(reason, MAX_TRANSFER_REASON_BYTES))
}

fn bounded_transfer_entry(mut entry: TransferEntry) -> TransferEntry {
    if entry.updated_at_ms == 0 {
        entry.updated_at_ms = entry.updated_at.saturating_mul(1_000);
    }
    entry.peer_username = entry
        .peer_username
        .map(|username| truncate_utf8_bytes(username, MAX_TRANSFER_USERNAME_BYTES));
    entry.filename = truncate_utf8_bytes(entry.filename, MAX_TRANSFER_FILENAME_BYTES);
    entry.local_path = entry
        .local_path
        .filter(|path| path.len() <= MAX_TRANSFER_LOCAL_PATH_BYTES);
    entry.batch_id = entry
        .batch_id
        .map(|batch_id| truncate_utf8_bytes(batch_id, MAX_TRANSFER_BATCH_ID_BYTES));
    entry.request_id = entry
        .request_id
        .map(|request_id| truncate_utf8_bytes(request_id, MAX_TRANSFER_REQUEST_ID_BYTES));
    if entry.direction == 0 && entry.request_id.is_none() {
        entry.request_id = Some(uuid::Uuid::new_v4().to_string());
    }
    entry.request_name = entry
        .request_name
        .or_else(|| (entry.direction == 0).then(|| virtual_basename(&entry.filename).to_owned()))
        .map(|name| truncate_utf8_bytes(name, MAX_TRANSFER_REQUEST_NAME_BYTES));
    entry.destination_directory = entry
        .destination_directory
        .filter(|path| path.len() <= MAX_TRANSFER_LOCAL_PATH_BYTES);
    entry.artist = entry
        .artist
        .map(|value| truncate_utf8_bytes(value, MAX_TRANSFER_METADATA_TEXT_BYTES));
    entry.album = entry
        .album
        .map(|value| truncate_utf8_bytes(value, MAX_TRANSFER_METADATA_TEXT_BYTES));
    entry.title = entry
        .title
        .map(|value| truncate_utf8_bytes(value, MAX_TRANSFER_METADATA_TEXT_BYTES));
    entry.status = truncate_utf8_bytes(entry.status, MAX_TRANSFER_STATUS_BYTES);
    entry.reason = bounded_transfer_reason(entry.reason);
    entry
}

#[derive(Clone, Debug)]
struct SessionSnapshot {
    state: &'static str,
    username: Option<String>,
    supporter: Option<bool>,
    privileges_seconds: Option<u32>,
    last_error: Option<String>,
    last_server_message: Option<String>,
    server_messages_seen: u64,
    reconnects: u64,
    connected_at: Option<u64>,
    updated_at: u64,
}

impl SessionSnapshot {
    fn disconnected(config: &AppConfig) -> Self {
        Self {
            state: "disconnected",
            username: config.username.as_deref().map(redact_username),
            supporter: None,
            privileges_seconds: None,
            last_error: None,
            last_server_message: None,
            server_messages_seen: 0,
            reconnects: 0,
            connected_at: None,
            updated_at: unix_timestamp(),
        }
    }

    fn json(&self) -> String {
        format!(
            "{{\"state\":\"{}\",\"username\":{},\"supporter\":{},\"privileges_seconds\":{},\"last_error\":{},\"last_server_message\":{},\"server_messages_seen\":{},\"reconnects\":{},\"connected_at\":{},\"updated_at\":{}}}",
            self.state,
            json_option(self.username.as_deref()),
            json_bool_option(self.supporter),
            json_u32_option(self.privileges_seconds),
            json_option(public_session_error(self.last_error.as_deref())),
            json_option(self.last_server_message.as_deref()),
            self.server_messages_seen,
            self.reconnects,
            json_u64_option(self.connected_at),
            self.updated_at
        )
    }

    fn summary_json(&self) -> String {
        format!(
            "{{\"state\":\"{}\",\"connected\":{},\"privileges_seconds\":{},\"server_messages_seen\":{},\"reconnects\":{},\"connected_at\":{},\"updated_at\":{}}}",
            self.state,
            self.state == "connected",
            json_u32_option(self.privileges_seconds),
            self.server_messages_seen,
            self.reconnects,
            json_u64_option(self.connected_at),
            self.updated_at
        )
    }
}

fn public_session_error(error: Option<&str>) -> Option<&'static str> {
    error.map(|error| {
        if error.starts_with("login failed") {
            "login failed"
        } else if error.starts_with("connect failed") {
            "connection failed"
        } else {
            "session operation failed"
        }
    })
}

