#[derive(Clone, Debug, PartialEq, Eq)]
struct RoomRecord {
    name: String,
    joined: bool,
    kind: &'static str,
    user_count: Option<u32>,
    operated: bool,
    last_error: Option<String>,
    ticker: Option<String>,
    members: Vec<String>,
    messages: Vec<RoomMessageRecord>,
    updated_at: u64,
}

impl RoomRecord {
    fn json(&self) -> String {
        let messages = self
            .messages
            .iter()
            .map(RoomMessageRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"name\":\"{}\",\"joined\":{},\"kind\":\"{}\",\"user_count\":{},\"operated\":{},\"last_error\":{},\"ticker\":{},\"members\":{},\"messages\":[{}],\"message_count\":{},\"updated_at\":{}}}",
            json_escape(&self.name),
            self.joined,
            self.kind,
            json_u32_option(self.user_count),
            self.operated,
            json_option(self.last_error.as_deref()),
            json_option(self.ticker.as_deref()),
            serde_json::to_string(&self.members).unwrap_or_else(|_| "[]".to_owned()),
            messages,
            self.messages.len(),
            self.updated_at
        )
    }

    fn slskd_info_json(&self) -> serde_json::Value {
        serde_json::json!({
            "name": self.name,
            "userCount": self.user_count.unwrap_or(0),
            "isPrivate": self.kind != "public",
            "isOwned": self.operated,
            "isModerated": self.operated,
            "lastError": self.last_error,
            "ticker": self.ticker,
            "memberCount": self.members.len(),
        })
    }

    fn slskd_room_json(&self) -> serde_json::Value {
        serde_json::json!({
            "name": self.name,
            "isPrivate": self.kind != "public",
            "users": self.members,
            "messages": self.messages.iter().map(|message| message.slskd_json(&self.name)).collect::<Vec<_>>(),
            "ticker": self.ticker,
            "lastError": self.last_error,
        })
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct RoomStore {
    records: Vec<RoomRecord>,
    next_message_id: u64,
    updated_at: u64,
    max_records: usize,
    max_members_per_room: usize,
}

impl RoomStore {
    fn new() -> Self {
        Self::with_limits(MAX_ROOM_RECORDS, MAX_ROOM_MEMBERS_PER_ROOM)
    }

    fn with_limits(max_records: usize, max_members_per_room: usize) -> Self {
        Self {
            records: Vec::new(),
            next_message_id: 1,
            updated_at: unix_timestamp(),
            max_records: max_records.max(1),
            max_members_per_room: max_members_per_room.max(1),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::RoomRecord>) -> Self {
        let mut store = Self::new();
        store.records = records
            .into_iter()
            .take(store.max_records)
            .map(|record| RoomRecord {
                name: bounded_room_name(&record.name),
                joined: record.subscribed,
                kind: if record.owner.is_some() {
                    "private"
                } else {
                    "local"
                },
                user_count: None,
                operated: false,
                last_error: None,
                ticker: None,
                members: Vec::new(),
                messages: Vec::new(),
                updated_at: u64::try_from(record.last_activity).unwrap_or_default(),
            })
            .collect();
        store.updated_at = store
            .records
            .iter()
            .map(|record| record.updated_at)
            .max()
            .unwrap_or_else(unix_timestamp);
        store
    }

    fn merge_configured(&mut self, rooms: &[String]) {
        for room in rooms {
            let _ = self.join(room.clone());
        }
    }

    fn join(&mut self, name: String) -> Option<RoomRecord> {
        let name = bounded_room_name(&name);
        let now = unix_timestamp();
        if let Some(record) = self.records.iter_mut().find(|record| record.name == name) {
            record.joined = true;
            record.last_error = None;
            record.updated_at = now;
            self.updated_at = now;
            return Some(record.clone());
        }
        if self.records.len() >= self.max_records {
            return None;
        }
        let record = RoomRecord {
            name,
            joined: true,
            kind: "local",
            user_count: None,
            operated: false,
            last_error: None,
            ticker: None,
            members: Vec::new(),
            messages: Vec::new(),
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn leave(&mut self, name: &str) -> Option<RoomRecord> {
        let name = bounded_room_name(name);
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|record| record.name == name)?;
        record.joined = false;
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn fail_join(&mut self, name: &str, reason: String) -> Option<RoomRecord> {
        let name = bounded_room_name(name);
        let reason = truncate_utf8_bytes(reason, MAX_ROOM_ERROR_BYTES);
        let now = unix_timestamp();
        if let Some(record) = self.records.iter_mut().find(|record| record.name == name) {
            record.joined = false;
            record.last_error = Some(reason);
            record.updated_at = now;
            self.updated_at = now;
            return Some(record.clone());
        }
        if self.records.len() >= self.max_records {
            return None;
        }
        let record = RoomRecord {
            name,
            joined: false,
            kind: "local",
            user_count: None,
            operated: false,
            last_error: Some(reason),
            ticker: None,
            members: Vec::new(),
            messages: Vec::new(),
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn apply_room_list(&mut self, room_list: &RoomList) {
        for entry in &room_list.public_rooms {
            self.upsert_room_list_entry(entry, "public", false);
        }
        for entry in &room_list.owned_private_rooms {
            self.upsert_room_list_entry(entry, "owned_private", true);
        }
        for entry in &room_list.private_rooms {
            let operated = room_list
                .operated_private_rooms
                .iter()
                .any(|room| room == &entry.name);
            self.upsert_room_list_entry(entry, "private", operated);
        }
        for room in &room_list.operated_private_rooms {
            let room = bounded_room_name(room);
            if self.records.len() < self.max_records
                && !self.records.iter().any(|record| record.name == room)
            {
                let now = unix_timestamp();
                self.records.push(RoomRecord {
                    name: room,
                    joined: false,
                    kind: "operated_private",
                    user_count: None,
                    operated: true,
                    last_error: None,
                    ticker: None,
                    members: Vec::new(),
                    messages: Vec::new(),
                    updated_at: now,
                });
                self.updated_at = now;
            }
        }
    }

    fn upsert_room_list_entry(
        &mut self,
        entry: &RoomListEntry,
        kind: &'static str,
        operated: bool,
    ) -> Option<RoomRecord> {
        let name = bounded_room_name(&entry.name);
        let now = unix_timestamp();
        if let Some(record) = self.records.iter_mut().find(|record| record.name == name) {
            record.kind = kind;
            record.user_count = Some(entry.user_count);
            record.operated = operated;
            record.last_error = None;
            record.updated_at = now;
            self.updated_at = now;
            return Some(record.clone());
        }
        if self.records.len() >= self.max_records {
            return None;
        }
        let record = RoomRecord {
            name,
            joined: false,
            kind,
            user_count: Some(entry.user_count),
            operated,
            last_error: None,
            ticker: None,
            members: Vec::new(),
            messages: Vec::new(),
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn add_message(&mut self, room: &str, username: String, body: String) -> Option<RoomRecord> {
        let room = bounded_room_name(room);
        let record_index = self.records.iter().position(|record| record.name == room)?;
        while self.total_messages() >= MAX_TOTAL_ROOM_MESSAGES {
            self.evict_oldest_message()?;
        }
        let now = unix_timestamp();
        let now_ms = unix_timestamp_millis().max(
            self.records
                .iter()
                .flat_map(|record| record.messages.iter())
                .map(|message| message.created_at_ms)
                .max()
                .unwrap_or(0)
                .saturating_add(1),
        );
        let id = self.allocate_message_id();
        let record = &mut self.records[record_index];
        record.messages.push(RoomMessageRecord {
            id,
            username: truncate_utf8_bytes(username, MAX_ROOM_USERNAME_BYTES),
            body: truncate_utf8_bytes(body, MAX_ROOM_MESSAGE_BODY_BYTES),
            created_at: now,
            created_at_ms: now_ms,
        });
        if record.messages.len() > MAX_ROOM_MESSAGES_PER_ROOM {
            let excess = record.messages.len() - MAX_ROOM_MESSAGES_PER_ROOM;
            record.messages.drain(0..excess);
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn allocate_message_id(&mut self) -> u64 {
        let mut candidate = self.next_message_id.max(1);
        for _ in 0..=self.total_messages() {
            if !self
                .records
                .iter()
                .flat_map(|room| room.messages.iter())
                .any(|message| message.id == candidate)
            {
                self.next_message_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded room message history must leave an available u64 id")
    }

    fn activity_json(&self, local_username: &str) -> String {
        let activity = self
            .records
            .iter()
            .filter(|room| room.joined)
            .filter_map(|room| {
                room.messages
                    .iter()
                    .rev()
                    .find(|message| message.username != local_username)
                    .map(|message| {
                        (
                            room.name.clone(),
                            serde_json::Value::from(message.created_at.saturating_mul(1_000)),
                        )
                    })
            })
            .collect::<serde_json::Map<String, serde_json::Value>>();
        serde_json::Value::Object(activity).to_string()
    }

    fn set_ticker(&mut self, room: &str, ticker: String) -> Option<RoomRecord> {
        let room = bounded_room_name(room);
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|record| record.name == room)?;
        record.ticker = Some(truncate_utf8_bytes(ticker, MAX_ROOM_TICKER_BYTES));
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn add_member(&mut self, room: &str, username: String) -> Result<Option<RoomRecord>, ()> {
        let room = bounded_room_name(room);
        let now = unix_timestamp();
        let username = truncate_utf8_bytes(username.trim().to_owned(), MAX_ROOM_USERNAME_BYTES);
        if username.is_empty() {
            return Ok(None);
        }
        let total_members = self.total_members();
        let record = match self.records.iter_mut().find(|record| record.name == room) {
            Some(record) => record,
            None => return Ok(None),
        };
        if !record
            .members
            .iter()
            .any(|member| member.eq_ignore_ascii_case(&username))
        {
            if record.members.len() >= self.max_members_per_room
                || total_members >= MAX_TOTAL_ROOM_MEMBERS
            {
                return Err(());
            }
            record.members.push(username);
        }
        record.user_count = Some(u32::try_from(record.members.len()).unwrap_or(u32::MAX));
        record.updated_at = now;
        self.updated_at = now;
        Ok(Some(record.clone()))
    }

    fn remove_member(&mut self, room: &str, username: &str) -> Option<RoomRecord> {
        let room = bounded_room_name(room);
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|record| record.name == room)?;
        let member = record
            .members
            .iter()
            .position(|member| member.eq_ignore_ascii_case(username))?;
        record.members.remove(member);
        record.user_count = Some(u32::try_from(record.members.len()).unwrap_or(u32::MAX));
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn total_messages(&self) -> usize {
        self.records
            .iter()
            .map(|record| record.messages.len())
            .sum()
    }

    fn total_members(&self) -> usize {
        self.records.iter().map(|record| record.members.len()).sum()
    }

    fn evict_oldest_message(&mut self) -> Option<()> {
        let room_index = self
            .records
            .iter()
            .enumerate()
            .filter_map(|(index, record)| {
                record
                    .messages
                    .first()
                    .map(|message| (index, message.created_at))
            })
            .min_by_key(|(index, created_at)| (*created_at, *index))?
            .0;
        self.records[room_index].messages.remove(0);
        Some(())
    }

    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let filtered_count = self
            .records
            .iter()
            .filter(|record| filter.joined.is_none_or(|joined| record.joined == joined))
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .count();
        format!(
            "{{\"entries\":{},\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            self.json_array(query),
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| filter.joined.is_none_or(|joined| record.joined == joined))
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(RoomRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }

    fn joined_names_json(&self) -> String {
        let records = self
            .records
            .iter()
            .filter(|record| record.joined)
            .map(|record| json_option(Some(record.name.as_str())))
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }

    fn slskd_available_json(&self) -> String {
        serde_json::Value::Array(
            self.records
                .iter()
                .map(RoomRecord::slskd_info_json)
                .collect::<Vec<_>>(),
        )
        .to_string()
    }

    fn summary_json(&self) -> String {
        let joined = self.records.iter().filter(|record| record.joined).count();
        let messages = self
            .records
            .iter()
            .map(|record| record.messages.len())
            .sum::<usize>();
        format!(
            "{{\"total\":{},\"joined\":{},\"messages\":{},\"updated_at\":{}}}",
            self.records.len(),
            joined,
            messages,
            self.updated_at
        )
    }
}

fn bounded_room_name(name: &str) -> String {
    truncate_utf8_bytes(name.to_owned(), MAX_ROOM_NAME_BYTES)
}

// Collection Models
fn unix_seconds_rfc3339(timestamp: u64) -> String {
    chrono::DateTime::<chrono::Utc>::from_timestamp(i64::try_from(timestamp).unwrap_or(i64::MAX), 0)
        .unwrap_or(chrono::DateTime::<chrono::Utc>::UNIX_EPOCH)
        .to_rfc3339_opts(chrono::SecondsFormat::Secs, true)
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CollectionItem {
    id: String,
    content_id: String,
    artist: String,
    title: String,
    kind: String,
    file_name: String,
    album: String,
    content_hash: String,
    added_at: u64,
}

impl CollectionItem {
    fn json(&self) -> String {
        format!(
            "{{\"id\":\"{}\",\"contentId\":\"{}\",\"content_id\":\"{}\",\"artist\":\"{}\",\"title\":\"{}\",\"fileName\":\"{}\",\"mediaKind\":\"{}\",\"kind\":\"{}\",\"addedAt\":{},\"added_at\":{}}}",
            json_escape(&self.id),
            json_escape(&self.content_id),
            json_escape(&self.content_id),
            json_escape(&self.artist),
            json_escape(&self.title),
            json_escape(if self.file_name.is_empty() { &self.title } else { &self.file_name }),
            json_escape(&self.kind),
            json_escape(&self.kind),
            self.added_at,
            self.added_at
        )
    }

    fn slskdn_json(&self, collection_id: &str, ordinal: usize) -> String {
        serde_json::json!({
            "id": self.id,
            "collectionId": collection_id,
            "ordinal": ordinal,
            "contentId": self.content_id,
            "mediaKind": (!self.kind.is_empty()).then_some(self.kind.as_str()),
            "fileName": (!self.file_name.is_empty()).then_some(self.file_name.as_str()),
            "title": (!self.title.is_empty()).then_some(self.title.as_str()),
            "artist": (!self.artist.is_empty()).then_some(self.artist.as_str()),
            "album": (!self.album.is_empty()).then_some(self.album.as_str()),
            "contentHash": (!self.content_hash.is_empty()).then_some(self.content_hash.as_str()),
        })
        .to_string()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CollectionRecord {
    id: String,
    owner_user_id: String,
    name: String,
    description: String,
    collection_type: String,
    items: Vec<CollectionItem>,
    created_at: u64,
    updated_at: u64,
}

impl CollectionRecord {
    fn json(&self) -> String {
        let items = self
            .items
            .iter()
            .map(CollectionItem::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"id\":\"{}\",\"title\":\"{}\",\"name\":\"{}\",\"type\":\"ShareList\",\"description\":\"{}\",\"items\":[{}],\"itemCount\":{},\"item_count\":{},\"createdAt\":{},\"created_at\":{},\"updatedAt\":{},\"updated_at\":{}}}",
            json_escape(&self.id),
            json_escape(&self.name),
            json_escape(&self.name),
            json_escape(&self.description),
            items,
            self.items.len(),
            self.items.len(),
            self.created_at,
            self.created_at,
            self.updated_at,
            self.updated_at
        )
    }

    fn slskdn_json(&self) -> String {
        serde_json::json!({
            "id": self.id,
            "ownerUserId": self.owner_user_id,
            "title": self.name,
            "description": (!self.description.is_empty()).then_some(self.description.as_str()),
            "type": self.collection_type,
            "createdAt": unix_seconds_rfc3339(self.created_at),
            "updatedAt": unix_seconds_rfc3339(self.updated_at),
        })
        .to_string()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CollectionStore {
    records: Vec<CollectionRecord>,
    next_id: u64,
    next_item_id: u64,
    updated_at: u64,
    max_records: usize,
    max_items_per_collection: usize,
}

impl CollectionStore {
    fn new() -> Self {
        Self::with_limits(MAX_COLLECTIONS, MAX_COLLECTION_ITEMS)
    }

    fn with_limits(max_records: usize, max_items_per_collection: usize) -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            next_item_id: 1,
            updated_at: unix_timestamp(),
            max_records: max_records.max(1),
            max_items_per_collection: max_items_per_collection.max(1),
        }
    }

    fn from_persisted(
        collections: Vec<crate::persistence::CollectionRecord>,
        items: Vec<crate::persistence::CollectionItemRecord>,
    ) -> Self {
        let mut next_id = 1;
        let mut next_item_id = 1;
        let mut updated_at = unix_timestamp();
        let mut records = Vec::new();
        let mut retained_items = 0_usize;
        let mut seen_collection_ids = HashSet::new();
        for record in collections {
            if let Some(number) = record
                .id
                .strip_prefix("col-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                next_id = next_id.max(number.saturating_add(1));
            }
            if records.len() < MAX_COLLECTIONS && seen_collection_ids.insert(record.id.clone()) {
                let created_at = u64::try_from(record.created_at).unwrap_or(0);
                let record_updated_at = u64::try_from(record.updated_at).unwrap_or(created_at);
                updated_at = updated_at.max(record_updated_at);
                records.push(CollectionRecord {
                    id: record.id,
                    owner_user_id: record.owner_user_id,
                    name: truncate_utf8_bytes(record.name, MAX_LIST_NAME_BYTES),
                    description: truncate_utf8_bytes(
                        record.description,
                        MAX_LIST_DESCRIPTION_BYTES,
                    ),
                    collection_type: record.collection_type,
                    items: Vec::new(),
                    created_at,
                    updated_at: record_updated_at,
                });
            }
        }
        let mut items = items;
        items.sort_by_key(|item| (item.collection_id.clone(), item.position, item.added_at));
        let mut seen_item_ids = HashSet::new();
        for item in items {
            if let Some(number) = item
                .id
                .strip_prefix("item-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                next_item_id = next_item_id.max(number.saturating_add(1));
            }
            if !seen_item_ids.insert(item.id.clone()) {
                continue;
            }
            let Some(collection) = records
                .iter_mut()
                .find(|record| record.id == item.collection_id)
            else {
                continue;
            };
            if collection.items.len() >= MAX_COLLECTION_ITEMS
                || retained_items >= MAX_TOTAL_COLLECTION_ITEMS
            {
                continue;
            }
            collection
                .items
                .push(bounded_collection_item(CollectionItem {
                    id: item.id,
                    content_id: item.content_id,
                    artist: item.artist,
                    title: item.title,
                    kind: item.kind,
                    file_name: item.file_name,
                    album: item.album,
                    content_hash: item.content_hash,
                    added_at: u64::try_from(item.added_at).unwrap_or(0),
                }));
            retained_items = retained_items.saturating_add(1);
        }
        Self {
            records,
            next_id,
            next_item_id,
            updated_at,
            max_records: MAX_COLLECTIONS,
            max_items_per_collection: MAX_COLLECTION_ITEMS,
        }
    }

    fn create(&mut self, name: String, description: String) -> Option<CollectionRecord> {
        let id = format!("col-{}", self.allocate_id());
        self.create_with_contract(id, String::new(), name, description, "ShareList".to_owned())
    }

    fn create_with_contract(
        &mut self,
        id: String,
        owner_user_id: String,
        name: String,
        description: String,
        collection_type: String,
    ) -> Option<CollectionRecord> {
        if self.records.len() >= self.max_records {
            return None;
        }
        let now = unix_timestamp();
        let record = CollectionRecord {
            id,
            owner_user_id: truncate_utf8_bytes(owner_user_id, MAX_LIST_NAME_BYTES),
            name: truncate_utf8_bytes(name, MAX_LIST_NAME_BYTES),
            description: truncate_utf8_bytes(description, MAX_LIST_DESCRIPTION_BYTES),
            collection_type,
            items: Vec::new(),
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn get(&self, id: &str) -> Option<CollectionRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(&mut self, id: &str, name: String, description: String) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.name = truncate_utf8_bytes(name, MAX_LIST_NAME_BYTES);
        record.description = truncate_utf8_bytes(description, MAX_LIST_DESCRIPTION_BYTES);
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn update_contract(
        &mut self,
        id: &str,
        name: Option<String>,
        description: Option<String>,
        collection_type: Option<String>,
    ) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|record| record.id == id)?;
        if let Some(name) = name {
            record.name = truncate_utf8_bytes(name, MAX_LIST_NAME_BYTES);
        }
        if let Some(description) = description {
            record.description = truncate_utf8_bytes(description, MAX_LIST_DESCRIPTION_BYTES);
        }
        if let Some(collection_type) = collection_type {
            record.collection_type = collection_type;
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    #[cfg(test)]
    fn add_item(
        &mut self,
        collection_id: &str,
        content_id: String,
        artist: String,
        title: String,
        kind: String,
    ) -> Result<Option<CollectionItem>, ()> {
        self.add_item_with_contract(
            collection_id,
            None,
            content_id,
            artist,
            title,
            kind,
            String::new(),
            String::new(),
            String::new(),
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn add_item_with_contract(
        &mut self,
        collection_id: &str,
        id: Option<String>,
        content_id: String,
        artist: String,
        title: String,
        kind: String,
        file_name: String,
        album: String,
        content_hash: String,
    ) -> Result<Option<CollectionItem>, ()> {
        let now = unix_timestamp();
        let Some(index) = self.records.iter().position(|r| r.id == collection_id) else {
            return Ok(None);
        };
        if self.records[index].items.len() >= self.max_items_per_collection
            || self.total_items() >= MAX_TOTAL_COLLECTION_ITEMS
        {
            return Err(());
        }
        let id = id.unwrap_or_else(|| format!("item-{}", self.allocate_item_id()));
        let item = bounded_collection_item(CollectionItem {
            id,
            content_id,
            artist,
            title,
            kind,
            file_name,
            album,
            content_hash,
            added_at: now,
        });
        let record = &mut self.records[index];
        record.items.push(item.clone());
        record.updated_at = now;
        self.updated_at = now;
        Ok(Some(item))
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            let id = format!("col-{candidate}");
            if !self.records.iter().any(|record| record.id == id) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded collection store must leave an available u64 id")
    }

    fn allocate_item_id(&mut self) -> u64 {
        let retained_items = self
            .records
            .iter()
            .map(|record| record.items.len())
            .sum::<usize>();
        let mut candidate = self.next_item_id.max(1);
        for _ in 0..=retained_items {
            let id = format!("item-{candidate}");
            if !self
                .records
                .iter()
                .flat_map(|record| &record.items)
                .any(|item| item.id == id)
            {
                self.next_item_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded collection items must leave an available u64 id")
    }

    fn update_item(
        &mut self,
        item_id: &str,
        artist: Option<String>,
        title: Option<String>,
        kind: Option<String>,
    ) -> Option<CollectionItem> {
        let now = unix_timestamp();
        for record in &mut self.records {
            if let Some(item) = record.items.iter_mut().find(|item| item.id == item_id) {
                if let Some(artist) = artist {
                    item.artist = truncate_utf8_bytes(artist, MAX_LIST_ARTIST_BYTES);
                }
                if let Some(title) = title {
                    item.title = truncate_utf8_bytes(title, MAX_LIST_TITLE_BYTES);
                }
                if let Some(kind) = kind {
                    item.kind = truncate_utf8_bytes(kind, MAX_LIST_KIND_BYTES);
                }
                record.updated_at = now;
                self.updated_at = now;
                return Some(item.clone());
            }
        }
        None
    }

    #[allow(clippy::too_many_arguments)]
    fn update_item_contract(
        &mut self,
        item_id: &str,
        content_id: Option<String>,
        artist: Option<String>,
        title: Option<String>,
        kind: Option<String>,
        file_name: Option<String>,
        album: Option<String>,
        content_hash: Option<String>,
    ) -> Option<CollectionItem> {
        let now = unix_timestamp();
        for record in &mut self.records {
            if let Some(item) = record.items.iter_mut().find(|item| item.id == item_id) {
                if let Some(content_id) = content_id {
                    if content_id.trim().is_empty() {
                        return None;
                    }
                    item.content_id = truncate_utf8_bytes(content_id, MAX_LIST_CONTENT_ID_BYTES);
                }
                if let Some(artist) = artist {
                    item.artist = truncate_utf8_bytes(artist, MAX_LIST_ARTIST_BYTES);
                }
                if let Some(title) = title {
                    item.title = truncate_utf8_bytes(title, MAX_LIST_TITLE_BYTES);
                }
                if let Some(kind) = kind {
                    item.kind = truncate_utf8_bytes(kind, MAX_LIST_KIND_BYTES);
                }
                if let Some(file_name) = file_name {
                    item.file_name = truncate_utf8_bytes(file_name, MAX_LIST_TITLE_BYTES);
                }
                if let Some(album) = album {
                    item.album = truncate_utf8_bytes(album, MAX_LIST_TITLE_BYTES);
                }
                if let Some(content_hash) = content_hash {
                    item.content_hash =
                        truncate_utf8_bytes(content_hash, MAX_LIST_CONTENT_ID_BYTES);
                }
                record.updated_at = now;
                self.updated_at = now;
                return Some(item.clone());
            }
        }
        None
    }

    fn remove_item(&mut self, item_id: &str) -> Option<CollectionItem> {
        let now = unix_timestamp();
        for record in &mut self.records {
            if let Some(pos) = record.items.iter().position(|item| item.id == item_id) {
                let item = record.items.remove(pos);
                record.updated_at = now;
                self.updated_at = now;
                return Some(item);
            }
        }
        None
    }

    fn collection_id_for_item(&self, item_id: &str) -> Option<String> {
        self.records
            .iter()
            .find(|record| record.items.iter().any(|item| item.id == item_id))
            .map(|record| record.id.clone())
    }

    fn total_items(&self) -> usize {
        self.records.iter().map(|record| record.items.len()).sum()
    }

    fn reorder_items(&mut self, collection_id: &str, body: &str) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == collection_id)?;
        let payload = serde_json::from_str::<serde_json::Value>(body).ok();
        let ids = payload
            .as_ref()
            .and_then(|value| {
                value
                    .get("item_ids")
                    .or_else(|| value.get("itemIds"))
                    .or_else(|| value.get("items"))
            })
            .and_then(serde_json::Value::as_array)
            .map(|array| {
                array
                    .iter()
                    .filter_map(serde_json::Value::as_str)
                    .map(str::to_owned)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if !ids.is_empty() {
            let mut ordered = Vec::new();
            for id in &ids {
                if let Some(pos) = record.items.iter().position(|item| item.id == *id) {
                    ordered.push(record.items.remove(pos));
                }
            }
            ordered.append(&mut record.items);
            record.items = ordered;
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    #[allow(dead_code)]
    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let filtered_count = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .count();
        format!(
            "{{\"entries\":{},\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            self.json_array(query),
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(CollectionRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

fn bounded_collection_item(mut item: CollectionItem) -> CollectionItem {
    item.content_id = truncate_utf8_bytes(item.content_id, MAX_LIST_CONTENT_ID_BYTES);
    item.artist = truncate_utf8_bytes(item.artist, MAX_LIST_ARTIST_BYTES);
    item.title = truncate_utf8_bytes(item.title, MAX_LIST_TITLE_BYTES);
    item.kind = truncate_utf8_bytes(item.kind, MAX_LIST_KIND_BYTES);
    item.file_name = truncate_utf8_bytes(item.file_name, MAX_LIST_TITLE_BYTES);
    item.album = truncate_utf8_bytes(item.album, MAX_LIST_TITLE_BYTES);
    item.content_hash = truncate_utf8_bytes(item.content_hash, MAX_LIST_CONTENT_ID_BYTES);
    item
}

