#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistItem {
    id: String,
    artist: String,
    title: String,
    kind: String,
    filter: String,
    enabled: bool,
    auto_download: bool,
    max_results: usize,
    max_downloads: Option<u64>,
    last_viewed_at: Option<u64>,
    last_searched_at: Option<u64>,
    last_match_count: usize,
    last_visible_hit_count: usize,
    last_hidden_locked_hit_count: usize,
    last_filtered_out_hit_count: usize,
    last_ignored_result_hit_count: usize,
    last_response_count: usize,
    total_search_count: u64,
    total_download_count: u64,
    last_search_id: Option<String>,
    added_at: u64,
}

impl WishlistItem {
    fn search_text(&self) -> String {
        match (self.artist.trim().is_empty(), self.title.trim().is_empty()) {
            (true, true) => String::new(),
            (true, false) => self.title.clone(),
            (false, true) => self.artist.clone(),
            (false, false) => format!("{} {}", self.artist, self.title),
        }
    }

    fn json(&self) -> String {
        let search_text = self.search_text();
        serde_json::json!({
            "id": self.id,
            "artist": self.artist,
            "title": self.title,
            "kind": self.kind,
            "added_at": self.added_at,
            "createdAt": self.added_at,
            "searchText": search_text,
            "filter": self.filter,
            "enabled": self.enabled,
            "autoDownload": self.auto_download,
            "maxResults": self.max_results,
            "maxDownloads": self.max_downloads,
            "lastViewedAt": self.last_viewed_at,
            "lastSearchedAt": self.last_searched_at,
            "lastMatchCount": self.last_match_count,
            "lastVisibleHitCount": self.last_visible_hit_count,
            "lastHiddenLockedHitCount": self.last_hidden_locked_hit_count,
            "lastFilteredOutHitCount": self.last_filtered_out_hit_count,
            "lastIgnoredResultHitCount": self.last_ignored_result_hit_count,
            "lastResponseCount": self.last_response_count,
            "totalSearchCount": self.total_search_count,
            "totalDownloadCount": self.total_download_count,
            "lastSearchId": self.last_search_id,
        })
        .to_string()
    }

    fn slskdn_json(&self) -> String {
        serde_json::json!({
            "id": self.id,
            "searchText": self.search_text(),
            "filter": self.filter,
            "enabled": self.enabled,
            "autoDownload": self.auto_download,
            "maxResults": self.max_results,
            "createdAt": unix_seconds_rfc3339(self.added_at),
            "lastSearchedAt": self.last_searched_at.map(unix_seconds_rfc3339),
            "lastMatchCount": self.last_match_count,
            "lastVisibleHitCount": self.last_visible_hit_count,
            "lastHiddenLockedHitCount": self.last_hidden_locked_hit_count,
            "lastFilteredOutHitCount": self.last_filtered_out_hit_count,
            "lastIgnoredResultHitCount": self.last_ignored_result_hit_count,
            "lastResponseCount": self.last_response_count,
            "totalSearchCount": self.total_search_count,
            "totalDownloadCount": self.total_download_count,
            "maxDownloads": self.max_downloads,
            "lastSearchId": self.last_search_id,
            "lastViewedAt": self.last_viewed_at.map(unix_seconds_rfc3339),
        })
        .to_string()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistRecord {
    id: String,
    items: Vec<WishlistItem>,
    updated_at: u64,
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistIgnoredResult {
    id: String,
    wishlist_item_id: String,
    username: String,
    directory: String,
    created_at: u64,
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistResultFilter {
    include: Vec<String>,
    exclude: Vec<String>,
}

impl WishlistResultFilter {
    fn parse(filter: &str) -> Self {
        let mut terms = Vec::new();
        let mut current = String::new();
        let mut quoted = false;
        for character in filter.chars() {
            match character {
                '"' => quoted = !quoted,
                character if character.is_whitespace() && !quoted => {
                    if !current.is_empty() {
                        terms.push(std::mem::take(&mut current));
                    }
                }
                character => current.push(character),
            }
        }
        if !current.is_empty() {
            terms.push(current);
        }

        let mut include = Vec::new();
        let mut exclude = Vec::new();
        for raw_term in terms {
            if raw_term.eq_ignore_ascii_case("OR") {
                continue;
            }
            let (target, term) = if let Some(term) = raw_term.strip_prefix('-') {
                (&mut exclude, term)
            } else {
                (&mut include, raw_term.as_str())
            };
            let term = term
                .trim()
                .trim_matches('"')
                .trim_start_matches('.')
                .to_ascii_lowercase();
            if !term.is_empty() && !target.contains(&term) {
                target.push(term);
            }
        }
        Self { include, exclude }
    }

    fn matches(&self, filename: &str) -> bool {
        let filename = filename.replace('\\', "/").to_ascii_lowercase();
        let extension = virtual_basename(&filename)
            .rsplit_once('.')
            .map(|(_, extension)| extension)
            .unwrap_or_default();
        if self.exclude.iter().any(|term| filename.contains(term)) {
            return false;
        }
        self.include.is_empty()
            || self
                .include
                .iter()
                .any(|term| extension == term || filename.contains(term))
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistResultPolicy {
    filter: WishlistResultFilter,
    max_results: usize,
}

impl WishlistIgnoredResult {
    fn json(&self) -> serde_json::Value {
        serde_json::json!({
            "id": self.id,
            "wishlistItemId": self.wishlist_item_id,
            "username": self.username,
            "directory": self.directory,
            "createdAt": self.created_at,
        })
    }

    fn slskdn_json(&self) -> serde_json::Value {
        serde_json::json!({
            "id": self.id,
            "wishlistItemId": self.wishlist_item_id,
            "username": self.username,
            "directory": self.directory,
            "createdAt": unix_seconds_rfc3339(self.created_at),
        })
    }

    fn matches(&self, username: &str, filename: &str) -> bool {
        self.username.eq_ignore_ascii_case(username)
            && normalize_wishlist_directory(&self.directory)
                .eq_ignore_ascii_case(&wishlist_parent_directory(filename))
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct WishlistStore {
    records: Vec<WishlistRecord>,
    ignored_results: Vec<WishlistIgnoredResult>,
    next_item_id: u64,
    updated_at: u64,
    max_items: usize,
}

impl WishlistStore {
    fn new() -> Self {
        Self::with_max_items(MAX_WISHLIST_ITEMS)
    }

    fn with_max_items(max_items: usize) -> Self {
        Self {
            records: Vec::new(),
            ignored_results: Vec::new(),
            next_item_id: 1,
            updated_at: unix_timestamp(),
            max_items: max_items.max(1),
        }
    }

    fn from_persisted_with_ignored(
        records: Vec<crate::persistence::WishlistItemRecord>,
        ignored_results: Vec<crate::persistence::WishlistIgnoredResultRecord>,
    ) -> Self {
        let mut store = Self::new();
        let mut items = Vec::new();
        let mut seen_ids = HashSet::new();
        for record in records {
            if let Some(number) = record
                .id
                .strip_prefix("wish-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                store.next_item_id = store.next_item_id.max(number.saturating_add(1));
            }
            if items.len() >= store.max_items || !seen_ids.insert(record.id.clone()) {
                continue;
            }
            items.push(WishlistItem {
                id: record.id,
                artist: truncate_utf8_bytes(record.artist, MAX_LIST_ARTIST_BYTES),
                title: truncate_utf8_bytes(record.title, MAX_LIST_TITLE_BYTES),
                kind: truncate_utf8_bytes(record.kind, MAX_LIST_KIND_BYTES),
                filter: truncate_utf8_bytes(record.filter, MAX_WISHLIST_FILTER_BYTES),
                enabled: record.enabled,
                auto_download: record.auto_download,
                max_results: usize::try_from(record.max_results)
                    .unwrap_or(100)
                    .clamp(1, MAX_WISHLIST_RESULTS),
                max_downloads: record
                    .max_downloads
                    .and_then(|value| u64::try_from(value).ok())
                    .filter(|value| *value > 0)
                    .map(|value| value.min(MAX_WISHLIST_DOWNLOADS)),
                last_viewed_at: record
                    .last_viewed_at
                    .and_then(|value| u64::try_from(value).ok()),
                last_searched_at: record
                    .last_searched_at
                    .and_then(|value| u64::try_from(value).ok()),
                last_match_count: usize::try_from(record.last_match_count).unwrap_or(0),
                last_visible_hit_count: usize::try_from(record.last_visible_hit_count).unwrap_or(0),
                last_hidden_locked_hit_count: usize::try_from(record.last_hidden_locked_hit_count)
                    .unwrap_or(0),
                last_filtered_out_hit_count: usize::try_from(record.last_filtered_out_hit_count)
                    .unwrap_or(0),
                last_ignored_result_hit_count: usize::try_from(
                    record.last_ignored_result_hit_count,
                )
                .unwrap_or(0),
                last_response_count: usize::try_from(record.last_response_count).unwrap_or(0),
                total_search_count: u64::try_from(record.total_search_count).unwrap_or(0),
                total_download_count: u64::try_from(record.total_download_count).unwrap_or(0),
                last_search_id: record
                    .last_search_id
                    .map(|id| truncate_utf8_bytes(id, MAX_SEARCH_TARGET_NAME_BYTES)),
                added_at: u64::try_from(record.added_at).unwrap_or(0),
            });
        }
        items.sort_by_key(|item| item.added_at);
        let updated_at = items
            .iter()
            .map(|item| item.added_at)
            .max()
            .unwrap_or_else(unix_timestamp);
        store.records.push(WishlistRecord {
            id: "default".to_owned(),
            items,
            updated_at,
        });
        let known_items = store
            .records
            .iter()
            .flat_map(|record| record.items.iter())
            .map(|item| item.id.as_str())
            .collect::<HashSet<_>>();
        let mut seen = HashSet::new();
        store.ignored_results = ignored_results
            .into_iter()
            .filter(|rule| known_items.contains(rule.wishlist_item_id.as_str()))
            .filter_map(|rule| {
                let username = truncate_utf8_bytes(
                    rule.username.trim().to_owned(),
                    MAX_SEARCH_RESULT_USERNAME_BYTES,
                );
                let directory = normalize_wishlist_directory(&rule.directory);
                let key = format!(
                    "{}\0{}\0{}",
                    rule.wishlist_item_id.to_lowercase(),
                    username.to_lowercase(),
                    directory.to_lowercase()
                );
                (!username.is_empty() && !directory.is_empty() && seen.insert(key)).then_some(
                    WishlistIgnoredResult {
                        id: rule.id,
                        wishlist_item_id: rule.wishlist_item_id,
                        username,
                        directory,
                        created_at: u64::try_from(rule.created_at).unwrap_or(0),
                    },
                )
            })
            .take(MAX_WISHLIST_IGNORED_RESULTS)
            .collect();
        store.updated_at = updated_at;
        store
    }

    fn get_or_create(&mut self) -> WishlistRecord {
        let now = unix_timestamp();
        if let Some(record) = self.records.iter_mut().find(|r| r.id == "default") {
            record.clone()
        } else {
            let record = WishlistRecord {
                id: "default".to_string(),
                items: Vec::new(),
                updated_at: now,
            };
            self.records.push(record.clone());
            self.updated_at = now;
            record
        }
    }

    fn add_item(
        &mut self,
        artist: String,
        title: String,
        kind: String,
    ) -> Result<WishlistItem, ()> {
        self.add_item_with_settings(artist, title, kind, String::new(), true, false, 100, None)
    }

    #[allow(clippy::too_many_arguments)]
    fn add_item_with_settings(
        &mut self,
        artist: String,
        title: String,
        kind: String,
        filter: String,
        enabled: bool,
        auto_download: bool,
        max_results: usize,
        max_downloads: Option<u64>,
    ) -> Result<WishlistItem, ()> {
        self.add_item_with_contract(
            None,
            artist,
            title,
            kind,
            filter,
            enabled,
            auto_download,
            max_results,
            max_downloads,
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn add_item_with_contract(
        &mut self,
        id: Option<String>,
        artist: String,
        title: String,
        kind: String,
        filter: String,
        enabled: bool,
        auto_download: bool,
        max_results: usize,
        max_downloads: Option<u64>,
    ) -> Result<WishlistItem, ()> {
        let now = unix_timestamp();
        self.get_or_create();
        let index = self
            .records
            .iter()
            .position(|record| record.id == "default")
            .ok_or(())?;
        if self.records[index].items.len() >= self.max_items {
            return Err(());
        }
        let id = id.unwrap_or_else(|| format!("wish-{}", self.allocate_item_id()));
        let item = WishlistItem {
            id,
            artist: truncate_utf8_bytes(artist, MAX_LIST_ARTIST_BYTES),
            title: truncate_utf8_bytes(title, MAX_LIST_TITLE_BYTES),
            kind: truncate_utf8_bytes(kind, MAX_LIST_KIND_BYTES),
            filter: truncate_utf8_bytes(filter.trim().to_owned(), MAX_WISHLIST_FILTER_BYTES),
            enabled,
            auto_download,
            max_results: max_results.clamp(1, MAX_WISHLIST_RESULTS),
            max_downloads: max_downloads.map(|value| value.min(MAX_WISHLIST_DOWNLOADS)),
            last_viewed_at: None,
            last_searched_at: None,
            last_match_count: 0,
            last_visible_hit_count: 0,
            last_hidden_locked_hit_count: 0,
            last_filtered_out_hit_count: 0,
            last_ignored_result_hit_count: 0,
            last_response_count: 0,
            total_search_count: 0,
            total_download_count: 0,
            last_search_id: None,
            added_at: now,
        };
        let record = &mut self.records[index];
        record.items.push(item.clone());
        record.updated_at = now;
        self.updated_at = now;
        Ok(item)
    }

    fn allocate_item_id(&mut self) -> u64 {
        let retained_items = self
            .records
            .iter()
            .map(|record| record.items.len())
            .sum::<usize>();
        let mut candidate = self.next_item_id.max(1);
        for _ in 0..=retained_items {
            let id = format!("wish-{candidate}");
            if !self
                .records
                .iter()
                .flat_map(|record| &record.items)
                .any(|item| item.id == id)
            {
                self.next_item_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded wishlist store must leave an available u64 id")
    }

    fn remaining_capacity(&mut self) -> usize {
        self.get_or_create();
        self.records
            .iter()
            .find(|record| record.id == "default")
            .map(|record| self.max_items.saturating_sub(record.items.len()))
            .unwrap_or(0)
    }

    fn can_add_items(&mut self, count: usize) -> bool {
        count <= self.remaining_capacity()
    }

    fn remove_item(&mut self, item_id: &str) -> Option<WishlistRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == "default")?;
        if let Some(pos) = record.items.iter().position(|i| i.id == item_id) {
            record.items.remove(pos);
            self.ignored_results
                .retain(|rule| rule.wishlist_item_id != item_id);
            record.updated_at = now;
            self.updated_at = now;
            Some(record.clone())
        } else {
            None
        }
    }

    #[allow(clippy::too_many_arguments)]
    fn update_item(
        &mut self,
        item_id: &str,
        artist: Option<String>,
        title: Option<String>,
        kind: Option<String>,
        filter: Option<String>,
        enabled: Option<bool>,
        auto_download: Option<bool>,
        max_results: Option<usize>,
        max_downloads: Option<Option<u64>>,
    ) -> Option<WishlistItem> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == "default")?;
        let item = record.items.iter_mut().find(|item| item.id == item_id)?;
        if let Some(artist) = artist {
            item.artist = truncate_utf8_bytes(artist, MAX_LIST_ARTIST_BYTES);
        }
        if let Some(title) = title {
            item.title = truncate_utf8_bytes(title, MAX_LIST_TITLE_BYTES);
        }
        if let Some(kind) = kind {
            item.kind = truncate_utf8_bytes(kind, MAX_LIST_KIND_BYTES);
        }
        if let Some(filter) = filter {
            item.filter = truncate_utf8_bytes(filter.trim().to_owned(), MAX_WISHLIST_FILTER_BYTES);
        }
        if let Some(enabled) = enabled {
            item.enabled = enabled;
        }
        if let Some(auto_download) = auto_download {
            item.auto_download = auto_download;
        }
        if let Some(max_results) = max_results {
            item.max_results = max_results.clamp(1, MAX_WISHLIST_RESULTS);
        }
        if let Some(max_downloads) = max_downloads {
            item.max_downloads = max_downloads.map(|value| value.min(MAX_WISHLIST_DOWNLOADS));
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(item.clone())
    }

    fn json_array(&mut self) -> String {
        let record = self.get_or_create();
        let items = record
            .items
            .iter()
            .map(|item| {
                let mut value = serde_json::from_str::<serde_json::Value>(&item.json())
                    .unwrap_or_else(|_| serde_json::json!({ "id": item.id }));
                let rules = self
                    .ignored_results
                    .iter()
                    .filter(|rule| rule.wishlist_item_id == item.id)
                    .map(WishlistIgnoredResult::json)
                    .collect::<Vec<_>>();
                value["ignoredResultCount"] = serde_json::json!(rules.len());
                value["ignoredResults"] = serde_json::Value::Array(rules);
                value.to_string()
            })
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", items)
    }

    fn search_terms(&self) -> Vec<String> {
        self.records
            .iter()
            .flat_map(|record| record.items.iter())
            .filter(|item| item.enabled)
            .map(|item| {
                if item.title.is_empty() {
                    item.artist.clone()
                } else if item.artist.is_empty() {
                    item.title.clone()
                } else {
                    format!("{} {}", item.artist, item.title)
                }
            })
            .filter(|term| !term.trim().is_empty())
            .collect()
    }

    fn get_item(&self, item_id: &str) -> Option<WishlistItem> {
        self.records
            .iter()
            .flat_map(|record| record.items.iter())
            .find(|item| item.id == item_id)
            .cloned()
    }

    fn result_policy_for(&self, item_id: &str) -> Option<WishlistResultPolicy> {
        let item = self.get_item(item_id)?;
        Some(WishlistResultPolicy {
            filter: WishlistResultFilter::parse(&item.filter),
            max_results: item.max_results,
        })
    }

    fn mark_viewed(&mut self, item_id: &str) -> Option<WishlistItem> {
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == "default")?;
        let item = record.items.iter_mut().find(|item| item.id == item_id)?;
        item.last_viewed_at = Some(now);
        record.updated_at = now;
        self.updated_at = now;
        Some(item.clone())
    }

    fn mark_all_viewed(&mut self) -> Vec<WishlistItem> {
        let now = unix_timestamp();
        let Some(record) = self
            .records
            .iter_mut()
            .find(|record| record.id == "default")
        else {
            return Vec::new();
        };
        for item in &mut record.items {
            item.last_viewed_at = Some(now);
        }
        record.updated_at = now;
        self.updated_at = now;
        record.items.clone()
    }

    fn record_completed_search(&mut self, search: &SearchRecord) -> Option<WishlistItem> {
        let item_id = search.wishlist_item_id()?;
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == "default")?;
        let item = record.items.iter_mut().find(|item| item.id == item_id)?;
        item.last_searched_at = Some(now);
        item.last_match_count = search.results.len();
        item.last_visible_hit_count = search.results.len();
        item.last_hidden_locked_hit_count = search.hidden_locked_count;
        item.last_filtered_out_hit_count = search.filtered_out_count;
        item.last_ignored_result_hit_count = search.ignored_result_count;
        item.last_response_count = search.raw_response_count;
        item.total_search_count = item.total_search_count.saturating_add(1);
        item.last_search_id = Some(search.id.clone());
        record.updated_at = now;
        self.updated_at = now;
        Some(item.clone())
    }

    fn record_auto_downloads(
        &mut self,
        item_id: &str,
        enqueued_count: usize,
    ) -> Option<WishlistItem> {
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == "default")?;
        let item = record.items.iter_mut().find(|item| item.id == item_id)?;
        item.total_download_count = item
            .total_download_count
            .saturating_add(u64::try_from(enqueued_count).unwrap_or(u64::MAX));
        if enqueued_count > 0
            && item
                .max_downloads
                .is_none_or(|limit| item.total_download_count >= limit)
        {
            item.enabled = false;
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(item.clone())
    }

    fn list_ignored_results(&self, item_id: &str) -> Option<Vec<WishlistIgnoredResult>> {
        self.get_item(item_id)?;
        let mut rules = self
            .ignored_results
            .iter()
            .filter(|rule| rule.wishlist_item_id == item_id)
            .cloned()
            .collect::<Vec<_>>();
        rules.sort_by(|left, right| {
            right
                .created_at
                .cmp(&left.created_at)
                .then_with(|| right.id.cmp(&left.id))
        });
        Some(rules)
    }

    fn ignore_result(
        &mut self,
        item_id: &str,
        username: &str,
        directory: &str,
    ) -> Result<(WishlistIgnoredResult, bool), &'static str> {
        if self.get_item(item_id).is_none() {
            return Err("not_found");
        }
        let username =
            truncate_utf8_bytes(username.trim().to_owned(), MAX_SEARCH_RESULT_USERNAME_BYTES);
        let normalized_directory = normalize_wishlist_directory(directory);
        if username.is_empty() || normalized_directory.is_empty() {
            return Err("invalid");
        }
        let directory = if uuid::Uuid::parse_str(item_id).is_ok() {
            truncate_utf8_bytes(
                directory.trim().to_owned(),
                MAX_SEARCH_RESULT_FILENAME_BYTES,
            )
        } else {
            normalized_directory.clone()
        };
        if let Some(existing) = self.ignored_results.iter().find(|rule| {
            rule.wishlist_item_id == item_id
                && rule.username.eq_ignore_ascii_case(&username)
                && normalize_wishlist_directory(&rule.directory)
                    .eq_ignore_ascii_case(&normalized_directory)
        }) {
            return Ok((existing.clone(), false));
        }
        if self.ignored_results.len() >= MAX_WISHLIST_IGNORED_RESULTS
            || self
                .ignored_results
                .iter()
                .filter(|rule| rule.wishlist_item_id == item_id)
                .count()
                >= MAX_WISHLIST_IGNORED_RESULTS_PER_ITEM
        {
            return Err("capacity");
        }
        let rule = WishlistIgnoredResult {
            id: uuid::Uuid::new_v4().to_string(),
            wishlist_item_id: item_id.to_owned(),
            username,
            directory,
            created_at: unix_timestamp(),
        };
        self.ignored_results.push(rule.clone());
        self.updated_at = rule.created_at;
        Ok((rule, true))
    }

    fn delete_ignored_result(&mut self, item_id: &str, rule_id: &str) -> bool {
        let before = self.ignored_results.len();
        self.ignored_results
            .retain(|rule| !(rule.wishlist_item_id == item_id && rule.id == rule_id));
        let deleted = self.ignored_results.len() != before;
        if deleted {
            self.updated_at = unix_timestamp();
        }
        deleted
    }

    fn ignored_results_for(&self, item_id: &str) -> Vec<WishlistIgnoredResult> {
        self.ignored_results
            .iter()
            .filter(|rule| rule.wishlist_item_id == item_id)
            .cloned()
            .collect()
    }

    fn item_id_for_search_text(&self, query: &str) -> Option<String> {
        self.records
            .iter()
            .flat_map(|record| record.items.iter())
            .find(|item| item.search_text() == query)
            .map(|item| item.id.clone())
    }
}

fn normalize_wishlist_directory(directory: &str) -> String {
    truncate_utf8_bytes(
        directory
            .replace('\\', "/")
            .trim()
            .trim_matches('/')
            .to_owned(),
        MAX_SEARCH_RESULT_FILENAME_BYTES,
    )
}

fn wishlist_parent_directory(filename: &str) -> String {
    let normalized = filename.replace('\\', "/");
    normalized
        .rsplit_once('/')
        .map(|(directory, _)| normalize_wishlist_directory(directory))
        .unwrap_or_default()
}

// Contact Models
#[derive(Clone, Debug, PartialEq, Eq)]
struct ContactRecord {
    id: String,
    username: String,
    online: bool,
    status: String,
    free_upload_slots: Option<u32>,
    queue_length: Option<u32>,
    created_at: u64,
    updated_at: u64,
}

impl ContactRecord {
    fn json(&self) -> String {
        format!(
            "{{\"id\":\"{}\",\"username\":\"{}\",\"online\":{},\"status\":\"{}\",\"free_upload_slots\":{},\"queue_length\":{},\"created_at\":{},\"updated_at\":{}}}",
            json_escape(&self.id),
            json_escape(&self.username),
            self.online,
            json_escape(&self.status),
            json_u32_option(self.free_upload_slots),
            json_u32_option(self.queue_length),
            self.created_at,
            self.updated_at
        )
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct ContactStore {
    records: Vec<ContactRecord>,
    next_id: u64,
    updated_at: u64,
    max_records: usize,
}

#[derive(Debug, PartialEq, Eq)]
enum ContactUpdateError {
    NotFound,
    DuplicateUsername,
}

impl ContactStore {
    fn new() -> Self {
        Self::with_max_records(MAX_CONTACT_RECORDS)
    }

    fn with_max_records(max_records: usize) -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
            max_records: max_records.max(1),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::ContactRecord>) -> Self {
        let mut next_id = 1;
        let mut updated_at = unix_timestamp();
        let mut projected = Vec::new();
        let mut seen_ids = std::collections::HashSet::new();
        for mut record in records {
            record.username = bounded_user_username(&record.username);
            if let Some(number) = record
                .id
                .strip_prefix("contact-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                next_id = next_id.max(number.saturating_add(1));
            }
            if projected.len() >= MAX_CONTACT_RECORDS
                || !seen_ids.insert(record.id.clone())
                || projected.iter().any(|existing: &ContactRecord| {
                    existing.username.eq_ignore_ascii_case(&record.username)
                })
            {
                continue;
            }
            let created_at = u64::try_from(record.created_at).unwrap_or(0);
            let record_updated_at = u64::try_from(record.updated_at).unwrap_or(created_at);
            updated_at = updated_at.max(record_updated_at);
            projected.push(ContactRecord {
                id: record.id,
                username: record.username,
                online: record.online,
                status: truncate_utf8_bytes(record.status, MAX_CONTACT_STATUS_BYTES),
                free_upload_slots: record
                    .free_upload_slots
                    .and_then(|value| u32::try_from(value).ok()),
                queue_length: record
                    .queue_length
                    .and_then(|value| u32::try_from(value).ok()),
                created_at,
                updated_at: record_updated_at,
            });
        }
        Self {
            records: projected,
            next_id,
            updated_at,
            max_records: MAX_CONTACT_RECORDS,
        }
    }

    fn create(&mut self, username: String) -> Result<(ContactRecord, bool), ()> {
        let username = bounded_user_username(&username);
        if let Some(record) = self
            .records
            .iter()
            .find(|record| record.username.eq_ignore_ascii_case(&username))
        {
            return Ok((record.clone(), false));
        }
        if self.records.len() >= self.max_records {
            return Err(());
        }
        let now = unix_timestamp();
        let id = format!("contact-{}", self.allocate_id());
        let record = ContactRecord {
            id,
            username,
            online: false,
            status: "offline".to_string(),
            free_upload_slots: None,
            queue_length: None,
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Ok((record, true))
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            let id = format!("contact-{candidate}");
            if !self.records.iter().any(|record| record.id == id) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded contact store must leave an available u64 id")
    }

    fn get(&self, id: &str) -> Option<ContactRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(
        &mut self,
        id: &str,
        username: Option<String>,
        online: Option<bool>,
    ) -> Result<ContactRecord, ContactUpdateError> {
        if !self.records.iter().any(|record| record.id == id) {
            return Err(ContactUpdateError::NotFound);
        }
        let username = username.map(|username| bounded_user_username(&username));
        if username.as_deref().is_some_and(|username| {
            self.records
                .iter()
                .any(|record| record.id != id && record.username.eq_ignore_ascii_case(username))
        }) {
            return Err(ContactUpdateError::DuplicateUsername);
        }
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|r| r.id == id)
            .expect("contact existence checked before mutation");
        if let Some(u) = username {
            record.username = u;
        }
        if let Some(o) = online {
            record.online = o;
            record.status = if o {
                "online".to_string()
            } else {
                "offline".to_string()
            };
        }
        record.updated_at = now;
        self.updated_at = now;
        Ok(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.username.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(ContactRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }

    fn nearby_json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| record.online)
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.username.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(ContactRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

// ShareGroup Models
#[derive(Clone, Debug)]
struct ShareGroupMember {
    username: String,
    added_at: u64,
}

impl ShareGroupMember {
    fn json(&self) -> String {
        format!(
            "{{\"username\":\"{}\",\"added_at\":{}}}",
            json_escape(&self.username),
            self.added_at
        )
    }
}

#[derive(Clone, Debug)]
struct ShareGroupRecord {
    id: String,
    name: String,
    description: String,
    members: Vec<ShareGroupMember>,
    created_at: u64,
    updated_at: u64,
}

impl ShareGroupRecord {
    fn json(&self) -> String {
        let members = self
            .members
            .iter()
            .map(ShareGroupMember::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"id\":\"{}\",\"name\":\"{}\",\"description\":\"{}\",\"members\":[{}],\"member_count\":{},\"created_at\":{},\"updated_at\":{}}}",
            json_escape(&self.id),
            json_escape(&self.name),
            json_escape(&self.description),
            members,
            self.members.len(),
            self.created_at,
            self.updated_at
        )
    }
}

#[derive(Clone, Debug)]
struct ShareGroupStore {
    records: Vec<ShareGroupRecord>,
    next_id: u64,
    updated_at: u64,
    max_records: usize,
    max_members_per_group: usize,
}

impl ShareGroupStore {
    fn new() -> Self {
        Self::with_limits(MAX_SHARE_GROUPS, MAX_SHARE_GROUP_MEMBERS)
    }

    fn with_limits(max_records: usize, max_members_per_group: usize) -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
            max_records: max_records.max(1),
            max_members_per_group: max_members_per_group.max(1),
        }
    }

    fn from_persisted(
        groups: Vec<crate::persistence::ShareGroupRecord>,
        members: Vec<crate::persistence::ShareGroupMemberRecord>,
    ) -> Self {
        let mut store = Self::new();
        let mut max_id = 0_u64;
        let mut retained_members = 0_usize;
        let mut seen_ids = std::collections::HashSet::new();
        for record in groups {
            if let Some(value) = record
                .id
                .strip_prefix("sg-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                max_id = max_id.max(value);
            }
            if store.records.len() < store.max_records && seen_ids.insert(record.id.clone()) {
                store.records.push(ShareGroupRecord {
                    id: record.id,
                    name: truncate_utf8_bytes(record.name, MAX_LIST_NAME_BYTES),
                    description: truncate_utf8_bytes(
                        record.description,
                        MAX_LIST_DESCRIPTION_BYTES,
                    ),
                    members: Vec::new(),
                    created_at: u64::try_from(record.created_at).unwrap_or_default(),
                    updated_at: u64::try_from(record.updated_at).unwrap_or_default(),
                });
            }
        }
        for mut member in members {
            member.username = bounded_user_username(&member.username);
            if let Some(group) = store
                .records
                .iter_mut()
                .find(|record| record.id == member.group_id)
            {
                if retained_members < MAX_TOTAL_SHARE_GROUP_MEMBERS
                    && group.members.len() < store.max_members_per_group
                    && !group
                        .members
                        .iter()
                        .any(|existing| existing.username.eq_ignore_ascii_case(&member.username))
                {
                    group.members.push(ShareGroupMember {
                        username: member.username,
                        added_at: u64::try_from(member.added_at).unwrap_or_default(),
                    });
                    retained_members = retained_members.saturating_add(1);
                }
            }
        }
        for group in &mut store.records {
            group.members.sort_by(|left, right| {
                left.username
                    .cmp(&right.username)
                    .then(left.added_at.cmp(&right.added_at))
            });
        }
        store.next_id = max_id.saturating_add(1).max(1);
        store.updated_at = store
            .records
            .iter()
            .map(|record| record.updated_at)
            .max()
            .unwrap_or_else(unix_timestamp);
        store
    }

    fn create(&mut self, name: String, description: String) -> Option<ShareGroupRecord> {
        if self.records.len() >= self.max_records {
            return None;
        }
        let now = unix_timestamp();
        let id = format!("sg-{}", self.allocate_id());
        let record = ShareGroupRecord {
            id,
            name: truncate_utf8_bytes(name, MAX_LIST_NAME_BYTES),
            description: truncate_utf8_bytes(description, MAX_LIST_DESCRIPTION_BYTES),
            members: Vec::new(),
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            let id = format!("sg-{candidate}");
            if !self.records.iter().any(|record| record.id == id) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded share-group store must leave an available u64 id")
    }

    fn get(&self, id: &str) -> Option<ShareGroupRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(&mut self, id: &str, name: String, description: String) -> Option<ShareGroupRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.name = truncate_utf8_bytes(name, MAX_LIST_NAME_BYTES);
        record.description = truncate_utf8_bytes(description, MAX_LIST_DESCRIPTION_BYTES);
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn add_member(
        &mut self,
        group_id: &str,
        username: String,
    ) -> Result<Option<(ShareGroupRecord, bool)>, ()> {
        let username = bounded_user_username(&username);
        let total_members = self.total_members();
        let now = unix_timestamp();
        let Some(record) = self.records.iter_mut().find(|r| r.id == group_id) else {
            return Ok(None);
        };
        let added = if record
            .members
            .iter()
            .any(|member| member.username.eq_ignore_ascii_case(&username))
        {
            false
        } else {
            if record.members.len() >= self.max_members_per_group
                || total_members >= MAX_TOTAL_SHARE_GROUP_MEMBERS
            {
                return Err(());
            }
            record.members.push(ShareGroupMember {
                username,
                added_at: now,
            });
            record.updated_at = now;
            self.updated_at = now;
            true
        };
        Ok(Some((record.clone(), added)))
    }

    fn remove_member(&mut self, group_id: &str, username: &str) -> Option<ShareGroupRecord> {
        let username = bounded_user_username(username);
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == group_id)?;
        if let Some(pos) = record
            .members
            .iter()
            .position(|member| member.username.eq_ignore_ascii_case(&username))
        {
            record.members.remove(pos);
            record.updated_at = now;
            self.updated_at = now;
            Some(record.clone())
        } else {
            None
        }
    }

    #[cfg(test)]
    fn user_group_json(&self, username: &str) -> String {
        let username = bounded_user_username(username);
        let groups = self
            .records
            .iter()
            .filter_map(|record| {
                let member = record
                    .members
                    .iter()
                    .find(|member| member.username == username)?;
                Some(serde_json::json!({
                    "id": record.id,
                    "name": record.name,
                    "description": record.description,
                    "added_at": member.added_at,
                }))
            })
            .collect::<Vec<_>>();
        let primary_group = groups
            .first()
            .and_then(|group| group.get("name"))
            .and_then(serde_json::Value::as_str)
            .unwrap_or("default");
        let primary_group_id = groups.first().and_then(|group| group.get("id")).cloned();
        serde_json::json!({
            "username": username,
            "group": primary_group,
            "group_id": primary_group_id,
            "groups": groups,
            "groupCount": groups.len(),
        })
        .to_string()
    }

    fn total_members(&self) -> usize {
        self.records.iter().map(|record| record.members.len()).sum()
    }

    #[allow(dead_code)]
    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let filtered_count = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .count();
        format!(
            "{{\"entries\":{},\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            self.json_array(query),
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .is_none_or(|q| record.name.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(ShareGroupRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

fn share_group_resource_id(path: &str) -> Option<&str> {
    let id = path.strip_prefix("/api/sharegroups/")?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn share_group_members_id(path: &str) -> Option<&str> {
    let path = path.strip_prefix("/api/sharegroups/")?;
    let id = path.strip_suffix("/members")?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn share_group_member_path(path: &str) -> Option<(&str, String)> {
    let path = path.strip_prefix("/api/sharegroups/")?;
    let (id, username) = path.split_once("/members/")?;
    if id.is_empty() || id.contains('/') || username.is_empty() || username.contains('/') {
        return None;
    }
    Some((id, decoded_path_segment(username)))
}

