#[derive(Clone, Debug, PartialEq, Eq)]
struct UserNoteStore {
    records: Vec<UserNoteRecord>,
    next_id: u64,
    updated_at: u64,
}

impl UserNoteStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::UserNoteRecord>) -> Self {
        let mut next_id = 1;
        let mut updated_at = unix_timestamp();
        for record in &records {
            if let Some(number) = record
                .id
                .strip_prefix("note-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                next_id = next_id.max(number.saturating_add(1));
            }
        }
        let mut seen_ids = std::collections::HashSet::new();
        let records = records
            .into_iter()
            .filter(|record| seen_ids.insert(record.id.clone()))
            .take(MAX_USER_NOTES)
            .map(|record| {
                let created_at = u64::try_from(record.created_at).unwrap_or(0);
                let record_updated_at = u64::try_from(record.updated_at).unwrap_or(created_at);
                updated_at = updated_at.max(record_updated_at);
                UserNoteRecord {
                    id: record.id,
                    username: bounded_user_username(&record.username),
                    note: truncate_utf8_bytes(record.note, MAX_USER_NOTE_BYTES),
                    color: truncate_utf8_bytes(record.color, 128),
                    icon: truncate_utf8_bytes(record.icon, 128),
                    is_high_priority: record.is_high_priority,
                    created_at,
                    updated_at: record_updated_at,
                }
            })
            .collect();
        Self {
            records,
            next_id,
            updated_at,
        }
    }

    fn create(&mut self, username: String, note: String) -> Option<UserNoteRecord> {
        if self.records.len() >= MAX_USER_NOTES {
            return None;
        }
        let id = format!("note-{}", self.allocate_id());
        let now = unix_timestamp();
        let record = UserNoteRecord {
            id,
            username: bounded_user_username(&username),
            note: truncate_utf8_bytes(note, MAX_USER_NOTE_BYTES),
            color: String::new(),
            icon: String::new(),
            is_high_priority: false,
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            let id = format!("note-{candidate}");
            if !self.records.iter().any(|record| record.id == id) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded user-note store must leave an available u64 id")
    }

    fn get(&self, id: &str) -> Option<UserNoteRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn get_by_username(&self, username: &str) -> Option<UserNoteRecord> {
        self.records
            .iter()
            .find(|record| record.username.eq_ignore_ascii_case(username))
            .cloned()
    }

    fn set_slskdn(
        &mut self,
        username: String,
        note: String,
        color: String,
        icon: String,
        is_high_priority: bool,
    ) -> Option<UserNoteRecord> {
        let username = bounded_user_username(&username);
        let now = unix_timestamp();
        if let Some(record) = self
            .records
            .iter_mut()
            .find(|record| record.username.eq_ignore_ascii_case(&username))
        {
            record.note = truncate_utf8_bytes(note, MAX_USER_NOTE_BYTES);
            record.color = truncate_utf8_bytes(color, 128);
            record.icon = truncate_utf8_bytes(icon, 128);
            record.is_high_priority = is_high_priority;
            record.updated_at = now;
            self.updated_at = now;
            return Some(record.clone());
        }
        if self.records.len() >= MAX_USER_NOTES {
            return None;
        }
        let record = UserNoteRecord {
            id: format!("note-{}", self.allocate_id()),
            username,
            note: truncate_utf8_bytes(note, MAX_USER_NOTE_BYTES),
            color: truncate_utf8_bytes(color, 128),
            icon: truncate_utf8_bytes(icon, 128),
            is_high_priority,
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn update(&mut self, id: &str, note: String) -> Option<UserNoteRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.note = truncate_utf8_bytes(note, MAX_USER_NOTE_BYTES);
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn delete_by_username(&mut self, username: &str) -> Option<UserNoteRecord> {
        let position = self
            .records
            .iter()
            .position(|record| record.username.eq_ignore_ascii_case(username))?;
        let removed = self.records.remove(position);
        self.updated_at = unix_timestamp();
        Some(removed)
    }

    fn json(&self, _query: Option<&str>) -> String {
        let records = self
            .records
            .iter()
            .map(UserNoteRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"updated_at\":{}}}",
            records,
            self.records.len(),
            self.updated_at
        )
    }
}

// Interest Models
#[derive(Clone, Debug, PartialEq, Eq)]
struct InterestRecord {
    id: String,
    name: String,
    kind: String,
    created_at: u64,
}

impl InterestRecord {
    fn json(&self) -> String {
        format!(
            "{{\"id\":\"{}\",\"name\":\"{}\",\"kind\":\"{}\",\"created_at\":{}}}",
            json_escape(&self.id),
            json_escape(&self.name),
            json_escape(&self.kind),
            self.created_at
        )
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct InterestStore {
    liked: Vec<InterestRecord>,
    hated: Vec<InterestRecord>,
    next_id: u64,
    updated_at: u64,
}

impl InterestStore {
    fn new() -> Self {
        Self {
            liked: Vec::new(),
            hated: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::InterestRecord>) -> Self {
        let mut store = Self::new();
        store.liked.clear();
        store.hated.clear();
        let mut seen_ids = std::collections::HashSet::new();
        let mut seen_liked = std::collections::HashSet::new();
        let mut seen_hated = std::collections::HashSet::new();
        for mut record in records {
            record.name = truncate_utf8_bytes(record.name, MAX_INTEREST_NAME_BYTES);
            if !seen_ids.insert(record.id.clone()) {
                continue;
            }
            if let Some(number) = record
                .id
                .split_once('-')
                .and_then(|(_, value)| value.parse::<u64>().ok())
            {
                store.next_id = store.next_id.max(number.saturating_add(1));
            }
            let created_at = u64::try_from(record.created_at).unwrap_or(0);
            store.updated_at = store.updated_at.max(created_at);
            let record = InterestRecord {
                id: record.id,
                name: record.name,
                kind: record.kind,
                created_at,
            };
            let normalized_name = record.name.to_ascii_lowercase();
            if record.kind == "hated" {
                if store.hated.len() < MAX_INTERESTS_PER_KIND && seen_hated.insert(normalized_name)
                {
                    store.hated.push(record);
                }
            } else {
                if store.liked.len() < MAX_INTERESTS_PER_KIND && seen_liked.insert(normalized_name)
                {
                    store.liked.push(record);
                }
            }
        }
        store
    }

    fn merge_configured(&mut self, liked: &[String], hated: &[String]) {
        for interest in liked {
            let _ = self.add_liked(interest.clone());
        }
        for interest in hated {
            let _ = self.add_hated(interest.clone());
        }
    }

    fn add_liked(&mut self, name: String) -> Option<(InterestRecord, bool)> {
        let name = truncate_utf8_bytes(name, MAX_INTEREST_NAME_BYTES);
        if let Some(record) = self
            .liked
            .iter()
            .find(|record| record.name.eq_ignore_ascii_case(&name))
        {
            return Some((record.clone(), false));
        }
        if self.liked.len() >= MAX_INTERESTS_PER_KIND {
            return None;
        }
        let id = format!("liked-{}", self.allocate_id());
        let now = unix_timestamp();
        let record = InterestRecord {
            id,
            name,
            kind: "liked".to_string(),
            created_at: now,
        };
        self.liked.push(record.clone());
        self.updated_at = now;
        Some((record, true))
    }

    fn add_hated(&mut self, name: String) -> Option<(InterestRecord, bool)> {
        let name = truncate_utf8_bytes(name, MAX_INTEREST_NAME_BYTES);
        if let Some(record) = self
            .hated
            .iter()
            .find(|record| record.name.eq_ignore_ascii_case(&name))
        {
            return Some((record.clone(), false));
        }
        if self.hated.len() >= MAX_INTERESTS_PER_KIND {
            return None;
        }
        let id = format!("hated-{}", self.allocate_id());
        let now = unix_timestamp();
        let record = InterestRecord {
            id,
            name,
            kind: "hated".to_string(),
            created_at: now,
        };
        self.hated.push(record.clone());
        self.updated_at = now;
        Some((record, true))
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=(self.liked.len() + self.hated.len()) {
            let suffix = format!("-{candidate}");
            if !self
                .liked
                .iter()
                .chain(&self.hated)
                .any(|record| record.id.ends_with(&suffix))
            {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded interest store must leave an available u64 id")
    }

    fn remove_liked(&mut self, id: &str) -> bool {
        if let Some(pos) = self.liked.iter().position(|r| r.id == id) {
            self.liked.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn remove_hated(&mut self, id: &str) -> bool {
        if let Some(pos) = self.hated.iter().position(|r| r.id == id) {
            self.hated.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn json_liked(&self) -> String {
        let records = self
            .liked
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"kind\":\"liked\",\"updated_at\":{}}}",
            records,
            self.liked.len(),
            self.updated_at
        )
    }

    fn json_hated(&self) -> String {
        let records = self
            .hated
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"kind\":\"hated\",\"updated_at\":{}}}",
            records,
            self.hated.len(),
            self.updated_at
        )
    }

    fn user_interests_json(&self, username: &str) -> String {
        let liked = self
            .liked
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>();
        let hated = self
            .hated
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>();
        format!(
            "{{\"username\":\"{}\",\"liked\":[{}],\"hated\":[{}],\"interests\":[{}],\"count\":{},\"updated_at\":{}}}",
            json_escape(username),
            liked.join(","),
            hated.join(","),
            liked.join(","),
            self.liked.len() + self.hated.len(),
            self.updated_at
        )
    }

    fn recommendations_json(&self, field: &str) -> String {
        let recommendations = self
            .liked
            .iter()
            .enumerate()
            .map(|(index, interest)| {
                format!(
                    "{{\"id\":\"rec-{}\",\"interest\":\"{}\",\"query\":\"{}\",\"score\":{},\"source\":\"liked-interest\"}}",
                    index + 1,
                    json_escape(&interest.name),
                    json_escape(&interest.name),
                    100_u64.saturating_sub(index as u64)
                )
            })
            .collect::<Vec<_>>();
        format!(
            "{{\"{}\":[{}],\"count\":{},\"updated_at\":{}}}",
            field,
            recommendations.join(","),
            recommendations.len(),
            self.updated_at
        )
    }

    fn item_recommendations_json(&self, item_id: &str) -> String {
        let recommendations = self
            .liked
            .iter()
            .enumerate()
            .map(|(index, interest)| {
                format!(
                    "{{\"id\":\"{}-rec-{}\",\"item_id\":\"{}\",\"interest\":\"{}\",\"score\":{},\"source\":\"liked-interest\"}}",
                    json_escape(item_id),
                    index + 1,
                    json_escape(item_id),
                    json_escape(&interest.name),
                    100_u64.saturating_sub(index as u64)
                )
            })
            .collect::<Vec<_>>();
        format!(
            "{{\"item_id\":\"{}\",\"recommendations\":[{}],\"count\":{},\"updated_at\":{}}}",
            json_escape(item_id),
            recommendations.join(","),
            recommendations.len(),
            self.updated_at
        )
    }
}

