const SOURCE_DISCOVERY_CYCLE_SECONDS: u64 = 270;
const MAX_SOURCE_DISCOVERY_SEARCHES: usize = 32;

#[derive(Clone, Debug, Default)]
struct SourceDiscoveryState {
    running: bool,
    search_term: String,
    hash_verification_enabled: bool,
    search_tokens: VecDeque<u32>,
    search_cycles: u64,
    last_cycle_new_files: usize,
    last_dispatch_at: Option<u64>,
}

impl SourceDiscoveryState {
    fn start(&mut self, search_term: String, hash_verification_enabled: bool, token: u32) {
        self.running = true;
        self.search_term = search_term;
        self.hash_verification_enabled = hash_verification_enabled;
        self.search_tokens.clear();
        self.record_dispatch(token);
    }

    fn record_dispatch(&mut self, token: u32) {
        if self.search_tokens.len() == MAX_SOURCE_DISCOVERY_SEARCHES {
            self.search_tokens.pop_front();
        }
        self.search_tokens.push_back(token);
        self.search_cycles = self.search_cycles.saturating_add(1);
        self.last_dispatch_at = Some(unix_timestamp());
    }
}

impl Default for BackfillState {
    fn default() -> Self {
        Self {
            state_path: None,
            enabled: true,
            is_idle: false,
            idle_since: None,
            total_attempts: 0,
            successful: 0,
            failed: 0,
            rate_limited: 0,
            active: 0,
            hashes_discovered: 0,
            last_cycle_time: None,
            next_cycle_time: None,
            peer_daily_counts: BTreeMap::new(),
        }
    }
}

impl BackfillState {
    fn load(state_dir: &Path) -> Result<Self, String> {
        use std::io::Read as _;

        let path = state_dir.join("backfill-state.json");
        let mut state = Self {
            state_path: Some(path.clone()),
            ..Self::default()
        };
        let metadata = match fs::symlink_metadata(&path) {
            Ok(metadata) => metadata,
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(state),
            Err(error) => return Err(format!("backfill state metadata failed: {error}")),
        };
        if metadata.file_type().is_symlink() || !metadata.is_file() {
            return Err("backfill state path must be a regular file".to_owned());
        }
        if metadata.len() > BACKFILL_STATE_MAX_BYTES {
            return Err("backfill state file is too large".to_owned());
        }
        let mut options = fs::OpenOptions::new();
        options.read(true);
        #[cfg(unix)]
        {
            use std::os::unix::fs::OpenOptionsExt;
            options.custom_flags(libc::O_NOFOLLOW | libc::O_NONBLOCK);
        }
        let mut file = options
            .open(&path)
            .map_err(|error| format!("backfill state read failed: {error}"))?;
        let opened = file
            .metadata()
            .map_err(|error| format!("backfill state metadata failed: {error}"))?;
        if !opened.is_file() || opened.len() > BACKFILL_STATE_MAX_BYTES {
            return Err("backfill state path or size is invalid".to_owned());
        }
        let mut body = Vec::new();
        std::io::Read::take(&mut file, BACKFILL_STATE_MAX_BYTES + 1)
            .read_to_end(&mut body)
            .map_err(|error| format!("backfill state read failed: {error}"))?;
        if body.len() as u64 > BACKFILL_STATE_MAX_BYTES {
            return Err("backfill state file is too large".to_owned());
        }
        let persisted = serde_json::from_slice::<PersistedBackfillState>(&body)
            .map_err(|error| format!("backfill state parse failed: {error}"))?;
        if persisted.version != 1 || persisted.peer_daily_counts.len() > BACKFILL_MAX_PEER_COUNTERS
        {
            return Err("backfill state version or capacity is invalid".to_owned());
        }
        let day = unix_timestamp() / 86_400;
        state.peer_daily_counts = persisted
            .peer_daily_counts
            .into_iter()
            .filter(|(username, (record_day, _))| {
                !username.is_empty()
                    && username.len() <= MAX_SEARCH_RESULT_USERNAME_BYTES
                    && *record_day == day
            })
            .collect();
        Ok(state)
    }

    fn persist(&self) -> Result<(), String> {
        let Some(path) = self.state_path.as_deref() else {
            return Ok(());
        };
        let body = serde_json::to_vec(&PersistedBackfillState {
            version: 1,
            peer_daily_counts: self.peer_daily_counts.clone(),
        })
        .map_err(|error| format!("backfill state serialization failed: {error}"))?;
        write_file_atomic(path, body)
            .map_err(|error| format!("backfill state write failed: {error}"))
    }

    fn peer_count_today(&mut self, username: &str, now: u64) -> u32 {
        let day = now / 86_400;
        self.peer_daily_counts
            .retain(|_, (record_day, _)| *record_day == day);
        let key = username.to_ascii_lowercase();
        if self.peer_daily_counts.len() >= BACKFILL_MAX_PEER_COUNTERS
            && !self.peer_daily_counts.contains_key(&key)
        {
            return BACKFILL_MAX_PER_PEER_PER_DAY;
        }
        let entry = self.peer_daily_counts.entry(key).or_insert((day, 0));
        if entry.0 != day {
            *entry = (day, 0);
        }
        entry.1
    }

    fn record_peer_success(&mut self, username: &str, now: u64) {
        let count = self.peer_count_today(username, now);
        if let Some(entry) = self
            .peer_daily_counts
            .get_mut(&username.to_ascii_lowercase())
        {
            entry.1 = count.saturating_add(1);
        }
    }

    fn config_json(&self) -> serde_json::Value {
        serde_json::json!({
            "maxGlobalConnections": 2,
            "maxPerPeerPerDay": BACKFILL_MAX_PER_PEER_PER_DAY,
            "maxHeaderBytes": BACKFILL_MAX_HEADER_BYTES,
            "minIdleTimeSeconds": BACKFILL_MIN_IDLE_SECONDS,
            "runIntervalSeconds": BACKFILL_RUN_INTERVAL_SECONDS,
            "transferTimeoutSeconds": 30,
            "enabled": self.enabled,
        })
    }

    fn stats_json(&self, now: u64) -> serde_json::Value {
        serde_json::json!({
            "totalAttempts": self.total_attempts,
            "successful": self.successful,
            "failed": self.failed,
            "rateLimited": self.rate_limited,
            "active": self.active,
            "hashesDiscovered": self.hashes_discovered,
            "lastCycleTime": self.last_cycle_time,
            "nextCycleTime": self.next_cycle_time,
            "isIdle": self.is_idle,
            "idleDuration": self.idle_since.map(|since| now.saturating_sub(since)),
        })
    }
}

impl RuntimeCompatState {
    fn new() -> Self {
        Self {
            application_restart_requested: false,
            application_reconnect_pending: false,
            vpn_reconnect_requested: false,
            vpn: vpn::Status::default(),
            gc_runs: 0,
            autoreplace_enabled: false,
            relay_agent_enabled: false,
            bridge_running: false,
            bridge_config_updates: 0,
            options_updates: 0,
            options_yaml_uploads: 0,
            options_yaml_validations: 0,
            profile_invites_created: 0,
            cache_warm_runs: 0,
            backfill_runs: 0,
            songid_runs: 0,
            songid_run_records: Vec::new(),
            lidarr_sync_runs: 0,
            lidarr_manual_imports: 0,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(record: &crate::persistence::RuntimeCompatRecord) -> Self {
        Self {
            application_restart_requested: record.application_restart_requested,
            application_reconnect_pending: false,
            vpn_reconnect_requested: false,
            vpn: vpn::Status::default(),
            gc_runs: u64::try_from(record.gc_runs).unwrap_or_default(),
            autoreplace_enabled: record.autoreplace_enabled,
            relay_agent_enabled: record.relay_agent_enabled,
            bridge_running: record.bridge_running,
            bridge_config_updates: u64::try_from(record.bridge_config_updates).unwrap_or_default(),
            options_updates: u64::try_from(record.options_updates).unwrap_or_default(),
            options_yaml_uploads: u64::try_from(record.options_yaml_uploads).unwrap_or_default(),
            options_yaml_validations: u64::try_from(record.options_yaml_validations)
                .unwrap_or_default(),
            profile_invites_created: u64::try_from(record.profile_invites_created)
                .unwrap_or_default(),
            cache_warm_runs: u64::try_from(record.cache_warm_runs).unwrap_or_default(),
            backfill_runs: u64::try_from(record.backfill_runs).unwrap_or_default(),
            songid_runs: u64::try_from(record.songid_runs).unwrap_or_default(),
            songid_run_records: Vec::new(),
            lidarr_sync_runs: u64::try_from(record.lidarr_sync_runs).unwrap_or_default(),
            lidarr_manual_imports: u64::try_from(record.lidarr_manual_imports).unwrap_or_default(),
            updated_at: u64::try_from(record.updated_at).unwrap_or_else(|_| unix_timestamp()),
        }
    }

    fn persistence_record(&self, relay: &RelayState) -> crate::persistence::RuntimeCompatRecord {
        crate::persistence::RuntimeCompatRecord {
            id: "runtime".to_owned(),
            application_restart_requested: self.application_restart_requested,
            gc_runs: i64::try_from(self.gc_runs).unwrap_or(i64::MAX),
            autoreplace_enabled: self.autoreplace_enabled,
            relay_enabled: relay.enabled,
            relay_agent_enabled: self.relay_agent_enabled,
            bridge_running: self.bridge_running,
            bridge_config_updates: i64::try_from(self.bridge_config_updates).unwrap_or(i64::MAX),
            options_updates: i64::try_from(self.options_updates).unwrap_or(i64::MAX),
            options_yaml_uploads: i64::try_from(self.options_yaml_uploads).unwrap_or(i64::MAX),
            options_yaml_validations: i64::try_from(self.options_yaml_validations)
                .unwrap_or(i64::MAX),
            profile_invites_created: i64::try_from(self.profile_invites_created)
                .unwrap_or(i64::MAX),
            cache_warm_runs: i64::try_from(self.cache_warm_runs).unwrap_or(i64::MAX),
            backfill_runs: i64::try_from(self.backfill_runs).unwrap_or(i64::MAX),
            songid_runs: i64::try_from(self.songid_runs).unwrap_or(i64::MAX),
            lidarr_sync_runs: i64::try_from(self.lidarr_sync_runs).unwrap_or(i64::MAX),
            lidarr_manual_imports: i64::try_from(self.lidarr_manual_imports).unwrap_or(i64::MAX),
            updated_at: i64::try_from(self.updated_at.max(relay.updated_at)).unwrap_or(i64::MAX),
        }
    }

    fn set_restart_requested(&mut self, requested: bool) -> serde_json::Value {
        self.application_restart_requested = requested;
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "accepted": true,
            "persisted": true,
            "pendingRestart": self.application_restart_requested,
            "updated_at": self.updated_at,
        })
    }

    fn set_reconnect_pending(&mut self, pending: bool) {
        self.application_reconnect_pending = pending;
        self.updated_at = unix_timestamp();
    }

    fn record_gc(&mut self) -> serde_json::Value {
        self.gc_runs = self.gc_runs.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "collected": true,
            "gcRuns": self.gc_runs,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn set_autoreplace(&mut self, enabled: bool) -> serde_json::Value {
        self.autoreplace_enabled = enabled;
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "enabled": self.autoreplace_enabled,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn set_relay_agent(&mut self, enabled: bool) -> serde_json::Value {
        self.relay_agent_enabled = enabled;
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "enabled": self.relay_agent_enabled,
            "relayAgentEnabled": self.relay_agent_enabled,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn set_bridge_running(&mut self, running: bool, configured: bool) -> serde_json::Value {
        self.bridge_running = running && configured;
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "status": if configured {
                if self.bridge_running { "running" } else { "stopped" }
            } else {
                "disabled"
            },
            "started": self.bridge_running,
            "stopped": !self.bridge_running,
            "configured": configured,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn record_bridge_config_update(
        &mut self,
        configured: bool,
        accepted_keys: Vec<String>,
    ) -> serde_json::Value {
        self.bridge_config_updates = self.bridge_config_updates.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "enabled": configured,
            "configured": configured,
            "persisted": true,
            "restart_required": true,
            "acceptedKeys": accepted_keys,
            "configUpdates": self.bridge_config_updates,
            "updated_at": self.updated_at,
        })
    }

    fn record_options_update(&mut self) -> u64 {
        self.options_updates = self.options_updates.saturating_add(1);
        self.updated_at = unix_timestamp();
        self.options_updates
    }

    fn record_profile_invite(&mut self) -> serde_json::Value {
        self.profile_invites_created = self.profile_invites_created.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "count": self.profile_invites_created,
            "updated_at": self.updated_at,
        })
    }

    fn record_cache_warm(&mut self, warmed: usize) -> serde_json::Value {
        self.cache_warm_runs = self.cache_warm_runs.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "status": if warmed == 0 { "empty" } else { "warmed" },
            "warmed": warmed,
            "runs": self.cache_warm_runs,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn record_backfill(&mut self, queued: usize) -> serde_json::Value {
        self.backfill_runs = self.backfill_runs.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "status": if queued == 0 { "idle" } else { "queued" },
            "queued": queued,
            "runs": self.backfill_runs,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn record_songid_run(
        &mut self,
        matches: Vec<serde_json::Value>,
        library_items: usize,
        shared_files: usize,
    ) -> Option<serde_json::Value> {
        self.songid_runs = self.allocate_songid_run_id();
        self.updated_at = unix_timestamp();
        let match_count = matches.len();
        let analysis_fields = serde_json::json!({
            "scorecard": {},
            "assessment": {"verdict": "unclassified", "confidence": 0, "summary": ""},
            "metadata": {"title": "", "artist": "", "album": "", "extra": {}},
            "provenance": {"signalCount": 0, "signals": [], "toolAvailable": false, "manifestHint": false, "verified": false},
            "perturbations": [],
            "stems": [],
            "corpusMatches": [],
            "clips": [],
            "transcripts": [],
            "ocr": [],
            "comments": [],
            "chapters": [],
            "segments": [],
            "mixGroups": [],
            "identityAssessment": {"verdict": "unclassified", "confidence": 0, "summary": ""},
            "syntheticAssessment": {"verdict": "insufficient_evidence", "confidence": "low", "syntheticScore": 0, "confidenceScore": 0, "knownFamilyScore": 0, "familyLabel": "none", "qualityClass": "clean_excerpt", "perturbationStability": 0, "topEvidenceFor": [], "topEvidenceAgainst": [], "notes": [], "summary": ""},
        });
        let mut record = serde_json::json!({
            "id": format!("songid-{}", self.songid_runs),
            "source": "",
            "sourceType": "text_query",
            "status": if matches.is_empty() { "completed" } else { "matched" },
            "query": "",
            "createdAt": chrono::Utc::now().to_rfc3339(),
            "summary": if matches.is_empty() { "SongID analysis completed." } else { "SongID matches found." },
            "currentStage": "completed",
            "percentComplete": 1.0,
            "artifactDirectory": "",
            "evidence": [],
            "tracks": [],
            "albums": [],
            "artists": [],
            "plans": [],
            "options": [],
            "libraryItems": library_items,
            "sharedFiles": shared_files,
            "matches": matches,
            "matchCount": match_count,
            "runs": self.songid_runs,
            "persisted": true,
            "updated_at": self.updated_at,
        });
        if let (Some(record), Some(fields)) = (record.as_object_mut(), analysis_fields.as_object())
        {
            record.extend(fields.clone());
        }
        if self.songid_run_records.len() == MAX_SONGID_RUNS {
            self.songid_run_records.remove(0);
        }
        self.songid_run_records.push(record.clone());
        Some(record)
    }

    fn allocate_songid_run_id(&self) -> u64 {
        let mut candidate = self.songid_runs.wrapping_add(1).max(1);
        for _ in 0..=self.songid_run_records.len() {
            let id = format!("songid-{candidate}");
            if !self.songid_run_records.iter().any(|record| {
                record.get("id").and_then(serde_json::Value::as_str) == Some(id.as_str())
            }) {
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded SongID run history must leave an available u64 id")
    }

    fn songid_run(&self, id: &str) -> Option<serde_json::Value> {
        self.songid_run_records
            .iter()
            .find(|run| run.get("id").and_then(serde_json::Value::as_str) == Some(id))
            .cloned()
    }

    fn record_lidarr_sync(&mut self, missing_count: usize, configured: bool) -> serde_json::Value {
        self.lidarr_sync_runs = self.lidarr_sync_runs.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "synced": true,
            "queued": missing_count > 0,
            "status": if configured { "configured" } else { "local" },
            "missingCount": missing_count,
            "runs": self.lidarr_sync_runs,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn record_lidarr_manual_import(
        &mut self,
        imported: usize,
        configured: bool,
        directory: String,
        items: Vec<serde_json::Value>,
    ) -> serde_json::Value {
        self.lidarr_manual_imports = self.lidarr_manual_imports.saturating_add(1);
        self.updated_at = unix_timestamp();
        serde_json::json!({
            "imported": imported,
            "status": if configured { "configured" } else { "local" },
            "directory": directory,
            "items": items,
            "runs": self.lidarr_manual_imports,
            "persisted": true,
            "updated_at": self.updated_at,
        })
    }

    fn json_value(&self) -> serde_json::Value {
        serde_json::json!({
            "pendingRestart": self.application_restart_requested,
            "pendingReconnect": self.application_reconnect_pending,
            "gcRuns": self.gc_runs,
            "autoreplaceEnabled": self.autoreplace_enabled,
            "relayAgentEnabled": self.relay_agent_enabled,
            "bridgeRunning": self.bridge_running,
            "bridgeConfigUpdates": self.bridge_config_updates,
            "optionsUpdates": self.options_updates,
            "optionsYamlUploads": self.options_yaml_uploads,
            "optionsYamlValidations": self.options_yaml_validations,
            "profileInvitesCreated": self.profile_invites_created,
            "cacheWarmRuns": self.cache_warm_runs,
            "backfillRuns": self.backfill_runs,
            "songidRuns": self.songid_runs,
            "lidarrSyncRuns": self.lidarr_sync_runs,
            "lidarrManualImports": self.lidarr_manual_imports,
            "updated_at": self.updated_at,
        })
    }
}

#[derive(Clone, Debug)]
struct SecurityBanRecord {
    kind: String,
    value: String,
    created_at: u64,
    reason: String,
    expires_at: u64,
    is_permanent: bool,
}

#[derive(Clone, Debug)]
struct SecurityState {
    bans: Vec<SecurityBanRecord>,
    violations: BTreeMap<String, u32>,
    reputation: BTreeMap<String, i32>,
    updated_at: u64,
}

impl SecurityState {
    fn new() -> Self {
        Self {
            bans: Vec::new(),
            violations: BTreeMap::new(),
            reputation: BTreeMap::new(),
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::SecurityBanRecord>) -> Self {
        let mut updated_at = unix_timestamp();
        let mut seen = std::collections::HashSet::new();
        let bans = records
            .into_iter()
            .filter_map(|record| {
                let value = normalize_security_ban_value(&record.kind, &record.value)?;
                let deduplication_value = if record.kind == "username" {
                    value.to_ascii_lowercase()
                } else {
                    value.clone()
                };
                seen.insert((record.kind.clone(), deduplication_value))
                    .then_some((record, value))
            })
            .take(MAX_SECURITY_BANS)
            .map(|(record, value)| {
                let created_at = u64::try_from(record.created_at).unwrap_or(0);
                updated_at = updated_at.max(created_at);
                SecurityBanRecord {
                    kind: record.kind,
                    value,
                    created_at,
                    reason: record.reason,
                    expires_at: u64::try_from(record.expires_at).unwrap_or(created_at),
                    is_permanent: record.is_permanent,
                }
            })
            .collect();
        Self {
            bans,
            violations: BTreeMap::new(),
            reputation: BTreeMap::new(),
            updated_at,
        }
    }

    fn ban(&mut self, kind: &str, value: String) -> Option<SecurityBanRecord> {
        self.ban_with_options(kind, value, "Manual ban".to_owned(), 3_600, false)
    }

    fn ban_with_options(
        &mut self,
        kind: &str,
        value: String,
        reason: String,
        duration_seconds: u64,
        is_permanent: bool,
    ) -> Option<SecurityBanRecord> {
        let value = normalize_security_ban_value(kind, &value)?;
        let now = unix_timestamp();
        let expires_at = now.saturating_add(duration_seconds);
        if let Some(record) = self.bans.iter_mut().find(|record| {
            record.kind == kind
                && if kind == "username" {
                    record.value.eq_ignore_ascii_case(&value)
                } else {
                    record.value == value
                }
        }) {
            record.created_at = now;
            record.reason = reason;
            record.expires_at = expires_at;
            record.is_permanent = is_permanent;
            self.updated_at = now;
            return Some(record.clone());
        }
        if self.bans.len() >= MAX_SECURITY_BANS {
            return None;
        }
        let record = SecurityBanRecord {
            kind: kind.to_owned(),
            value,
            created_at: now,
            reason,
            expires_at,
            is_permanent,
        };
        self.bans.push(record.clone());
        self.updated_at = now;
        Some(record)
    }

    fn unban(&mut self, kind: &str, value: &str) -> bool {
        let Some(value) = normalize_security_ban_value(kind, value) else {
            return false;
        };
        let before = self.bans.len();
        self.bans.retain(|record| {
            let value_matches = if kind == "username" {
                record.value.eq_ignore_ascii_case(&value)
            } else {
                record.value == value
            };
            !(record.kind == kind && value_matches)
        });
        let removed = before != self.bans.len();
        if removed {
            self.updated_at = unix_timestamp();
        }
        removed
    }

    fn record_peer_violation(
        &mut self,
        username: &str,
        settings: &crate::config::SecuritySettings,
    ) -> bool {
        let username = bounded_user_username(username.trim());
        if username.is_empty() || !settings.enabled {
            return false;
        }
        let key = username.to_ascii_lowercase();
        let violation_count = self
            .violations
            .get(&key)
            .copied()
            .unwrap_or(0)
            .saturating_add(1);
        self.violations.insert(key.clone(), violation_count);
        let score = self.reputation.entry(key.clone()).or_insert(100);
        *score = score.saturating_sub(10).max(0);
        self.updated_at = unix_timestamp();
        if settings.violation_tracker.enabled
            && self.violations.get(&key).copied().unwrap_or(0)
                >= settings.violation_tracker.violations_before_auto_ban
        {
            self.violations.insert(key, 0);
            return self
                .ban_with_options(
                    "username",
                    username,
                    "Automatic security-policy ban".to_owned(),
                    settings.violation_tracker.base_ban_duration.as_secs(),
                    false,
                )
                .is_some();
        }
        false
    }

    fn active_bans(&self) -> usize {
        self.bans.len()
    }

    fn json_value(&self) -> serde_json::Value {
        let bans = self
            .bans
            .iter()
            .map(|record| {
                serde_json::json!({
                    "kind": record.kind,
                    "type": record.kind,
                    "value": record.value,
                    "created_at": record.created_at,
                })
            })
            .collect::<Vec<_>>();
        serde_json::json!({
            "bans": bans,
            "count": self.bans.len(),
            "updated_at": self.updated_at,
        })
    }

    fn slskdn_bans_json(&self) -> String {
        let now = unix_timestamp();
        serde_json::Value::Array(
            self.bans
                .iter()
                .filter(|record| record.expires_at > now)
                .map(|record| {
                    let remaining = record.expires_at.saturating_sub(now);
                    let days = remaining / 86_400;
                    let hours = (remaining % 86_400) / 3_600;
                    let minutes = (remaining % 3_600) / 60;
                    let seconds = remaining % 60;
                    serde_json::json!({
                        "key": if record.kind == "ip" {
                            format!("IP:{}", record.value)
                        } else {
                            format!("User:{}", record.value.to_ascii_lowercase())
                        },
                        "reason": record.reason,
                        "bannedAt": unix_seconds_rfc3339(record.created_at),
                        "expiresAt": unix_seconds_rfc3339(record.expires_at),
                        "isPermanent": record.is_permanent,
                        "timeRemaining": format!("{days}.{hours:02}:{minutes:02}:{seconds:02}"),
                    })
                })
                .collect(),
        )
        .to_string()
    }
}

fn normalize_security_ban_value(kind: &str, value: &str) -> Option<String> {
    match kind {
        "username" => {
            let value =
                truncate_utf8_bytes(value.trim().to_owned(), MAX_SECURITY_BAN_USERNAME_BYTES);
            (!value.is_empty()).then_some(value)
        }
        "ip" => value
            .trim()
            .parse::<std::net::IpAddr>()
            .ok()
            .map(|address| address.to_string()),
        _ => None,
    }
}

fn security_ban_options(body: &str) -> (String, u64, bool) {
    let reason = extract_json_string_field(body, "reason")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "Manual ban".to_owned());
    let is_permanent = extract_json_bool_field(body, "permanent").unwrap_or(false);
    let parsed_duration = extract_json_string_field(body, "duration").and_then(|duration| {
        let (days, clock) = duration
            .split_once('.')
            .and_then(|(days, clock)| days.parse::<u64>().ok().map(|days| (days, clock)))
            .unwrap_or((0, duration.as_str()));
        let parts = clock.split(':').collect::<Vec<_>>();
        if parts.len() != 3 {
            return None;
        }
        let hours = parts[0].parse::<u64>().ok()?;
        let minutes = parts[1].parse::<u64>().ok()?;
        let seconds = parts[2].split('.').next()?.parse::<u64>().ok()?;
        (minutes < 60 && seconds < 60).then(|| {
            days.saturating_mul(86_400)
                .saturating_add(hours.saturating_mul(3_600))
                .saturating_add(minutes.saturating_mul(60))
                .saturating_add(seconds)
        })
    });
    let duration_seconds = if is_permanent {
        3_650 * 86_400
    } else {
        parsed_duration
            .or_else(|| {
                extract_json_u64_field(body, "durationMinutes")
                    .map(|minutes| minutes.saturating_mul(60))
            })
            .unwrap_or(3_600)
    };
    (reason, duration_seconds, is_permanent)
}

fn security_ban_route_tail(path: &str) -> Option<Vec<&str>> {
    let segments = path.strip_prefix("/api/")?.split('/').collect::<Vec<_>>();
    match segments.as_slice() {
        ["bans", tail @ ..] | [_, "bans", tail @ ..] => Some(tail.to_vec()),
        _ => None,
    }
}

fn webhook_resource_id<'a>(path: &'a str, prefix: &str) -> Option<&'a str> {
    let id = path.strip_prefix(prefix)?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn webhook_test_id<'a>(path: &'a str, prefix: &str) -> Option<&'a str> {
    let path = path.strip_prefix(prefix)?;
    let id = path.strip_suffix("/test")?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

// Share Grant Models
#[derive(Clone, Debug)]
struct ShareGrantRecord {
    id: String,
    collection_id: String,
    username: String,
    shared_at: u64,
    permissions: String,
}

impl ShareGrantRecord {
    fn json(&self) -> String {
        format!(
            "{{\"id\":\"{}\",\"collection_id\":\"{}\",\"username\":\"{}\",\"shared_at\":{},\"permissions\":\"{}\"}}",
            json_escape(&self.id),
            json_escape(&self.collection_id),
            json_escape(&self.username),
            self.shared_at,
            json_escape(&self.permissions)
        )
    }
}

#[derive(Clone, Debug)]
struct ShareGrantStore {
    records: Vec<ShareGrantRecord>,
    next_id: u64,
    updated_at: u64,
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct ShareAccessTokenRecord {
    grant_id: String,
    expires_at: u64,
}

#[derive(Debug)]
struct ShareAccessTokenStore {
    records: BTreeMap<String, ShareAccessTokenRecord>,
    max_records: usize,
}

impl Default for ShareAccessTokenStore {
    fn default() -> Self {
        Self::with_max_records(MAX_SHARE_ACCESS_TOKENS)
    }
}

impl ShareAccessTokenStore {
    fn with_max_records(max_records: usize) -> Self {
        Self {
            records: BTreeMap::new(),
            max_records: max_records.max(1),
        }
    }

    fn issue(&mut self, grant_id: String, ttl_seconds: u64) -> Option<(String, u64)> {
        let now = unix_timestamp();
        self.prune(now);
        if self.records.len() >= self.max_records {
            return None;
        }
        let token = secure_share_grant_token()?;
        let expires_at =
            now.saturating_add(ttl_seconds.clamp(1, MAX_SHARE_ACCESS_TOKEN_TTL_SECONDS));
        self.records.insert(
            share_access_token_digest(&token),
            ShareAccessTokenRecord {
                grant_id,
                expires_at,
            },
        );
        Some((token, expires_at))
    }

    fn from_persisted(
        records: Vec<crate::persistence::ShareAccessTokenRecord>,
        valid_grant_ids: &HashSet<&str>,
    ) -> Self {
        let now = unix_timestamp();
        let mut store = Self::default();
        for record in records.into_iter().take(store.max_records) {
            let Ok(expires_at) = u64::try_from(record.expires_at) else {
                continue;
            };
            if expires_at <= now
                || !valid_grant_ids.contains(record.grant_id.as_str())
                || record.token_digest.len() != 64
                || !record
                    .token_digest
                    .bytes()
                    .all(|byte| byte.is_ascii_hexdigit())
            {
                continue;
            }
            store.records.insert(
                record.token_digest.to_ascii_lowercase(),
                ShareAccessTokenRecord {
                    grant_id: record.grant_id,
                    expires_at,
                },
            );
        }
        store
    }

    fn validate(&mut self, token: &str) -> Option<ShareAccessTokenRecord> {
        let now = unix_timestamp();
        self.prune(now);
        self.records.get(&share_access_token_digest(token)).cloned()
    }

    fn revoke_grant(&mut self, grant_id: &str) {
        self.records.retain(|_, record| record.grant_id != grant_id);
    }

    fn remove_if_unchanged(&mut self, digest: &str, expected: &ShareAccessTokenRecord) {
        if self.records.get(digest) == Some(expected) {
            self.records.remove(digest);
        }
    }

    fn prune(&mut self, now: u64) {
        self.records.retain(|_, record| record.expires_at > now);
    }
}

fn share_access_token_digest(token: &str) -> String {
    use sha2::{Digest, Sha256};

    hex::encode(Sha256::digest(token.as_bytes()))
}

impl ShareGrantStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::ShareGrantRecord>) -> Self {
        let mut next_id = 1;
        let mut updated_at = unix_timestamp();
        for record in &records {
            if let Some(number) = record
                .id
                .strip_prefix("grant-")
                .and_then(|value| value.parse::<u64>().ok())
            {
                next_id = next_id.max(number.saturating_add(1));
            }
        }
        let mut seen_ids = std::collections::HashSet::new();
        let mut seen_grants = std::collections::HashSet::new();
        let records = records
            .into_iter()
            .filter_map(|record| {
                let username = normalize_share_grant_username(&record.username)?;
                (seen_ids.insert(record.id.clone())
                    && seen_grants
                        .insert((record.collection_id.clone(), username.to_ascii_lowercase())))
                .then_some((record, username))
            })
            .take(MAX_SHARE_GRANTS)
            .map(|(record, username)| {
                let shared_at = u64::try_from(record.shared_at).unwrap_or(0);
                updated_at = updated_at.max(shared_at);
                ShareGrantRecord {
                    id: record.id,
                    collection_id: record.collection_id,
                    username,
                    shared_at,
                    permissions: bounded_share_grant_permissions(&record.permissions),
                }
            })
            .collect();
        Self {
            records,
            next_id,
            updated_at,
        }
    }

    fn create(
        &mut self,
        collection_id: String,
        username: String,
    ) -> Option<(ShareGrantRecord, bool)> {
        let username = normalize_share_grant_username(&username)?;
        if let Some(record) = self.records.iter().find(|record| {
            record.collection_id == collection_id && record.username.eq_ignore_ascii_case(&username)
        }) {
            return Some((record.clone(), false));
        }
        if self.records.len() >= MAX_SHARE_GRANTS {
            return None;
        }
        let id = format!("grant-{}", self.allocate_id());
        let now = unix_timestamp();
        let record = ShareGrantRecord {
            id,
            collection_id,
            username,
            shared_at: now,
            permissions: "read".to_string(),
        };
        self.records.push(record.clone());
        self.updated_at = now;
        Some((record, true))
    }

    fn allocate_id(&mut self) -> u64 {
        let mut candidate = self.next_id.max(1);
        for _ in 0..=self.records.len() {
            let id = format!("grant-{candidate}");
            if !self.records.iter().any(|record| record.id == id) {
                self.next_id = candidate.wrapping_add(1).max(1);
                return candidate;
            }
            candidate = candidate.wrapping_add(1).max(1);
        }
        unreachable!("bounded share-grant store must leave an available u64 id")
    }

    fn get(&self, id: &str) -> Option<ShareGrantRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn get_by_collection(&self, collection_id: &str) -> Vec<ShareGrantRecord> {
        self.records
            .iter()
            .filter(|r| r.collection_id == collection_id)
            .cloned()
            .collect()
    }

    fn update(&mut self, id: &str, permissions: String) -> Option<ShareGrantRecord> {
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.permissions = bounded_share_grant_permissions(&permissions);
        self.updated_at = unix_timestamp();
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn delete_by_collection(&mut self, collection_id: &str) -> Vec<ShareGrantRecord> {
        let mut removed = Vec::new();
        self.records.retain(|record| {
            if record.collection_id == collection_id {
                removed.push(record.clone());
                false
            } else {
                true
            }
        });
        if !removed.is_empty() {
            self.updated_at = unix_timestamp();
        }
        removed
    }

    #[allow(dead_code)]
    fn json(&self) -> String {
        format!(
            "{{\"entries\":{},\"count\":{},\"updated_at\":{}}}",
            self.json_array(),
            self.records.len(),
            self.updated_at
        )
    }

    fn json_array(&self) -> String {
        let records = self
            .records
            .iter()
            .map(ShareGrantRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

fn normalize_share_grant_username(username: &str) -> Option<String> {
    let username = truncate_utf8_bytes(username.trim().to_owned(), MAX_USER_USERNAME_BYTES);
    (!username.is_empty()).then_some(username)
}

fn bounded_share_grant_permissions(permissions: &str) -> String {
    let permissions = truncate_utf8_bytes(
        permissions.trim().to_owned(),
        MAX_SHARE_GRANT_PERMISSIONS_BYTES,
    );
    if permissions.is_empty() {
        "read".to_owned()
    } else {
        permissions
    }
}

fn share_grant_resource_id(path: &str) -> Option<&str> {
    let id = path.strip_prefix("/api/share-grants/")?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn share_grant_collection_id(path: &str) -> Option<&str> {
    let id = path.strip_prefix("/api/share-grants/by-collection/")?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn share_grant_helper_id<'a>(path: &'a str, helper: &str) -> Option<&'a str> {
    let path = path.strip_prefix("/api/share-grants/")?;
    let id = path.strip_suffix(&format!("/{helper}"))?;
    (!id.is_empty() && !id.contains('/')).then_some(id)
}

fn share_grant_manifest_id(path: &str) -> Option<&str> {
    share_grant_helper_id(path, "manifest")
}

fn share_stream_content_id(path: &str) -> Option<String> {
    let path = path.strip_prefix("/api/streams/")?;
    let content_id = path.strip_suffix("/share-ticket")?;
    (!content_id.is_empty() && !content_id.contains('/')).then(|| decoded_path_segment(content_id))
}

