async fn reconfigure_regular_listener(
    state: &AppState,
    bind: Option<String>,
) -> Result<bool, String> {
    let Some(commands) = state.regular_listener_commands.as_ref() else {
        return Ok(bind != state.config.listener_bind);
    };
    let (response, receiver) = oneshot::channel();
    commands
        .send(ListenerCommand::Reconfigure { bind, response })
        .await
        .map_err(|_| "regular listener manager is unavailable".to_owned())?;
    receiver
        .await
        .map_err(|_| "regular listener manager dropped its response".to_owned())?
}

async fn reconfigure_obfuscated_listener(
    state: &AppState,
    bind: Option<String>,
) -> Result<bool, String> {
    let Some(commands) = state.obfuscated_listener_commands.as_ref() else {
        return Ok(bind != state.config.obfuscated_listener_bind);
    };
    let (response, receiver) = oneshot::channel();
    commands
        .send(ListenerCommand::Reconfigure { bind, response })
        .await
        .map_err(|_| "obfuscated listener manager is unavailable".to_owned())?;
    receiver
        .await
        .map_err(|_| "obfuscated listener manager dropped its response".to_owned())?
}

async fn effective_user_info_description(state: &AppState) -> String {
    let base = state
        .user_info_description
        .read()
        .unwrap_or_else(std::sync::PoisonError::into_inner)
        .clone();
    if state.config.controller_compatibility_target != ControllerCompatibilityTarget::Slskdn {
        return base;
    }
    let now_playing = state.now_playing.read().await;
    let Some(record) = now_playing
        .records
        .iter()
        .max_by_key(|record| record.updated_at)
    else {
        return base;
    };
    format!(
        "{base}\n\n🎵 Listening to: {} – {}",
        record.artist, record.title
    )
}

async fn effective_user_info_picture(state: &AppState) -> Option<Vec<u8>> {
    let path = state
        .user_info_picture
        .read()
        .unwrap_or_else(std::sync::PoisonError::into_inner)
        .clone()?;
    match fs::read(&path) {
        Ok(picture) => Some(picture),
        Err(error) => {
            record_daemon_log(
                state,
                logging::LogLevel::Warn,
                "soulseek",
                format!(
                    "Failed to read Soulseek picture {}: {error}",
                    path.display()
                ),
            )
            .await;
            None
        }
    }
}

fn controller_forbidden_response() -> HttpResponse {
    HttpResponse {
        status: "403 Forbidden",
        content_type: "",
        body: String::new(),
    }
}

fn controller_options_validation_failure_response(state: &AppState) -> Option<HttpResponse> {
    let error = state
        .controller_options_validation_error
        .read()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    error.as_ref()?;
    Some(match state.config.controller_compatibility_target {
        ControllerCompatibilityTarget::Slskd => HttpResponse {
            status: "500 Internal Server Error",
            content_type: "application/json; charset=utf-8",
            body: serde_json::Value::String("A validation error has occurred.".to_owned())
                .to_string(),
        },
        ControllerCompatibilityTarget::Slskdn => HttpResponse {
            status: "500 Internal Server Error",
            content_type: "application/problem+json",
            body: serde_json::json!({
                "title": "Internal Server Error",
                "status": 500,
                "detail": "An unexpected error occurred.",
                "traceId": "0H00000000000:00000001",
            })
            .to_string(),
        },
    })
}

#[derive(Debug, Default)]
struct RevokedJwtStore {
    records: BTreeMap<String, u64>,
}

impl RevokedJwtStore {
    fn revoke(&mut self, jti: String, expires_at: u64, now: u64) {
        self.records.retain(|_, expiry| *expiry > now);
        if expires_at > now {
            self.records.insert(jti, expires_at);
        }
    }

    fn contains(&mut self, jti: &str, now: u64) -> bool {
        self.records.retain(|_, expiry| *expiry > now);
        self.records.contains_key(jti)
    }
}

#[derive(Clone, Copy, Debug)]
struct LoginAttempt {
    failures: u8,
    last_failure: u64,
    lockout_until: u64,
}

#[derive(Debug, Default)]
struct LoginAttemptStore {
    records: BTreeMap<String, LoginAttempt>,
}

impl LoginAttemptStore {
    const MAX_RECORDS: usize = 10_000;
    const MAX_FAILURES: u8 = 5;
    const WINDOW_SECONDS: u64 = 10 * 60;
    const LOCKOUT_SECONDS: u64 = 5 * 60;

    fn is_locked(&mut self, keys: &[String], now: u64) -> bool {
        self.prune(now);
        keys.iter().any(|key| {
            self.records
                .get(key)
                .is_some_and(|attempt| attempt.lockout_until > now)
        })
    }

    fn record_failure(&mut self, keys: &[String], now: u64) {
        self.prune(now);
        for key in keys {
            if !self.records.contains_key(key) && self.records.len() >= Self::MAX_RECORDS {
                if let Some(oldest) = self
                    .records
                    .iter()
                    .min_by_key(|(_, attempt)| attempt.last_failure)
                    .map(|(key, _)| key.clone())
                {
                    self.records.remove(&oldest);
                }
            }
            let previous = self.records.get(key).copied();
            let failures = previous
                .filter(|attempt| now.saturating_sub(attempt.last_failure) <= Self::WINDOW_SECONDS)
                .map(|attempt| attempt.failures.saturating_add(1))
                .unwrap_or(1);
            self.records.insert(
                key.clone(),
                LoginAttempt {
                    failures,
                    last_failure: now,
                    lockout_until: if failures >= Self::MAX_FAILURES {
                        now.saturating_add(Self::LOCKOUT_SECONDS)
                    } else {
                        0
                    },
                },
            );
        }
    }

    fn clear(&mut self, keys: &[String]) {
        for key in keys {
            self.records.remove(key);
        }
    }

    fn prune(&mut self, now: u64) {
        self.records.retain(|_, attempt| {
            attempt.lockout_until > now
                || now.saturating_sub(attempt.last_failure) <= Self::WINDOW_SECONDS
        });
    }
}

async fn request_uses_revoked_jwt(state: &AppState, authorization: Option<&str>) -> bool {
    let Some(token) = authorization.and_then(|value| value.strip_prefix("Bearer ")) else {
        return false;
    };
    let now = unix_timestamp();
    let Some(claims) = utils::verify_admin_jwt(&state.config, token, now) else {
        return false;
    };
    state.revoked_jwts.write().await.contains(&claims.jti, now)
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum LifecycleCommand {
    Shutdown,
    Restart,
}

fn schedule_lifecycle_command(state: &AppState, command: LifecycleCommand) {
    let Some(sender) = state.lifecycle_commands.clone() else {
        return;
    };
    tokio::spawn(async move {
        // Let the HTTP response flush before the accept loop tears down the runtime.
        time::sleep(Duration::from_millis(100)).await;
        let _ = sender.send(command).await;
    });
}

fn spawn_replacement_process() -> Result<(), String> {
    let executable = std::env::current_exe()
        .map_err(|error| format!("failed to resolve current executable: {error}"))?;
    std::process::Command::new(executable)
        .args(std::env::args_os().skip(1))
        .spawn()
        .map(|_| ())
        .map_err(|error| format!("failed to restart slskr: {error}"))
}

