fn slskdn_adversarial_yaml_update(
    current: &str,
    payload: &serde_json::Value,
) -> Result<String, String> {
    let object = payload
        .as_object()
        .ok_or_else(|| "Settings cannot be null".to_owned())?;
    let default_yaml = SLSKDN_DEFAULT_ADVERSARIAL_YAML.replace("__SLSKDN_EMPTY__", "");
    let mut rendered = default_yaml
        .trim_end_matches(['\r', '\n'])
        .strip_suffix("...")
        .unwrap_or(&default_yaml)
        .trim_end_matches(['\r', '\n'])
        .lines()
        .map(str::to_owned)
        .collect::<Vec<_>>();
    apply_slskdn_adversarial_json_object(
        &mut rendered,
        &["security".to_owned(), "adversarial".to_owned()],
        object,
    );

    let mut current_lines = current
        .trim_end_matches(['\r', '\n'])
        .lines()
        .map(str::to_owned)
        .collect::<Vec<_>>();
    if current_lines
        .last()
        .is_some_and(|line| line.trim() == "...")
    {
        current_lines.pop();
    }
    while current_lines.last().is_some_and(|line| line.is_empty()) {
        current_lines.pop();
    }

    let security_index = current_lines.iter().position(|line| line == "security:");
    let rendered_adversarial = rendered.iter().skip(1).cloned().collect::<Vec<_>>();
    match security_index {
        None => {
            current_lines.extend(rendered);
        }
        Some(security_index) => {
            let security_end = current_lines
                .iter()
                .enumerate()
                .skip(security_index + 1)
                .find(|(_, line)| !line.is_empty() && yaml_indentation(line) == 0)
                .map(|(index, _)| index)
                .unwrap_or(current_lines.len());
            let adversarial_index = current_lines
                .iter()
                .enumerate()
                .take(security_end)
                .skip(security_index + 1)
                .find(|(_, line)| *line == "  adversarial:")
                .map(|(index, _)| index);
            if let Some(adversarial_index) = adversarial_index {
                let adversarial_end = current_lines
                    .iter()
                    .enumerate()
                    .take(security_end)
                    .skip(adversarial_index + 1)
                    .find(|(_, line)| !line.is_empty() && yaml_indentation(line) <= 2)
                    .map(|(index, _)| index)
                    .unwrap_or(security_end);
                current_lines.splice(adversarial_index..adversarial_end, rendered_adversarial);
            } else {
                current_lines.splice(security_end..security_end, rendered_adversarial);
            }
        }
    }
    let mut output = current_lines.join("\n");
    output.push_str("\n...\n");
    Ok(output)
}

fn yaml_indentation(line: &str) -> usize {
    line.bytes().take_while(|byte| *byte == b' ').count()
}

fn apply_slskdn_adversarial_json_object(
    lines: &mut Vec<String>,
    parent_path: &[String],
    object: &serde_json::Map<String, serde_json::Value>,
) {
    for (key, value) in object {
        let mut path = parent_path.to_vec();
        path.push(camel_to_snake_case(key));
        match value {
            serde_json::Value::Object(nested) if nested.is_empty() => {}
            serde_json::Value::Object(nested) => {
                if !replace_slskdn_yaml_value(lines, &path, value) {
                    apply_slskdn_adversarial_json_object(lines, &path, nested);
                }
            }
            _ => {
                replace_slskdn_yaml_value(lines, &path, value);
            }
        }
    }
}

fn replace_slskdn_yaml_value(
    lines: &mut Vec<String>,
    target_path: &[String],
    value: &serde_json::Value,
) -> bool {
    let mut stack = Vec::<(usize, String)>::new();
    for index in 0..lines.len() {
        let line = &lines[index];
        let trimmed = line.trim_start();
        if trimmed.is_empty() || trimmed.starts_with('-') || matches!(trimmed, "---" | "...") {
            continue;
        }
        let Some((key, _)) = trimmed.split_once(':') else {
            continue;
        };
        let indentation = yaml_indentation(line);
        while stack
            .last()
            .is_some_and(|(ancestor_indentation, _)| *ancestor_indentation >= indentation)
        {
            stack.pop();
        }
        let mut path = stack.iter().map(|(_, key)| key.clone()).collect::<Vec<_>>();
        path.push(key.to_owned());
        if path == target_path {
            if value.is_object()
                && lines
                    .iter()
                    .skip(index + 1)
                    .find(|candidate| !candidate.trim().is_empty())
                    .is_some_and(|candidate| yaml_indentation(candidate) > indentation)
            {
                return false;
            }
            let end = lines
                .iter()
                .enumerate()
                .skip(index + 1)
                .find(|(_, candidate)| {
                    let candidate = candidate.as_str();
                    !candidate.trim().is_empty()
                        && !candidate.trim_start().starts_with('-')
                        && yaml_indentation(candidate) <= indentation
                })
                .map(|(end, _)| end)
                .unwrap_or(lines.len());
            let replacement = slskdn_yaml_value_lines(key, indentation, target_path, value);
            lines.splice(index..end, replacement);
            return true;
        }
        stack.push((indentation, key.to_owned()));
    }
    false
}

fn slskdn_yaml_value_lines(
    key: &str,
    indentation: usize,
    path: &[String],
    value: &serde_json::Value,
) -> Vec<String> {
    let prefix = " ".repeat(indentation);
    match value {
        serde_json::Value::Array(values) if values.is_empty() => {
            vec![format!("{prefix}{key}: []")]
        }
        serde_json::Value::Array(values) => {
            let mut output = vec![format!("{prefix}{key}:")];
            output.extend(values.iter().map(|value| {
                format!(
                    "{prefix}- {}",
                    slskdn_yaml_scalar(path, value).unwrap_or_default()
                )
            }));
            output
        }
        serde_json::Value::Object(object) if object.is_empty() => {
            vec![format!("{prefix}{key}: {{}}")]
        }
        serde_json::Value::Object(object) => {
            let mut output = vec![format!("{prefix}{key}:")];
            for (child_key, child_value) in object {
                let child_key = camel_to_snake_case(child_key);
                let child_path = path
                    .iter()
                    .cloned()
                    .chain(std::iter::once(child_key.clone()))
                    .collect::<Vec<_>>();
                output.extend(slskdn_yaml_value_lines(
                    &child_key,
                    indentation + 2,
                    &child_path,
                    child_value,
                ));
            }
            output
        }
        _ => vec![format!(
            "{prefix}{key}: {}",
            slskdn_yaml_scalar(path, value).unwrap_or_default()
        )],
    }
}

fn slskdn_yaml_scalar(path: &[String], value: &serde_json::Value) -> Option<String> {
    match value {
        serde_json::Value::Null => Some(String::new()),
        serde_json::Value::Bool(value) => Some(value.to_string()),
        serde_json::Value::Number(value) => Some(value.to_string()),
        serde_json::Value::String(value) => {
            let enum_value = if path.last().is_some_and(|key| {
                matches!(
                    key.as_str(),
                    "profile" | "mode" | "primary_transport" | "isolation_method"
                )
            }) || path.last().is_some_and(|key| key == "preference_order")
            {
                [
                    "Disabled",
                    "Standard",
                    "Enhanced",
                    "Maximum",
                    "Custom",
                    "Direct",
                    "Tor",
                    "I2P",
                    "RelayOnly",
                    "Auto",
                    "WebSocket",
                    "HttpTunnel",
                    "Obfs4",
                    "Meek",
                    "DirectQuic",
                    "TorOnionQuic",
                    "I2PQuic",
                    "SocksAuth",
                ]
                .into_iter()
                .find(|candidate| candidate.eq_ignore_ascii_case(value))
                .unwrap_or(value)
            } else {
                value
            };
            if enum_value.is_empty() {
                Some("''".to_owned())
            } else if enum_value.starts_with([
                '-', '?', ':', '!', '&', '*', '#', '{', '}', '[', ']', ',', '|', '>', '@', '`',
            ]) || enum_value.ends_with(char::is_whitespace)
                || enum_value.starts_with(char::is_whitespace)
                || enum_value.contains(": ")
                || enum_value.contains(" #")
                || matches!(
                    enum_value.to_ascii_lowercase().as_str(),
                    "true" | "false" | "null" | "~"
                )
                || enum_value.parse::<f64>().is_ok()
            {
                Some(format!("'{}'", enum_value.replace('\'', "''")))
            } else {
                Some(enum_value.to_owned())
            }
        }
        serde_json::Value::Array(_) | serde_json::Value::Object(_) => None,
    }
}

fn validate_slskdn_adversarial_settings(payload: &serde_json::Value) -> Result<(), &'static str> {
    let bucket_sizes = payload
        .pointer("/privacy/padding/bucketSizes")
        .or_else(|| payload.pointer("/privacy/padding/bucket_sizes"));
    if bucket_sizes
        .and_then(serde_json::Value::as_array)
        .is_some_and(|values| values.iter().any(|value| value.as_i64().unwrap_or(0) <= 0))
    {
        return Err("Bucket sizes must be positive");
    }
    Ok(())
}

async fn apply_controller_yaml_upload(body: &str, state: &AppState) -> HttpResponse {
    let text = match slskd_options_config_body(body) {
        Ok(text) => text,
        Err(error) => return routing::bad_request_response(&error),
    };
    if text.len() > MAX_CONTROLLER_YAML_BYTES {
        return HttpResponse {
            status: "413 Payload Too Large",
            content_type: "application/json",
            body: serde_json::json!("YAML is too large").to_string(),
        };
    }
    let parsed = match parse_controller_yaml(&text) {
        Ok(parsed) => parsed,
        Err(error) => return routing::bad_request_response(&error),
    };
    if let Some(error) = controller_yaml_target_validation_error(
        &parsed,
        state.config.controller_compatibility_target,
    ) {
        return HttpResponse {
            status: "400 Bad Request",
            content_type: "application/json; charset=utf-8",
            body: serde_json::Value::String(error).to_string(),
        };
    }
    if let Err(error) = write_controller_compatibility_yaml(&state.config, &text) {
        eprintln!("configuration update failed: {error}");
        return routing::internal_server_error_response("Failed to update configuration file");
    }
    apply_watched_controller_configuration(state, Some(&text), &state.controller_cli_environment)
        .await;
    if effective_controller_no_config_watch(state) {
        state.runtime.write().await.set_restart_requested(true);
    }
    record_event(
        state,
        "options.yaml.updated",
        "options/yaml",
        Some(format!("bytes={}", text.len())),
    )
    .await;
    HttpResponse {
        status: "200 OK",
        content_type: "",
        body: String::new(),
    }
}

fn slskd_options_config_validate_response(
    body: &str,
    target: ControllerCompatibilityTarget,
) -> Result<HttpResponse, String> {
    let text = slskd_options_config_body(body)?;
    let parsed = parse_controller_yaml(&text);
    let parse_failed = parsed.is_err();
    let validation = parsed
        .as_ref()
        .err()
        .cloned()
        .or_else(|| controller_yaml_target_validation_error(parsed.as_ref().ok()?, target));
    let (content_type, body) = match validation {
        None => ("", String::new()),
        Some(error) => {
            let error = if target == ControllerCompatibilityTarget::Slskd
                && parse_failed
                && text.trim_start().starts_with("web:")
            {
                "No node deserializer was able to deserialize the node into type slskd.Options+WebOptions, slskd, Version=1.0.0.0, Culture=neutral, PublicKeyToken=null".to_owned()
            } else {
                error
            };
            (
                "application/json; charset=utf-8",
                serde_json::Value::String(error).to_string(),
            )
        }
    };
    Ok(HttpResponse {
        status: "200 OK",
        content_type,
        body,
    })
}

fn json_object_field_ci<'a>(
    object: &'a serde_json::Map<String, serde_json::Value>,
    name: &str,
) -> Option<&'a serde_json::Value> {
    object
        .iter()
        .find(|(key, _)| key.eq_ignore_ascii_case(name))
        .map(|(_, value)| value)
}

fn options_model_binding_problem_response() -> HttpResponse {
    HttpResponse {
        status: "400 Bad Request",
        content_type: "application/json; charset=utf-8",
        body: r#"{"title":"One or more validation errors occurred.","status":400,"detail":"The request is invalid.","errors":{}}"#.to_owned(),
    }
}

fn normalize_controller_options_overlay(
    body: &str,
    target: ControllerCompatibilityTarget,
) -> Result<serde_json::Value, String> {
    let payload = serde_json::from_str::<serde_json::Value>(body)
        .map_err(|_| "Invalid options overlay".to_owned())?;
    let object = payload
        .as_object()
        .ok_or_else(|| "Options overlay is required".to_owned())?;
    let mut normalized = serde_json::Map::new();

    if let Some(soulseek) = json_object_field_ci(object, "soulseek") {
        let soulseek = soulseek
            .as_object()
            .ok_or_else(|| "Invalid options overlay".to_owned())?;
        let mut normalized_soulseek = serde_json::Map::new();
        if let Some(address) = json_object_field_ci(soulseek, "listenIpAddress") {
            let address = address
                .as_str()
                .filter(|value| value.parse::<IpAddr>().is_ok())
                .ok_or_else(|| "Invalid options overlay".to_owned())?;
            normalized_soulseek.insert(
                "listenIpAddress".to_owned(),
                serde_json::Value::String(address.to_owned()),
            );
        }
        if let Some(port) = json_object_field_ci(soulseek, "listenPort") {
            let port = port
                .as_u64()
                .filter(|port| (1024..=65535).contains(port))
                .ok_or_else(|| "Invalid options overlay".to_owned())?;
            normalized_soulseek.insert("listenPort".to_owned(), serde_json::json!(port));
        }
        if target == ControllerCompatibilityTarget::Slskdn {
            if let Some(auto_response) =
                json_object_field_ci(soulseek, "privateMessageAutoResponse")
            {
                let auto_response = auto_response
                    .as_object()
                    .ok_or_else(|| "Invalid options overlay".to_owned())?;
                if let Some(enabled) = json_object_field_ci(auto_response, "enabled") {
                    let enabled = enabled
                        .as_bool()
                        .ok_or_else(|| "Invalid options overlay".to_owned())?;
                    normalized_soulseek.insert(
                        "privateMessageAutoResponse".to_owned(),
                        serde_json::json!({"enabled": enabled}),
                    );
                }
            }
        }
        if !normalized_soulseek.is_empty() {
            normalized.insert(
                "soulseek".to_owned(),
                serde_json::Value::Object(normalized_soulseek),
            );
        }
    }

    if target == ControllerCompatibilityTarget::Slskdn {
        if let Some(integration) = json_object_field_ci(object, "integration") {
            if !integration.is_object() {
                return Err("Invalid options overlay".to_owned());
            }
            normalized.insert(
                "integration".to_owned(),
                controller_yaml_api_projection(integration.clone()),
            );
        }
    }
    Ok(serde_json::Value::Object(normalized))
}

async fn apply_controller_options_overlay(body: &str, state: &AppState) -> HttpResponse {
    let overlay = match normalize_controller_options_overlay(
        body,
        state.config.controller_compatibility_target,
    ) {
        Ok(overlay) => overlay,
        Err(error) => return routing::bad_request_response(&error),
    };
    let listen_changed = overlay
        .get("soulseek")
        .and_then(serde_json::Value::as_object)
        .is_some_and(|soulseek| {
            soulseek.contains_key("listenIpAddress") || soulseek.contains_key("listenPort")
        });
    if let Some(enabled) = overlay
        .pointer("/soulseek/privateMessageAutoResponse/enabled")
        .and_then(serde_json::Value::as_bool)
    {
        state
            .private_message_auto_response_settings
            .write()
            .await
            .enabled = enabled;
        if !enabled {
            *state.private_message_auto_responses.write().await =
                PrivateMessageAutoResponseTracker::default();
        }
    }
    state.options_overlay.write().await.apply(overlay.clone());
    if listen_changed
        && state.config.controller_compatibility_target == ControllerCompatibilityTarget::Slskdn
        && state.session.read().await.state == "connected"
    {
        state.runtime.write().await.set_reconnect_pending(true);
    }
    record_event(
        state,
        "options.updated",
        "options",
        Some("volatile=true".to_owned()),
    )
    .await;
    HttpResponse {
        status: "200 OK",
        content_type: "application/json; charset=utf-8",
        body: overlay.to_string(),
    }
}

fn slskd_options_mutation_response(
    body: &str,
    acknowledgements: u64,
    acknowledgement_persistence_enabled: bool,
) -> Result<String, String> {
    let payload = serde_json::from_str::<serde_json::Value>(body)
        .map_err(|error| format!("invalid options JSON: {error}"))?;
    let Some(object) = payload.as_object() else {
        return Err("options payload must be a JSON object".to_owned());
    };
    let accepted_keys = object.keys().cloned().collect::<Vec<_>>();
    Ok(serde_json::json!({
        "status": "accepted",
        "persisted": acknowledgement_persistence_enabled,
        "configPersisted": false,
        "restart_required": false,
        "runtimeMutationEnabled": false,
        "acceptedKeys": accepted_keys,
        "acknowledgements": acknowledgements,
        "note": "runtime option mutation is not enabled",
        "message": if acknowledgement_persistence_enabled {
            "persisted compatibility acknowledgement"
        } else {
            "non-persisted compatibility acknowledgement"
        },
        "compatibility": {
            "surface": "slskd-options",
            "mutationPersistence": if acknowledgement_persistence_enabled {
                "runtime_compat_state"
            } else {
                "none"
            },
        },
    })
    .to_string())
}

fn slskd_server_state_json(
    session: &SessionSnapshot,
    config: &AppConfig,
    runtime_credentials_configured: bool,
    connected_endpoint: Option<&str>,
) -> serde_json::Value {
    let connected = session.state == "connected";
    let state = match session.state {
        "connected" => "Connected, LoggedIn",
        "connecting" => "Connecting",
        "disconnecting" => "Disconnecting",
        "error" => "Error",
        _ => "Disconnected",
    };
    let config_credentials_configured = config.credentials().is_some();
    let credential_source = if runtime_credentials_configured {
        "runtime"
    } else if config_credentials_configured {
        "config"
    } else {
        "none"
    };
    let connected_endpoint = connected.then_some(connected_endpoint).flatten();
    let connected_address = connected_endpoint.and_then(|endpoint| {
        endpoint
            .rsplit_once(':')
            .map(|(address, _)| address.trim_matches(['[', ']']))
    });
    let mut response = serde_json::json!({
        "credentialsConfigured": runtime_credentials_configured || config_credentials_configured,
        "credentialSource": credential_source,
        "credentialStore": config.credential_store.as_str(),
        "credentialStoreModes": credential_store::supported_store_modes(),
        "writableCredentialStoreModes": credential_store::writable_store_modes(),
        "state": state,
        "isConnected": connected,
        "isConnecting": session.state == "connecting",
        "isDisconnecting": session.state == "disconnecting",
        "isLoggedIn": connected,
        "isLoggingIn": session.state == "connecting",
        "isTransitioning": session.state == "connecting" || session.state == "disconnecting",
        "lastError": public_session_error(session.last_error.as_deref()),
        "runtimeCredentialsConfigured": runtime_credentials_configured,
    });
    let object = response
        .as_object_mut()
        .expect("server compatibility response must be an object");
    if connected {
        object.insert("address".to_owned(), serde_json::json!(connected_address));
        object.insert(
            "ipEndPoint".to_owned(),
            serde_json::json!(connected_endpoint),
        );
    } else if config.controller_compatibility_target == ControllerCompatibilityTarget::Slskdn {
        object.insert("address".to_owned(), serde_json::json!(""));
        object.insert(
            "ipEndPoint".to_owned(),
            serde_json::json!("255.255.255.255:0"),
        );
    }
    response
}

#[expect(
    clippy::too_many_arguments,
    reason = "application state intentionally aggregates independent runtime stores"
)]
fn slskd_application_state_json(
    session: &SessionSnapshot,
    share_lifecycle: &ShareLifecycleState,
    rooms: &RoomStore,
    users: &UserStore,
    relay: &RelayState,
    runtime: &RuntimeCompatState,
    distributed_network: &DistributedRuntime,
    distributed_settings: crate::config::SoulseekDistributedSettings,
    config: &AppConfig,
    runtime_credentials_configured: bool,
    connected_endpoint: Option<&str>,
    version: serde_json::Value,
) -> String {
    let mut vpn = serde_json::json!({
        "isReady": runtime.vpn.is_ready,
        "isConnected": runtime.vpn.is_connected,
        "publicIPAddress": runtime.vpn.public_ip_address.map(|value| value.to_string()),
        "location": runtime.vpn.location,
        "forwardedPort": runtime.vpn.forwarded_port,
    });
    if config.controller_compatibility_target == ControllerCompatibilityTarget::Slskdn {
        vpn["portForwards"] = serde_json::Value::Array(
            runtime
                .vpn
                .port_forwards
                .iter()
                .map(vpn::PortForward::json)
                .collect(),
        );
    }
    serde_json::json!({
        "version": version,
        "pendingReconnect": runtime.application_reconnect_pending,
        "pendingRestart": runtime.application_restart_requested,
        "server": slskd_server_state_json(
            session,
            config,
            runtime_credentials_configured,
            connected_endpoint,
        ),
        "connectionWatchdog": {
            "enabled": config.reconnect,
            "reconnectDelaySeconds": config.reconnect_delay.as_secs(),
        },
        "vpn": vpn,
        "health": {
            "search": {"incoming": {"latency": 0, "queueDepth": 0, "dropRate": 0}},
        },
        "relay": {
            "enabled": relay.enabled,
            "agentEnabled": runtime.relay_agent_enabled,
            "updated_at": relay.updated_at,
        },
        "bridge": {
            "enabled": config.integrations.bridge.enabled,
            "running": runtime.bridge_running,
            "configUpdates": runtime.bridge_config_updates,
            "host": null,
            "port": null,
            "endpointConfigured": config.integrations.bridge.endpoint_configured(),
        },
        "operations": {
            "profileInvitesCreated": runtime.profile_invites_created,
            "cacheWarmRuns": runtime.cache_warm_runs,
            "backfillRuns": runtime.backfill_runs,
            "songidRuns": runtime.songid_runs,
            "lidarrSyncRuns": runtime.lidarr_sync_runs,
            "lidarrManualImports": runtime.lidarr_manual_imports,
        },
        "runtime": runtime.json_value(),
        "user": {
            "username": session.username,
            "privilegesSeconds": session.privileges_seconds,
        },
        "distributedNetwork": distributed_network.application_json(
            distributed_settings,
            session.state == "connected",
            config.controller_compatibility_target,
        ),
        "shares": share_lifecycle.json(config.controller_compatibility_target),
        "rooms": rooms.records.iter().map(|room| room.name.clone()).collect::<Vec<_>>(),
        "users": users.records.iter().map(|user| user.username.clone()).collect::<Vec<_>>(),
    })
    .to_string()
}

fn capabilities_response() -> HttpResponse {
    let capability_json = serde_json::json!({
        "client": "slskr",
        "version": APP_VERSION,
        "features": ["dht", "hash_exchange", "mesh_sync", "flac_hash_db", "swarm_download", "partial_download"],
        "protocol_version": 1,
        "capabilities": 63,
        "mesh_seq_id": 0,
    });
    HttpResponse {
        status: "200 OK",
        content_type: "application/json",
        body: serde_json::json!({
            "version": format!("slskr/{APP_VERSION}+dht+mesh+swarm"),
            "impl": "slskr",
            "compat": "slskdn-v1",
            "features": capability_json["features"].clone(),
            "obfuscation": {"type1": true, "mode": "compatibility"},
            "feature": {"dht": true, "mesh": true, "swarm": true},
            "tag": "slskr_caps:v1;dht=1;mesh=1;swarm=1;hashx=1;flacdb=1",
            "json": serde_json::to_string_pretty(&capability_json).unwrap_or_else(|_| "{}".to_owned()),
            "api_version": "v0",
            "client_version": APP_VERSION,
            "supports": ["login","peers","shares","searches","transfers","users","messages","rooms","room-list-sync","browser-session-auth"],
        }).to_string(),
    }
}

async fn network_stats_value(state: &AppState, include_peers: bool) -> serde_json::Value {
    let searches = state.searches.read().await;
    let search_count = searches.records.len();
    let search_result_count = searches
        .records
        .iter()
        .map(|record| record.results.len())
        .sum::<usize>();
    drop(searches);

    let shares = state.shares.read().await;
    let shared_file_count = shares.entries.len();
    let shared_bytes = shares.entries.iter().map(|entry| entry.size).sum::<u64>();
    drop(shares);

    let events = state.events.read().await;
    let completed_backfills = events
        .records
        .iter()
        .filter(|event| event.kind.contains("backfill") || event.kind.contains("hashdb"))
        .count();
    drop(events);

    let users = state.users.read().await;
    let mesh = state.mesh.read().await;
    let candidate_usernames = mesh.candidate_usernames(&users);
    let discovered_peers = if include_peers {
        mesh.capability_records_json()
    } else {
        Vec::new()
    };
    let mesh_peers = if include_peers {
        candidate_usernames
            .iter()
            .map(|username| {
                serde_json::json!({
                    "username": username,
                    "meshCapable": mesh.capability_records.iter().any(|descriptor| {
                        descriptor.username.eq_ignore_ascii_case(username)
                            && MeshRendezvous::accepts_descriptor(descriptor)
                    }),
                })
            })
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let capability_record_count = mesh.capability_records.len();
    drop(mesh);
    drop(users);

    let transfers = state.transfers.read().await;
    let swarm_jobs = transfers
        .entries
        .iter()
        .filter(|entry| entry.status == "in_progress")
        .map(|entry| {
            let total_bytes = entry.size.unwrap_or_default();
            let progress_percent = if total_bytes == 0 {
                0.0
            } else {
                entry.bytes_transferred as f64 * 100.0 / total_bytes as f64
            };
            serde_json::json!({
                "activeSources": usize::from(entry.peer_username.is_some()),
                "downloadedBytes": entry.bytes_transferred,
                "filename": entry.filename,
                "jobId": format!("transfer-{}", entry.id),
                "progressPercent": progress_percent,
                "totalBytes": total_bytes,
            })
        })
        .collect::<Vec<_>>();
    drop(transfers);

    let queued_backfills = search_count + search_result_count + shared_file_count;
    let now = unix_timestamp();
    serde_json::json!({
        "backfill": {
            "isActive": queued_backfills > 0,
            "isRunning": false,
            "queued": queued_backfills,
            "completed": completed_backfills,
            "searches": search_count,
            "searchResults": search_result_count,
            "sharedFiles": shared_file_count,
        },
        "capabilitiesJson": capabilities_response().body,
        "capabilitiesVersion": APP_VERSION,
        "dht": {
            "dhtNodeCount": 0,
            "isLanOnly": false,
            "lanOnly": false,
            "isBeaconCapable": false,
            "isDhtRunning": false,
            "verifiedBeaconCount": 0,
        },
        "discoveredPeers": discovered_peers,
        "hashDb": {
            "currentSeqId": now,
            "totalHashEntries": shared_file_count,
            "totalEntries": shared_file_count,
            "totalBytes": shared_bytes,
        },
        "mesh": {
            "currentSeqId": now,
            "localSeqId": now,
            "isSyncing": false,
            "knownMeshPeers": candidate_usernames.len(),
            "connectedPeerCount": 0,
            "capabilityRecords": capability_record_count,
            "interestTag": MESH_RENDEZVOUS_INTEREST_TAG,
            "warnings": [],
        },
        "meshPeers": mesh_peers,
        "swarmJobs": swarm_jobs,
        "transport": {
            "status": "Healthy",
            "health": "Healthy",
            "description": "Mesh transport unavailable in this runtime",
            "transportPreference": "Auto",
            "connectedPeers": 0,
            "totalPeers": 0,
            "activeCircuits": 0,
            "activeStreams": 0,
            "bootstrapPeers": [],
            "isolatedPeers": 0,
            "quorumPeers": 0,
            "relayedPeers": 0,
            "natType": "Unknown",
            "publicEndpoint": null,
            "lastDhtError": null,
            "lastDhtPublishUtc": null,
        },
    })
}

fn capabilities_negotiate_response(body: &str) -> HttpResponse {
    let server_capabilities = ["shares", "telemetry"];

    // Parse requested capabilities from body
    let requested = extract_json_string_array_field(body, "capabilities").unwrap_or_default();

    // Compute intersection
    let mut accepted = Vec::new();
    let mut unsupported = Vec::new();

    for req_cap in requested {
        if server_capabilities.contains(&req_cap.as_str()) {
            accepted.push(req_cap);
        } else {
            unsupported.push(req_cap);
        }
    }

    let response_body = serde_json::json!({
        "accepted": accepted,
        "unsupported": unsupported,
        "server_capabilities": server_capabilities,
    })
    .to_string();

    HttpResponse {
        status: "200 OK",
        content_type: "application/json",
        body: response_body,
    }
}

fn url_encode(value: &str) -> String {
    let mut encoded = String::new();
    for byte in value.bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                encoded.push(byte as char);
            }
            _ => encoded.push_str(&format!("%{byte:02X}")),
        }
    }
    encoded
}

fn secure_oauth_state() -> Option<String> {
    secure_oauth_state_with(|bytes| SysRng.try_fill_bytes(bytes).is_ok())
}

fn secure_oauth_state_with(fill: impl FnOnce(&mut [u8; 32]) -> bool) -> Option<String> {
    let mut bytes = [0_u8; 32];
    fill(&mut bytes).then(|| format!("slskr-{}", hex::encode(bytes)))
}

fn secure_spotify_code_verifier() -> Option<String> {
    const ALPHABET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~";
    let mut bytes = [0_u8; 64];
    SysRng.try_fill_bytes(&mut bytes).ok()?;
    Some(
        bytes
            .into_iter()
            .map(|byte| char::from(ALPHABET[usize::from(byte) % ALPHABET.len()]))
            .collect(),
    )
}

fn secure_share_grant_token() -> Option<String> {
    secure_share_grant_token_with(|bytes| SysRng.try_fill_bytes(bytes).is_ok())
}

fn secure_share_grant_token_with(fill: impl FnOnce(&mut [u8; 32]) -> bool) -> Option<String> {
    let mut bytes = [0_u8; 32];
    fill(&mut bytes).then(|| format!("share-{}", hex::encode(bytes)))
}

fn request_share_token(
    authorization: Option<&str>,
    headers: &RequestSecurityHeaders,
) -> Option<String> {
    if let Some(token) = headers
        .x_share_token
        .as_deref()
        .map(str::trim)
        .filter(|token| !token.is_empty())
    {
        return Some(token.to_owned());
    }

    let authorization = authorization?.trim();
    let (scheme, value) = authorization.split_once(' ')?;
    if !scheme.eq_ignore_ascii_case("bearer") {
        return None;
    }
    let (prefix, token) = value.trim().split_once(':')?;
    let token = token.trim();
    (prefix.eq_ignore_ascii_case("share") && !token.is_empty()).then(|| token.to_owned())
}

fn query_parameter(query: Option<&str>, name: &str) -> Option<String> {
    query?.split('&').find_map(|pair| {
        let (key, value) = pair.split_once('=').unwrap_or((pair, ""));
        percent_decode_component(key)
            .eq_ignore_ascii_case(name)
            .then(|| percent_decode_component(value))
    })
}

fn webhook_from_persisted(record: crate::persistence::WebhookRecord) -> Option<webhooks::Webhook> {
    let events = record
        .events
        .split(',')
        .filter_map(webhooks::WebhookEvent::from_wire)
        .collect::<Vec<_>>();
    if events.is_empty() {
        return None;
    }
    Some(webhooks::Webhook {
        id: record.id,
        url: record.url,
        events,
        secret: record.secret,
        active: record.active,
        created_at: record.created_at,
        last_triggered: record.last_triggered,
        retry_count: u32::try_from(record.retry_count).unwrap_or(0),
        max_retries: u32::try_from(record.max_retries).unwrap_or(3),
        timeout_seconds: u32::try_from(record.timeout_seconds).unwrap_or(30),
    })
}

fn webhook_persistence_record(webhook: &webhooks::Webhook) -> crate::persistence::WebhookRecord {
    crate::persistence::WebhookRecord {
        id: webhook.id.clone(),
        url: webhook.url.clone(),
        events: webhook
            .events
            .iter()
            .map(ToString::to_string)
            .collect::<Vec<_>>()
            .join(","),
        secret: webhook.secret.clone(),
        active: webhook.active,
        created_at: webhook.created_at,
        last_triggered: webhook.last_triggered,
        retry_count: i32::try_from(webhook.retry_count).unwrap_or(i32::MAX),
        max_retries: i32::try_from(webhook.max_retries).unwrap_or(i32::MAX),
        timeout_seconds: i32::try_from(webhook.timeout_seconds).unwrap_or(i32::MAX),
    }
}

fn spotify_redirect_uri(state: &AppState, spotify: &config::SpotifyIntegrationSettings) -> String {
    spotify.redirect_uri.clone().unwrap_or_else(|| {
        let host = if state.config.http_bind.ip().is_unspecified() {
            format!("127.0.0.1:{}", state.config.http_bind.port())
        } else {
            state.config.http_bind.to_string()
        };
        format!("http://{host}/api/v0/integrations/spotify/callback")
    })
}

const SPOTIFY_CONNECTION_AAD: &[u8] = b"slskr.source-feeds.spotify-token-store.v1";

fn spotify_connection_path(state_dir: &Path) -> PathBuf {
    state_dir
        .join("source-feeds")
        .join("spotify-connection.json")
}

fn spotify_connection_key(signing_key: &SigningKey) -> [u8; 32] {
    let mut digest = Sha256::new();
    digest.update(SPOTIFY_CONNECTION_AAD);
    digest.update(signing_key.to_bytes());
    digest.finalize().into()
}

fn load_spotify_connection_store(
    state_dir: &Path,
    signing_key: &SigningKey,
) -> SpotifyConnectionStore {
    use std::io::Read as _;

    let path = spotify_connection_path(state_dir);
    let Ok(metadata) = fs::symlink_metadata(&path) else {
        return SpotifyConnectionStore::default();
    };
    if metadata.file_type().is_symlink() || !metadata.is_file() || metadata.len() > 1024 * 1024 {
        return SpotifyConnectionStore::default();
    }
    let mut options = fs::OpenOptions::new();
    options.read(true);
    #[cfg(unix)]
    {
        use std::os::unix::fs::OpenOptionsExt;
        options.custom_flags(libc::O_CLOEXEC | libc::O_NOFOLLOW | libc::O_NONBLOCK);
    }
    let Ok(mut file) = options.open(path) else {
        return SpotifyConnectionStore::default();
    };
    let Ok(opened) = file.metadata() else {
        return SpotifyConnectionStore::default();
    };
    if !opened.is_file() || opened.len() > 1024 * 1024 {
        return SpotifyConnectionStore::default();
    }
    let mut encoded = String::new();
    if std::io::Read::take(&mut file, 1024 * 1024 + 1)
        .read_to_string(&mut encoded)
        .is_err()
        || encoded.len() > 1024 * 1024
    {
        return SpotifyConnectionStore::default();
    }
    let Ok(envelope) = serde_json::from_str::<ProtectedSpotifyConnection>(&encoded) else {
        return SpotifyConnectionStore::default();
    };
    if envelope.version != 1 {
        return SpotifyConnectionStore::default();
    }
    let Ok(nonce) = URL_SAFE_NO_PAD.decode(envelope.nonce) else {
        return SpotifyConnectionStore::default();
    };
    let Ok(nonce): Result<[u8; 12], _> = nonce.try_into() else {
        return SpotifyConnectionStore::default();
    };
    let Ok(mut ciphertext) = URL_SAFE_NO_PAD.decode(envelope.ciphertext) else {
        return SpotifyConnectionStore::default();
    };
    let Ok(unbound) = ring::aead::UnboundKey::new(
        &ring::aead::AES_256_GCM,
        &spotify_connection_key(signing_key),
    ) else {
        return SpotifyConnectionStore::default();
    };
    let key = ring::aead::LessSafeKey::new(unbound);
    let Ok(plaintext) = key.open_in_place(
        ring::aead::Nonce::assume_unique_for_key(nonce),
        ring::aead::Aad::from(SPOTIFY_CONNECTION_AAD),
        &mut ciphertext,
    ) else {
        return SpotifyConnectionStore::default();
    };
    serde_json::from_slice(plaintext).unwrap_or_default()
}

fn persist_spotify_connection_store(
    state: &AppState,
    store: &SpotifyConnectionStore,
) -> Result<(), String> {
    let path = spotify_connection_path(&state.config.state_dir);
    let directory = path.parent().expect("Spotify connection path has a parent");
    ensure_private_storage_dir(directory, "Spotify connection state")?;
    let mut nonce = [0_u8; 12];
    SysRng
        .try_fill_bytes(&mut nonce)
        .map_err(|_| "secure randomness unavailable for Spotify connection state".to_owned())?;
    let unbound = ring::aead::UnboundKey::new(
        &ring::aead::AES_256_GCM,
        &spotify_connection_key(&state.capability_signing_key),
    )
    .map_err(|_| "Spotify connection encryption key is invalid".to_owned())?;
    let key = ring::aead::LessSafeKey::new(unbound);
    let mut ciphertext = serde_json::to_vec(store)
        .map_err(|error| format!("Spotify connection encode failed: {error}"))?;
    key.seal_in_place_append_tag(
        ring::aead::Nonce::assume_unique_for_key(nonce),
        ring::aead::Aad::from(SPOTIFY_CONNECTION_AAD),
        &mut ciphertext,
    )
    .map_err(|_| "Spotify connection encryption failed".to_owned())?;
    let envelope = ProtectedSpotifyConnection {
        version: 1,
        nonce: URL_SAFE_NO_PAD.encode(nonce),
        ciphertext: URL_SAFE_NO_PAD.encode(ciphertext),
    };
    let body = serde_json::to_vec(&envelope)
        .map_err(|error| format!("Spotify connection envelope encode failed: {error}"))?;
    write_file_atomic(&path, body)
        .map_err(|error| format!("Spotify connection persistence failed: {error}"))?;
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        fs::set_permissions(&path, fs::Permissions::from_mode(0o600))
            .map_err(|error| format!("Spotify connection permissions failed: {error}"))?;
    }
    Ok(())
}

fn delete_spotify_connection_store(state: &AppState) -> Result<(), String> {
    let path = spotify_connection_path(&state.config.state_dir);
    match fs::remove_file(path) {
        Ok(()) => Ok(()),
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(()),
        Err(error) => Err(format!("Spotify connection delete failed: {error}")),
    }
}

async fn spotify_token_request(
    spotify: &config::SpotifyIntegrationSettings,
    token_url: &str,
    form: &[(&str, String)],
) -> Result<serde_json::Value, String> {
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(spotify.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Spotify client: {error}"))?
        .post(token_url)
        .form(form)
        .send()
        .await
        .map_err(|error| format!("Spotify token request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Spotify returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Spotify token").await
}

async fn spotify_profile_request(
    spotify: &config::SpotifyIntegrationSettings,
    profile_url: &str,
    access_token: &str,
) -> Result<serde_json::Value, String> {
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(spotify.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Spotify client: {error}"))?
        .get(profile_url)
        .bearer_auth(access_token)
        .send()
        .await
        .map_err(|error| format!("Spotify profile request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Spotify returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Spotify profile").await
}

async fn complete_spotify_authorization(
    state: &AppState,
    spotify: &config::SpotifyIntegrationSettings,
    pending: &OAuthStateRecord,
    code: &str,
    token_url: &str,
    profile_url: &str,
) -> Result<serde_json::Value, String> {
    let client_id = spotify.client_id.as_deref().unwrap_or_default();
    let verifier = pending
        .code_verifier
        .as_deref()
        .ok_or_else(|| "Spotify authorization state is invalid or expired".to_owned())?;
    let token = spotify_token_request(
        spotify,
        token_url,
        &[
            ("client_id", client_id.to_owned()),
            ("grant_type", "authorization_code".to_owned()),
            ("code", code.to_owned()),
            ("redirect_uri", pending.redirect_uri.clone()),
            ("code_verifier", verifier.to_owned()),
        ],
    )
    .await?;
    let access_token = token
        .get("access_token")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default();
    let refresh_token = token
        .get("refresh_token")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default();
    if access_token.trim().is_empty() || refresh_token.trim().is_empty() {
        return Err("Spotify token response was incomplete".to_owned());
    }
    let profile = spotify_profile_request(spotify, profile_url, access_token).await?;
    let expires_in = token
        .get("expires_in")
        .and_then(serde_json::Value::as_i64)
        .unwrap_or_default();
    let store = SpotifyConnectionStore {
        access_token: access_token.to_owned(),
        refresh_token: refresh_token.to_owned(),
        scope: token
            .get("scope")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_owned(),
        expires_at: i64::try_from(unix_timestamp())
            .unwrap_or(i64::MAX)
            .saturating_add(expires_in.saturating_sub(30).max(30)),
        display_name: profile
            .get("display_name")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_owned(),
        spotify_user_id: profile
            .get("id")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_owned(),
    };
    persist_spotify_connection_store(state, &store)?;
    let status = store.status_json(spotify.configured());
    *state.spotify_connection.write().await = store;
    Ok(status)
}

fn normalize_spotify_source_target(kind: &str, id: &str) -> SpotifySourceTarget {
    let kind = match kind.trim().to_ascii_lowercase().as_str() {
        "collection" | "liked" | "saved-tracks" => "saved-tracks",
        "saved-albums" => "saved-albums",
        "followed-artists" => "followed-artists",
        "playlists" => "playlists",
        other => other,
    }
    .to_owned();
    let (requires_user_token, scope_hint) = match kind.as_str() {
        "saved-tracks" | "saved-albums" => (true, "user-library-read"),
        "followed-artists" => (true, "user-follow-read"),
        "playlists" => (true, "playlist-read-private playlist-read-collaborative"),
        _ => (false, ""),
    };
    SpotifySourceTarget {
        kind,
        id: id.trim().to_owned(),
        requires_user_token,
        scope_hint: scope_hint.to_owned(),
    }
}

fn parse_spotify_source_target(source_text: &str) -> SpotifySourceTarget {
    let trimmed = source_text.trim();
    let lower = trimmed.to_ascii_lowercase();
    if lower.starts_with("spotify:") {
        let mut parts = trimmed.split(':');
        let _ = parts.next();
        let kind = parts.next().unwrap_or_default();
        let id = parts.next().unwrap_or_default();
        return normalize_spotify_source_target(kind, id);
    }
    if let Ok(url) = reqwest::Url::parse(trimmed) {
        if url
            .host_str()
            .is_some_and(|host| host.eq_ignore_ascii_case("open.spotify.com"))
        {
            let parts = url
                .path_segments()
                .map(|segments| segments.filter(|part| !part.is_empty()).collect::<Vec<_>>())
                .unwrap_or_default();
            let kind = parts.first().copied().unwrap_or_default();
            let id = parts.get(1).copied().unwrap_or_default();
            if kind.eq_ignore_ascii_case("collection") {
                let path = url.path().to_ascii_lowercase();
                return if path.contains("albums") {
                    normalize_spotify_source_target("saved-albums", "")
                } else if path.contains("following") || path.contains("artists") {
                    normalize_spotify_source_target("followed-artists", "")
                } else {
                    normalize_spotify_source_target("saved-tracks", "")
                };
            }
            return normalize_spotify_source_target(kind, id);
        }
    }
    normalize_spotify_source_target(&lower, "")
}

fn looks_like_spotify_source(source_text: &str, source_kind: &str) -> bool {
    source_kind.eq_ignore_ascii_case("spotify")
        || source_text
            .trim_start()
            .to_ascii_lowercase()
            .starts_with("spotify:")
        || reqwest::Url::parse(source_text.trim()).is_ok_and(|url| {
            url.host_str()
                .is_some_and(|host| host.eq_ignore_ascii_case("open.spotify.com"))
        })
}

async fn refresh_spotify_user_access_token(
    state: &AppState,
    spotify: &config::SpotifyIntegrationSettings,
    token_url: &str,
) -> Result<String, String> {
    let _permit = state
        .spotify_token_gate
        .acquire()
        .await
        .map_err(|_| "Spotify token gate is unavailable".to_owned())?;
    let current = state.spotify_connection.read().await.clone();
    let now = i64::try_from(unix_timestamp()).unwrap_or(i64::MAX);
    if !current.access_token.trim().is_empty() && current.expires_at > now.saturating_add(60) {
        return Ok(current.access_token);
    }
    if current.refresh_token.trim().is_empty() {
        return Ok(String::new());
    }
    let token = spotify_token_request(
        spotify,
        token_url,
        &[
            (
                "client_id",
                spotify.client_id.as_deref().unwrap_or_default().to_owned(),
            ),
            ("grant_type", "refresh_token".to_owned()),
            ("refresh_token", current.refresh_token.clone()),
        ],
    )
    .await?;
    let access_token = token
        .get("access_token")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default()
        .trim();
    if access_token.is_empty() {
        return Err("Spotify refresh response was incomplete".to_owned());
    }
    let expires_in = token
        .get("expires_in")
        .and_then(serde_json::Value::as_i64)
        .unwrap_or_default();
    let mut refreshed = current;
    refreshed.access_token = access_token.to_owned();
    if let Some(value) = token
        .get("refresh_token")
        .and_then(serde_json::Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        refreshed.refresh_token = value.to_owned();
    }
    if let Some(value) = token
        .get("scope")
        .and_then(serde_json::Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        refreshed.scope = value.to_owned();
    }
    refreshed.expires_at = now.saturating_add(expires_in.saturating_sub(30).max(30));
    persist_spotify_connection_store(state, &refreshed)?;
    *state.spotify_connection.write().await = refreshed;
    Ok(access_token.to_owned())
}

async fn spotify_app_access_token(
    spotify: &config::SpotifyIntegrationSettings,
    token_url: &str,
) -> Result<String, String> {
    let client_id = spotify.client_id.as_deref().unwrap_or_default().trim();
    let client_secret = spotify.client_secret.as_deref().unwrap_or_default().trim();
    if !spotify.enabled || client_id.is_empty() || client_secret.is_empty() {
        return Ok(String::new());
    }
    use base64::Engine as _;
    let credentials =
        base64::engine::general_purpose::STANDARD.encode(format!("{client_id}:{client_secret}"));
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(spotify.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Spotify client: {error}"))?
        .post(token_url)
        .header("Authorization", format!("Basic {credentials}"))
        .form(&[("grant_type", "client_credentials")])
        .send()
        .await
        .map_err(|error| format!("Spotify token request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Spotify returned HTTP {}", response.status()));
    }
    let token = read_bounded_integration_json(response, "Spotify token").await?;
    Ok(token
        .get("access_token")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default()
        .to_owned())
}

async fn spotify_source_access_token(
    state: &AppState,
    spotify: &config::SpotifyIntegrationSettings,
    target: &SpotifySourceTarget,
    provided: &str,
    token_url: &str,
) -> Result<String, String> {
    if !provided.trim().is_empty() {
        return Ok(provided.trim().to_owned());
    }
    if target.requires_user_token {
        return refresh_spotify_user_access_token(state, spotify, token_url).await;
    }
    let app_token = spotify_app_access_token(spotify, token_url).await?;
    if !app_token.trim().is_empty() {
        return Ok(app_token);
    }
    refresh_spotify_user_access_token(state, spotify, token_url).await
}

async fn spotify_get_json(
    spotify: &config::SpotifyIntegrationSettings,
    url: String,
    token: &str,
) -> Result<serde_json::Value, String> {
    let token = token.trim();
    let token = token
        .get(..7)
        .filter(|prefix| prefix.eq_ignore_ascii_case("Bearer "))
        .map(|_| &token[7..])
        .unwrap_or(token)
        .trim();
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(spotify.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Spotify client: {error}"))?
        .get(url)
        .bearer_auth(token)
        .send()
        .await
        .map_err(|error| format!("Spotify API request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Spotify returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Spotify API").await
}

fn spotify_track_row(
    track: &serde_json::Value,
    source: &str,
    source_id: &str,
    album_override: Option<&str>,
) -> Option<SpotifySourceRow> {
    if !track.is_object() {
        return None;
    }
    let title = track
        .get("name")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default()
        .to_owned();
    let artist = track
        .get("artists")
        .and_then(serde_json::Value::as_array)
        .map(|artists| {
            artists
                .iter()
                .filter_map(|artist| artist.get("name").and_then(serde_json::Value::as_str))
                .filter(|name| !name.trim().is_empty())
                .collect::<Vec<_>>()
                .join(" ")
        })
        .unwrap_or_default();
    let album = album_override
        .map(str::to_owned)
        .or_else(|| {
            track
                .pointer("/album/name")
                .and_then(serde_json::Value::as_str)
                .map(str::to_owned)
        })
        .unwrap_or_default();
    Some(SpotifySourceRow {
        raw_text: title.clone(),
        title,
        artist,
        album,
        source: source.to_owned(),
        source_id: source_id.to_owned(),
        provider_url: track
            .pointer("/external_urls/spotify")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_owned(),
    })
}

fn spotify_page_done(page: &serde_json::Value, item_count: usize, offset: usize) -> bool {
    item_count == 0
        || page.get("next").is_none_or(serde_json::Value::is_null)
        || page
            .get("total")
            .and_then(serde_json::Value::as_u64)
            .is_some_and(|total| offset.saturating_add(item_count) >= total as usize)
}

async fn fetch_spotify_playlist_tracks(
    spotify: &config::SpotifyIntegrationSettings,
    api_base: &str,
    token: &str,
    playlist_id: &str,
    rows: &mut Vec<SpotifySourceRow>,
    limit: usize,
) -> Result<u64, String> {
    let mut requests = 0_u64;
    let mut offset = 0_usize;
    while rows.len() < limit {
        let page_limit = 50_usize.min(limit - rows.len());
        let page = spotify_get_json(
            spotify,
            format!(
                "{}/playlists/{}/items?limit={page_limit}&offset={offset}&additional_types=track",
                api_base.trim_end_matches('/'),
                url_encode(playlist_id)
            ),
            token,
        )
        .await?;
        requests += 1;
        let items = page
            .get("items")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default();
        for item in &items {
            if let Some(row) = spotify_track_row(
                item.get("track").unwrap_or(&serde_json::Value::Null),
                "spotify:playlist",
                playlist_id,
                None,
            ) {
                rows.push(row);
            }
        }
        if spotify_page_done(&page, items.len(), offset) {
            break;
        }
        offset = offset.saturating_add(items.len());
    }
    Ok(requests)
}

async fn fetch_spotify_track_pages(
    spotify: &config::SpotifyIntegrationSettings,
    api_base: &str,
    token: &str,
    path: &str,
    source: &str,
    rows: &mut Vec<SpotifySourceRow>,
    limit: usize,
) -> Result<u64, String> {
    let mut requests = 0_u64;
    let mut offset = 0_usize;
    while rows.len() < limit {
        let page_limit = 50_usize.min(limit - rows.len());
        let page = spotify_get_json(
            spotify,
            format!(
                "{}{path}?limit={page_limit}&offset={offset}",
                api_base.trim_end_matches('/')
            ),
            token,
        )
        .await?;
        requests += 1;
        let items = page
            .get("items")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default();
        for item in &items {
            let track = item.get("track").unwrap_or(&serde_json::Value::Null);
            let source_id = track
                .get("id")
                .and_then(serde_json::Value::as_str)
                .unwrap_or_default();
            if let Some(row) = spotify_track_row(track, source, source_id, None) {
                rows.push(row);
            }
        }
        if spotify_page_done(&page, items.len(), offset) {
            break;
        }
        offset = offset.saturating_add(items.len());
    }
    Ok(requests)
}

async fn fetch_spotify_playlist_collection(
    spotify: &config::SpotifyIntegrationSettings,
    api_base: &str,
    token: &str,
    path: &str,
    rows: &mut Vec<SpotifySourceRow>,
    limit: usize,
) -> Result<u64, String> {
    let mut requests = 0_u64;
    let mut offset = 0_usize;
    while rows.len() < limit {
        let page = spotify_get_json(
            spotify,
            format!(
                "{}{path}?limit=20&offset={offset}",
                api_base.trim_end_matches('/')
            ),
            token,
        )
        .await?;
        requests += 1;
        let items = page
            .get("items")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default();
        for playlist in &items {
            let playlist_id = playlist
                .get("id")
                .and_then(serde_json::Value::as_str)
                .unwrap_or_default();
            requests +=
                fetch_spotify_playlist_tracks(spotify, api_base, token, playlist_id, rows, limit)
                    .await?;
            if rows.len() >= limit {
                break;
            }
        }
        if spotify_page_done(&page, items.len(), offset) {
            break;
        }
        offset = offset.saturating_add(items.len());
    }
    Ok(requests)
}

fn build_spotify_source_result(
    target: &SpotifySourceTarget,
    rows: Vec<SpotifySourceRow>,
    network_request_count: u64,
) -> serde_json::Value {
    let mut seen = HashSet::new();
    let mut suggestions = Vec::new();
    let mut skipped_rows = Vec::new();
    let mut duplicate_count = 0_u64;
    let mut skipped_count = 0_u64;
    for (index, row) in rows.iter().enumerate() {
        let parts = [row.artist.trim(), row.title.trim(), row.album.trim()]
            .into_iter()
            .filter(|part| !part.is_empty())
            .collect::<Vec<_>>();
        let search_text = if parts.len() >= 2 || row.artist.trim().is_empty() {
            parts.join(" ")
        } else {
            String::new()
        };
        if search_text.is_empty() {
            skipped_count += 1;
            skipped_rows.push(serde_json::json!({
                "rowNumber": index + 1,
                "reason": "Missing artist/title metadata",
                "rawText": row.raw_text,
            }));
            continue;
        }
        let normalized = search_text
            .split_whitespace()
            .collect::<Vec<_>>()
            .join(" ")
            .to_ascii_lowercase();
        let evidence_key = format!("spotify:{}:{normalized}", row.source);
        if !seen.insert(evidence_key.clone()) {
            duplicate_count += 1;
            continue;
        }
        suggestions.push(serde_json::json!({
            "title": if row.title.trim().is_empty() { search_text.as_str() } else { row.title.as_str() },
            "artist": row.artist,
            "album": row.album,
            "searchText": search_text,
            "source": row.source,
            "sourceId": row.source_id,
            "sourceItemId": row.source_id,
            "providerUrl": row.provider_url,
            "evidenceKey": evidence_key,
            "reason": format!("Imported from spotify {}.", target.kind),
        }));
    }
    serde_json::json!({
        "provider": "spotify",
        "sourceKind": target.kind,
        "sourceId": target.id,
        "totalRows": rows.len(),
        "suggestionCount": suggestions.len(),
        "duplicateCount": duplicate_count,
        "skippedCount": skipped_count,
        "networkRequestCount": network_request_count,
        "requiresAccessToken": false,
        "requiredScopeHint": "",
        "suggestions": suggestions,
        "skippedRows": skipped_rows,
    })
}

async fn preview_spotify_source_feed(
    state: &AppState,
    source_text: &str,
    provider_access_token: &str,
    limit: usize,
    token_url: &str,
    api_base: &str,
) -> Result<serde_json::Value, String> {
    let target = parse_spotify_source_target(source_text);
    let spotify = state.integration_settings.read().await.spotify.clone();
    let token =
        spotify_source_access_token(state, &spotify, &target, provider_access_token, token_url)
            .await?;
    if token.trim().is_empty() {
        let scope = if target.requires_user_token {
            target.scope_hint.as_str()
        } else {
            "Configure integrations.spotify.client_id/client_secret, connect a Spotify account, or provide a Spotify bearer token."
        };
        return Ok(serde_json::json!({
            "provider": "spotify",
            "sourceKind": target.kind,
            "sourceId": target.id,
            "totalRows": 0,
            "suggestionCount": 0,
            "duplicateCount": 0,
            "skippedCount": 0,
            "networkRequestCount": 0,
            "requiresAccessToken": true,
            "requiredScopeHint": scope,
            "suggestions": [],
            "skippedRows": [],
        }));
    }

    let base = api_base.trim_end_matches('/');
    let mut rows = Vec::new();
    let mut requests = 0_u64;
    match target.kind.as_str() {
        "playlist" => {
            requests +=
                fetch_spotify_playlist_tracks(&spotify, base, &token, &target.id, &mut rows, limit)
                    .await?;
        }
        "album" => {
            let album = spotify_get_json(
                &spotify,
                format!("{base}/albums/{}", url_encode(&target.id)),
                &token,
            )
            .await?;
            requests += 1;
            let album_name = album
                .get("name")
                .and_then(serde_json::Value::as_str)
                .unwrap_or_default();
            for track in album
                .pointer("/tracks/items")
                .and_then(serde_json::Value::as_array)
                .into_iter()
                .flatten()
            {
                if let Some(row) =
                    spotify_track_row(track, "spotify:album", &target.id, Some(album_name))
                {
                    rows.push(row);
                }
            }
        }
        "track" => {
            let track = spotify_get_json(
                &spotify,
                format!("{base}/tracks/{}", url_encode(&target.id)),
                &token,
            )
            .await?;
            requests += 1;
            if let Some(row) = spotify_track_row(&track, "spotify:track", &target.id, None) {
                rows.push(row);
            }
        }
        "artist" => {
            let top = spotify_get_json(
                &spotify,
                format!(
                    "{base}/artists/{}/top-tracks?market={}",
                    url_encode(&target.id),
                    url_encode(&spotify.market)
                ),
                &token,
            )
            .await?;
            requests += 1;
            for track in top
                .get("tracks")
                .and_then(serde_json::Value::as_array)
                .into_iter()
                .flatten()
                .take(limit)
            {
                if let Some(row) =
                    spotify_track_row(track, "spotify:artist-top-tracks", &target.id, None)
                {
                    rows.push(row);
                }
            }
        }
        "saved-tracks" => {
            requests += fetch_spotify_track_pages(
                &spotify,
                base,
                &token,
                "/me/tracks",
                "spotify:liked",
                &mut rows,
                limit,
            )
            .await?;
        }
        "saved-albums" => {
            let mut offset = 0_usize;
            while rows.len() < limit {
                let page_limit = 20_usize.min(limit - rows.len());
                let page = spotify_get_json(
                    &spotify,
                    format!("{base}/me/albums?limit={page_limit}&offset={offset}"),
                    &token,
                )
                .await?;
                requests += 1;
                let items = page
                    .get("items")
                    .and_then(serde_json::Value::as_array)
                    .cloned()
                    .unwrap_or_default();
                for item in &items {
                    let album = item.get("album").unwrap_or(&serde_json::Value::Null);
                    let name = album
                        .get("name")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    let artist = album
                        .get("artists")
                        .and_then(serde_json::Value::as_array)
                        .map(|artists| {
                            artists
                                .iter()
                                .filter_map(|artist| {
                                    artist.get("name").and_then(serde_json::Value::as_str)
                                })
                                .collect::<Vec<_>>()
                                .join(" ")
                        })
                        .unwrap_or_default();
                    rows.push(SpotifySourceRow {
                        title: name.clone(),
                        artist,
                        album: name.clone(),
                        source: "spotify:saved-albums".to_owned(),
                        source_id: album
                            .get("id")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        provider_url: album
                            .pointer("/external_urls/spotify")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        raw_text: name,
                    });
                }
                if spotify_page_done(&page, items.len(), offset) {
                    break;
                }
                offset = offset.saturating_add(items.len());
            }
        }
        "followed-artists" => {
            let mut after = String::new();
            while rows.len() < limit {
                let page_limit = 50_usize.min(limit - rows.len());
                let after_query = if after.is_empty() {
                    String::new()
                } else {
                    format!("&after={}", url_encode(&after))
                };
                let page = spotify_get_json(
                    &spotify,
                    format!("{base}/me/following?type=artist&limit={page_limit}{after_query}"),
                    &token,
                )
                .await?;
                requests += 1;
                let artists = page
                    .pointer("/artists/items")
                    .and_then(serde_json::Value::as_array)
                    .cloned()
                    .unwrap_or_default();
                for artist in &artists {
                    let name = artist
                        .get("name")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    rows.push(SpotifySourceRow {
                        title: name.clone(),
                        artist: name.clone(),
                        album: String::new(),
                        source: "spotify:followed-artists".to_owned(),
                        source_id: artist
                            .get("id")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        provider_url: artist
                            .pointer("/external_urls/spotify")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        raw_text: name,
                    });
                }
                after = page
                    .pointer("/artists/cursors/after")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or_default()
                    .to_owned();
                if artists.is_empty() || after.is_empty() {
                    break;
                }
            }
        }
        "playlists" => {
            requests += fetch_spotify_playlist_collection(
                &spotify,
                base,
                &token,
                "/me/playlists",
                &mut rows,
                limit,
            )
            .await?;
        }
        "user" => {
            requests += fetch_spotify_playlist_collection(
                &spotify,
                base,
                &token,
                &format!("/users/{}/playlists", url_encode(&target.id)),
                &mut rows,
                limit,
            )
            .await?;
        }
        _ => {}
    }
    Ok(build_spotify_source_result(&target, rows, requests))
}

fn source_provider(source_text: &str, source_kind: &str) -> Option<&'static str> {
    let normalized = source_kind.replace('.', "").to_ascii_lowercase();
    if normalized != "auto" {
        return match normalized.as_str() {
            "youtube" => Some("youtube"),
            "lastfm" => Some("lastfm"),
            "apple" | "itunes" => Some("apple"),
            "listenbrainz" => Some("listenbrainz"),
            _ => None,
        };
    }
    let url = reqwest::Url::parse(source_text.trim()).ok()?;
    let host = url.host_str()?.to_ascii_lowercase();
    if host == "youtube.com" || host.ends_with(".youtube.com") || host == "youtu.be" {
        Some("youtube")
    } else if host == "last.fm" || host.ends_with(".last.fm") {
        Some("lastfm")
    } else if host == "music.apple.com" || host == "itunes.apple.com" {
        Some("apple")
    } else if host == "bandcamp.com" || host.ends_with(".bandcamp.com") {
        Some("bandcamp")
    } else if host == "listenbrainz.org" || host.ends_with(".listenbrainz.org") {
        Some("listenbrainz")
    } else {
        None
    }
}

fn loose_source_row(text: &str, source: &str, row_number: usize) -> SpotifySourceRow {
    let text = text.trim();
    let (artist, title) = text
        .split_once(" - ")
        .map(|(artist, title)| (artist.trim(), title.trim()))
        .unwrap_or(("", text));
    SpotifySourceRow {
        title: title.to_owned(),
        artist: artist.to_owned(),
        source: source.to_owned(),
        source_id: row_number.to_string(),
        raw_text: text.to_owned(),
        ..Default::default()
    }
}

fn build_provider_source_result(
    provider: &str,
    source_text: &str,
    rows: Vec<SpotifySourceRow>,
    network_request_count: u64,
) -> serde_json::Value {
    let mut result = build_spotify_source_result(
        &SpotifySourceTarget {
            kind: "url".to_owned(),
            id: source_text.to_owned(),
            requires_user_token: false,
            scope_hint: String::new(),
        },
        rows,
        network_request_count,
    );
    result["provider"] = serde_json::json!(provider);
    result["sourceKind"] = serde_json::json!("url");
    result["sourceId"] = serde_json::json!(source_text);
    if let Some(suggestions) = result["suggestions"].as_array_mut() {
        for suggestion in suggestions {
            let source = suggestion["source"].as_str().unwrap_or_default();
            let normalized = suggestion["searchText"]
                .as_str()
                .unwrap_or_default()
                .split_whitespace()
                .collect::<Vec<_>>()
                .join(" ")
                .to_ascii_lowercase();
            suggestion["evidenceKey"] =
                serde_json::json!(format!("{provider}:{source}:{normalized}"));
            suggestion["reason"] = serde_json::json!(format!("Imported from {provider} url."));
        }
    }
    result
}

async fn provider_get_json(
    timeout_seconds: u64,
    url: String,
    label: &str,
) -> Result<serde_json::Value, String> {
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build provider client: {error}"))?
        .get(url)
        .header("User-Agent", "slskdN-source-feed-import/1.0")
        .send()
        .await
        .map_err(|error| format!("{label} request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("{label} returned HTTP {}", response.status()));
    }
    read_bounded_source_provider_json(response, label).await
}

async fn read_bounded_source_provider_bytes(
    response: reqwest::Response,
    label: &str,
) -> Result<Vec<u8>, String> {
    if response
        .content_length()
        .is_some_and(|length| length > MAX_SOURCE_PROVIDER_RESPONSE_BYTES as u64)
    {
        return Err(format!(
            "{label} response exceeds {MAX_SOURCE_PROVIDER_RESPONSE_BYTES} bytes"
        ));
    }
    let mut body = Vec::new();
    let mut stream = response.bytes_stream();
    while let Some(chunk) = stream.next().await {
        let chunk = chunk.map_err(|error| format!("{label} response read failed: {error}"))?;
        if body.len().saturating_add(chunk.len()) > MAX_SOURCE_PROVIDER_RESPONSE_BYTES {
            return Err(format!(
                "{label} response exceeds {MAX_SOURCE_PROVIDER_RESPONSE_BYTES} bytes"
            ));
        }
        body.extend_from_slice(&chunk);
    }
    Ok(body)
}

async fn read_bounded_source_provider_json(
    response: reqwest::Response,
    label: &str,
) -> Result<serde_json::Value, String> {
    let body = read_bounded_source_provider_bytes(response, label).await?;
    serde_json::from_slice(&body).map_err(|error| format!("invalid {label} JSON: {error}"))
}

fn decode_markup_entities(value: &str) -> String {
    let mut decoded = String::with_capacity(value.len());
    let mut remaining = value;
    while let Some(ampersand) = remaining.find('&') {
        decoded.push_str(&remaining[..ampersand]);
        remaining = &remaining[ampersand..];
        let Some(semicolon) = remaining.find(';') else {
            decoded.push_str(remaining);
            return decoded.trim().to_owned();
        };
        let entity = &remaining[1..semicolon];
        let replacement = match entity {
            "amp" => Some('&'),
            "apos" => Some('\''),
            "gt" => Some('>'),
            "lt" => Some('<'),
            "quot" => Some('"'),
            _ if entity.starts_with("#x") || entity.starts_with("#X") => {
                u32::from_str_radix(&entity[2..], 16)
                    .ok()
                    .and_then(char::from_u32)
            }
            _ if entity.starts_with('#') => {
                entity[1..].parse::<u32>().ok().and_then(char::from_u32)
            }
            _ => None,
        };
        if let Some(replacement) = replacement {
            decoded.push(replacement);
        } else {
            decoded.push_str(&remaining[..=semicolon]);
        }
        remaining = &remaining[semicolon + 1..];
    }
    decoded.push_str(remaining);
    decoded.trim().to_owned()
}

fn markup_tag_attributes(tag: &str) -> Vec<(String, String)> {
    let bytes = tag.as_bytes();
    let mut index = 0_usize;
    while index < bytes.len() && !bytes[index].is_ascii_whitespace() {
        index += 1;
    }
    let mut attributes = Vec::new();
    while index < bytes.len() {
        while index < bytes.len()
            && (bytes[index].is_ascii_whitespace() || matches!(bytes[index], b'/' | b'>'))
        {
            index += 1;
        }
        let name_start = index;
        while index < bytes.len()
            && !bytes[index].is_ascii_whitespace()
            && !matches!(bytes[index], b'=' | b'/' | b'>')
        {
            index += 1;
        }
        if name_start == index {
            break;
        }
        let name = tag[name_start..index].to_owned();
        while index < bytes.len() && bytes[index].is_ascii_whitespace() {
            index += 1;
        }
        if bytes.get(index) != Some(&b'=') {
            attributes.push((name, String::new()));
            continue;
        }
        index += 1;
        while index < bytes.len() && bytes[index].is_ascii_whitespace() {
            index += 1;
        }
        let quote = bytes
            .get(index)
            .copied()
            .filter(|byte| matches!(byte, b'\'' | b'"'));
        if quote.is_some() {
            index += 1;
        }
        let value_start = index;
        while index < bytes.len()
            && quote.map_or_else(
                || !bytes[index].is_ascii_whitespace() && !matches!(bytes[index], b'/' | b'>'),
                |quote| bytes[index] != quote,
            )
        {
            index += 1;
        }
        attributes.push((name, decode_markup_entities(&tag[value_start..index])));
        if quote.is_some() && index < bytes.len() {
            index += 1;
        }
    }
    attributes
}

fn metadata_value(html: &str, property: &str) -> String {
    let lower = html.to_ascii_lowercase();
    let mut offset = 0_usize;
    while let Some(relative) = lower[offset..].find("<meta") {
        let start = offset + relative;
        let Some(end_relative) = lower[start..].find('>') else {
            break;
        };
        let end = start + end_relative + 1;
        let attributes = markup_tag_attributes(&html[start + 1..end - 1]);
        let matches_property = attributes.iter().any(|(name, value)| {
            (name.eq_ignore_ascii_case("property") || name.eq_ignore_ascii_case("name"))
                && value.eq_ignore_ascii_case(property)
        });
        if matches_property {
            if let Some((_, value)) = attributes
                .iter()
                .find(|(name, _)| name.eq_ignore_ascii_case("content"))
            {
                return value.clone();
            }
        }
        offset = end;
    }
    String::new()
}

fn metadata_title(html: &str) -> String {
    let lower = html.to_ascii_lowercase();
    let Some(start) = lower.find("<title") else {
        return String::new();
    };
    let Some(open_end_relative) = lower[start..].find('>') else {
        return String::new();
    };
    let content_start = start + open_end_relative + 1;
    let Some(close_relative) = lower[content_start..].find("</title>") else {
        return String::new();
    };
    decode_markup_entities(
        &html[content_start..content_start + close_relative]
            .split_whitespace()
            .collect::<Vec<_>>()
            .join(" "),
    )
}

fn clean_provider_title(title: &str, provider: &str) -> String {
    let mut cleaned = title.trim().to_owned();
    let suffixes: &[&str] = match provider {
        "youtube" => &[" - YouTube"],
        "bandcamp" => &[" | Bandcamp"],
        "lastfm" => &[" | Last.fm", " — Last.fm"],
        "apple" => &[" by Apple Music", " on Apple Music"],
        _ => &[],
    };
    for suffix in suffixes {
        if cleaned
            .get(cleaned.len().saturating_sub(suffix.len())..)
            .is_some_and(|tail| tail.eq_ignore_ascii_case(suffix))
        {
            cleaned.truncate(cleaned.len() - suffix.len());
            cleaned = cleaned.trim().to_owned();
        }
    }
    cleaned.trim_matches('"').to_owned()
}

fn provider_metadata_row(
    provider: &str,
    source_text: &str,
    html: &str,
) -> Option<SpotifySourceRow> {
    let title = [
        metadata_value(html, "music:song"),
        metadata_value(html, "og:title"),
        metadata_value(html, "twitter:title"),
        metadata_title(html),
    ]
    .into_iter()
    .find(|value| !value.trim().is_empty())
    .unwrap_or_default();
    let title = clean_provider_title(&title, provider);
    if title.trim().is_empty() {
        return None;
    }
    let artist = [
        metadata_value(html, "music:musician:description"),
        metadata_value(html, "byl"),
        metadata_value(html, "article:author"),
    ]
    .into_iter()
    .find(|value| !value.trim().is_empty())
    .unwrap_or_default();
    let mut row = loose_source_row(&title, provider, 1);
    if !artist.trim().is_empty() {
        row.artist = artist;
    }
    row.provider_url = source_text.to_owned();
    Some(row)
}

fn validate_provider_metadata_url(
    url: &str,
) -> Result<(reqwest::Url, ResolvedIntegrationTarget), String> {
    let parsed =
        reqwest::Url::parse(url).map_err(|error| format!("provider URL is invalid: {error}"))?;
    if !matches!(parsed.scheme(), "http" | "https") {
        return Err("provider URL scheme must be http or https".to_owned());
    }
    if !parsed.username().is_empty() || parsed.password().is_some() {
        return Err("provider URL must not contain embedded credentials".to_owned());
    }
    if parsed.fragment().is_some() {
        return Err("provider URL must not contain a fragment".to_owned());
    }
    if source_provider(url, "auto").is_none() {
        return Err("provider URL host is not supported".to_owned());
    }
    let host = parsed
        .host_str()
        .ok_or_else(|| "provider URL must include a host".to_owned())?
        .to_owned();
    let port = parsed
        .port_or_known_default()
        .ok_or_else(|| "provider URL port is unknown".to_owned())?;
    let addrs = (host.as_str(), port)
        .to_socket_addrs()
        .map_err(|error| format!("provider URL resolution failed: {error}"))?
        .collect::<Vec<_>>();
    if addrs.is_empty() {
        return Err("provider URL did not resolve".to_owned());
    }
    if addrs
        .iter()
        .any(|address| is_blocked_integration_ip(address.ip()))
    {
        return Err("provider URL resolves to a private address".to_owned());
    }
    Ok((parsed, ResolvedIntegrationTarget { host, addrs }))
}

async fn fetch_provider_metadata_page(
    provider: &str,
    source_text: &str,
    timeout_seconds: u64,
) -> Result<Option<SpotifySourceRow>, String> {
    let (url, resolved) = validate_provider_metadata_url(source_text)?;
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(timeout_seconds))
        .redirect(reqwest::redirect::Policy::none())
        .resolve_to_addrs(&resolved.host, &resolved.addrs)
        .build()
        .map_err(|error| format!("failed to build provider client: {error}"))?;
    let response = client
        .get(url)
        .header("User-Agent", "slskdN-source-feed-import/1.0")
        .send()
        .await
        .map_err(|error| format!("provider metadata request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!(
            "provider metadata returned HTTP {}",
            response.status()
        ));
    }
    let body = read_bounded_source_provider_bytes(response, "provider metadata").await?;
    let html = String::from_utf8_lossy(&body);
    Ok(provider_metadata_row(provider, source_text, &html))
}

async fn send_ntfy_notification(
    options: &config::NtfyIntegrationSettings,
    title: &str,
    body: &str,
) -> Result<(), String> {
    let resolved = validate_integration_base_url(&options.url)?;
    send_ntfy_notification_to(options, title, body, &options.url, &resolved).await
}

async fn send_ntfy_notification_to(
    options: &config::NtfyIntegrationSettings,
    title: &str,
    body: &str,
    endpoint: &str,
    resolved: &ResolvedIntegrationTarget,
) -> Result<(), String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(30))
        .redirect(reqwest::redirect::Policy::none())
        .resolve_to_addrs(&resolved.host, &resolved.addrs)
        .build()
        .map_err(|error| format!("failed to build Ntfy client: {error}"))?;
    let mut request = client
        .post(endpoint)
        .header("Title", format!("{}: {title}", options.notification_prefix))
        .header("Content-Type", "text/plain; charset=utf-8")
        .body(body.to_owned());
    if !options.access_token.trim().is_empty() {
        request = request.bearer_auth(&options.access_token);
    }
    let response = request
        .send()
        .await
        .map_err(|error| format!("Ntfy request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Ntfy returned HTTP {}", response.status()));
    }
    Ok(())
}

async fn send_pushover_notification(
    options: &config::PushoverIntegrationSettings,
    title: &str,
    body: &str,
    endpoint: &str,
) -> Result<(), String> {
    let prefixed_title = format!("{}: {title}", options.notification_prefix);
    let response = reqwest::Client::builder()
        .timeout(Duration::from_secs(30))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Pushover client: {error}"))?
        .post(endpoint)
        .form(&[
            ("token", options.token.as_str()),
            ("user", options.user_key.as_str()),
            ("title", prefixed_title.as_str()),
            ("message", body),
        ])
        .send()
        .await
        .map_err(|error| format!("Pushover request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Pushover returned HTTP {}", response.status()));
    }
    Ok(())
}

async fn send_pushbullet_notification(
    options: &config::PushbulletIntegrationSettings,
    title: &str,
    body: &str,
    endpoint: &str,
) -> Result<(), String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(30))
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .map_err(|error| format!("failed to build Pushbullet client: {error}"))?;
    let payload = serde_json::json!({"title": format!("{} {title}", options.notification_prefix), "body": body, "type": "note"});
    let attempts = options.retry_attempts.max(1);
    let mut last_error = String::new();
    for _ in 0..attempts {
        match client
            .post(endpoint)
            .header("Access-Token", &options.access_token)
            .header("User-Agent", format!("slskR v{APP_VERSION}"))
            .json(&payload)
            .send()
            .await
        {
            Ok(response) if response.status().is_success() => return Ok(()),
            Ok(response) => last_error = format!("Pushbullet returned HTTP {}", response.status()),
            Err(error) => last_error = format!("Pushbullet request failed: {error}"),
        }
    }
    Err(last_error)
}

async fn send_private_message_notifications(state: &AppState, username: &str, message: &str) {
    let key = format!("notification:pm:{username}");
    if !state
        .private_message_auto_responses
        .write()
        .await
        .should_respond(&key, unix_timestamp(), 30)
    {
        return;
    }
    let integrations = state.integration_settings.read().await.clone();
    let title = format!("Private Message from {username}");
    if integrations.pushbullet.enabled && integrations.pushbullet.notify_on_private_message {
        if integrations.pushbullet.cooldown_time < 0 {
            record_daemon_log(
                state,
                logging::LogLevel::Warn,
                "pushbullet",
                "Pushbullet cooldown is negative".to_owned(),
            )
            .await;
            return;
        }
        let cooldown = u64::try_from(integrations.pushbullet.cooldown_time)
            .unwrap_or_default()
            .saturating_add(999)
            / 1_000;
        let push_key = format!("pushbullet:pm:{username}");
        if state
            .private_message_auto_responses
            .write()
            .await
            .should_respond(&push_key, unix_timestamp(), cooldown)
        {
            if let Err(error) = send_pushbullet_notification(
                &integrations.pushbullet,
                &title,
                message,
                "https://api.pushbullet.com/v2/pushes",
            )
            .await
            {
                record_daemon_log(state, logging::LogLevel::Warn, "pushbullet", error).await;
            }
        }
    }
    if integrations.ntfy.enabled && integrations.ntfy.notify_on_private_message {
        if let Err(error) = send_ntfy_notification(&integrations.ntfy, &title, message).await {
            record_daemon_log(state, logging::LogLevel::Error, "ntfy", error).await;
        }
    }
    if integrations.pushover.enabled && integrations.pushover.notify_on_private_message {
        if let Err(error) = send_pushover_notification(
            &integrations.pushover,
            &title,
            message,
            "https://api.pushover.net/1/messages.json",
        )
        .await
        {
            record_daemon_log(state, logging::LogLevel::Error, "pushover", error).await;
        }
    }
}

