fn youtube_playlist_id(source_text: &str) -> String {
    reqwest::Url::parse(source_text.trim())
        .ok()
        .and_then(|url| {
            url.query_pairs()
                .find(|(key, _)| key == "list")
                .map(|(_, value)| value.into_owned())
        })
        .unwrap_or_default()
}

fn lastfm_target(source_text: &str) -> (String, &'static str, &'static str) {
    let Ok(url) = reqwest::Url::parse(source_text.trim()) else {
        return (String::new(), "", "");
    };
    let parts = url
        .path_segments()
        .map(|parts| parts.filter(|part| !part.is_empty()).collect::<Vec<_>>())
        .unwrap_or_default();
    let Some(user_index) = parts
        .iter()
        .position(|part| part.eq_ignore_ascii_case("user"))
    else {
        return (String::new(), "", "");
    };
    let user = parts.get(user_index + 1).copied().unwrap_or_default();
    let suffix = parts
        .iter()
        .skip(user_index + 2)
        .copied()
        .collect::<Vec<_>>()
        .join("/")
        .to_ascii_lowercase();
    if suffix.contains("loved") {
        (user.to_owned(), "user.getlovedtracks", "lastfm:loved")
    } else if suffix.contains("toptracks") {
        (user.to_owned(), "user.gettoptracks", "lastfm:top-tracks")
    } else {
        (
            user.to_owned(),
            "user.getrecenttracks",
            "lastfm:recent-tracks",
        )
    }
}

fn apple_source_ids(source_text: &str) -> Vec<String> {
    let Ok(url) = reqwest::Url::parse(source_text.trim()) else {
        return Vec::new();
    };
    if let Some(id) = url
        .query_pairs()
        .find(|(key, _)| key == "i")
        .map(|(_, value)| value.into_owned())
        .filter(|value| !value.trim().is_empty())
    {
        return vec![id];
    }
    url.path_segments()
        .into_iter()
        .flatten()
        .rev()
        .find(|segment| !segment.is_empty() && segment.bytes().all(|byte| byte.is_ascii_digit()))
        .map(|segment| vec![segment.to_owned()])
        .unwrap_or_default()
}

fn listenbrainz_user(source_text: &str) -> String {
    let Ok(url) = reqwest::Url::parse(source_text.trim()) else {
        return String::new();
    };
    let parts = url
        .path_segments()
        .map(|parts| parts.filter(|part| !part.is_empty()).collect::<Vec<_>>())
        .unwrap_or_default();
    parts
        .iter()
        .position(|part| part.eq_ignore_ascii_case("user"))
        .and_then(|index| parts.get(index + 1))
        .copied()
        .unwrap_or_default()
        .to_owned()
}

async fn preview_configured_provider_source_feed(
    state: &AppState,
    source_text: &str,
    source_kind: &str,
    limit: usize,
    youtube_api_base: &str,
    lastfm_api_base: &str,
    apple_api_base: &str,
    listenbrainz_api_base: &str,
) -> Result<Option<serde_json::Value>, String> {
    let Some(provider) = source_provider(source_text, source_kind) else {
        return Ok(None);
    };
    let integrations = state.integration_settings.read().await.clone();
    let timeout = integrations.spotify.timeout_seconds;
    let mut rows = Vec::new();
    let mut requests = 0_u64;
    match provider {
        "youtube" => {
            let playlist_id = youtube_playlist_id(source_text);
            if integrations.youtube.configured() && !playlist_id.is_empty() {
                let api_key = integrations.youtube.api_key.as_deref().unwrap_or_default();
                let mut page_token = String::new();
                while rows.len() < limit {
                    let page_limit = 50_usize.min(limit - rows.len());
                    let page_query = if page_token.is_empty() {
                        String::new()
                    } else {
                        format!("&pageToken={}", url_encode(&page_token))
                    };
                    let page = provider_get_json(
                        timeout,
                        format!(
                            "{}?part=snippet&maxResults={page_limit}&playlistId={}&key={}{page_query}",
                            youtube_api_base.trim_end_matches('/'),
                            url_encode(&playlist_id),
                            url_encode(api_key),
                        ),
                        "YouTube",
                    )
                    .await?;
                    requests += 1;
                    let items = page
                        .get("items")
                        .and_then(serde_json::Value::as_array)
                        .cloned()
                        .unwrap_or_default();
                    let starting_row = rows.len();
                    for (index, item) in items.iter().enumerate() {
                        let title = item
                            .pointer("/snippet/title")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default();
                        let video_id = item
                            .pointer("/snippet/resourceId/videoId")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default();
                        let mut row =
                            loose_source_row(title, "youtube:playlist", starting_row + index + 1);
                        if !video_id.is_empty() {
                            row.source_id = video_id.to_owned();
                            row.provider_url =
                                format!("https://www.youtube.com/watch?v={}", url_encode(video_id));
                        } else {
                            row.provider_url = source_text.to_owned();
                        }
                        rows.push(row);
                    }
                    page_token = page
                        .get("nextPageToken")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    if items.is_empty() || page_token.is_empty() {
                        break;
                    }
                }
            }
        }
        "lastfm" => {
            let (user, method, source) = lastfm_target(source_text);
            if integrations.lastfm.configured() && !user.is_empty() {
                let api_key = integrations.lastfm.api_key.as_deref().unwrap_or_default();
                let page = provider_get_json(
                    timeout,
                    format!(
                        "{}?method={method}&user={}&api_key={}&format=json&limit={}",
                        lastfm_api_base.trim_end_matches('/'),
                        url_encode(&user),
                        url_encode(api_key),
                        200_usize.min(limit),
                    ),
                    "Last.fm",
                )
                .await?;
                requests = 1;
                let tracks = page
                    .pointer("/recenttracks/track")
                    .or_else(|| page.pointer("/lovedtracks/track"))
                    .or_else(|| page.pointer("/toptracks/track"))
                    .and_then(serde_json::Value::as_array)
                    .cloned()
                    .unwrap_or_default();
                for (index, track) in tracks.iter().take(limit).enumerate() {
                    let title = track
                        .get("name")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    rows.push(SpotifySourceRow {
                        title: title.clone(),
                        artist: track
                            .pointer("/artist/name")
                            .or_else(|| track.pointer("/artist/#text"))
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        album: track
                            .pointer("/album/#text")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        source: source.to_owned(),
                        source_id: track
                            .get("mbid")
                            .and_then(serde_json::Value::as_str)
                            .filter(|value| !value.trim().is_empty())
                            .map(str::to_owned)
                            .unwrap_or_else(|| (index + 1).to_string()),
                        provider_url: track
                            .get("url")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        raw_text: title,
                    });
                }
            }
        }
        "apple" => {
            for id in apple_source_ids(source_text).into_iter().take(2) {
                let page = provider_get_json(
                    timeout,
                    format!(
                        "{}?id={}&entity=song&limit={}",
                        apple_api_base.trim_end_matches('/'),
                        url_encode(&id),
                        200_usize.min(limit),
                    ),
                    "Apple Music",
                )
                .await?;
                requests += 1;
                for item in page
                    .get("results")
                    .and_then(serde_json::Value::as_array)
                    .into_iter()
                    .flatten()
                    .filter(|item| {
                        item.get("trackName")
                            .and_then(serde_json::Value::as_str)
                            .is_some_and(|value| !value.trim().is_empty())
                    })
                {
                    let title = item
                        .get("trackName")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    rows.push(SpotifySourceRow {
                        title: title.clone(),
                        artist: item
                            .get("artistName")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        album: item
                            .get("collectionName")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        source: "apple".to_owned(),
                        source_id: item
                            .get("trackId")
                            .and_then(serde_json::Value::as_i64)
                            .map(|value| value.to_string())
                            .unwrap_or_default(),
                        provider_url: item
                            .get("trackViewUrl")
                            .and_then(serde_json::Value::as_str)
                            .filter(|value| !value.trim().is_empty())
                            .unwrap_or(source_text)
                            .to_owned(),
                        raw_text: title,
                    });
                }
                if rows.len() >= limit {
                    break;
                }
            }
        }
        "listenbrainz" => {
            let user = listenbrainz_user(source_text);
            if !user.is_empty() {
                let page = provider_get_json(
                    timeout,
                    format!(
                        "{}/1/user/{}/listens?count={}",
                        listenbrainz_api_base.trim_end_matches('/'),
                        url_encode(&user),
                        100_usize.min(limit),
                    ),
                    "ListenBrainz",
                )
                .await?;
                requests = 1;
                for (index, listen) in page
                    .pointer("/payload/listens")
                    .and_then(serde_json::Value::as_array)
                    .into_iter()
                    .flatten()
                    .take(limit)
                    .enumerate()
                {
                    let metadata = listen
                        .get("track_metadata")
                        .unwrap_or(&serde_json::Value::Null);
                    let title = metadata
                        .get("track_name")
                        .and_then(serde_json::Value::as_str)
                        .unwrap_or_default()
                        .to_owned();
                    rows.push(SpotifySourceRow {
                        title: title.clone(),
                        artist: metadata
                            .get("artist_name")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        album: metadata
                            .get("release_name")
                            .and_then(serde_json::Value::as_str)
                            .unwrap_or_default()
                            .to_owned(),
                        source: "listenbrainz:listens".to_owned(),
                        source_id: metadata
                            .pointer("/additional_info/recording_msid")
                            .and_then(serde_json::Value::as_str)
                            .filter(|value| !value.trim().is_empty())
                            .map(str::to_owned)
                            .unwrap_or_else(|| (index + 1).to_string()),
                        provider_url: source_text.to_owned(),
                        raw_text: title,
                    });
                }
            }
        }
        "bandcamp" => {}
        _ => unreachable!(),
    }
    if rows.is_empty() {
        if let Some(row) = fetch_provider_metadata_page(provider, source_text, timeout).await? {
            rows.push(row);
        }
        requests += 1;
    }
    Ok(Some(build_provider_source_result(
        provider,
        source_text,
        rows.into_iter().take(limit).collect(),
        requests,
    )))
}

fn detect_local_source_kind(source_text: &str) -> &'static str {
    let trimmed = source_text.trim_start();
    if trimmed.to_ascii_lowercase().starts_with("#extm3u")
        || trimmed.to_ascii_lowercase().contains("#extinf")
    {
        "m3u"
    } else if trimmed.to_ascii_lowercase().starts_with("<rss")
        || trimmed.to_ascii_lowercase().starts_with("<feed")
        || trimmed.to_ascii_lowercase().starts_with("<opml")
    {
        "rss"
    } else {
        let first_line = source_text
            .lines()
            .find(|line| !line.trim().is_empty())
            .unwrap_or_default();
        if first_line.contains(',') && first_line.to_ascii_lowercase().contains("track") {
            "csv"
        } else {
            "text"
        }
    }
}

fn local_csv_rows(source_text: &str, include_album: bool) -> Vec<SpotifySourceRow> {
    let rows = parse_wishlist_csv_rows(source_text);
    let Some(first) = rows.first() else {
        return Vec::new();
    };
    let header_names = first
        .iter()
        .map(|value| normalized_wishlist_csv_header(value))
        .collect::<Vec<_>>();
    let has_header = header_names.iter().any(|value| {
        matches!(
            value.as_str(),
            "trackname"
                | "track"
                | "title"
                | "songname"
                | "song"
                | "artistname"
                | "artist"
                | "artists"
                | "albumname"
                | "album"
        )
    });
    let title_index = has_header
        .then(|| {
            wishlist_csv_column(
                first,
                &["trackname", "track", "title", "songname", "song", "name"],
            )
        })
        .flatten()
        .unwrap_or(0);
    let artist_index = has_header
        .then(|| wishlist_csv_column(first, &["artistname", "artistnames", "artists", "artist"]))
        .flatten()
        .unwrap_or(1);
    let album_index = has_header
        .then(|| wishlist_csv_column(first, &["albumname", "album", "release"]))
        .flatten()
        .unwrap_or(2);
    let url_index = has_header
        .then(|| wishlist_csv_column(first, &["url", "spotifyurl", "trackurl", "link"]))
        .flatten();
    rows.iter()
        .enumerate()
        .skip(usize::from(has_header))
        .map(|(index, row)| {
            let cell = |column: usize| {
                row.get(column)
                    .map(|value| value.trim())
                    .unwrap_or_default()
            };
            let title = cell(title_index).to_owned();
            SpotifySourceRow {
                title: title.clone(),
                artist: cell(artist_index).to_owned(),
                album: include_album
                    .then(|| cell(album_index).to_owned())
                    .unwrap_or_default(),
                source: "csv".to_owned(),
                source_id: (index + 1).to_string(),
                provider_url: url_index
                    .and_then(|column| row.get(column))
                    .map(|value| value.trim().to_owned())
                    .unwrap_or_default(),
                raw_text: row.join(","),
            }
        })
        .collect()
}

fn local_playlist_rows(source_text: &str) -> Vec<SpotifySourceRow> {
    source_text
        .lines()
        .enumerate()
        .filter_map(|(index, line)| {
            let line = line.trim();
            if !line
                .get(..8)
                .is_some_and(|prefix| prefix.eq_ignore_ascii_case("#EXTINF:"))
            {
                return None;
            }
            let title = line.rsplit_once(',')?.1;
            Some(loose_source_row(title, "m3u", index + 1))
        })
        .collect()
}

fn local_xml_values(source_text: &str, element: &str) -> Vec<String> {
    let lower = String::from_utf8(
        source_text
            .as_bytes()
            .iter()
            .map(u8::to_ascii_lowercase)
            .collect(),
    )
    .expect("ASCII case conversion preserves UTF-8");
    let mut values = Vec::new();
    let mut offset = 0_usize;
    while let Some(relative) = lower[offset..].find('<') {
        let start = offset + relative;
        let Some(tag_end_relative) = lower[start..].find('>') else {
            break;
        };
        let tag_end = start + tag_end_relative;
        let tag = source_text[start + 1..tag_end].trim();
        if tag.starts_with('/') || tag.starts_with('!') || tag.starts_with('?') {
            offset = tag_end + 1;
            continue;
        }
        let tag_name = tag
            .split_ascii_whitespace()
            .next()
            .unwrap_or_default()
            .trim_end_matches('/');
        if !tag_name
            .rsplit(':')
            .next()
            .is_some_and(|name| name.eq_ignore_ascii_case(element))
        {
            offset = tag_end + 1;
            continue;
        }
        let close = format!("</{}>", tag_name.to_ascii_lowercase());
        let content_start = start + tag_end_relative + 1;
        let Some(close_relative) = lower[content_start..].find(&close) else {
            offset = tag_end + 1;
            continue;
        };
        let content_end = content_start + close_relative;
        values.push(decode_markup_entities(
            source_text[content_start..content_end].trim(),
        ));
        offset = content_end + close.len();
    }
    values
}

fn local_xml_rows(source_text: &str) -> Vec<SpotifySourceRow> {
    let mut rows = Vec::new();
    let lower = source_text.to_ascii_lowercase();
    let mut offset = 0_usize;
    while let Some(relative) = lower[offset..].find('<') {
        let start = offset + relative;
        let Some(tag_end_relative) = lower[start..].find('>') else {
            break;
        };
        let tag_end = start + tag_end_relative;
        let tag = source_text[start + 1..tag_end].trim();
        let tag_name = tag
            .split_ascii_whitespace()
            .next()
            .unwrap_or_default()
            .trim_end_matches('/');
        let local_name = tag_name.rsplit(':').next().unwrap_or_default();
        if !tag.starts_with('/')
            && (local_name.eq_ignore_ascii_case("item") || local_name.eq_ignore_ascii_case("entry"))
        {
            let close = format!("</{}>", tag_name.to_ascii_lowercase());
            let content_start = tag_end + 1;
            if let Some(close_relative) = lower[content_start..].find(&close) {
                let content_end = content_start + close_relative;
                let container = &source_text[content_start..content_end];
                let title = local_xml_values(container, "title")
                    .into_iter()
                    .next()
                    .unwrap_or_default();
                rows.push(loose_source_row(&title, "rss", rows.len() + 1));
                offset = content_end + close.len();
                continue;
            }
        }
        offset = tag_end + 1;
    }

    let mut outline_index = 0_usize;
    let mut offset = 0_usize;
    while let Some(relative) = lower[offset..].find('<') {
        let start = offset + relative;
        let Some(tag_end_relative) = lower[start..].find('>') else {
            break;
        };
        let tag_end = start + tag_end_relative;
        let tag = source_text[start + 1..tag_end].trim();
        let tag_name = tag
            .split_ascii_whitespace()
            .next()
            .unwrap_or_default()
            .trim_end_matches('/');
        if !tag.starts_with('/')
            && tag_name
                .rsplit(':')
                .next()
                .is_some_and(|name| name.eq_ignore_ascii_case("outline"))
        {
            outline_index += 1;
            let attributes = markup_tag_attributes(tag);
            let text = attributes
                .iter()
                .find(|(name, _)| name == "text")
                .or_else(|| attributes.iter().find(|(name, _)| name == "title"))
                .map(|(_, value)| value.as_str())
                .unwrap_or_default();
            rows.push(loose_source_row(text, "opml", outline_index));
        }
        offset = tag_end + 1;
    }
    rows
}

fn preview_local_source_feed(
    source_text: &str,
    requested_kind: &str,
    include_album: bool,
    limit: usize,
) -> serde_json::Value {
    let kind = if requested_kind == "auto" {
        detect_local_source_kind(source_text)
    } else {
        requested_kind
    };
    let rows = match kind {
        "csv" => local_csv_rows(source_text, include_album),
        "m3u" | "pls" => local_playlist_rows(source_text),
        "rss" | "opml" => local_xml_rows(source_text),
        _ => source_text
            .lines()
            .filter(|line| !line.trim().is_empty())
            .enumerate()
            .map(|(index, line)| loose_source_row(line, "text", index + 1))
            .collect(),
    };
    let mut result =
        build_provider_source_result("local", "", rows.into_iter().take(limit).collect(), 0);
    result["sourceKind"] = serde_json::json!(kind);
    result["sourceId"] = serde_json::json!("");
    if let Some(suggestions) = result["suggestions"].as_array_mut() {
        for suggestion in suggestions {
            suggestion["reason"] = serde_json::json!(format!("Imported from local {kind}."));
        }
    }
    result
}

fn html_escape(value: &str) -> String {
    value
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#39;")
}

fn spotify_callback_html(message: &str) -> String {
    format!(
        "<!doctype html>\n<html>\n  <head><title>Spotify Connection</title></head>\n  <body>\n    <p>{}</p>\n    <script>\n      if (window.opener) {{\n        window.opener.postMessage({{ type: 'slskdn:spotify-connected' }}, window.location.origin);\n      }}\n    </script>\n  </body>\n</html>",
        html_escape(message)
    )
}

async fn fetch_lidarr_system_status(
    lidarr: &config::LidarrIntegrationSettings,
) -> Result<serde_json::Value, String> {
    let base_url = lidarr
        .url
        .as_deref()
        .ok_or("Lidarr URL is not configured")?;
    let resolved = validate_lidarr_base_url(base_url)?;
    let api_key = lidarr
        .api_key
        .as_deref()
        .ok_or("Lidarr API key is not configured")?;
    let url = format!("{}/api/v1/system/status", base_url.trim_end_matches('/'));
    let mut client_builder = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(lidarr.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none());
    for addr in &resolved.addrs {
        client_builder = client_builder.resolve(&resolved.host, *addr);
    }
    let client = client_builder
        .build()
        .map_err(|error| format!("failed to build Lidarr client: {error}"))?;
    let response = client
        .get(url)
        .header("X-Api-Key", api_key)
        .send()
        .await
        .map_err(|error| format!("Lidarr status request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Lidarr returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Lidarr status").await
}

async fn fetch_lidarr_wanted_missing(
    lidarr: &config::LidarrIntegrationSettings,
    page: u64,
    page_size: u64,
) -> Result<serde_json::Value, String> {
    let base_url = lidarr
        .url
        .as_deref()
        .ok_or("Lidarr URL is not configured")?;
    let resolved = validate_lidarr_base_url(base_url)?;
    let api_key = lidarr
        .api_key
        .as_deref()
        .ok_or("Lidarr API key is not configured")?;
    let url = format!(
        "{}/api/v1/wanted/missing?page={}&pageSize={}&includeArtist=true&monitored=true",
        base_url.trim_end_matches('/'),
        page.max(1),
        page_size.clamp(1, 250),
    );
    let mut client_builder = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(lidarr.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none());
    for addr in &resolved.addrs {
        client_builder = client_builder.resolve(&resolved.host, *addr);
    }
    let client = client_builder
        .build()
        .map_err(|error| format!("failed to build Lidarr client: {error}"))?;
    let response = client
        .get(url)
        .header("X-Api-Key", api_key)
        .send()
        .await
        .map_err(|error| format!("Lidarr wanted request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Lidarr returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Lidarr wanted").await
}

async fn sync_lidarr_wanted_to_wishlist(
    state: &AppState,
    lidarr: &config::LidarrIntegrationSettings,
) -> Result<serde_json::Value, String> {
    let mut wanted_count = 0_u64;
    let mut created_count = 0_u64;
    let mut duplicate_count = 0_u64;
    let mut skipped_count = 0_u64;
    if !lidarr.enabled {
        return Ok(serde_json::json!({
            "enabled": false,
            "wantedCount": wanted_count,
            "createdCount": created_count,
            "duplicateCount": duplicate_count,
            "skippedCount": skipped_count,
        }));
    }

    let mut existing = state
        .wishlist
        .read()
        .await
        .records
        .iter()
        .flat_map(|record| record.items.iter())
        .map(|item| {
            format!(
                "{}\u{1f}{}",
                item.search_text().trim().to_ascii_lowercase(),
                item.filter.trim().to_ascii_lowercase()
            )
        })
        .collect::<HashSet<_>>();
    let mut page = 1_u64;
    const PAGE_SIZE: u64 = 250;

    loop {
        let response = fetch_lidarr_wanted_missing(lidarr, page, PAGE_SIZE).await?;
        wanted_count = response
            .get("totalRecords")
            .and_then(serde_json::Value::as_u64)
            .unwrap_or_default();
        let records = response
            .get("records")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default();
        if records.is_empty() {
            break;
        }

        let mut created = Vec::new();
        let mut reached_cap = false;
        {
            let mut wishlist = state.wishlist.write().await;
            for album in records {
                if created_count.saturating_add(created.len() as u64) >= lidarr.max_items_per_sync {
                    reached_cap = true;
                    break;
                }
                let title = album
                    .get("title")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or_default()
                    .trim()
                    .to_owned();
                let artist = album
                    .pointer("/artist/artistName")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or_default()
                    .trim()
                    .to_owned();
                let search_text = match (artist.is_empty(), title.is_empty()) {
                    (true, true) => String::new(),
                    (true, false) => title.clone(),
                    (false, true) => artist.clone(),
                    (false, false) => format!("{artist} {title}"),
                };
                if search_text.is_empty() {
                    skipped_count = skipped_count.saturating_add(1);
                    continue;
                }
                let key = format!(
                    "{}\u{1f}{}",
                    search_text.to_ascii_lowercase(),
                    lidarr.wishlist_filter.trim().to_ascii_lowercase()
                );
                if !existing.insert(key) {
                    duplicate_count = duplicate_count.saturating_add(1);
                    continue;
                }
                match wishlist.add_item_with_settings(
                    artist,
                    title,
                    "Audio".to_owned(),
                    lidarr.wishlist_filter.clone(),
                    true,
                    lidarr.auto_download,
                    usize::try_from(lidarr.wishlist_max_results).unwrap_or(MAX_WISHLIST_RESULTS),
                    None,
                ) {
                    Ok(item) => created.push(item),
                    Err(()) => {
                        skipped_count = skipped_count.saturating_add(1);
                        reached_cap = true;
                        break;
                    }
                }
            }
        }
        for item in &created {
            persist_wishlist_item_checked(state, item).await?;
        }
        created_count = created_count.saturating_add(created.len() as u64);

        if reached_cap || page.saturating_mul(PAGE_SIZE) >= wanted_count {
            break;
        }
        page = page.saturating_add(1);
    }

    let result = serde_json::json!({
        "enabled": true,
        "wantedCount": wanted_count,
        "createdCount": created_count,
        "duplicateCount": duplicate_count,
        "skippedCount": skipped_count,
    });
    {
        let mut sync = state.lidarr_sync_state.write().await;
        sync.last_sync_at = Some(chrono::Utc::now().to_rfc3339());
        sync.last_error = None;
        sync.last_result = Some(result.clone());
    }
    Ok(result)
}

fn lidarr_map_import_path(path: &str, from_prefix: &str, to_prefix: &str) -> String {
    let absolute = if Path::new(path).is_absolute() {
        PathBuf::from(path)
    } else {
        std::env::current_dir()
            .unwrap_or_else(|_| PathBuf::from("/"))
            .join(path)
    };
    let normalized = absolute.to_string_lossy().to_string();
    if from_prefix.trim().is_empty() || to_prefix.trim().is_empty() {
        return normalized;
    }
    let from = from_prefix.trim_end_matches(['/', '\\']);
    let same = normalized == from;
    let child = normalized
        .strip_prefix(from)
        .is_some_and(|suffix| suffix.starts_with('/') || suffix.starts_with('\\'));
    if !same && !child {
        return normalized;
    }
    let relative = normalized[from.len()..].trim_start_matches(['/', '\\']);
    if to_prefix.contains('/') && !to_prefix.contains('\\') {
        let prefix = to_prefix.trim_end_matches(['/', '\\']);
        if relative.is_empty() {
            prefix.to_owned()
        } else {
            format!("{prefix}/{}", relative.replace('\\', "/"))
        }
    } else {
        Path::new(to_prefix)
            .join(relative)
            .to_string_lossy()
            .to_string()
    }
}

fn lidarr_safe_import_candidate(candidate: &serde_json::Value) -> bool {
    let valid_rejections = candidate
        .get("rejections")
        .and_then(serde_json::Value::as_array)
        .is_none_or(|rejections| {
            rejections.iter().all(|rejection| {
                rejection
                    .get("reason")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .contains("missing tracks")
            })
        });
    candidate
        .get("id")
        .and_then(serde_json::Value::as_i64)
        .is_some_and(|value| value > 0)
        && candidate
            .get("path")
            .and_then(serde_json::Value::as_str)
            .is_some_and(|value| !value.trim().is_empty())
        && candidate
            .pointer("/artist/id")
            .and_then(serde_json::Value::as_i64)
            .is_some_and(|value| value > 0)
        && candidate
            .pointer("/album/id")
            .and_then(serde_json::Value::as_i64)
            .is_some_and(|value| value > 0)
        && candidate
            .get("albumReleaseId")
            .and_then(serde_json::Value::as_i64)
            .is_some_and(|value| value > 0)
        && candidate
            .get("tracks")
            .and_then(serde_json::Value::as_array)
            .is_some_and(|value| !value.is_empty())
        && candidate
            .get("quality")
            .is_some_and(|value| !value.is_null())
        && !candidate
            .get("additionalFile")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false)
        && valid_rejections
}

async fn fetch_lidarr_manual_import_candidates(
    lidarr: &config::LidarrIntegrationSettings,
    directory: &str,
) -> Result<Vec<serde_json::Value>, String> {
    let base_url = lidarr
        .url
        .as_deref()
        .ok_or("Lidarr URL is not configured")?;
    let resolved = validate_lidarr_base_url(base_url)?;
    let api_key = lidarr
        .api_key
        .as_deref()
        .ok_or("Lidarr API key is not configured")?;
    let url = format!(
        "{}/api/v1/manualimport?folder={}&filterExistingFiles=false&replaceExistingFiles={}",
        base_url.trim_end_matches('/'),
        url_encode(directory),
        lidarr.import_replace_existing_files,
    );
    let mut builder = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(lidarr.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none());
    for addr in &resolved.addrs {
        builder = builder.resolve(&resolved.host, *addr);
    }
    let response = builder
        .build()
        .map_err(|error| format!("failed to build Lidarr client: {error}"))?
        .get(url)
        .header("X-Api-Key", api_key)
        .send()
        .await
        .map_err(|error| format!("Lidarr manual import request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Lidarr returned HTTP {}", response.status()));
    }
    read_bounded_integration_json(response, "Lidarr manual import")
        .await?
        .as_array()
        .cloned()
        .ok_or_else(|| "Lidarr manual import response was not an array".to_owned())
}

async fn import_lidarr_completed_directory(
    state: &AppState,
    lidarr: &config::LidarrIntegrationSettings,
    directory: &str,
) -> Result<serde_json::Value, String> {
    let empty_result = |enabled: bool, auto_import_enabled: bool| {
        serde_json::json!({
            "enabled": enabled,
            "autoImportEnabled": auto_import_enabled,
            "directory": "",
            "candidateCount": 0,
            "safeCandidateCount": 0,
            "rejectedCandidateCount": 0,
            "commandId": 0,
            "importMode": "",
            "skippedReason": "",
        })
    };
    if !lidarr.enabled || !lidarr.auto_import_completed {
        return Ok(empty_result(lidarr.enabled, lidarr.auto_import_completed));
    }
    if directory.trim().is_empty() {
        let mut result = empty_result(true, true);
        result["skippedReason"] = serde_json::json!("Directory is empty");
        return Ok(result);
    }

    let mapped_directory =
        lidarr_map_import_path(directory, &lidarr.import_path_from, &lidarr.import_path_to);
    let now = unix_timestamp();
    {
        let mut recent = state.lidarr_recent_imports.write().await;
        recent.retain(|_, processed_at| now.saturating_sub(*processed_at) <= 60 * 60);
        if recent.insert(mapped_directory.clone(), now).is_some() {
            let mut result = empty_result(true, true);
            result["directory"] = serde_json::json!(mapped_directory);
            result["skippedReason"] = serde_json::json!("Recently processed");
            return Ok(result);
        }
    }

    let _permit = state
        .lidarr_import_gate
        .acquire()
        .await
        .map_err(|_| "Lidarr import gate is unavailable".to_owned())?;
    let candidates = fetch_lidarr_manual_import_candidates(lidarr, &mapped_directory).await?;
    let candidate_count = candidates.len();
    let mut safe = candidates
        .into_iter()
        .filter(lidarr_safe_import_candidate)
        .collect::<Vec<_>>();
    for candidate in &mut safe {
        candidate["replaceExistingFiles"] = serde_json::json!(lidarr.import_replace_existing_files);
        if candidate
            .pointer("/artist/foreignArtistId")
            .and_then(serde_json::Value::as_str)
            .is_none()
        {
            candidate["artist"]["foreignArtistId"] = serde_json::Value::String(String::new());
        }
    }
    let safe_count = safe.len();
    let rejected_count = candidate_count.saturating_sub(safe_count);
    if safe.is_empty() {
        return Ok(serde_json::json!({
            "enabled": true,
            "autoImportEnabled": true,
            "directory": mapped_directory,
            "candidateCount": candidate_count,
            "safeCandidateCount": 0,
            "rejectedCandidateCount": rejected_count,
            "commandId": 0,
            "importMode": "",
            "skippedReason": if candidate_count == 0 {
                "Lidarr found no import candidates"
            } else {
                "Lidarr candidates had rejections or ambiguous matches"
            },
        }));
    }
    let import_mode = if lidarr.import_mode.eq_ignore_ascii_case("copy") {
        "Copy"
    } else {
        "Move"
    };
    let command_id = start_lidarr_manual_import(lidarr, safe, import_mode).await?;
    Ok(serde_json::json!({
        "enabled": true,
        "autoImportEnabled": true,
        "directory": mapped_directory,
        "candidateCount": candidate_count,
        "safeCandidateCount": safe_count,
        "rejectedCandidateCount": rejected_count,
        "commandId": command_id,
        "importMode": import_mode,
        "skippedReason": "",
    }))
}

fn transfer_remote_directory(filename: &str) -> &str {
    filename
        .rfind(['/', '\\'])
        .map_or("", |separator| &filename[..separator])
}

async fn maybe_import_lidarr_completed_download(state: &AppState, transfer: &TransferEntry) {
    if transfer.direction != 0 || transfer.status != "succeeded" {
        return;
    }
    let Some(local_directory) = transfer
        .local_path
        .as_deref()
        .and_then(|path| Path::new(path).parent())
        .map(|path| path.to_string_lossy().to_string())
    else {
        return;
    };
    let remote_directory = transfer_remote_directory(&transfer.filename);
    let has_pending_file = state
        .transfers
        .read()
        .await
        .entries
        .iter()
        .any(|candidate| {
            candidate.id != transfer.id
                && candidate.direction == 0
                && candidate.peer_username == transfer.peer_username
                && transfer_remote_directory(&candidate.filename) == remote_directory
                && !matches!(
                    candidate.status.as_str(),
                    "succeeded" | "completed" | "cancelled" | "failed" | "rejected"
                )
        });
    if has_pending_file {
        return;
    }
    let lidarr = state.integration_settings.read().await.lidarr.clone();
    if !lidarr.enabled || !lidarr.auto_import_completed {
        return;
    }
    if let Err(error) = import_lidarr_completed_directory(state, &lidarr, &local_directory).await {
        record_daemon_log(
            state,
            logging::LogLevel::Warn,
            "lidarr",
            format!("Lidarr auto-import failed for {local_directory}: {error}"),
        )
        .await;
    }
}

async fn maybe_upload_ftp_completed_download(state: &AppState, transfer: &TransferEntry) {
    if transfer.direction != 0 || transfer.status != "succeeded" {
        return;
    }
    let Some(local_path) = transfer.local_path.as_deref() else {
        return;
    };
    let root = effective_downloads_dir(state);
    let Ok(local_path) = ensure_scoped_download_path(&root, local_path) else {
        return;
    };
    let options = state.integration_settings.read().await.ftp.clone();
    if !options.enabled {
        return;
    }
    let target = state.config.controller_compatibility_target;
    tokio::spawn(async move {
        if let Err(error) = ftp::upload_completed_file(&options, target, &local_path).await {
            eprintln!("[FTP] Completed-download upload failed: {error}");
        }
    });
}

async fn start_lidarr_manual_import(
    lidarr: &config::LidarrIntegrationSettings,
    files: Vec<serde_json::Value>,
    import_mode: &str,
) -> Result<i64, String> {
    let base_url = lidarr
        .url
        .as_deref()
        .ok_or("Lidarr URL is not configured")?;
    let resolved = validate_lidarr_base_url(base_url)?;
    let api_key = lidarr
        .api_key
        .as_deref()
        .ok_or("Lidarr API key is not configured")?;
    let mut builder = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(lidarr.timeout_seconds))
        .redirect(reqwest::redirect::Policy::none());
    for addr in &resolved.addrs {
        builder = builder.resolve(&resolved.host, *addr);
    }
    let response = builder
        .build()
        .map_err(|error| format!("failed to build Lidarr client: {error}"))?
        .post(format!("{}/api/v1/command", base_url.trim_end_matches('/')))
        .header("X-Api-Key", api_key)
        .json(&serde_json::json!({
            "name": "ManualImport",
            "sendUpdatesToClient": false,
            "files": files,
            "importMode": import_mode,
            "replaceExistingFiles": lidarr.import_replace_existing_files,
        }))
        .send()
        .await
        .map_err(|error| format!("Lidarr command request failed: {error}"))?;
    if !response.status().is_success() {
        return Err(format!("Lidarr returned HTTP {}", response.status()));
    }
    let value = read_bounded_integration_json(response, "Lidarr command").await?;
    value
        .as_i64()
        .or_else(|| value.get("id").and_then(serde_json::Value::as_i64))
        .ok_or_else(|| "Lidarr command response did not include an id".to_owned())
}

async fn read_bounded_integration_json(
    response: reqwest::Response,
    label: &str,
) -> Result<serde_json::Value, String> {
    if response
        .content_length()
        .is_some_and(|length| length > MAX_INTEGRATION_RESPONSE_BYTES as u64)
    {
        return Err(format!(
            "{label} response exceeds {MAX_INTEGRATION_RESPONSE_BYTES} bytes"
        ));
    }

    let mut body = Vec::new();
    let mut stream = response.bytes_stream();
    while let Some(chunk) = stream.next().await {
        let chunk = chunk.map_err(|error| format!("{label} response read failed: {error}"))?;
        if body.len().saturating_add(chunk.len()) > MAX_INTEGRATION_RESPONSE_BYTES {
            return Err(format!(
                "{label} response exceeds {MAX_INTEGRATION_RESPONSE_BYTES} bytes"
            ));
        }
        body.extend_from_slice(&chunk);
    }

    serde_json::from_slice(&body).map_err(|error| format!("invalid {label} JSON: {error}"))
}

struct ResolvedIntegrationTarget {
    host: String,
    addrs: Vec<SocketAddr>,
}

#[allow(dead_code)]
fn validate_integration_base_url(base_url: &str) -> Result<ResolvedIntegrationTarget, String> {
    let parsed = reqwest::Url::parse(base_url)
        .map_err(|error| format!("integration URL is invalid: {error}"))?;
    match parsed.scheme() {
        "http" | "https" => {}
        _ => return Err("integration URL scheme must be http or https".to_owned()),
    }
    let host = parsed
        .host_str()
        .ok_or_else(|| "integration URL must include a host".to_owned())?;
    if !parsed.username().is_empty() || parsed.password().is_some() {
        return Err("integration URL must not contain embedded credentials".to_owned());
    }
    if parsed.query().is_some() || parsed.fragment().is_some() {
        return Err("integration URL must not contain a query or fragment".to_owned());
    }
    let allow_private = matches!(
        env::var("SLSKR_ALLOW_PRIVATE_INTEGRATION_URLS")
            .unwrap_or_default()
            .to_ascii_lowercase()
            .as_str(),
        "1" | "true" | "yes"
    );
    if allow_private {
        let port = parsed
            .port_or_known_default()
            .ok_or_else(|| "integration URL port is unknown".to_owned())?;
        return Ok(ResolvedIntegrationTarget {
            host: host.to_owned(),
            addrs: (host, port)
                .to_socket_addrs()
                .map_err(|error| format!("integration URL resolution failed: {error}"))?
                .collect(),
        });
    }
    if host.eq_ignore_ascii_case("localhost") {
        return Err("integration URL host is private".to_owned());
    }
    if let Ok(ip) = host.parse::<IpAddr>() {
        if is_blocked_integration_ip(ip) {
            return Err("integration URL IP is private".to_owned());
        }
    }
    let port = parsed
        .port_or_known_default()
        .ok_or_else(|| "integration URL port is unknown".to_owned())?;
    let addrs = (host, port)
        .to_socket_addrs()
        .map_err(|error| format!("integration URL resolution failed: {error}"))?
        .collect::<Vec<_>>();
    if addrs.is_empty() {
        return Err("integration URL did not resolve".to_owned());
    }
    if addrs
        .iter()
        .any(|addr| is_blocked_integration_ip(addr.ip()))
    {
        return Err("integration URL resolves to a private address".to_owned());
    }
    Ok(ResolvedIntegrationTarget {
        host: host.to_owned(),
        addrs,
    })
}

fn validate_lidarr_base_url(base_url: &str) -> Result<ResolvedIntegrationTarget, String> {
    let parsed = reqwest::Url::parse(base_url)
        .map_err(|error| format!("integration URL is invalid: {error}"))?;
    if !matches!(parsed.scheme(), "http" | "https") {
        return Err("integration URL scheme must be http or https".to_owned());
    }
    let host = parsed
        .host_str()
        .ok_or_else(|| "integration URL must include a host".to_owned())?;
    if !parsed.username().is_empty() || parsed.password().is_some() {
        return Err("integration URL must not contain embedded credentials".to_owned());
    }
    if parsed.query().is_some() || parsed.fragment().is_some() {
        return Err("integration URL must not contain a query or fragment".to_owned());
    }
    let port = parsed
        .port_or_known_default()
        .ok_or_else(|| "integration URL port is unknown".to_owned())?;
    let addrs = (host, port)
        .to_socket_addrs()
        .map_err(|error| format!("integration URL resolution failed: {error}"))?
        .collect::<Vec<_>>();
    if addrs.is_empty() {
        return Err("integration URL did not resolve".to_owned());
    }
    if addrs
        .iter()
        .any(|address| address.ip().is_unspecified() || address.ip().is_multicast())
    {
        return Err("integration URL resolves to an unusable address".to_owned());
    }
    Ok(ResolvedIntegrationTarget {
        host: host.to_owned(),
        addrs,
    })
}

#[allow(dead_code)]
fn is_blocked_integration_ip(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ip) => is_blocked_outbound_ipv4(ip),
        IpAddr::V6(ip) => {
            if let Some(v4) = ip.to_ipv4_mapped().or_else(|| ip.to_ipv4()) {
                return is_blocked_integration_ip(IpAddr::V4(v4));
            }
            if let Some(v4) = nat64_embedded_ipv4(ip) {
                return is_blocked_outbound_ipv4(v4);
            }
            let segments = ip.segments();
            if segments[0] == 0x2002 || (segments[0] == 0x2001 && segments[1] == 0) {
                return true;
            }
            ip.is_loopback()
                || ip.is_unspecified()
                || ip.is_multicast()
                || (segments[0] == 0x2001 && segments[1] == 0x0db8)
                || (segments[0] & 0xfe00) == 0xfc00
                || (segments[0] & 0xffc0) == 0xfe80
                || (segments[0] & 0xffc0) == 0xfec0
                || is_non_global_special_use_ipv6(ip)
        }
    }
}

