        serde_json::json!({
            "enabled": false,
            "healthy": false,
            "searches": 0,
            "searchResults": 0,
            "transfers": 0,
            "transferEvents": 0,
            "shares": 0,
            "events": 0,
            "messages": 0,
            "users": 0,
            "userStats": 0,
            "browse": 0,
            "rooms": 0,
            "userNotes": 0,
            "interests": 0,
            "securityBans": 0,
            "wishlist": 0,
            "contacts": 0,
            "shareGrants": 0,
            "sharegroups": 0,
            "sharegroupMembers": 0,
            "collections": 0,
            "collectionItems": 0,
            "libraryItems": 0,
            "destinations": 0,
            "nowPlaying": 0,
            "runtimeState": 0,
            "oauthStates": 0,
            "webhooks": 0,
            "webhookLogs": 0,
        })
