async fn database_cleanup_value(state: &AppState, body: &str) -> serde_json::Value {
    let days = extract_json_i32_field(body, "days").unwrap_or(30).max(0);
    let mut transfers = state.transfers.write().await;
    let before = transfers.entries.len();
    transfers
        .entries
        .retain(|entry| is_active_transfer_status(&entry.status) || entry.status == "queued");
    let pruned_transfers = before.saturating_sub(transfers.entries.len());
    transfers.persist_state();
    drop(transfers);

    let persisted_cleaned = if let Some(db) = state.db.as_ref() {
        match db.cleanup_old_records(days).await {
            Ok(count) => serde_json::json!({
                "enabled": true,
                "healthy": true,
                "cleaned": count,
            }),
            Err(error) => {
                eprintln!("database cleanup failed: {error}");
                serde_json::json!({
                    "enabled": true,
                    "healthy": false,
                    "cleaned": 0,
                    "error": "database cleanup unavailable",
                })
            }
        }
    } else {
        serde_json::json!({
            "enabled": false,
            "healthy": false,
            "cleaned": 0,
        })
    };
    let status = if persisted_cleaned["healthy"].as_bool().unwrap_or(true) {
        "ok"
    } else if persisted_cleaned["enabled"].as_bool().unwrap_or(false) {
        "error"
    } else {
        "skipped"
    };

    serde_json::json!({
        "status": status,
        "days": days,
        "cleaned": persisted_cleaned["cleaned"],
        "persisted": persisted_cleaned,
        "pruned_transfers": pruned_transfers,
        "projectionCleanup": {
            "transfers": pruned_transfers,
        },
    })
}

fn retention_age_for_transfer(
    retention: crate::config::TransferRetentionSettings,
    status: &str,
) -> Option<u64> {
    match status {
        "succeeded" | "completed" => retention.succeeded_minutes,
        "cancelled" => retention.cancelled_minutes.or(retention.failed_minutes),
        "failed" | "errored" | "aborted" | "rejected" | "timed_out" => {
            retention.errored_minutes.or(retention.failed_minutes)
        }
        _ => None,
    }
}

fn prune_files_older_than(root: &Path, age_minutes: u64, now: SystemTime) {
    let cutoff = now
        .checked_sub(Duration::from_secs(age_minutes.saturating_mul(60)))
        .unwrap_or(SystemTime::UNIX_EPOCH);
    let Ok(entries) = fs::read_dir(root) else {
        return;
    };
    for entry in entries.flatten() {
        let path = entry.path();
        let Ok(metadata) = fs::symlink_metadata(&path) else {
            continue;
        };
        if metadata.file_type().is_symlink() {
            continue;
        }
        if metadata.is_dir() {
            prune_files_older_than(&path, age_minutes, now);
            let _ = fs::remove_dir(&path);
        } else if metadata.is_file() && metadata.modified().is_ok_and(|modified| modified < cutoff)
        {
            let _ = fs::remove_file(path);
        }
    }
}

async fn run_retention_once(state: &AppState) {
    let now = unix_timestamp();
    let age_minutes = state.config.retention.search_minutes;
    let max_age_days = state.config.search_retention.max_age_days;
    let max_count = state.config.search_retention.max_count;
    let removed_searches = {
        let mut searches = state.searches.write().await;
        let mut removed = Vec::new();
        searches.records.retain(|record| {
            if record.status == "active" {
                return true;
            }
            let expired_by_minutes = age_minutes.is_some_and(|minutes| {
                record.updated_at.saturating_add(minutes.saturating_mul(60)) <= now
            });
            let expired_by_days = max_age_days != 0
                && record
                    .updated_at
                    .saturating_add(max_age_days.saturating_mul(86_400))
                    <= now;
            if expired_by_minutes || expired_by_days {
                removed.push(record.clone());
                false
            } else {
                true
            }
        });
        if max_count != 0 {
            let mut completed = searches
                .records
                .iter()
                .filter(|record| record.status != "active")
                .map(|record| (record.updated_at, record.token))
                .collect::<Vec<_>>();
            completed.sort_unstable_by(|left, right| right.cmp(left));
            let excess = completed
                .into_iter()
                .skip(max_count)
                .map(|(_, token)| token)
                .collect::<HashSet<_>>();
            searches.records.retain(|record| {
                if excess.contains(&record.token) {
                    removed.push(record.clone());
                    false
                } else {
                    true
                }
            });
        }
        removed
    };
    let _ = delete_persisted_searches(state, &removed_searches).await;

    let removed_transfers = {
        let mut transfers = state.transfers.write().await;
        let ids = transfers
            .entries
            .iter()
            .filter(|entry| {
                let settings = if entry.direction == 1 {
                    state.config.retention.upload
                } else {
                    state.config.retention.download
                };
                retention_age_for_transfer(settings, &entry.status).is_some_and(|minutes| {
                    entry.updated_at.saturating_add(minutes.saturating_mul(60)) <= now
                })
            })
            .map(|entry| entry.id)
            .collect::<Vec<_>>();
        transfers.remove_entries(&ids)
    };
    let _ = delete_persisted_transfers(state, &removed_transfers).await;

    let complete = state.config.retention.files_complete_minutes;
    let incomplete = state.config.retention.files_incomplete_minutes;
    let downloads = effective_downloads_dir(state);
    let incomplete_dir = effective_incomplete_dir(state);
    let _ = tokio::task::spawn_blocking(move || {
        let now = SystemTime::now();
        if let Some(age) = complete {
            prune_files_older_than(&downloads, age, now);
        }
        if let Some(age) = incomplete {
            prune_files_older_than(&incomplete_dir, age, now);
        }
    })
    .await;

    let log_cutoff = SystemTime::now()
        .checked_sub(Duration::from_secs(
            state.config.retention.logs_days.saturating_mul(86_400),
        ))
        .unwrap_or(SystemTime::UNIX_EPOCH);
    if let Ok(entries) = fs::read_dir(state.config.state_dir.join("logs")) {
        for entry in entries.flatten() {
            if entry
                .metadata()
                .ok()
                .and_then(|metadata| metadata.modified().ok())
                .is_some_and(|modified| modified < log_cutoff)
            {
                let _ = fs::remove_file(entry.path());
            }
        }
    }
}

fn spawn_retention_scheduler(state: Arc<AppState>) {
    tokio::spawn(async move {
        run_retention_once(&state).await;
        let mut interval = time::interval(state.config.search_retention.cleanup_interval);
        interval.set_missed_tick_behavior(time::MissedTickBehavior::Skip);
        interval.tick().await;
        loop {
            interval.tick().await;
            run_retention_once(&state).await;
        }
    });
}

async fn database_vacuum_value(state: &AppState) -> serde_json::Value {
    if let Some(db) = state.db.as_ref() {
        match db.vacuum().await {
            Ok(()) => serde_json::json!({
                "vacuumed": true,
                "enabled": true,
                "status": "ok",
            }),
            Err(error) => {
                eprintln!("database vacuum failed: {error}");
                serde_json::json!({
                    "vacuumed": false,
                    "enabled": true,
                    "status": "error",
                    "error": "database vacuum unavailable",
                })
            }
        }
    } else {
        serde_json::json!({
            "vacuumed": false,
            "enabled": false,
            "status": "skipped",
            "note": "database not initialized",
        })
    }
}

async fn handle_http_connection(stream: TcpStream, state: Arc<AppState>) -> Result<(), String> {
    let remote_addr = stream.peer_addr().ok();
    handle_http_stream(stream, remote_addr, false, state).await
}

async fn handle_http_stream<S>(
    stream: S,
    remote_addr: Option<SocketAddr>,
    secure: bool,
    state: Arc<AppState>,
) -> Result<(), String>
where
    S: tokio::io::AsyncRead + tokio::io::AsyncWrite + Unpin + Send + 'static,
{
    let (read_half, write_half) = tokio::io::split(stream);
    let mut reader = tokio::io::BufReader::new(read_half);
    let mut writer = tokio::io::BufWriter::new(write_half);

    loop {
        let request_timer = logging::start_timer();

        // Read next request (returns None on clean close, Err on 413/malformed)
        let read_result = http_server::read_http_request_with_body_limit(
            &mut reader,
            state.config.controller_web_max_request_body_size,
        )
        .await;
        let (req, keep_alive) = match read_result {
            Ok(Some(pair)) => pair,
            Ok(None) => break, // client closed connection
            Err(e) => {
                if e.contains("too large")
                    && state.config.controller_compatibility_target
                        == ControllerCompatibilityTarget::Slskdn
                {
                    // Frozen slskdN#65a14a8 lets Kestrel's body-limit
                    // BadHttpRequestException reach its generic exception
                    // handler, producing a 500 Problem Details response.
                    // Upstream correction: snapetech/slskdN#276.
                    let body = format!(
                        "{{\"title\":\"Internal Server Error\",\"status\":500,\"detail\":\"An unexpected error occurred.\",\"traceId\":\"{}\"}}",
                        uuid::Uuid::new_v4().simple()
                    );
                    let _ = writer
                        .write_all(
                            format!(
                                "HTTP/1.1 500 Internal Server Error\r\ncontent-type: application/problem+json\r\ncache-control: no-cache,no-store\r\nexpires: -1\r\npragma: no-cache\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{}",
                                body.len(),
                                body
                            )
                            .as_bytes(),
                        )
                        .await;
                    let _ = writer.flush().await;
                    break;
                }
                let (status, body) = if e.contains("too large") {
                    (
                        "413 Payload Too Large",
                        r#"{"error":"request body too large"}"#,
                    )
                } else {
                    ("400 Bad Request", r#"{"error":"bad request"}"#)
                };
                let _ = writer
                    .write_all(
                        format!(
                            "HTTP/1.1 {status}\r\ncontent-type: application/json\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{}",
                            body.len(),
                            body
                        )
                        .as_bytes(),
                    )
                    .await;
                let _ = writer.flush().await;
                break;
            }
        };

        if state.config.controller_web.https.force && !secure {
            let host = req.headers.host.as_deref().unwrap_or("localhost");
            let hostname = host
                .strip_prefix('[')
                .and_then(|value| value.split_once(']').map(|(host, _)| format!("[{host}]")))
                .unwrap_or_else(|| host.split(':').next().unwrap_or("localhost").to_owned());
            let https_port = state
                .config
                .controller_web
                .https
                .binds
                .first()
                .map_or(5031, SocketAddr::port);
            let location = format!("https://{hostname}:{https_port}{}", req.path);
            let response = format!(
                "HTTP/1.1 307 Temporary Redirect\r\nLocation: {location}\r\nContent-Length: 0\r\nConnection: close\r\n\r\n"
            );
            writer
                .write_all(response.as_bytes())
                .await
                .map_err(|error| error.to_string())?;
            writer.flush().await.map_err(|error| error.to_string())?;
            break;
        }

        let method = req.method.as_str();
        let path_storage;
        let path = if state.config.controller_web.url_base == "/" {
            req.path.as_str()
        } else {
            let (request_path, query) = req
                .path
                .split_once('?')
                .map_or((req.path.as_str(), None), |(path, query)| {
                    (path, Some(query))
                });
            let base = state.config.controller_web.url_base.as_str();
            let stripped = if request_path == base {
                Some("/")
            } else {
                request_path
                    .strip_prefix(base)
                    .filter(|path| path.starts_with('/'))
            };
            let Some(stripped) = stripped else {
                let response = routing::not_found_response();
                http_server::write_http_response(&mut writer, &response, keep_alive, "").await?;
                if !keep_alive {
                    break;
                }
                continue;
            };
            path_storage = query.map_or_else(
                || stripped.to_owned(),
                |query| format!("{stripped}?{query}"),
            );
            path_storage.as_str()
        };
        let body = match req.body_as_str() {
            Ok(body) => body,
            Err(_) => {
                let body = r#"{"error":"request body must be valid UTF-8"}"#;
                let _ = writer
                    .write_all(
                        format!(
                            "HTTP/1.1 400 Bad Request\r\ncontent-type: application/json\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{}",
                            body.len(),
                            body
                        )
                        .as_bytes(),
                    )
                    .await;
                let _ = writer.flush().await;
                break;
            }
        };
        let websocket_route = routing::parse_route(method, path);
        let websocket_path = if let Some(versioned_path) = websocket_route
            .normalized_path
            .strip_prefix("/api/v0/")
            .or_else(|| websocket_route.normalized_path.strip_prefix("/api/v1/"))
            .or_else(|| websocket_route.normalized_path.strip_prefix("/api/v2/"))
        {
            format!("/api/{}", versioned_path)
        } else {
            websocket_route.normalized_path.to_string()
        };
        let websocket_protocol_authorization = (method == "GET"
            && websocket_path == "/api/events/ws")
            .then(|| {
                websocket_protocol_authorization(req.headers.sec_websocket_protocol.as_deref())
            })
            .flatten();
        if mixed_websocket_auth_credentials(
            &req.headers,
            websocket_protocol_authorization.as_deref(),
        ) {
            let response = routing::bad_request_response("multiple authentication mechanisms");
            let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
            break;
        }
        let api_key_authorization = req
            .headers
            .x_api_key
            .as_ref()
            .map(|api_key| format!("ApiKey {api_key}"));
        let authorization = req
            .headers
            .authorization
            .as_deref()
            .or(api_key_authorization.as_deref())
            .or(websocket_protocol_authorization.as_deref());
        let mut sec_headers = RequestSecurityHeaders::from_http_headers(&req.headers);
        sec_headers.remote_addr = remote_addr;

        // The frozen slskdN controller applies distinct fixed-window partitions
        // before authorization. An authenticated principal bypasses only the
        // general anonymous API partition; mesh, inbox, event injection, and
        // warm-cache policies still apply.
        let rate_limit_user = authenticated_rate_limit_user_key(
            &state.config,
            authorization,
            sec_headers.cookie.as_deref(),
        );
        let username = rate_limit_user.as_deref();
        let rate_limit_remote_addr =
            rate_limit_remote_addr(&state.config, remote_addr, &req.headers);
        let controller_metrics_request =
            method == "GET" && path == controller_metrics_path(&state.config);
        let controller_rate_policy = controller_rate_limit_policy(
            &state.config,
            method,
            path,
            username,
            rate_limit_remote_addr,
        );
        if controller_rate_policy
            .as_ref()
            .is_some_and(|policy| policy.max_requests == 0)
        {
            // Frozen slskdN#65a14a8 accepts non-positive permit counts,
            // then FixedWindowRateLimiter throws when the affected partition
            // is first materialized. Its exception middleware exposes the
            // failure as generic 500 Problem Details.
            let body = format!(
                "{{\"title\":\"Internal Server Error\",\"status\":500,\"detail\":\"An unexpected error occurred.\",\"traceId\":\"{}\"}}",
                uuid::Uuid::new_v4().simple()
            );
            let _ = writer
                .write_all(
                    format!(
                        "HTTP/1.1 500 Internal Server Error\r\ncontent-type: application/problem+json\r\ncache-control: no-cache,no-store\r\nexpires: -1\r\npragma: no-cache\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{}",
                        body.len(),
                        body
                    )
                    .as_bytes(),
                )
                .await;
            let _ = writer.flush().await;
            break;
        }
        let allowed = if controller_metrics_request {
            true
        } else if let Some(policy) = controller_rate_policy.as_ref() {
            state
                .rate_limiter
                .check_ip_partition(
                    rate_limit_remote_addr,
                    &policy.partition,
                    policy.max_requests,
                    policy.window_seconds,
                )
                .await
        } else {
            true
        };

        if method == "GET" && websocket_path == "/api/events/ws" {
            if !allowed {
                let response = routing::HttpResponse {
                    status: "429 Too Many Requests",
                    content_type: "",
                    body: String::new(),
                };
                let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
                break;
            }
            let fallback_host = state.config.http_bind.to_string();
            if !request_origin_matches_host(&sec_headers, &fallback_host) {
                let response = routing::forbidden_response("websocket origin rejected");
                let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
                break;
            }

            if request_uses_revoked_jwt(&state, authorization).await {
                let response = routing::unauthorized_response();
                let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
                break;
            }

            if let Err(reason) = routing::check_route_auth(
                &state.config,
                method,
                &websocket_path,
                authorization,
                &sec_headers,
            ) {
                let response = match reason {
                    "unauthorized" => routing::unauthorized_response(),
                    "forbidden" => routing::forbidden_response("forbidden"),
                    _ => routing::forbidden_response(reason),
                };
                let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
                break;
            }

            let websocket_key = req.headers.sec_websocket_key.as_deref();
            let websocket_version = req.headers.sec_websocket_version.as_deref();
            let upgrade = req.headers.upgrade.as_deref();
            let is_upgrade = req.headers.connection_has_token("upgrade")
                && upgrade == Some("websocket")
                && websocket_version == Some("13");

            if let Some(websocket_key) =
                websocket_key.filter(|key| is_upgrade && events_ws::valid_sec_websocket_key(key))
            {
                let Ok(_websocket_permit) =
                    Arc::clone(&state.websocket_connections).try_acquire_owned()
                else {
                    let response = routing::HttpResponse {
                        status: "503 Service Unavailable",
                        content_type: "application/json",
                        body: r#"{"error":"too many websocket connections"}"#.to_owned(),
                    };
                    let _ =
                        http_server::write_http_response(&mut writer, &response, false, "").await;
                    break;
                };
                let accepted_protocol =
                    websocket_auth_protocol(req.headers.sec_websocket_protocol.as_deref());
                events_ws::write_upgrade_response(&mut writer, websocket_key, accepted_protocol)
                    .await?;
                events_ws::stream_events(
                    reader,
                    &mut writer,
                    &state.events,
                    state.event_tx.subscribe(),
                )
                .await?;
            } else {
                let response = routing::bad_request_response("invalid websocket upgrade");
                let _ = http_server::write_http_response(&mut writer, &response, false, "").await;
            }
            break;
        }

        // Log request
        let req_log = logging::HttpRequestLog {
            method: method.to_string(),
            path: path.to_string(),
            query: req.query.clone(),
            remote_addr: remote_addr.map(|a| a.to_string()),
            timestamp: logging::format_timestamp(),
        };
        let request_id = generate_request_id();

        // Frozen slskdN only installs CORS middleware when enabled with a
        // non-empty origin list, and only short-circuits genuine preflights.
        // The slskd profile retains slskR's established OPTIONS contract.
        let slskdn_cors_middleware_active = state.config.controller_compatibility_target
            == ControllerCompatibilityTarget::Slskdn
            && state.config.controller_web_cors.enabled
            && !state.config.controller_web_cors.allowed_origins.is_empty();
        let slskdn_cors_preflight = slskdn_cors_middleware_active
            && is_cors_preflight(method)
            && req.headers.origin.is_some()
            && req.headers.access_control_request_method.is_some();
        if (state.config.controller_compatibility_target == ControllerCompatibilityTarget::Slskd
            && is_cors_preflight(method))
            || slskdn_cors_preflight
        {
            let fallback_host = state.config.http_bind.to_string();
            let cors_str = controller_cors_headers(
                &state.config,
                &req.headers,
                &fallback_host,
                slskdn_cors_preflight,
            );
            let status = if slskdn_cors_preflight {
                "204 No Content"
            } else {
                "200 OK"
            };
            let _ = writer
                .write_all(
                    format!(
                        "HTTP/1.1 {status}\r\ncontent-length: 0\r\nconnection: {}\r\n{}\r\n",
                        if keep_alive { "keep-alive" } else { "close" },
                        cors_str
                    )
                    .as_bytes(),
                )
                .await;
            let _ = writer.flush().await;
            if !keep_alive {
                break;
            }
            continue;
        }

        let non_api_controller_route = path == "/.well-known/webfinger"
            || path.starts_with("/actors/")
            || path == "/mesh/http/services"
            || path == "/swagger"
            || path.starts_with("/swagger/")
            || path == controller_metrics_path(&state.config);
        if matches!(method, "GET" | "HEAD")
            && allowed
            && !non_api_controller_route
            && !state.config.controller_headless
        {
            let fallback_host = state.config.http_bind.to_string();
            let cors_str =
                controller_cors_headers(&state.config, &req.headers, &fallback_host, false);
            match write_web_static_response(
                &mut writer,
                path,
                Some(&state.config.controller_web.content_path),
                method == "GET",
                keep_alive,
                &cors_str,
            )
            .await
            {
                Ok(Some(content_length)) => {
                    let resp_log = logging::HttpResponseLog {
                        status_code: 200,
                        content_length,
                        duration_ms: logging::elapsed_ms(request_timer),
                        error: None,
                    };
                    let log_config = logging::LogConfig {
                        level: *state.log_level.read().await,
                        log_requests: state.config.controller_web.logging,
                        log_responses: state.config.controller_web.logging,
                        log_errors_only: false,
                        no_color: state.config.logger.no_color,
                    };
                    logging::log_transaction(
                        &log_config,
                        &logging::HttpTransactionLog {
                            request: req_log.clone(),
                            response: resp_log.clone(),
                        },
                    );
                    record_http_log(
                        &state,
                        &request_id,
                        &logging::HttpTransactionLog {
                            request: req_log,
                            response: resp_log,
                        },
                    )
                    .await;
                    if !keep_alive {
                        break;
                    }
                    continue;
                }
                Ok(None) => {}
                Err(error) => {
                    eprintln!("web static response failed: {error}");
                    let response = web_static_error_response(&error);
                    let _ =
                        http_server::write_http_response(&mut writer, &response, false, "").await;
                    break;
                }
            }
        }

        let request_target = req.query.as_deref().map(|query| format!("{path}?{query}"));
        let routed_path = request_target.as_deref().unwrap_or(path);
        let mut response = if !allowed {
            routing::HttpResponse {
                status: "429 Too Many Requests",
                content_type: "",
                body: String::new(),
            }
        } else {
            match route_http_request_with_headers(
                method,
                routed_path,
                authorization,
                body,
                &state,
                sec_headers.clone(),
            )
            .await
            {
                Ok(r) => r,
                Err(e) => routing::HttpResponse {
                    status: "500 Internal Server Error",
                    content_type: "application/json",
                    body: format!("{{\"error\":\"{}\"}}", json_escape(&e)),
                },
            }
        };

        let application_dump = application_dump_request(method, path, &state.config);
        let preview_ticket = preview_stream_ticket_path(path);
        let preview_stream = preview_ticket.is_some();
        let mut remote_preview = None;
        let mut remote_preview_head = None;
        let mut preview_permit = None;
        if preview_stream
            && allowed
            && matches!(method, "GET" | "HEAD")
            && response.status == "200 OK"
        {
            match Arc::clone(&state.preview_streams).try_acquire_owned() {
                Ok(permit) => preview_permit = Some(permit),
                Err(_) => {
                    response = routing::HttpResponse {
                        status: "429 Too Many Requests",
                        content_type: "application/json",
                        body: r#"{"error":"preview stream limit reached"}"#.to_owned(),
                    };
                }
            }
        }
        let stream_file = if allowed
            && (application_dump || matches!(method, "GET" | "HEAD"))
            && response.status == "200 OK"
        {
            if application_dump {
                match open_application_dump_file(&state).await {
                    Ok(stream) => Some(stream),
                    Err(error) => {
                        eprintln!("application dump failed: {error}");
                        response = routing::internal_server_error_response(
                            "failed to create application dump",
                        );
                        None
                    }
                }
            } else if let Some(stream_id) = primary_stream_id(path) {
                match open_primary_stream_file(&state, &stream_id, req.query.as_deref()).await {
                    Ok(Some(stream)) => Some(stream),
                    Ok(None) => {
                        response = routing::not_found_response();
                        None
                    }
                    Err(error) => {
                        eprintln!("local stream open failed: {error}");
                        response = routing::not_found_response();
                        None
                    }
                }
            } else if let Some((family, ticket)) = preview_ticket.as_ref() {
                match open_local_preview_stream_file(&state, family, ticket).await {
                    Ok(Some(stream)) => Some(stream),
                    Ok(None) => {
                        if method == "HEAD" {
                            let ticket_record = {
                                let mut tickets = state.stream_tickets.write().await;
                                tickets.get(ticket)
                            };
                            match remote_preview_head_ticket(ticket_record, family) {
                                Some(record) => remote_preview_head = Some(record),
                                None => response = routing::not_found_response(),
                            }
                            None
                        } else if *family == "mesh" {
                            match open_remote_mesh_preview_file(&state, family, ticket).await {
                                Ok(stream) => stream,
                                Err(error) => {
                                    eprintln!("remote mesh preview open failed: {error}");
                                    response = routing::not_found_response();
                                    None
                                }
                            }
                        } else {
                            match open_remote_peer_preview_stream(&state, family, ticket).await {
                                Ok(stream) => remote_preview = stream,
                                Err(error) => {
                                    eprintln!("remote preview stream open failed: {error}");
                                    response = routing::not_found_response();
                                }
                            }
                            None
                        }
                    }
                    Err(error) => {
                        eprintln!("local preview stream open failed: {error}");
                        response = routing::not_found_response();
                        None
                    }
                }
            } else {
                None
            }
        } else {
            None
        };

        // Build extra headers. ASP.NET Core's frozen global limiter does not
        // emit quota headers unless an OnRejected handler adds them; neither
        // frozen controller does so.
        let cache_hdr =
            cache_control_header(method, response.content_type, path).unwrap_or_default();
        let etag_hdr = if method == "GET" && response.content_type.contains("json") {
            format!("ETag: {}\r\n", generate_etag(&response.body))
        } else {
            String::new()
        };
        let fallback_host = state.config.http_bind.to_string();
        let cors_str = controller_cors_headers(&state.config, &req.headers, &fallback_host, false);
        let location_hdr = if method == "GET"
            && path == "/swagger"
            && response.status == "301 Moved Permanently"
        {
            "Location: swagger/index.html\r\n"
        } else {
            ""
        };
        let metrics_authenticate_hdr = if controller_metrics_request
            && response.status == "401 Unauthorized"
            && state.config.controller_compatibility_target == ControllerCompatibilityTarget::Slskdn
        {
            "WWW-Authenticate: Basic realm=\"metrics\"\r\n"
        } else {
            ""
        };
        let extra = format!(
            "{}{}{}{}{}X-Request-ID: {}\r\n",
            cache_hdr, etag_hdr, cors_str, location_hdr, metrics_authenticate_hdr, request_id
        );

        if let Some(stream) = stream_file {
            let cleanup_path = stream.cleanup_path.clone();
            let disposition = if application_dump {
                "Content-Disposition: attachment; filename=slskd.dmp; filename*=UTF-8''slskd.dmp\r\n"
            } else {
                ""
            };
            let stream_extra = format!(
                "{}{}X-Request-ID: {}\r\n",
                cors_str, disposition, request_id
            );
            let written = http_server::write_file_response(
                &mut writer,
                stream.file,
                stream.length,
                &stream.content_type,
                req.headers.range.as_deref(),
                !preview_stream && !application_dump,
                application_dump || method == "GET",
                keep_alive,
                &stream_extra,
            )
            .await;
            if let Some(path) = cleanup_path {
                let _ = fs::remove_file(path);
            }
            let written = written?;
            let resp_log = logging::HttpResponseLog {
                status_code: written.status_code,
                content_length: usize::try_from(written.content_length).unwrap_or(usize::MAX),
                duration_ms: logging::elapsed_ms(request_timer),
                error: None,
            };
            let log_config = logging::LogConfig {
                level: *state.log_level.read().await,
                log_requests: state.config.controller_web.logging,
                log_responses: state.config.controller_web.logging,
                log_errors_only: false,
                no_color: state.config.logger.no_color,
            };
            logging::log_transaction(
                &log_config,
                &logging::HttpTransactionLog {
                    request: req_log.clone(),
                    response: resp_log.clone(),
                },
            );
            record_http_log(
                &state,
                &request_id,
                &logging::HttpTransactionLog {
                    request: req_log,
                    response: resp_log,
                },
            )
            .await;
            drop(preview_permit);
            if !keep_alive {
                break;
            }
            continue;
        }

        if let Some(ticket) = remote_preview_head {
            let stream_extra = format!("{}X-Request-ID: {}\r\n", cors_str, request_id);
            let written = write_remote_preview_head_response(
                &mut writer,
                &ticket,
                keep_alive,
                &stream_extra,
                state.config.peer_response_timeout,
            )
            .await?;
            let resp_log = logging::HttpResponseLog {
                status_code: written.status_code,
                content_length: usize::try_from(written.content_length).unwrap_or(usize::MAX),
                duration_ms: logging::elapsed_ms(request_timer),
                error: None,
            };
            let log_config = logging::LogConfig {
                level: *state.log_level.read().await,
                log_requests: state.config.controller_web.logging,
                log_responses: state.config.controller_web.logging,
                log_errors_only: false,
                no_color: state.config.logger.no_color,
            };
            logging::log_transaction(
                &log_config,
                &logging::HttpTransactionLog {
                    request: req_log.clone(),
                    response: resp_log.clone(),
                },
            );
            record_http_log(
                &state,
                &request_id,
                &logging::HttpTransactionLog {
                    request: req_log,
                    response: resp_log,
                },
            )
            .await;
            drop(preview_permit);
            if !keep_alive {
                break;
            }
            continue;
        }

        if let Some(preview) = remote_preview {
            let stream_extra = format!("{}X-Request-ID: {}\r\n", cors_str, request_id);
            let written = write_peer_preview_response(
                &mut writer,
                preview,
                method == "GET",
                keep_alive,
                &stream_extra,
                state.config.peer_response_timeout,
            )
            .await?;
            let resp_log = logging::HttpResponseLog {
                status_code: written.status_code,
                content_length: usize::try_from(written.content_length).unwrap_or(usize::MAX),
                duration_ms: logging::elapsed_ms(request_timer),
                error: None,
            };
            let log_config = logging::LogConfig {
                level: *state.log_level.read().await,
                log_requests: state.config.controller_web.logging,
                log_responses: state.config.controller_web.logging,
                log_errors_only: false,
                no_color: state.config.logger.no_color,
            };
            logging::log_transaction(
                &log_config,
                &logging::HttpTransactionLog {
                    request: req_log.clone(),
                    response: resp_log.clone(),
                },
            );
            record_http_log(
                &state,
                &request_id,
                &logging::HttpTransactionLog {
                    request: req_log,
                    response: resp_log,
                },
            )
            .await;
            drop(preview_permit);
            if !keep_alive {
                break;
            }
            continue;
        }

        // Write response
        http_server::write_http_response(&mut writer, &response, keep_alive, &extra).await?;

        // Log
        let resp_log = logging::HttpResponseLog {
            status_code: logging::status_code_from_string(response.status),
            content_length: response.body.len(),
            duration_ms: logging::elapsed_ms(request_timer),
            error: None,
        };
        let log_config = logging::LogConfig {
            level: *state.log_level.read().await,
            log_requests: state.config.controller_web.logging,
            log_responses: state.config.controller_web.logging,
            log_errors_only: false,
            no_color: state.config.logger.no_color,
        };
        logging::log_transaction(
            &log_config,
            &logging::HttpTransactionLog {
                request: req_log.clone(),
                response: resp_log.clone(),
            },
        );
        record_http_log(
            &state,
            &request_id,
            &logging::HttpTransactionLog {
                request: req_log,
                response: resp_log,
            },
        )
        .await;

        if !keep_alive {
            break;
        }
    }
    Ok(())
}

pub fn index_html() -> String {
    if let Some(html) = read_web_index_html() {
        return html;
    }

    fallback_dashboard_html()
}

pub fn fallback_dashboard_html() -> String {
    r#"<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>slskr</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #101317;
      --panel: #181d22;
      --panel-soft: #20262c;
      --line: #313941;
      --text: #edf2f5;
      --muted: #a9b4bd;
      --green: #74c69d;
      --blue: #8ab4f8;
      --amber: #f2c66d;
      --red: #ff8a80;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      min-width: 320px;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: var(--bg);
      color: var(--text);
    }
    main {
      width: min(1180px, calc(100% - 32px));
      margin: 0 auto;
      padding: 24px 0 40px;
    }
    header {
      display: flex;
      align-items: flex-end;
      justify-content: space-between;
      gap: 16px;
      padding: 0 0 18px;
      border-bottom: 1px solid var(--line);
    }
    h1, h2 {
      margin: 0;
      letter-spacing: 0;
    }
    h1 { font-size: 28px; line-height: 1.1; }
    h2 { font-size: 15px; line-height: 1.3; }
    .version { color: var(--muted); font-size: 13px; margin-top: 6px; }
    .status {
      display: inline-flex;
      align-items: center;
      gap: 8px;
      min-height: 30px;
      padding: 5px 10px;
      border: 1px solid var(--line);
      border-radius: 6px;
      background: var(--panel);
      color: var(--muted);
      font-size: 13px;
      white-space: nowrap;
    }
    .notice {
      margin-top: 18px;
      padding: 12px 14px;
      border: 1px solid var(--amber);
      border-radius: 8px;
      background: rgba(242, 198, 109, .12);
      color: var(--text);
      font-size: 14px;
      line-height: 1.45;
    }
    .notice a {
      color: var(--blue);
      font-weight: 700;
    }
    .dot {
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background: var(--amber);
    }
    .dot.online { background: var(--green); }
    .dot.error { background: var(--red); }
    .grid {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 12px;
      margin-top: 18px;
    }
    .panel {
      background: var(--panel);
      border: 1px solid var(--line);
      border-radius: 8px;
      padding: 14px;
      min-width: 0;
    }
    .metric {
      min-height: 96px;
    }
    .label {
      color: var(--muted);
      font-size: 12px;
      text-transform: uppercase;
      letter-spacing: .08em;
    }
    .value {
      margin-top: 8px;
      font-size: 30px;
      line-height: 1;
      font-weight: 720;
      overflow-wrap: anywhere;
    }
    .sub {
      margin-top: 8px;
      color: var(--muted);
      font-size: 13px;
      overflow-wrap: anywhere;
    }
    .wide { grid-column: span 2; }
    .full { grid-column: 1 / -1; }
    .toolbar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      margin-bottom: 12px;
    }
    .filters {
      display: flex;
      flex-wrap: wrap;
      justify-content: flex-end;
      gap: 8px;
      min-width: 0;
    }
    .filters input, .filters select {
      width: 150px;
      min-height: 32px;
      font-size: 13px;
    }
    .actions {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }
    form {
      display: grid;
      grid-template-columns: 1fr auto;
      gap: 8px;
      margin-top: 12px;
    }
    .stack {
      display: grid;
      grid-template-columns: 1fr;
      gap: 8px;
    }
    input, select {
      width: 100%;
      min-height: 34px;
      border: 1px solid var(--line);
      border-radius: 6px;
      background: var(--panel-soft);
      color: var(--text);
      padding: 6px 9px;
      font: inherit;
      min-width: 0;
    }
    input:focus, select:focus, button:focus {
      outline: 2px solid var(--blue);
      outline-offset: 1px;
    }
    button {
      border: 1px solid var(--line);
      border-radius: 6px;
      background: var(--panel-soft);
      color: var(--text);
      min-height: 32px;
      padding: 6px 10px;
      font: inherit;
      cursor: pointer;
    }
    button:hover { border-color: var(--blue); }
    .button-row {
      display: flex;
      flex-wrap: wrap;
      gap: 6px;
    }
    .button-row button {
      min-height: 28px;
      padding: 4px 8px;
      font-size: 12px;
    }
    table {
      width: 100%;
      border-collapse: collapse;
      table-layout: fixed;
      font-size: 13px;
    }
    th, td {
      padding: 9px 8px;
      border-top: 1px solid var(--line);
      text-align: left;
      vertical-align: top;
      overflow-wrap: anywhere;
    }
    th {
      color: var(--muted);
      font-weight: 650;
      font-size: 12px;
    }
    .empty {
      color: var(--muted);
      padding: 10px 0 0;
      font-size: 13px;
    }
    .toast {
      min-height: 20px;
      color: var(--muted);
      font-size: 13px;
      margin-top: 8px;
      overflow-wrap: anywhere;
    }
    @media (max-width: 900px) {
      .grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
      .wide { grid-column: 1 / -1; }
      .actions { grid-template-columns: 1fr; }
    }
    @media (max-width: 560px) {
      main { width: min(100% - 20px, 1180px); padding-top: 16px; }
      header { align-items: flex-start; flex-direction: column; }
      .grid { grid-template-columns: 1fr; }
      .metric { min-height: 86px; }
      .value { font-size: 26px; }
      table { font-size: 12px; }
      th, td { padding: 8px 6px; }
    }
  </style>
</head>
<body>
  <main>
    <header>
      <div>
        <h1>slskr</h1>
        <div class="version">Fallback dashboard · __VERSION__</div>
      </div>
      <div class="status"><span id="status-dot" class="dot"></span><span id="status-text">Loading</span></div>
    </header>
    <section class="notice">
      This is the minimal fallback dashboard. The full React Web UI is the default at
      <a href="/">/</a> when production assets are installed. If this page appears at
      the root URL, build or install <code>web/build</code>, or set
      <code>SLSKR_WEB_BUILD_DIR</code> to the built UI directory.
    </section>

    <section class="grid" aria-live="polite">
      <article class="panel metric"><div class="label">Session</div><div id="session-state" class="value">-</div><div id="session-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Shares</div><div id="share-files" class="value">-</div><div id="share-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Searches</div><div id="search-count" class="value">-</div><div id="search-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Transfers</div><div id="transfer-count" class="value">-</div><div id="transfer-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Listeners</div><div id="listener-count" class="value">-</div><div id="listener-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Browse Cache</div><div id="browse-count" class="value">-</div><div id="browse-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Messages</div><div id="message-count" class="value">-</div><div id="message-sub" class="sub">-</div></article>
      <article class="panel metric"><div class="label">Rooms</div><div id="room-count" class="value">-</div><div id="room-sub" class="sub">-</div></article>

      <section class="actions full">
        <article class="panel">
          <h2>Session</h2>
          <div class="button-row" id="session-actions">
            <button type="button" data-session-action="connect">Connect</button>
            <button type="button" data-session-action="ping">Ping</button>
            <button type="button" data-session-action="privileges/check">Privileges</button>
            <button type="button" data-session-action="disconnect">Disconnect</button>
          </div>
          <div id="session-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Search</h2>
          <form id="search-form">
            <div class="stack">
              <input id="search-query" name="query" autocomplete="off" placeholder="artist album track">
              <select id="search-target" name="target">
                <option value="global">Global</option>
                <option value="wishlist">Wishlist</option>
                <option value="user">User</option>
                <option value="room">Room</option>
              </select>
              <input id="search-target-name" name="target_name" autocomplete="off" placeholder="user or room">
            </div>
            <button type="submit">Start</button>
          </form>
          <div id="search-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Watch User</h2>
          <form id="watch-form">
            <input id="watch-username" name="username" autocomplete="off" placeholder="username">
            <div class="button-row">
              <button type="submit">Watch</button>
              <button id="unwatch-button" type="button">Unwatch</button>
            </div>
          </form>
          <div id="watch-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Browse User</h2>
          <form id="browse-request-form">
            <input id="browse-username" name="username" autocomplete="off" placeholder="username">
            <input id="browse-folder" name="folder" autocomplete="off" placeholder="folder">
            <button type="submit">Browse</button>
          </form>
          <div id="browse-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Share Scan</h2>
          <form id="share-rescan-form">
            <button type="submit">Rescan</button>
          </form>
          <div id="share-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Transfer</h2>
          <form id="transfer-form">
            <div class="stack">
              <input id="transfer-filename" name="filename" autocomplete="off" placeholder="remote/file.ext">
              <input id="transfer-peer" name="peer" autocomplete="off" placeholder="peer">
              <input id="transfer-local-path" name="local_path" autocomplete="off" placeholder="local path">
              <input id="transfer-size" name="size" inputmode="numeric" autocomplete="off" placeholder="size bytes">
              <input id="transfer-progress" name="progress" inputmode="numeric" autocomplete="off" placeholder="progress bytes">
              <select id="transfer-direction" name="direction">
                <option value="0">Download</option>
                <option value="1">Upload</option>
              </select>
            </div>
            <button type="submit">Queue</button>
          </form>
          <div id="transfer-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Message</h2>
          <form id="message-form">
            <div class="stack">
              <input id="message-username" name="username" autocomplete="off" placeholder="username">
              <input id="message-body" name="body" autocomplete="off" placeholder="message">
            </div>
            <button type="submit">Send</button>
          </form>
          <div id="message-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Join Room</h2>
          <form id="room-join-form">
            <input id="room-join-name" name="room" autocomplete="off" placeholder="room">
            <button type="submit">Join</button>
          </form>
          <div id="room-join-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Room Message</h2>
          <form id="room-message-form">
            <div class="stack">
              <input id="room-message-name" name="room" autocomplete="off" placeholder="room">
              <input id="room-message-username" name="username" autocomplete="off" placeholder="username">
              <input id="room-message-body" name="body" autocomplete="off" placeholder="message">
            </div>
            <button type="submit">Send</button>
          </form>
          <div id="room-message-action-status" class="toast"></div>
        </article>
        <article class="panel">
          <h2>Browser Session</h2>
          <form id="token-form">
            <input id="api-token" name="token" type="password" autocomplete="current-password" autocapitalize="none" spellcheck="false" placeholder="bearer token">
            <button type="submit">Sign in</button>
          </form>
          <div id="token-action-status" class="toast"></div>
        </article>
      </section>

      <section class="panel wide">
        <div class="toolbar">
          <h2>Recent Searches</h2>
          <div class="filters">
            <input id="search-filter-q" autocomplete="off" placeholder="filter">
            <select id="search-filter-status">
              <option value="">Any status</option>
              <option value="active">Active</option>
              <option value="completed">Completed</option>
            </select>
            <button id="refresh-searches" type="button">Refresh</button>
          </div>
        </div>
        <div id="search-table"></div>
      </section>
      <section class="panel wide">
        <div class="toolbar">
          <h2>Transfer Queue</h2>
          <div class="filters">
            <input id="transfer-filter-q" autocomplete="off" placeholder="filter">
            <select id="transfer-filter-status">
              <option value="">Any status</option>
              <option value="queued">Queued</option>
              <option value="in_progress">In progress</option>
              <option value="succeeded">Succeeded</option>
              <option value="cancelled">Cancelled</option>
              <option value="failed">Failed</option>
            </select>
            <button id="refresh-transfers" type="button">Refresh</button>
          </div>
        </div>
        <div id="transfer-table"></div>
      </section>
      <section class="panel wide">
        <div class="toolbar"><h2>Users</h2><button id="refresh-users" type="button">Refresh</button></div>
        <div id="user-table"></div>
      </section>
      <section class="panel wide">
        <div class="toolbar">
          <h2>Share Catalog</h2>
          <div class="filters">
            <input id="share-filter-q" autocomplete="off" placeholder="filter">
            <input id="share-filter-extension" autocomplete="off" placeholder="extension">
            <button id="refresh-shares" type="button">Refresh</button>
          </div>
        </div>
        <div id="share-table"></div>
      </section>
      <section class="panel wide">
        <div class="toolbar">
          <h2>Messages</h2>
          <div class="filters">
            <input id="message-filter-q" autocomplete="off" placeholder="filter">
            <select id="message-filter-direction">
              <option value="">Any direction</option>
              <option value="inbound">Inbound</option>
              <option value="outbound">Outbound</option>
            </select>
            <button id="refresh-messages" type="button">Refresh</button>
          </div>
        </div>
        <div id="message-table"></div>
      </section>
      <section class="panel wide">
        <div class="toolbar">
          <h2>Rooms</h2>
          <div class="filters">
            <input id="room-filter-q" autocomplete="off" placeholder="filter">
            <select id="room-filter-joined">
              <option value="">Any room</option>
              <option value="true">Joined</option>
              <option value="false">Not joined</option>
            </select>
            <button id="refresh-rooms" type="button">Refresh</button>
            <button id="sync-rooms" type="button">Sync</button>
          </div>
        </div>
        <div id="room-table"></div>
      </section>
      <section class="panel full">
        <div class="toolbar">
          <h2>Browse Cache</h2>
          <div class="filters">
            <input id="browse-filter-q" autocomplete="off" placeholder="filter">
            <select id="browse-filter-status">
              <option value="">Any status</option>
              <option value="requested">Requested</option>
              <option value="indirect_pending">Indirect</option>
              <option value="partial">Partial</option>
              <option value="ready">Ready</option>
              <option value="failed">Failed</option>
            </select>
            <button id="refresh-browse" type="button">Refresh</button>
          </div>
        </div>
        <div id="browse-table"></div>
      </section>
    </section>
  </main>
  <script>
    const text = (id, value) => { document.getElementById(id).textContent = value; };
    const number = (value) => new Intl.NumberFormat().format(value || 0);
    let apiToken = "";
    const bytes = (value) => {
      let amount = value || 0;
      const units = ["B", "KiB", "MiB", "GiB", "TiB"];
      let index = 0;
      while (amount >= 1024 && index < units.length - 1) {
        amount = amount / 1024;
        index += 1;
      }
      return `${amount.toFixed(index === 0 ? 0 : 1)} ${units[index]}`;
    };
    const requestHeaders = (extra = {}) => {
      const headers = { ...extra };
      if (apiToken) headers.authorization = `Bearer ${apiToken}`;
      return headers;
    };
    const fetchJson = async (path) => {
      const response = await fetch(path, { headers: requestHeaders({ "accept": "application/json" }) });
      if (!response.ok) throw new Error(`${response.status} ${response.statusText}`);
      return response.json();
    };
    const deleteJson = async (path) => {
      const response = await fetch(path, {
        method: "DELETE",
        headers: requestHeaders({ "accept": "application/json" })
      });
      if (!response.ok) throw new Error(`${response.status} ${response.statusText}`);
      return response.json();
    };
    const postJson = async (path, body) => {
      const response = await fetch(path, {
        method: "POST",
        headers: requestHeaders({ "accept": "application/json", "content-type": "application/json" }),
        body: JSON.stringify(body)
      });
      if (!response.ok) {
        let message = `${response.status} ${response.statusText}`;
        try {
          const error = await response.json();
          if (error.error) message = error.error;
        } catch (_) {}
        throw new Error(message);
      }
      return response.json();
    };
    const escapeHtml = (value) => String(value ?? "").replace(/[&<>"']/g, (char) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      "\"": "&quot;",
      "'": "&#39;"
    })[char]);
    const table = (rows, columns, empty) => {
      if (!rows.length) return `<div class="empty">${escapeHtml(empty)}</div>`;
      const head = columns.map((column) => `<th>${escapeHtml(column.label)}</th>`).join("");
      const body = rows.map((row) => `<tr>${columns.map((column) => {
        const value = column.value(row);
        return `<td>${column.html ? value : escapeHtml(value)}</td>`;
      }).join("")}</tr>`).join("");
      return `<table><thead><tr>${head}</tr></thead><tbody>${body}</tbody></table>`;
    };
    const field = (id) => document.getElementById(id).value.trim();
    const queryString = (params) => {
      const query = new URLSearchParams();
      Object.entries(params).forEach(([name, value]) => {
        if (value !== undefined && value !== null && value !== "") query.set(name, value);
      });
      return query.toString();
    };
    async function loadStats() {
      const stats = await fetchJson("/api/v0/stats");
      const connected = stats.session?.connected;
      const dot = document.getElementById("status-dot");
      dot.className = `dot ${connected ? "online" : ""}`;
      text("status-text", connected ? "Connected" : stats.session?.state || "Disconnected");
      text("session-state", stats.session?.state || "-");
      const privileges = stats.session?.privileges_seconds == null ? "unknown privileges" : `${number(stats.session.privileges_seconds)}s privileges`;
      text("session-sub", `${number(stats.session?.server_messages_seen)} server messages, ${number(stats.session?.reconnects)} reconnects, ${privileges}`);
      text("share-files", number(stats.shares?.files));
      text("share-sub", `${bytes(stats.shares?.bytes)} across ${number(stats.shares?.roots)} roots`);
      text("search-count", number(stats.searches?.total));
      text("search-sub", `${number(stats.searches?.active)} active, ${number(stats.searches?.results)} results`);
      text("transfer-count", number(stats.transfers?.total));
      text("transfer-sub", `${number(stats.transfers?.in_progress)} active, ${bytes(stats.transfers?.bytes_transferred)} moved`);
      text("listener-count", number((stats.listeners?.regular_accepts || 0) + (stats.listeners?.obfuscated_accepts || 0)));
      text("listener-sub", `${number(stats.listeners?.peer_messages)} peer, ${number(stats.listeners?.errors)} errors`);
      text("browse-count", number(stats.browse?.total));
      text("browse-sub", `${number(stats.browse?.indirect_pending)} indirect, ${number(stats.browse?.partial)} partial, ${number(stats.browse?.ready)} ready, ${number(stats.browse?.failed)} failed, ${number(stats.browse?.files)} files`);
      text("message-count", number(stats.messages?.total));
      text("message-sub", `${number(stats.messages?.inbound)} in, ${number(stats.messages?.outbound)} out`);
      text("room-count", number(stats.rooms?.total));
      text("room-sub", `${number(stats.rooms?.joined)} joined, ${number(stats.rooms?.messages)} messages`);
    }
    async function loadSearches() {
      const query = queryString({
        q: field("search-filter-q"),
        status: field("search-filter-status"),
        limit: 6
      });
      const data = await fetchJson(`/api/v0/searches/records?${query}`);
      document.getElementById("search-table").innerHTML = table(data.entries || [], [
        { label: "Query", value: (row) => row.query },
        { label: "Target", value: (row) => row.target_name ? `${row.target}:${row.target_name}` : row.target },
        { label: "Status", value: (row) => row.status },
        { label: "Results", value: (row) => row.result_count },
        { label: "Actions", html: true, value: (row) => searchActions(row) }
      ], "No searches");
    }
    function searchActions(row) {
      const disabled = row.status === "completed";
      return `<div class="button-row">
        <button type="button" data-search-action="complete" data-search-token="${row.token}" ${disabled ? "disabled" : ""}>Complete</button>
      </div>`;
    }
    async function loadTransfers() {
      const query = queryString({
        q: field("transfer-filter-q"),
        status: field("transfer-filter-status"),
        limit: 6
      });
      const data = await fetchJson(`/api/v0/transfers?${query}`);
      document.getElementById("transfer-table").innerHTML = table(data.entries || [], [
        { label: "File", value: (row) => row.filename },
        { label: "Peer", value: (row) => row.peer_username || "-" },
        { label: "Status", value: (row) => row.status },
        { label: "Progress", value: (row) => `${bytes(row.bytes_transferred)} / ${row.size ? bytes(row.size) : "-"}` },
        { label: "Actions", html: true, value: (row) => transferActions(row) }
      ], "No transfers");
    }
    function transferActions(row) {
      const active = row.status === "in_progress" || row.status === "peer_lookup" || row.status === "peer_negotiating" || row.status === "accepted" || row.status === "indirect_pending";
      const disabledStart = active || row.status === "succeeded" || row.status === "cancelled" || row.status === "failed";
      const disabledFinish = row.status === "succeeded" || row.status === "cancelled" || row.status === "failed";
      return `<div class="button-row">
        <button type="button" data-transfer-action="start" data-transfer-id="${row.id}" ${disabledStart ? "disabled" : ""}>Start</button>
        <button type="button" data-transfer-action="progress" data-transfer-id="${row.id}" ${disabledFinish ? "disabled" : ""}>Progress</button>
        <button type="button" data-transfer-action="complete" data-transfer-id="${row.id}" ${disabledFinish ? "disabled" : ""}>Done</button>
        <button type="button" data-transfer-action="cancel" data-transfer-id="${row.id}" ${disabledFinish ? "disabled" : ""}>Cancel</button>
        <button type="button" data-transfer-action="fail" data-transfer-id="${row.id}" ${disabledFinish ? "disabled" : ""}>Fail</button>
      </div>`;
    }
    async function loadUsers() {
      const data = await fetchJson("/api/v0/users");
      document.getElementById("user-table").innerHTML = table(data.entries || [], [
        { label: "Username", value: (row) => row.username },
        { label: "Watched", value: (row) => row.watched ? "yes" : "no" },
        { label: "Status", value: (row) => row.status || "-" },
        { label: "Files", value: (row) => row.file_count ?? "-" },
        { label: "Speed", value: (row) => row.average_speed ? `${number(row.average_speed)}/s` : "-" },
        { label: "Actions", html: true, value: (row) => userActions(row) }
      ], "No users");
    }
    function userActions(row) {
      return `<div class="button-row">
        <button type="button" data-user-action="watch" data-username="${escapeHtml(row.username)}">Watch</button>
        <button type="button" data-user-action="stats" data-username="${escapeHtml(row.username)}">Stats</button>
        <button type="button" data-user-action="browse" data-username="${escapeHtml(row.username)}">Browse</button>
        <button type="button" data-user-action="unwatch" data-username="${escapeHtml(row.username)}" ${row.watched ? "" : "disabled"}>Unwatch</button>
      </div>`;
    }
    async function loadShares() {
      const query = queryString({
        q: field("share-filter-q"),
        extension: field("share-filter-extension"),
        limit: 8
      });
      const data = await fetchJson(`/api/v0/shares/catalog?${query}`);
      document.getElementById("share-table").innerHTML = table(data.files || [], [
        { label: "Path", value: (row) => row.path },
        { label: "Extension", value: (row) => row.extension || "-" },
        { label: "Size", value: (row) => bytes(row.size) },
        { label: "Attributes", value: (row) => row.attribute_count }
      ], "No indexed files");
    }
    async function loadMessages() {
      const query = queryString({
        q: field("message-filter-q"),
        direction: field("message-filter-direction"),
        limit: 6
      });
      const data = await fetchJson(`/api/v0/messages?${query}`);
      document.getElementById("message-table").innerHTML = table(data.entries || [], [
        { label: "User", value: (row) => row.username },
        { label: "Direction", value: (row) => row.direction },
        { label: "Body", value: (row) => row.body },
        { label: "Ack", value: (row) => row.acknowledged ? "yes" : "no" },
        { label: "Actions", html: true, value: (row) => messageActions(row) }
      ], "No messages");
    }
    function messageActions(row) {
      const disabled = row.acknowledged;
      return `<div class="button-row">
        <button type="button" data-message-action="ack" data-message-id="${row.id}" ${disabled ? "disabled" : ""}>Ack</button>
      </div>`;
    }
    async function loadRooms() {
      const query = queryString({
        q: field("room-filter-q"),
        joined: field("room-filter-joined"),
        limit: 6
      });
      const data = await fetchJson(`/api/v0/rooms?${query}`);
      document.getElementById("room-table").innerHTML = table(data.entries || [], [
        { label: "Room", value: (row) => row.name },
        { label: "Joined", value: (row) => row.joined ? "yes" : "no" },
        { label: "Users", value: (row) => row.user_count ?? "-" },
        { label: "Messages", value: (row) => row.message_count },
        { label: "Last", value: (row) => (row.messages || []).slice(-1)[0]?.body || "-" },
        { label: "Actions", html: true, value: (row) => roomActions(row) }
      ], "No rooms");
    }
    function roomActions(row) {
      return `<div class="button-row">
        <button type="button" data-room-action="leave" data-room="${escapeHtml(row.name)}" ${row.joined ? "" : "disabled"}>Leave</button>
      </div>`;
    }
    async function loadBrowse() {
      const query = queryString({
        q: field("browse-filter-q"),
        status: field("browse-filter-status"),
        limit: 6
      });
      const data = await fetchJson(`/api/v0/browse?${query}`);
      document.getElementById("browse-table").innerHTML = table(data.entries || [], [
        { label: "User", value: (row) => row.username },
        { label: "Status", value: (row) => row.status },
        { label: "Files", value: (row) => row.count },
        { label: "Bytes", value: (row) => bytes(row.total_bytes) }
      ], "No browse records");
    }
    async function loadAll() {
      try {
        await Promise.all([loadStats(), loadSearches(), loadTransfers(), loadUsers(), loadShares(), loadMessages(), loadRooms(), loadBrowse()]);
      } catch (error) {
        document.getElementById("status-dot").className = "dot error";
        text("status-text", error.message);
      }
    }
    async function runSessionAction(action) {
      try {
        await postJson(`/api/v0/session/${action}`, {});
        text("session-action-status", `${action} accepted`);
        await loadStats();
      } catch (error) {
        text("session-action-status", error.message);
      }
    }
    async function submitSearch(event) {
      event.preventDefault();
      const query = document.getElementById("search-query").value.trim();
      const target = document.getElementById("search-target").value;
      const targetName = document.getElementById("search-target-name").value.trim();
      if (!query) {
        text("search-action-status", "Query required");
        return;
      }
      const body = { query, target };
      if (target === "user") body.username = targetName;
      if (target === "room") body.room = targetName;
      try {
        const record = await postJson("/api/v0/searches", body);
        text("search-action-status", `Search ${record.token} started`);
        document.getElementById("search-query").value = "";
        await Promise.all([loadStats(), loadSearches()]);
      } catch (error) {
        text("search-action-status", error.message);
      }
    }
    async function runSearchAction(token, action) {
      try {
        await postJson(`/api/v0/searches/${token}/${action}`, {});
        text("search-action-status", `Search ${token} ${action}`);
        await Promise.all([loadStats(), loadSearches()]);
      } catch (error) {
        text("search-action-status", error.message);
      }
    }
    async function submitWatch(event) {
      event.preventDefault();
      const username = document.getElementById("watch-username").value.trim();
      if (!username) {
        text("watch-action-status", "Username required");
        return;
      }
      try {
        await postJson("/api/v0/users/watch", { username });
        text("watch-action-status", `${username} watched`);
        document.getElementById("watch-username").value = "";
        await Promise.all([loadStats(), loadUsers()]);
      } catch (error) {
        text("watch-action-status", error.message);
      }
    }
    async function submitUnwatch() {
      const username = document.getElementById("watch-username").value.trim();
      if (!username) {
        text("watch-action-status", "Username required");
        return;
      }
      try {
        await deleteJson(`/api/v0/users/${encodeURIComponent(username)}/watch`);
        text("watch-action-status", `${username} unwatched`);
        await Promise.all([loadStats(), loadUsers()]);
      } catch (error) {
        text("watch-action-status", error.message);
      }
    }
    async function submitBrowseRequest(event) {
      event.preventDefault();
      const username = document.getElementById("browse-username").value.trim();
      const folder = document.getElementById("browse-folder").value.trim();
      if (!username) {
        text("browse-action-status", "Username required");
        return;
      }
      try {
        if (folder) {
          await postJson(`/api/v0/users/${encodeURIComponent(username)}/browse/folder`, { folder });
          text("browse-action-status", `Folder browse requested for ${username}`);
        } else {
          await postJson(`/api/v0/users/${encodeURIComponent(username)}/browse/request`, {});
          text("browse-action-status", `Browse requested for ${username}`);
        }
        await Promise.all([loadStats(), loadBrowse()]);
      } catch (error) {
        text("browse-action-status", error.message);
      }
    }
    async function submitShareRescan(event) {
      event.preventDefault();
      try {
        const snapshot = await postJson("/api/v0/shares/rescan", {});
        text("share-action-status", `${number(snapshot.files)} files indexed`);
        await Promise.all([loadStats(), loadShares()]);
      } catch (error) {
        text("share-action-status", error.message);
      }
    }
    async function submitTransfer(event) {
      event.preventDefault();
      const filename = document.getElementById("transfer-filename").value.trim();
      const peer = document.getElementById("transfer-peer").value.trim();
      const localPath = document.getElementById("transfer-local-path").value.trim();
      const size = document.getElementById("transfer-size").value.trim();
      const direction = Number(document.getElementById("transfer-direction").value);
      if (!filename) {
        text("transfer-action-status", "Filename required");
        return;
      }
      const body = { filename, direction };
      if (peer) body.peer_username = peer;
      if (localPath) body.local_path = localPath;
      if (size) body.size = Number(size);
      try {
        const transfer = await postJson("/api/v0/transfers", body);
        text("transfer-action-status", `Transfer ${transfer.id} queued`);
        document.getElementById("transfer-filename").value = "";
        document.getElementById("transfer-local-path").value = "";
        await Promise.all([loadStats(), loadTransfers()]);
      } catch (error) {
        text("transfer-action-status", error.message);
      }
    }
    async function runTransferAction(id, action) {
      const body = {};
      if (action === "progress") {
        const progress = document.getElementById("transfer-progress").value.trim();
        body.bytes_transferred = progress ? Number(progress) : 1024;
      }
      if (action === "cancel" || action === "fail") body.reason = "dashboard";
      try {
        await postJson(`/api/v0/transfers/${id}/${action}`, body);
        text("transfer-action-status", `Transfer ${id} ${action}`);
        await Promise.all([loadStats(), loadTransfers()]);
      } catch (error) {
        text("transfer-action-status", error.message);
      }
    }
    async function submitMessage(event) {
      event.preventDefault();
      const username = document.getElementById("message-username").value.trim();
      const body = document.getElementById("message-body").value.trim();
      if (!username || !body) {
        text("message-action-status", "Username and message required");
        return;
      }
      try {
        await postJson("/api/v0/messages", { username, body });
        text("message-action-status", `Message queued for ${username}`);
        document.getElementById("message-body").value = "";
        await Promise.all([loadStats(), loadMessages()]);
      } catch (error) {
        text("message-action-status", error.message);
      }
    }
    async function runMessageAction(id, action) {
      try {
        await postJson(`/api/v0/messages/${id}/${action}`, {});
        text("message-action-status", `Message ${id} ${action}`);
        await Promise.all([loadStats(), loadMessages()]);
      } catch (error) {
        text("message-action-status", error.message);
      }
    }
    async function runUserAction(username, action) {
      try {
        if (action === "watch") {
          await postJson("/api/v0/users/watch", { username });
          text("watch-action-status", `${username} watched`);
          await Promise.all([loadStats(), loadUsers()]);
        } else if (action === "browse") {
          await postJson(`/api/v0/users/${encodeURIComponent(username)}/browse/request`, {});
          text("browse-action-status", `Browse requested for ${username}`);
          await Promise.all([loadStats(), loadUsers(), loadBrowse()]);
        } else if (action === "stats") {
          await postJson(`/api/v0/users/${encodeURIComponent(username)}/stats/request`, {});
          text("watch-action-status", `Stats requested for ${username}`);
          await loadUsers();
        } else if (action === "unwatch") {
          await deleteJson(`/api/v0/users/${encodeURIComponent(username)}/watch`);
          text("watch-action-status", `${username} unwatched`);
          await Promise.all([loadStats(), loadUsers()]);
        }
      } catch (error) {
        text("watch-action-status", error.message);
      }
    }
    async function submitRoomJoin(event) {
      event.preventDefault();
      const room = document.getElementById("room-join-name").value.trim();
      if (!room) {
        text("room-join-action-status", "Room required");
        return;
      }
      try {
        await postJson(`/api/v0/rooms/${encodeURIComponent(room)}/join`, {});
        text("room-join-action-status", `${room} joined`);
        document.getElementById("room-message-name").value = room;
        await Promise.all([loadStats(), loadRooms()]);
      } catch (error) {
        text("room-join-action-status", error.message);
      }
    }
    async function submitRoomMessage(event) {
      event.preventDefault();
      const room = document.getElementById("room-message-name").value.trim();
      const username = document.getElementById("room-message-username").value.trim();
      const body = document.getElementById("room-message-body").value.trim();
      if (!room || !username || !body) {
        text("room-message-action-status", "Room, username, and message required");
        return;
      }
      try {
        await postJson(`/api/v0/rooms/${encodeURIComponent(room)}/messages`, { username, body });
        text("room-message-action-status", `Message queued for ${room}`);
        document.getElementById("room-message-body").value = "";
        await Promise.all([loadStats(), loadRooms()]);
      } catch (error) {
        text("room-message-action-status", error.message);
      }
    }
    async function syncRooms() {
      try {
        await postJson("/api/v0/rooms/refresh", {});
        text("room-join-action-status", "Room refresh requested");
        await loadRooms();
      } catch (error) {
        text("room-join-action-status", error.message);
      }
    }
    async function runRoomAction(room, action) {
      try {
        if (action === "leave") {
          await deleteJson(`/api/v0/rooms/${encodeURIComponent(room)}/join`);
          text("room-join-action-status", `${room} left`);
          await Promise.all([loadStats(), loadRooms()]);
        }
      } catch (error) {
        text("room-join-action-status", error.message);
      }
    }
    function saveToken(event) {
      event.preventDefault();
      apiToken = document.getElementById("api-token").value.trim();
      if (apiToken) {
        text("token-action-status", "Session active");
      } else {
        text("token-action-status", "Session cleared");
      }
      loadAll();
    }
    document.getElementById("refresh-searches").addEventListener("click", loadSearches);
    document.getElementById("refresh-transfers").addEventListener("click", loadTransfers);
    document.getElementById("refresh-users").addEventListener("click", loadUsers);
    document.getElementById("refresh-shares").addEventListener("click", loadShares);
    document.getElementById("refresh-messages").addEventListener("click", loadMessages);
    document.getElementById("refresh-rooms").addEventListener("click", loadRooms);
    document.getElementById("sync-rooms").addEventListener("click", syncRooms);
    document.getElementById("refresh-browse").addEventListener("click", loadBrowse);
    ["search-filter-q", "search-filter-status"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadSearches);
    });
    ["transfer-filter-q", "transfer-filter-status"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadTransfers);
    });
    ["share-filter-q", "share-filter-extension"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadShares);
    });
    ["message-filter-q", "message-filter-direction"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadMessages);
    });
    ["room-filter-q", "room-filter-joined"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadRooms);
    });
    ["browse-filter-q", "browse-filter-status"].forEach((id) => {
      document.getElementById(id).addEventListener("change", loadBrowse);
    });
    document.getElementById("session-actions").addEventListener("click", (event) => {
      const action = event.target?.dataset?.sessionAction;
      if (action) runSessionAction(action);
    });
    document.getElementById("transfer-table").addEventListener("click", (event) => {
      const action = event.target?.dataset?.transferAction;
      const id = event.target?.dataset?.transferId;
      if (action && id) runTransferAction(id, action);
    });
    document.getElementById("search-table").addEventListener("click", (event) => {
      const action = event.target?.dataset?.searchAction;
      const token = event.target?.dataset?.searchToken;
      if (action && token) runSearchAction(token, action);
    });
    document.getElementById("message-table").addEventListener("click", (event) => {
      const action = event.target?.dataset?.messageAction;
      const id = event.target?.dataset?.messageId;
      if (action && id) runMessageAction(id, action);
    });
    document.getElementById("user-table").addEventListener("click", (event) => {
      const action = event.target?.dataset?.userAction;
      const username = event.target?.dataset?.username;
      if (action && username) runUserAction(username, action);
    });
    document.getElementById("room-table").addEventListener("click", (event) => {
      const action = event.target?.dataset?.roomAction;
      const room = event.target?.dataset?.room;
      if (action && room) runRoomAction(room, action);
    });
    document.getElementById("search-form").addEventListener("submit", submitSearch);
    document.getElementById("watch-form").addEventListener("submit", submitWatch);
    document.getElementById("unwatch-button").addEventListener("click", submitUnwatch);
    document.getElementById("browse-request-form").addEventListener("submit", submitBrowseRequest);
    document.getElementById("share-rescan-form").addEventListener("submit", submitShareRescan);
    document.getElementById("transfer-form").addEventListener("submit", submitTransfer);
    document.getElementById("message-form").addEventListener("submit", submitMessage);
    document.getElementById("room-join-form").addEventListener("submit", submitRoomJoin);
    document.getElementById("room-message-form").addEventListener("submit", submitRoomMessage);
    document.getElementById("token-form").addEventListener("submit", saveToken);
    loadAll();
    setInterval(loadStats, 5000);
  </script>
</body>
</html>"#
        .replace(
            "__VERSION__",
            &format!("{CLIENT_MAJOR_VERSION}.{CLIENT_MINOR_VERSION}"),
        )
}

async fn rebuild_share_index(state: &AppState) -> Result<ShareIndexSnapshot, String> {
    let _scan_permit = Arc::clone(&state.share_scans)
        .try_acquire_owned()
        .map_err(|_| SHARE_SCAN_BUSY_ERROR.to_owned())?;
    {
        let mut lifecycle = state.share_lifecycle.write().await;
        lifecycle.scanning = true;
        lifecycle.faulted = false;
        lifecycle.cancelled = false;
        lifecycle.scan_progress = 0.0;
    }
    let mut config = state.config.clone();
    config.share_settings = state.share_settings.read().await.clone();
    let snapshot = tokio::task::spawn_blocking(move || build_share_index(&config))
        .await
        .map_err(|_| SHARE_SCAN_WORKER_ERROR.to_owned());
    let snapshot = match snapshot {
        Ok(snapshot) => snapshot,
        Err(error) => {
            let mut lifecycle = state.share_lifecycle.write().await;
            lifecycle.scanning = false;
            lifecycle.faulted = true;
            return Err(error);
        }
    };
    let mut shares = state.shares.write().await;
    let previous = std::mem::replace(&mut *shares, snapshot.clone());
    if let Err(error) = persist_share_index_checked(state, &snapshot).await {
        *shares = previous;
        let mut lifecycle = state.share_lifecycle.write().await;
        lifecycle.scanning = false;
        lifecycle.faulted = true;
        return Err(error);
    }
    drop(shares);
    *state.share_lifecycle.write().await = ShareLifecycleState::from_snapshot(&snapshot);
    Ok(snapshot)
}

fn share_rebuild_error_response(error: &str) -> HttpResponse {
    if error == SHARE_SCAN_BUSY_ERROR {
        routing::service_unavailable_response(SHARE_SCAN_BUSY_ERROR)
    } else {
        routing::service_unavailable_response("share index unavailable")
    }
}

async fn persist_share_index_checked(
    state: &AppState,
    snapshot: &ShareIndexSnapshot,
) -> Result<bool, String> {
    let Some(db) = state.db.as_ref() else {
        return Ok(false);
    };
    let records = persisted_share_file_records(snapshot);
    db.replace_share_files(&records)
        .await
        .map_err(|error| format!("share index persistence failed: {error}"))?;
    Ok(true)
}

fn persisted_share_file_records(
    snapshot: &ShareIndexSnapshot,
) -> Vec<persistence::ShareFileRecord> {
    let updated_at = snapshot.updated_at as i64;
    snapshot
        .entries
        .iter()
        .map(|entry| {
            let root_label = entry
                .filename
                .split(['/', '\\'])
                .next()
                .filter(|value| !value.is_empty())
                .unwrap_or("shares")
                .to_owned();
            persistence::ShareFileRecord {
                filename: entry.filename.clone(),
                size: entry.size as i64,
                extension: entry.extension.clone(),
                root_label,
                local_path: snapshot
                    .local_paths
                    .get(&entry.filename)
                    .map(|path| path.display().to_string()),
                attributes_json: encode_share_attributes(&entry.attributes),
                updated_at,
            }
        })
        .collect()
}

fn encode_share_attributes(attributes: &[FileAttribute]) -> String {
    attributes
        .iter()
        .map(|attribute| format!("{}:{}", attribute.code, attribute.value))
        .collect::<Vec<_>>()
        .join(",")
}

fn decode_share_attributes(value: &str) -> Vec<FileAttribute> {
    value
        .split(',')
        .filter_map(|pair| {
            let (code, value) = pair.split_once(':')?;
            Some(FileAttribute {
                code: code.parse().ok()?,
                value: value.parse().ok()?,
            })
        })
        .take(slskr_client::protocol::peer::MAX_FILE_ATTRIBUTES)
        .collect()
}

fn build_share_index(config: &AppConfig) -> ShareIndexSnapshot {
    let filters = compile_controller_regexes(
        &config.share_settings.filters,
        config.controller_case_sensitive_regex,
    )
    .expect("validated share filters must compile");
    let mut scan = scan_share_dirs(
        &config.share_settings.directories,
        config.share_settings.follow_symlinks,
        config.share_settings.include_hidden,
        config.share_settings.max_files,
        config.share_settings.probe_media_attributes,
        config.share_settings.cache_workers,
        &filters,
    );
    let fixture_files = config.share_settings.fixture_entries.len();
    let mut entries = config.share_settings.fixture_entries.clone();
    entries.append(&mut scan.entries);
    let cache_path = share_cache_path(&config.state_dir);
    let (cache_written_at, cache_error) = write_share_cache_if_enabled(
        config.share_settings.cache_tsv_enabled,
        &cache_path,
        &entries,
    );

    ShareIndexSnapshot {
        entries,
        local_paths: scan.local_paths,
        roots: scan.roots,
        fixture_files,
        scan_errors: scan.errors,
        cache_path,
        cache_enabled: config.share_settings.cache_tsv_enabled,
        cache_written_at,
        cache_error,
        updated_at: unix_timestamp(),
    }
}

fn scan_share_dirs(
    directories: &[ShareDirectory],
    follow_symlinks: bool,
    include_hidden: bool,
    max_files: usize,
    probe_media_attributes: bool,
    workers: usize,
    filters: &[ControllerRegex],
) -> ShareScan {
    let options = ShareScanOptions {
        follow_symlinks,
        include_hidden,
        max_files,
        probe_media_attributes,
    };
    let exclusions = directories
        .iter()
        .filter(|directory| directory.is_excluded)
        .map(|directory| directory.local_path.clone())
        .collect::<Vec<_>>();

    let mut ordered_directories = directories.to_vec();
    ordered_directories.sort_by(|left, right| {
        right
            .local_path
            .as_os_str()
            .len()
            .cmp(&left.local_path.as_os_str().len())
    });
    let active = ordered_directories
        .iter()
        .enumerate()
        .filter(|(_, directory)| !directory.is_excluded)
        .map(|(index, directory)| (index, directory.clone()))
        .collect::<Vec<_>>();
    let worker_count = workers.max(1).min(active.len().max(1));
    let mut groups = (0..worker_count).map(|_| Vec::new()).collect::<Vec<_>>();
    for (position, item) in active.into_iter().enumerate() {
        groups[position % worker_count].push(item);
    }
    let scanned = std::thread::scope(|scope| {
        groups
            .into_iter()
            .map(|group| {
                let exclusions = &exclusions;
                let filters = filters;
                scope.spawn(move || {
                    group
                        .into_iter()
                        .map(|(index, directory)| {
                            let scan = scan_single_share_directory(
                                &directory,
                                &exclusions,
                                filters,
                                options,
                            );
                            (index, scan)
                        })
                        .collect::<Vec<_>>()
                })
            })
            .collect::<Vec<_>>()
            .into_iter()
            .flat_map(|worker| worker.join().unwrap_or_default())
            .collect::<BTreeMap<_, _>>()
    });

    let mut entries = Vec::new();
    let mut local_paths = BTreeMap::new();
    let mut root_summaries = Vec::new();
    let mut errors = Vec::new();
    for (index, directory) in ordered_directories.iter().enumerate() {
        let mut scan = scanned.get(&index).cloned().unwrap_or(ShareScan {
            entries: Vec::new(),
            local_paths: BTreeMap::new(),
            roots: Vec::new(),
            errors: Vec::new(),
        });
        let remaining = max_files.saturating_sub(entries.len());
        scan.entries.truncate(remaining);
        let accepted = scan
            .entries
            .iter()
            .map(|entry| entry.filename.as_str())
            .collect::<HashSet<_>>();
        scan.local_paths
            .retain(|filename, _| accepted.contains(filename.as_str()));
        root_summaries.push(share_root_summary(directory, &scan.entries));
        entries.append(&mut scan.entries);
        local_paths.append(&mut scan.local_paths);
        errors.append(&mut scan.errors);
        if entries.len() >= max_files {
            break;
        }
    }

    ShareScan {
        entries,
        local_paths,
        roots: root_summaries,
        errors,
    }
}

fn scan_single_share_directory(
    directory: &ShareDirectory,
    exclusions: &[PathBuf],
    filters: &[ControllerRegex],
    options: ShareScanOptions,
) -> ShareScan {
    let mut entries = Vec::new();
    let mut local_paths = BTreeMap::new();
    let mut errors = Vec::new();
    let mut scanned_entries = 0;
    let mut output = ShareScanOutput {
        entries: &mut entries,
        local_paths: &mut local_paths,
        errors: &mut errors,
        scanned_entries: &mut scanned_entries,
    };
    scan_share_root(
        &directory.local_path,
        &directory.alias,
        exclusions,
        filters,
        options,
        &mut output,
    );
    ShareScan {
        entries,
        local_paths,
        roots: Vec::new(),
        errors,
    }
}

fn share_root_summary(directory: &ShareDirectory, entries: &[FileEntry]) -> ShareRoot {
    ShareRoot {
        label: directory.alias.clone(),
        local_path: directory.local_path.clone(),
        raw: directory.raw.clone(),
        directories: entries
            .iter()
            .filter_map(|entry| entry.filename.split_once('/').map(|(_, path)| path))
            .filter_map(|path| path.rsplit_once('/').map(|(directory, _)| directory))
            .flat_map(|directory| {
                let parts = directory.split('/').collect::<Vec<_>>();
                (1..=parts.len())
                    .map(move |count| parts[..count].join("/"))
                    .collect::<Vec<_>>()
            })
            .collect::<HashSet<_>>()
            .len(),
        files: entries.len(),
        bytes: entries.iter().map(|entry| entry.size).sum(),
        extensions: summarize_extensions(entries),
        statistics_ready: true,
    }
}

fn summarize_extensions(entries: &[FileEntry]) -> Vec<ShareExtensionSummary> {
    let mut summaries = BTreeMap::<String, (usize, u64)>::new();
    for entry in entries {
        let extension = if entry.extension.is_empty() {
            "(none)".to_owned()
        } else {
            entry.extension.to_ascii_lowercase()
        };
        let summary = summaries.entry(extension).or_default();
        summary.0 += 1;
        summary.1 += entry.size;
    }
    summaries
        .into_iter()
        .map(|(extension, (files, bytes))| ShareExtensionSummary {
            extension,
            files,
            bytes,
        })
        .collect()
}

struct ShareScanOutput<'a> {
    entries: &'a mut Vec<FileEntry>,
    local_paths: &'a mut BTreeMap<String, PathBuf>,
    errors: &'a mut Vec<String>,
    scanned_entries: &'a mut usize,
}

fn scan_share_root(
    root: &Path,
    label: &str,
    exclusions: &[PathBuf],
    filters: &[ControllerRegex],
    options: ShareScanOptions,
    output: &mut ShareScanOutput<'_>,
) {
    if output.entries.len() >= options.max_files {
        return;
    }

    #[cfg(unix)]
    if !options.follow_symlinks {
        scan_share_root_unix(root, label, exclusions, filters, options, output);
        return;
    }

    let metadata = if options.follow_symlinks {
        fs::metadata(root)
    } else {
        fs::symlink_metadata(root)
    };
    let Ok(metadata) = metadata else {
        output.errors.push(format!(
            "{}: metadata unavailable",
            json_safe_share_label(label)
        ));
        return;
    };
    if !metadata.is_dir() {
        output
            .errors
            .push(format!("{}: not a directory", json_safe_share_label(label)));
        return;
    }
    let canonical_root = if options.follow_symlinks {
        match root.canonicalize() {
            Ok(path) => Some(path),
            Err(_) => {
                output.errors.push(format!(
                    "{}: canonical root unavailable",
                    json_safe_share_label(label)
                ));
                return;
            }
        }
    } else {
        None
    };

    let mut stack = vec![root.to_path_buf()];
    while let Some(directory) = stack.pop() {
        if output.entries.len() >= options.max_files {
            output
                .errors
                .push("share scan stopped at SLSKR_SHARE_SCAN_MAX_FILES".to_owned());
            return;
        }

        let read_dir = match fs::read_dir(&directory) {
            Ok(read_dir) => read_dir,
            Err(_) => {
                output.errors.push(format!(
                    "{}: directory unreadable",
                    json_safe_share_label(label)
                ));
                continue;
            }
        };

        for child in read_dir {
            if output.entries.len() >= options.max_files {
                output
                    .errors
                    .push("share scan stopped at SLSKR_SHARE_SCAN_MAX_FILES".to_owned());
                return;
            }

            if !reserve_share_scan_entry(output.scanned_entries) {
                output.errors.push(SHARE_SCAN_ENTRY_LIMIT_ERROR.to_owned());
                return;
            }

            let Ok(child) = child else {
                output.errors.push(format!(
                    "{}: entry unreadable",
                    json_safe_share_label(label)
                ));
                continue;
            };
            let path = child.path();
            if exclusions.iter().any(|excluded| path.starts_with(excluded)) {
                continue;
            }
            if filters
                .iter()
                .any(|filter| filter.is_match(&path.to_string_lossy()))
            {
                continue;
            }
            if !options.include_hidden && is_hidden_share_path(root, &path) {
                continue;
            }

            let metadata = if options.follow_symlinks {
                fs::metadata(&path)
            } else {
                fs::symlink_metadata(&path)
            };
            let Ok(metadata) = metadata else {
                output.errors.push(format!(
                    "{}: entry metadata unavailable",
                    json_safe_share_label(label)
                ));
                continue;
            };
            if metadata.file_type().is_symlink() && !options.follow_symlinks {
                continue;
            }
            if metadata.is_dir() {
                stack.push(path);
                continue;
            }
            if !metadata.is_file() {
                continue;
            }
            if let Some(canonical_root) = canonical_root.as_ref() {
                let Ok(canonical_path) = path.canonicalize() else {
                    output.errors.push(format!(
                        "{}: entry canonical path unavailable",
                        json_safe_share_label(label)
                    ));
                    continue;
                };
                if !canonical_path.starts_with(canonical_root) {
                    continue;
                }
            }

            let Ok(relative) = path.strip_prefix(root) else {
                continue;
            };
            let filename = format!("{}/{}", label, virtual_share_path(relative));
            let extension = extension_for(&filename);
            let attributes = if options.probe_media_attributes {
                probe_media_attributes(&path, &extension, metadata.len())
            } else {
                Vec::new()
            };
            output.local_paths.insert(filename.clone(), path.clone());
            output.entries.push(FileEntry {
                filename_encoding: Default::default(),
                extension_encoding: Default::default(),
                code: 1,
                filename: filename.clone(),
                size: metadata.len(),
                extension,
                attributes,
            });
        }
    }
}

#[cfg(unix)]
fn scan_share_root_unix(
    root: &Path,
    label: &str,
    exclusions: &[PathBuf],
    filters: &[ControllerRegex],
    options: ShareScanOptions,
    output: &mut ShareScanOutput<'_>,
) {
    use rustix::fs::{open, openat, Dir, Mode, OFlags};
    use std::os::unix::ffi::OsStrExt;

    let directory_flags = OFlags::RDONLY | OFlags::DIRECTORY | OFlags::NOFOLLOW | OFlags::CLOEXEC;
    let file_flags = OFlags::RDONLY | OFlags::NONBLOCK | OFlags::NOFOLLOW | OFlags::CLOEXEC;
    let root_directory = match open(root, directory_flags, Mode::empty()) {
        Ok(directory) => directory,
        Err(_) => {
            output.errors.push(format!(
                "{}: directory unavailable",
                json_safe_share_label(label)
            ));
            return;
        }
    };
    let mut stack = vec![(PathBuf::new(), root_directory)];
    while let Some((relative_directory, directory)) = stack.pop() {
        if output.entries.len() >= options.max_files {
            output
                .errors
                .push("share scan stopped at SLSKR_SHARE_SCAN_MAX_FILES".to_owned());
            return;
        }
        let mut reader = match Dir::read_from(&directory) {
            Ok(reader) => reader,
            Err(_) => {
                output.errors.push(format!(
                    "{}: directory unreadable",
                    json_safe_share_label(label)
                ));
                continue;
            }
        };
        while let Some(child) = reader.read() {
            if output.entries.len() >= options.max_files {
                output
                    .errors
                    .push("share scan stopped at SLSKR_SHARE_SCAN_MAX_FILES".to_owned());
                return;
            }
            if !reserve_share_scan_entry(output.scanned_entries) {
                output.errors.push(SHARE_SCAN_ENTRY_LIMIT_ERROR.to_owned());
                return;
            }
            let Ok(child) = child else {
                output.errors.push(format!(
                    "{}: entry unreadable",
                    json_safe_share_label(label)
                ));
                continue;
            };
            let name = child.file_name();
            if matches!(name.to_bytes(), b"." | b"..") {
                continue;
            }
            let name_os = std::ffi::OsStr::from_bytes(name.to_bytes());
            if !options.include_hidden && name_os.to_string_lossy().starts_with('.') {
                continue;
            }
            let relative = relative_directory.join(name_os);
            if filters
                .iter()
                .any(|filter| filter.is_match(&root.join(&relative).to_string_lossy()))
            {
                continue;
            }
            if exclusions
                .iter()
                .any(|excluded| root.join(&relative).starts_with(excluded))
            {
                continue;
            }
            if let Ok(child_directory) = openat(&directory, name, directory_flags, Mode::empty()) {
                if stack.len() >= MAX_SHARE_SCAN_PENDING_DIRECTORIES {
                    output
                        .errors
                        .push(SHARE_SCAN_PENDING_DIRECTORY_LIMIT_ERROR.to_owned());
                    return;
                }
                stack.push((relative, child_directory));
                continue;
            }
            let Ok(file) = openat(&directory, name, file_flags, Mode::empty()) else {
                continue;
            };
            let mut file = fs::File::from(file);
            let Ok(metadata) = file.metadata() else {
                output.errors.push(format!(
                    "{}: entry metadata unavailable",
                    json_safe_share_label(label)
                ));
                continue;
            };
            if !metadata.is_file() {
                continue;
            }
            let filename = format!("{}/{}", label, virtual_share_path(&relative));
            let extension = extension_for(&filename);
            let attributes = if options.probe_media_attributes {
                probe_media_attributes_from_file(&mut file, &extension, metadata.len())
            } else {
                Vec::new()
            };
            output
                .local_paths
                .insert(filename.clone(), root.join(&relative));
            output.entries.push(FileEntry {
                filename_encoding: Default::default(),
                extension_encoding: Default::default(),
                code: 1,
                filename: filename.clone(),
                size: metadata.len(),
                extension,
                attributes,
            });
        }
    }
}

fn share_root_id(alias: &str) -> String {
    let mut digest = <Sha1 as Sha1Digest>::new();
    Sha1Digest::update(&mut digest, alias.as_bytes());
    hex::encode_upper(Sha1Digest::finalize(digest))
}

fn virtual_share_path(path: &Path) -> String {
    path.components()
        .filter_map(|component| match component {
            std::path::Component::Normal(name) => name.to_str().map(sanitize_share_component),
            _ => None,
        })
        .collect::<Vec<_>>()
        .join("/")
}

fn sanitize_share_component(value: &str) -> String {
    value.replace(['\\', '/'], "_").trim().to_owned()
}

fn is_hidden_share_path(root: &Path, path: &Path) -> bool {
    path.strip_prefix(root)
        .ok()
        .map(|relative| {
            relative.components().any(|component| {
                matches!(component, std::path::Component::Normal(name) if name.to_string_lossy().starts_with('.'))
            })
        })
        .unwrap_or(false)
}

fn json_safe_share_label(label: &str) -> String {
    label.chars().take(80).collect()
}

fn share_cache_path(state_dir: &Path) -> PathBuf {
    state_dir.join("share-index.tsv")
}

fn write_share_cache_if_enabled(
    enabled: bool,
    path: &Path,
    entries: &[FileEntry],
) -> (Option<u64>, Option<String>) {
    if !enabled {
        return (None, None);
    }
    match write_share_cache(path, entries) {
        Ok(()) => (Some(unix_timestamp()), None),
        Err(error) => (None, Some(error)),
    }
}

fn write_share_cache(path: &Path, entries: &[FileEntry]) -> Result<(), String> {
    let mut body = String::from("slskr-share-index-v1\n");
    for entry in entries {
        body.push_str(&entry.code.to_string());
        body.push('\t');
        body.push_str(&entry.size.to_string());
        body.push('\t');
        body.push_str(&escape_cache_field(&entry.extension));
        body.push('\t');
        body.push_str(&escape_cache_field(&entry.filename));
        body.push('\n');
    }
    write_file_atomic(path, body).map_err(|error| format!("share cache write failed: {error}"))
}

fn transfer_events_path(state_dir: &Path) -> PathBuf {
    state_dir.join("transfer-events.tsv")
}

fn transfer_state_path(state_dir: &Path) -> PathBuf {
    state_dir.join("transfer-state.json")
}

fn write_transfer_events_header(path: &Path) -> Result<(), String> {
    write_file_atomic(
        path,
        "slskr-transfer-events-v2\nid\tdirection\ttoken\tsize\tbytes_transferred\tstatus\treason\tfilename\n",
    )
    .map_err(|error| format!("transfer events header write failed: {error}"))
}

fn rotate_transfer_events_if_needed(path: &Path) -> Result<(), String> {
    let metadata = match fs::symlink_metadata(path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(()),
        Err(error) => return Err(format!("transfer event metadata read failed: {error}")),
    };
    if metadata.file_type().is_symlink() || !metadata.is_file() {
        return Err("transfer event path must be a regular file".to_owned());
    }
    if metadata.len() <= MAX_TRANSFER_EVENTS_BYTES {
        return Ok(());
    }

    let rotated_path = path.with_extension("tsv.old");
    if rotated_path.exists() {
        fs::remove_file(&rotated_path)
            .map_err(|error| format!("transfer event rotation cleanup failed: {error}"))?;
    }
    fs::rename(path, &rotated_path)
        .map_err(|error| format!("transfer event rotation failed: {error}"))?;
    write_transfer_events_header(path)
}

#[derive(Debug, Deserialize, Serialize)]
struct TransferStateFile {
    version: u32,
    entries: Vec<TransferEntry>,
}

fn load_transfer_state(path: &Path, history_limit: usize) -> Result<Vec<TransferEntry>, String> {
    use std::io::Read;

    #[cfg(not(unix))]
    {
        let metadata = match fs::symlink_metadata(path) {
            Ok(metadata) => metadata,
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
            Err(error) => return Err(format!("transfer state metadata read failed: {error}")),
        };
        if metadata.file_type().is_symlink() || !metadata.is_file() {
            return Err("transfer state path must be a regular file".to_owned());
        }
    }
    let mut options = fs::OpenOptions::new();
    options.read(true);
    #[cfg(unix)]
    {
        use std::os::unix::fs::OpenOptionsExt;
        options.custom_flags(libc::O_NOFOLLOW | libc::O_NONBLOCK);
    }
    let file = match options.open(path) {
        Ok(file) => file,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
        Err(error) => return Err(format!("transfer state open failed: {error}")),
    };
    let opened_metadata = file
        .metadata()
        .map_err(|error| format!("transfer state metadata read failed: {error}"))?;
    if !opened_metadata.is_file() {
        return Err("transfer state path must be a regular file".to_owned());
    }
    let size = opened_metadata.len();
    if size > MAX_TRANSFER_STATE_BYTES {
        return Err(format!(
            "transfer state file is too large: {size} bytes, max is {MAX_TRANSFER_STATE_BYTES}"
        ));
    }
    let mut body = String::new();
    file.take(MAX_TRANSFER_STATE_BYTES + 1)
        .read_to_string(&mut body)
        .map_err(|error| format!("transfer state read failed: {error}"))?;
    if body.len() as u64 > MAX_TRANSFER_STATE_BYTES {
        return Err(format!(
            "transfer state file is too large: more than {MAX_TRANSFER_STATE_BYTES} bytes"
        ));
    }
    let mut state = serde_json::from_str::<TransferStateFile>(&body)
        .map_err(|error| format!("transfer state parse failed: {error}"))?;
    if state.version != 1 {
        return Err(format!(
            "unsupported transfer state version: {}",
            state.version
        ));
    }
    let now = unix_timestamp();
    for entry in &mut state.entries {
        if is_active_transfer_status(&entry.status) {
            entry.status = "queued".to_owned();
            entry.reason = Some("resumed after restart".to_owned());
            entry.started_at = None;
            entry.start_offset = entry.bytes_transferred;
            entry.updated_at = now;
        }
    }
    state.entries = state
        .entries
        .into_iter()
        .map(bounded_transfer_entry)
        .collect();
    let mut seen_ids = std::collections::HashSet::new();
    state.entries.reverse();
    state.entries.retain(|entry| seen_ids.insert(entry.id));
    state.entries.reverse();
    if state.entries.len() > history_limit {
        let extra = state.entries.len() - history_limit;
        state.entries.drain(0..extra);
    }
    Ok(state.entries)
}

fn write_transfer_state(path: &Path, entries: &[TransferEntry]) -> Result<(), String> {
    let state = TransferStateFile {
        version: 1,
        entries: entries.to_vec(),
    };
    let body = serde_json::to_string_pretty(&state)
        .map_err(|error| format!("transfer state encode failed: {error}"))?;
    write_file_atomic(path, body).map_err(|error| format!("transfer state write failed: {error}"))
}

fn write_file_atomic(path: &Path, contents: impl AsRef<[u8]>) -> std::io::Result<()> {
    let parent = path.parent().unwrap_or_else(|| Path::new("."));
    let file_name = path
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or("slskr-state");
    let temp_path = parent.join(format!(
        ".{file_name}.{}.{}.tmp",
        std::process::id(),
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|duration| duration.as_nanos())
            .unwrap_or(0)
    ));

    write_file_atomic_with_temp_path(path, &temp_path, contents.as_ref())
}

fn write_file_atomic_with_temp_path(
    path: &Path,
    temp_path: &Path,
    contents: &[u8],
) -> std::io::Result<()> {
    use std::io::Write;

    {
        let mut file = fs::OpenOptions::new()
            .write(true)
            .create_new(true)
            .open(temp_path)?;
        file.write_all(contents)?;
        file.sync_all()?;
    }

    match replace_file(temp_path, path) {
        Ok(()) => Ok(()),
        Err(error) => {
            let _ = fs::remove_file(temp_path);
            Err(error)
        }
    }
}

#[cfg(unix)]
fn replace_file(source: &Path, destination: &Path) -> std::io::Result<()> {
    fs::rename(source, destination)
}

#[cfg(not(unix))]
fn replace_file(source: &Path, destination: &Path) -> std::io::Result<()> {
    // std::fs::rename does not replace an existing destination on Windows.
    // The state directory is private and both names are fixed beneath it, so
    // removing the old entry first is the safe-code fallback available here.
    match fs::remove_file(destination) {
        Ok(()) => {}
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
        Err(error) => return Err(error),
    }
    fs::rename(source, destination)
}

fn append_transfer_event(path: &Path, entry: &TransferEntry) -> Result<(), String> {
    use std::io::Write;

    rotate_transfer_events_if_needed(path)?;

    let mut file = open_transfer_event_file(path)?;
    writeln!(
        file,
        "{}\t{}\t{}\t{}\t{}\t{}\t{}\t{}",
        entry.id,
        entry.direction,
        entry.token,
        entry.size.map(|size| size.to_string()).unwrap_or_default(),
        entry.bytes_transferred,
        escape_cache_field(&entry.status),
        escape_cache_field(entry.reason.as_deref().unwrap_or_default()),
        escape_cache_field(&entry.filename)
    )
    .map_err(|error| format!("transfer event append failed: {error}"))
}

fn open_transfer_event_file(path: &Path) -> Result<fs::File, String> {
    let mut options = fs::OpenOptions::new();
    options.create(true).append(true);
    #[cfg(unix)]
    {
        use std::os::unix::fs::OpenOptionsExt;
        options.custom_flags(libc::O_NOFOLLOW | libc::O_NONBLOCK);
    }
    let file = options
        .open(path)
        .map_err(|error| format!("transfer event open failed: {error}"))?;
    let metadata = file
        .metadata()
        .map_err(|error| format!("transfer event metadata read failed: {error}"))?;
    if !metadata.is_file() {
        return Err("transfer event path must be a regular file".to_owned());
    }
    Ok(file)
}

fn escape_cache_field(value: &str) -> String {
    let mut escaped = String::with_capacity(value.len());
    for character in value.chars() {
        match character {
            '\\' => escaped.push_str("\\\\"),
            '\t' => escaped.push_str("\\t"),
            '\n' => escaped.push_str("\\n"),
            '\r' => escaped.push_str("\\r"),
            _ => escaped.push(character),
        }
    }
    escaped
}

fn extension_for(filename: &str) -> String {
    filename
        .rsplit_once('.')
        .map(|(_, extension)| extension.to_ascii_lowercase())
        .unwrap_or_default()
}

fn probe_media_attributes(path: &Path, extension: &str, file_size: u64) -> Vec<FileAttribute> {
    let Ok(mut file) = fs::File::open(path) else {
        return Vec::new();
    };
    probe_media_attributes_from_file(&mut file, extension, file_size)
}

fn probe_media_attributes_from_file(
    file: &mut fs::File,
    extension: &str,
    file_size: u64,
) -> Vec<FileAttribute> {
    if file.seek(SeekFrom::Start(0)).is_err() {
        return Vec::new();
    }
    let mut bytes = Vec::new();
    if file.take(256 * 1024).read_to_end(&mut bytes).is_err() {
        return Vec::new();
    }
    match extension.to_ascii_lowercase().as_str() {
        "wav" => probe_wav_attributes(&bytes),
        "flac" => probe_flac_attributes(&bytes, file_size),
        "mp3" => probe_mp3_attributes(&bytes, file_size),
        _ => Vec::new(),
    }
}

fn media_attributes(
    bitrate: Option<u32>,
    duration: Option<u32>,
    variable_bitrate: Option<bool>,
    sample_rate: Option<u32>,
    bit_depth: Option<u32>,
) -> Vec<FileAttribute> {
    [
        (0, bitrate),
        (1, duration),
        (2, variable_bitrate.map(u32::from)),
        (4, sample_rate),
        (5, bit_depth),
    ]
    .into_iter()
    .filter_map(|(code, value)| value.map(|value| FileAttribute { code, value }))
    .collect()
}

fn probe_wav_attributes(bytes: &[u8]) -> Vec<FileAttribute> {
    if bytes.len() < 12 || &bytes[..4] != b"RIFF" || &bytes[8..12] != b"WAVE" {
        return Vec::new();
    }
    let mut offset = 12_usize;
    let mut sample_rate = None;
    let mut byte_rate = None;
    let mut bit_depth = None;
    let mut data_bytes = None;
    while offset.saturating_add(8) <= bytes.len() {
        let id = &bytes[offset..offset + 4];
        let size = u32::from_le_bytes(bytes[offset + 4..offset + 8].try_into().unwrap()) as usize;
        let data_start = offset + 8;
        let data_end = data_start.saturating_add(size).min(bytes.len());
        if id == b"fmt " && data_end.saturating_sub(data_start) >= 16 {
            sample_rate = Some(u32::from_le_bytes(
                bytes[data_start + 4..data_start + 8].try_into().unwrap(),
            ));
            byte_rate = Some(u32::from_le_bytes(
                bytes[data_start + 8..data_start + 12].try_into().unwrap(),
            ));
            bit_depth = Some(u16::from_le_bytes(
                bytes[data_start + 14..data_start + 16].try_into().unwrap(),
            ) as u32);
        } else if id == b"data" {
            data_bytes = Some(size as u64);
        }
        offset = data_start.saturating_add(size).saturating_add(size % 2);
    }
    let duration = byte_rate
        .filter(|rate| *rate > 0)
        .zip(data_bytes)
        .map(|(rate, size)| (size / u64::from(rate)).max(1) as u32);
    let bitrate = byte_rate.map(|rate| rate.saturating_mul(8) / 1_000);
    media_attributes(bitrate, duration, Some(false), sample_rate, bit_depth)
}

fn probe_flac_attributes(bytes: &[u8], file_size: u64) -> Vec<FileAttribute> {
    if bytes.len() < 42 || &bytes[..4] != b"fLaC" {
        return Vec::new();
    }
    let mut offset = 4_usize;
    while offset.saturating_add(4) <= bytes.len() {
        let kind = bytes[offset] & 0x7f;
        let last = bytes[offset] & 0x80 != 0;
        let length = ((bytes[offset + 1] as usize) << 16)
            | ((bytes[offset + 2] as usize) << 8)
            | bytes[offset + 3] as usize;
        let start = offset + 4;
        let end = start.saturating_add(length);
        if end > bytes.len() {
            return Vec::new();
        }
        if kind == 0 && length >= 34 {
            let packed = u64::from_be_bytes(bytes[start + 10..start + 18].try_into().unwrap());
            let sample_rate = ((packed >> 44) & 0x0f_ffff) as u32;
            let bit_depth = (((packed >> 36) & 0x1f) + 1) as u32;
            let total_samples = packed & 0x0f_ffff_ffff;
            let duration =
                (sample_rate > 0).then(|| (total_samples / u64::from(sample_rate)).max(1) as u32);
            let bitrate = duration
                .filter(|seconds| *seconds > 0)
                .map(|seconds| (file_size.saturating_mul(8) / u64::from(seconds) / 1_000) as u32);
            return media_attributes(
                bitrate,
                duration,
                Some(false),
                Some(sample_rate),
                Some(bit_depth),
            );
        }
        if last {
            break;
        }
        offset = end;
    }
    Vec::new()
}

fn probe_mp3_attributes(bytes: &[u8], file_size: u64) -> Vec<FileAttribute> {
    const MPEG1_LAYER3_BITRATES: [u16; 16] = [
        0, 32, 40, 48, 56, 64, 80, 96, 112, 128, 160, 192, 224, 256, 320, 0,
    ];
    const MPEG2_LAYER3_BITRATES: [u16; 16] = [
        0, 8, 16, 24, 32, 40, 48, 56, 64, 80, 96, 112, 128, 144, 160, 0,
    ];
    for frame in bytes.windows(4) {
        if frame[0] != 0xff || frame[1] & 0xe0 != 0xe0 {
            continue;
        }
        let version = (frame[1] >> 3) & 0x03;
        let layer = (frame[1] >> 1) & 0x03;
        if version == 1 || layer != 1 {
            continue;
        }
        let bitrate_index = (frame[2] >> 4) as usize;
        let sample_index = ((frame[2] >> 2) & 0x03) as usize;
        if sample_index == 3 {
            continue;
        }
        let bitrate = if version == 3 {
            MPEG1_LAYER3_BITRATES[bitrate_index]
        } else {
            MPEG2_LAYER3_BITRATES[bitrate_index]
        } as u32;
        if bitrate == 0 {
            continue;
        }
        let base_sample_rate = [44_100_u32, 48_000, 32_000][sample_index];
        let sample_rate = match version {
            3 => base_sample_rate,
            2 => base_sample_rate / 2,
            _ => base_sample_rate / 4,
        };
        let duration = (file_size.saturating_mul(8) / u64::from(bitrate) / 1_000).max(1) as u32;
        return media_attributes(
            Some(bitrate),
            Some(duration),
            Some(false),
            Some(sample_rate),
            None,
        );
    }
    Vec::new()
}

async fn build_file_search_response(
    state: &AppState,
    token: u32,
    query: &str,
) -> Option<FileSearchResponse> {
    if state
        .search_request_filters
        .read()
        .await
        .iter()
        .any(|filter| filter.is_match(query))
    {
        return None;
    }
    let mut results = {
        let shares = state.shares.read().await;
        search_shares(&shares.entries, query)
    };
    let response_file_limit = state
        .core_workflow_settings
        .read()
        .await
        .incoming_search
        .response_file_limit;
    results.truncate(response_file_limit);
    if results.is_empty() {
        return None;
    }

    Some(FileSearchResponse {
        username: state
            .config
            .username
            .clone()
            .unwrap_or_else(|| "slskr".to_owned()),
        token,
        results,
        slot_free: true,
        average_speed: 0,
        queue_length: 0,
        unknown: 0,
        private_results: Vec::new(),
    })
}

fn search_shares(entries: &[FileEntry], query: &str) -> Vec<FileEntry> {
    let terms = query
        .split_whitespace()
        .map(str::to_ascii_lowercase)
        .collect::<Vec<_>>();
    if terms.is_empty() {
        return Vec::new();
    }
    entries
        .iter()
        .filter(|entry| {
            let filename = entry.filename.to_ascii_lowercase();
            terms.iter().all(|term| filename.contains(term))
        })
        .cloned()
        .collect()
}

fn build_shared_file_list_payload(entries: &[FileEntry]) -> Result<Vec<u8>, String> {
    let mut writer = Writer::new();
    let folders = group_share_entries(entries);
    writer.write_u32_le(
        u32::try_from(folders.len()).map_err(|_| "too many shared folders".to_owned())?,
    );
    for (folder, files) in folders {
        writer
            .write_string(&folder)
            .map_err(|error| error.to_string())?;
        writer.write_u32_le(
            u32::try_from(files.len()).map_err(|_| "too many shared files".to_owned())?,
        );
        for file in files {
            encode_file_entry(&mut writer, &file)?;
        }
    }
    compress_zlib_payload(&writer.into_inner()).map_err(|error| error.to_string())
}

fn build_empty_browse_payload() -> Result<Vec<u8>, String> {
    let mut writer = Writer::new();
    writer.write_u32_le(0);
    writer.write_u32_le(0);
    writer.write_u32_le(0);
    compress_zlib_payload(&writer.into_inner()).map_err(|error| error.to_string())
}

fn build_folder_contents_payload(entries: &[FileEntry], folder: &str) -> Result<Vec<u8>, String> {
    let matching = entries
        .iter()
        .filter(|entry| virtual_folder(&entry.filename) == folder)
        .cloned()
        .collect::<Vec<_>>();
    build_shared_file_list_payload(&matching)
}

fn build_empty_folder_contents_payload(token: u32, folder: &str) -> Result<Vec<u8>, String> {
    let mut writer = Writer::new();
    writer.write_u32_le(token);
    writer
        .write_string(folder)
        .map_err(|error| error.to_string())?;
    writer.write_u32_le(1);
    writer
        .write_string(folder)
        .map_err(|error| error.to_string())?;
    writer.write_u32_le(0);
    compress_zlib_payload(&writer.into_inner()).map_err(|error| error.to_string())
}

fn parse_shared_file_list_payload(payload: &[u8]) -> Result<Vec<BrowseEntry>, String> {
    let decompressed = decompress_zlib_payload(payload).map_err(|error| error.to_string())?;
    let mut reader = Reader::new(&decompressed);
    let mut entries = Vec::new();
    parse_shared_file_list_section(&mut reader, &mut entries)?;
    while !reader.is_empty() {
        parse_shared_file_list_section(&mut reader, &mut entries)?;
    }
    Ok(entries)
}

fn parse_shared_file_list_section(
    reader: &mut Reader<'_>,
    entries: &mut Vec<BrowseEntry>,
) -> Result<(), String> {
    let folder_count = reader
        .read_bounded_count("shared folders", 8)
        .map_err(|error| error.to_string())?;
    for _ in 0..folder_count {
        let (folder, folder_encoding) = reader
            .read_string_with_encoding()
            .map_err(|error| error.to_string())?;
        let file_count = reader
            .read_bounded_count("shared files", 21)
            .map_err(|error| error.to_string())?;
        for _ in 0..file_count {
            let code = reader.read_u8().map_err(|error| error.to_string())?;
            let (filename, filename_encoding) = reader
                .read_string_with_encoding()
                .map_err(|error| error.to_string())?;
            let size = reader.read_u64_le().map_err(|error| error.to_string())?;
            let (extension, _) = reader
                .read_string_with_encoding()
                .map_err(|error| error.to_string())?;
            let attribute_count = reader
                .read_bounded_count("shared file attributes", 8)
                .map_err(|error| error.to_string())?;
            for _ in 0..attribute_count {
                let _code = reader.read_u32_le().map_err(|error| error.to_string())?;
                let _value = reader.read_u32_le().map_err(|error| error.to_string())?;
            }
            if code == 1 {
                if entries.len() >= MAX_BROWSE_ENTRIES_PER_USER {
                    return Err(format!(
                        "shared file list exceeds {MAX_BROWSE_ENTRIES_PER_USER} entries"
                    ));
                }
                entries.push(bounded_browse_entry(BrowseEntry {
                    filename: join_virtual_path(&folder, &filename),
                    size,
                    extension,
                    path_encoding: if folder_encoding == ProtocolTextEncoding::Utf8 {
                        filename_encoding
                    } else {
                        folder_encoding
                    },
                }));
            }
        }
    }
    Ok(())
}

fn parse_folder_file_list_payload(
    payload: &[u8],
    folder: &str,
    folder_encoding: ProtocolTextEncoding,
) -> Result<Vec<BrowseEntry>, String> {
    let decompressed = decompress_zlib_payload(payload).map_err(|error| error.to_string())?;
    let mut reader = Reader::new(&decompressed);
    let file_count = reader
        .read_bounded_count("folder files", 21)
        .map_err(|error| error.to_string())?;
    let mut entries = Vec::new();
    for _ in 0..file_count {
        let code = reader.read_u8().map_err(|error| error.to_string())?;
        let (filename, filename_encoding) = reader
            .read_string_with_encoding()
            .map_err(|error| error.to_string())?;
        let size = reader.read_u64_le().map_err(|error| error.to_string())?;
        let (extension, _) = reader
            .read_string_with_encoding()
            .map_err(|error| error.to_string())?;
        let attribute_count = reader
            .read_bounded_count("folder file attributes", 8)
            .map_err(|error| error.to_string())?;
        for _ in 0..attribute_count {
            let _code = reader.read_u32_le().map_err(|error| error.to_string())?;
            let _value = reader.read_u32_le().map_err(|error| error.to_string())?;
        }
        if code == 1 {
            if entries.len() >= MAX_BROWSE_ENTRIES_PER_USER {
                return Err(format!(
                    "folder file list exceeds {MAX_BROWSE_ENTRIES_PER_USER} entries"
                ));
            }
            entries.push(bounded_browse_entry(BrowseEntry {
                filename: join_virtual_path(folder, &filename),
                size,
                extension,
                path_encoding: if folder_encoding == ProtocolTextEncoding::Utf8 {
                    filename_encoding
                } else {
                    folder_encoding
                },
            }));
        }
    }
    reader.finish().map_err(|error| error.to_string())?;
    Ok(entries)
}

fn join_virtual_path(folder: &str, filename: &str) -> String {
    if folder.is_empty() {
        filename.to_owned()
    } else {
        format!("{folder}/{filename}")
    }
}

fn virtual_folder(filename: &str) -> &str {
    filename
        .rsplit_once('/')
        .map(|(folder, _)| folder)
        .unwrap_or("")
}

fn group_share_entries(entries: &[FileEntry]) -> Vec<(String, Vec<FileEntry>)> {
    let mut folders: Vec<(String, Vec<FileEntry>)> = Vec::new();
    for entry in entries {
        let (folder, filename) = entry
            .filename
            .rsplit_once('/')
            .map(|(folder, filename)| (folder.to_owned(), filename.to_owned()))
            .unwrap_or_else(|| ("".to_owned(), entry.filename.clone()));
        let mut file = entry.clone();
        file.filename = filename;
        if let Some((_, files)) = folders
            .iter_mut()
            .find(|(existing_folder, _)| *existing_folder == folder)
        {
            files.push(file);
        } else {
            folders.push((folder, vec![file]));
        }
    }
    folders
}

fn group_browse_entries(entries: &[BrowseEntry]) -> Vec<(String, Vec<BrowseEntry>)> {
    let mut folders: Vec<(String, Vec<BrowseEntry>)> = Vec::new();
    for entry in entries {
        let (folder, filename) = entry
            .filename
            .rsplit_once('/')
            .map(|(folder, filename)| (folder.to_owned(), filename.to_owned()))
            .unwrap_or_else(|| ("".to_owned(), entry.filename.clone()));
        let mut file = entry.clone();
        file.filename = filename;
        if let Some((_, files)) = folders
            .iter_mut()
            .find(|(existing_folder, _)| *existing_folder == folder)
        {
            files.push(file);
        } else {
            folders.push((folder, vec![file]));
        }
    }
    folders
}

fn encode_file_entry(writer: &mut Writer, entry: &FileEntry) -> Result<(), String> {
    writer.write_u8(entry.code);
    writer
        .write_string(&entry.filename)
        .map_err(|error| error.to_string())?;
    writer.write_u64_le(entry.size);
    writer
        .write_string(&entry.extension)
        .map_err(|error| error.to_string())?;
    writer.write_u32_le(
        u32::try_from(entry.attributes.len()).map_err(|_| "too many attributes".to_owned())?,
    );
    for attribute in &entry.attributes {
        writer.write_u32_le(attribute.code);
        writer.write_u32_le(attribute.value);
    }
    Ok(())
}

